                            : 'bg-white border-slate-100 text-slate-500'
                        }`}
                      >
                        {p === 'family' ? 'Família' : p === 'friends' ? 'Amigos' : p === 'couple' ? 'Casal' : 'Com Crianças'}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-widest">Observações (opcional)</label>
                  <textarea 
                    className="w-full h-24 p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary transition-all text-sm text-slate-900"
                    placeholder="Conte-nos um pouco mais sobre sua visita..."
                    value={formData.observation}
                    onChange={(e) => setFormData({...formData, observation: e.target.value})}
                  />
                </div>

                <div className="flex space-x-4">
                  <button 
                    type="button"
                    onClick={() => setStep(1)}
                    className="flex-1 py-4 bg-slate-100 text-slate-500 font-bold rounded-2xl hover:bg-slate-200 transition-all flex items-center justify-center space-x-2"
                  >
                    <ChevronLeft className="w-5 h-5" />
                    <span>Voltar</span>
                  </button>
                  <button 
                    type="submit"
                    className="flex-[2] py-4 bg-primary text-white font-bold rounded-2xl shadow-lg flex items-center justify-center space-x-2 hover:bg-[#003680] transition-all"
                  >
                    <span>Finalizar Avaliação</span>
                    <Send className="w-5 h-5" />
                  </button>
                </div>
              </div>
            )}
          </form>
        </div>
      </div>
    </div>
  );
};

export default FeedbackForm;

import React, { useState, useEffect } from 'react';
import { User, UserRole, Company } from './types';
import { MOCK_USERS, MOCK_COMPANIES } from './constants';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import CaseManagement from './components/CaseManagement';
import FeedbackForm from './components/FeedbackForm';
import { LogIn, ShieldAlert } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedCompanyId, setSelectedCompanyId] = useState<string>('');
  const [isPublicForm, setIsPublicForm] = useState(false);
  const [loginEmail, setLoginEmail] = useState('');
  const [loginPass, setLoginPass] = useState('');
  const [error, setError] = useState('');

  // Auto-select company based on role
  useEffect(() => {
    if (user) {
      if (user.role === UserRole.MASTER) {
        setSelectedCompanyId(MOCK_COMPANIES[0].id);
      } else if (user.companyId) {
        setSelectedCompanyId(user.companyId);
      }
    }
  }, [user]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const found = MOCK_USERS.find(u => u.email === loginEmail);
    if (found) {
      setUser(found);
      setError('');
    } else {
      setError('Credenciais inválidas. Tente master@ativare.com ou dono@pizza.com');
    }
  };

  const handleLogout = () => {
    setUser(null);
    setActiveTab('dashboard');
  };

  // Public Feedback Form Access
  if (isPublicForm) {
    const comp = MOCK_COMPANIES[0]; // Simulation: always first company for public link
    return <FeedbackForm company={comp} onFinished={() => setIsPublicForm(false)} />;
  }

  // Auth Guard
  if (!user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-6 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]">
