          <div className="text-center mb-10">
            <div className="w-16 h-16 bg-primary rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-xl shadow-primary/30">
              <span className="text-3xl font-black text-white italic">A</span>
            </div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tight">Ativare <span className="text-primary">Experience</span></h1>
            <p className="text-slate-500 font-medium mt-2">Plataforma Profissional de Gestão de CX</p>
          </div>

          <div className="bg-white rounded-[32px] shadow-2xl p-10 border border-white">
            <form onSubmit={handleLogin} className="space-y-6">
              <div className="space-y-2">
                <label className="text-xs font-black uppercase tracking-widest text-slate-400">E-mail Corporativo</label>
                <input 
                  type="email" 
                  value={loginEmail}
                  onChange={(e) => setLoginEmail(e.target.value)}
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary transition-all text-sm font-semibold text-slate-900"
                  placeholder="ex: voce@empresa.com"
                  required
                />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-black uppercase tracking-widest text-slate-400">Sua Senha</label>
                <input 
                  type="password" 
                  value={loginPass}
                  onChange={(e) => setLoginPass(e.target.value)}
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary transition-all text-sm font-semibold text-slate-900"
                  placeholder="••••••••"
                  required
                />
              </div>

              {error && (
                <div className="p-4 bg-red-50 rounded-2xl border border-red-100 flex items-start space-x-3">
                  <ShieldAlert className="w-5 h-5 text-red-500 mt-0.5 shrink-0" />
                  <p className="text-xs font-bold text-red-600 leading-relaxed">{error}</p>
                </div>
              )}

              <button 
                type="submit"
                className="w-full py-4 bg-primary text-white font-bold rounded-2xl shadow-lg shadow-primary/20 hover:bg-[#003680] hover:-translate-y-1 transition-all flex items-center justify-center space-x-2"
              >
                <LogIn className="w-5 h-5" />
                <span>Entrar no Sistema</span>
              </button>
            </form>

            <div className="mt-8 pt-8 border-t border-slate-100 flex flex-col items-center space-y-4">
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Acesso Rápido para Testes</p>
              <div className="flex flex-wrap justify-center gap-2">
                <button onClick={() => { setLoginEmail('master@ativare.com'); setLoginPass('123456'); }} className="px-3 py-1 bg-slate-100 text-[10px] font-black uppercase rounded-lg hover:bg-slate-200 transition-all text-slate-600">Master</button>
                <button onClick={() => { setLoginEmail('dono@pizza.com'); setLoginPass('123456'); }} className="px-3 py-1 bg-slate-100 text-[10px] font-black uppercase rounded-lg hover:bg-slate-200 transition-all text-slate-600">Business</button>
                <button onClick={() => setIsPublicForm(true)} className="px-3 py-1 bg-accent text-white text-[10px] font-black uppercase rounded-lg hover:opacity-90 transition-all">Página de Avaliação</button>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // Active Dashboard
  return (
    <Layout 
      user={user} 
      onLogout={handleLogout} 
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
      selectedCompanyId={selectedCompanyId}
      setSelectedCompanyId={setSelectedCompanyId}
    >
      {activeTab === 'dashboard' && <Dashboard companyId={selectedCompanyId} />}
      {activeTab === 'cases' && <CaseManagement companyId={selectedCompanyId} />}

      {(activeTab === 'feedbacks' || activeTab === 'customers' || activeTab === 'benchmarking' || activeTab === 'bi') && (
        <div className="bg-white rounded-[32px] p-12 text-center border border-dashed border-slate-200">
          <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 text-slate-300">
            <ShieldAlert className="w-10 h-10" />
