import React, { useState, useMemo } from 'react';
import { dataStore } from '../services/dataStore';
import { Feedback, NPSCategory } from '../types';
import { 
  Search, 
  Filter, 
  ChevronDown, 
  ChevronUp, 
  Share2, 
  Calendar, 
  Star, 
  User,
  Phone,
  Mail,
  MapPin,
