                      </td>
                    </tr>

                    {/* Expanded Detail View */}
                    {expandedId === f.id && (
                      <tr>
                        <td colSpan={5} className="px-8 py-6 bg-slate-50/50">
                          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 animate-in slide-in-from-top duration-300">
