import { Feedback, Case, Customer, NPSCategory, CaseStatus, ContactLog, ContactLogType } from '../types';
import { MOCK_COMPANIES } from '../constants';

class DataStore {
  private feedbacks: Feedback[] = [];
  private cases: Case[] = [];
  private customers: Customer[] = [];

  constructor() {
    this.initMockData();
  }

  private initMockData() {
    MOCK_COMPANIES.forEach(comp => {
      // Create some unique customers first
      for (let j = 0; j < 10; j++) {
        const phone = `1198888000${j}`;
        const customerId = `cust-${comp.id}-${j}`;

        // Feedbacks for this specific customer
        const customerFeedbacks: Feedback[] = [];
        const numFeedbacks = Math.floor(Math.random() * 3) + 1;

        for(let i = 0; i < numFeedbacks; i++) {
          const scores = {
            service: Math.floor(Math.random() * 6) + 5,
            food: Math.floor(Math.random() * 6) + 5,
            drinks: Math.floor(Math.random() * 6) + 5,
            structure: Math.floor(Math.random() * 6) + 5,
          };
          const avg = (scores.service + scores.food + scores.drinks + scores.structure) / 4;
          let cat: NPSCategory = 'PASSIVE';
          if (avg >= 9) cat = 'PROMOTER';
          else if (avg <= 6) cat = 'DETRACTOR';

          const f: Feedback = {
            id: `f-${comp.id}-${j}-${i}`,
            companyId: comp.id,
            customerId: customerId,
            customerName: `Cliente Exemplo ${j}`,
            customerPhone: phone,
            howKnown: 'Instagram',
            scores,
            profile: i === 0 ? 'family' : 'friends',
            observation: cat === 'DETRACTOR' ? 'Demorou muito.' : 'Excelente!',
            createdAt: new Date(Date.now() - (i * 5 * 24 * 60 * 60 * 1000)).toISOString(),
            category: cat,
            averageScore: avg,
            email: `cliente${j}@email.com`
          };
          this.feedbacks.push(f);
          customerFeedbacks.push(f);

          if (cat === 'DETRACTOR') {
            this.cases.push({
              id: `case-${f.id}`,
              feedbackId: f.id,
              companyId: comp.id,
              status: 'OPEN',
              notes: [{ id: 'n1', userId: 'system', userName: 'System', text: 'Caso Automático', createdAt: f.createdAt }],
              updatedAt: new Date().toISOString()
            });
          }
        }

        // Create Customer Record
        const totalAvg = customerFeedbacks.reduce((acc, curr) => acc + curr.averageScore, 0) / customerFeedbacks.length;
        this.customers.push({
          id: customerId,
          companyId: comp.id,
          name: customerFeedbacks[0].customerName,
          phone: phone,
          email: customerFeedbacks[0].email,
          profile: customerFeedbacks[0].profile,
          firstSeen: customerFeedbacks[customerFeedbacks.length - 1].createdAt,
          lastSeen: customerFeedbacks[0].createdAt,
          averageScore: totalAvg,
          totalFeedbacks: customerFeedbacks.length,
          category: totalAvg >= 9 ? 'PROMOTER' : totalAvg <= 6 ? 'DETRACTOR' : 'PASSIVE',
          contactLogs: [
            { id: 'l1', type: 'VISIT', text: 'Primeira visita registrada', userId: 'system', userName: 'System', createdAt: customerFeedbacks[customerFeedbacks.length - 1].createdAt }
          ]
        });
      }
    });
  }

  getFeedbacks(companyId?: string) {
    return companyId ? this.feedbacks.filter(f => f.companyId === companyId) : this.feedbacks;
  }

  getCustomers(companyId: string) {
    return this.customers.filter(c => c.companyId === companyId);
  }

  getCustomerHistory(customerId: string) {
    return this.feedbacks
      .filter(f => f.customerId === customerId)
      .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }

  addContactLog(customerId: string, log: Omit<ContactLog, 'id' | 'createdAt'>) {
    const customer = this.customers.find(c => c.id === customerId);
    if (customer) {
      customer.contactLogs.unshift({
        ...log,
        id: `log-${Date.now()}`,
        createdAt: new Date().toISOString()
      });
    }
  }

  getCaseForFeedback(feedbackId: string) {
    return this.cases.find(c => c.feedbackId === feedbackId);
  }

  getCases(companyId?: string) {
    return companyId ? this.cases.filter(c => c.companyId === companyId) : this.cases;
  }

  createCaseFromFeedback(feedbackId: string, companyId: string, internalObservation: string, userName: string, userId: string) {
    if (this.getCaseForFeedback(feedbackId)) return;
    const newCase: Case = {
      id: `case-${feedbackId}`,
      feedbackId,
      companyId,
      status: 'OPEN',
      notes: [{ id: `n-${Date.now()}`, userId, userName, text: internalObservation || 'Aberto via CRM', createdAt: new Date().toISOString() }],
      updatedAt: new Date().toISOString()
    };
    this.cases.push(newCase);
    return newCase;
  }

  addCaseNote(caseId: string, userId: string, userName: string, text: string) {
    const c = this.cases.find(x => x.id === caseId);
    if (c) {
      c.notes.push({ id: `note-${Date.now()}`, userId, userName, text, createdAt: new Date().toISOString() });
      c.updatedAt = new Date().toISOString();
    }
  }

  resolveCase(caseId: string, resolution: string, userName: string, userId: string) {
    const c = this.cases.find(x => x.id === caseId);
    if (c) {
      c.status = 'RESOLVED';
      c.resolutionText = resolution;
      c.notes.push({ id: `res-${Date.now()}`, userId, userName, text: `Resolvido: ${resolution}`, createdAt: new Date().toISOString() });
      c.updatedAt = new Date().toISOString();
    }
  }

  addFeedback(feedback: Omit<Feedback, 'id' | 'createdAt' | 'category' | 'averageScore'>) {
    const avg = (feedback.scores.service + feedback.scores.food + feedback.scores.drinks + feedback.scores.structure) / 4;
    let cat: NPSCategory = avg >= 9 ? 'PROMOTER' : avg <= 6 ? 'DETRACTOR' : 'PASSIVE';
    const createdAt = new Date().toISOString();

    const newFeedback: Feedback = { ...feedback, id: `f-${Date.now()}`, createdAt, category: cat, averageScore: avg };
    this.feedbacks.push(newFeedback);

    // Update or Create Customer
    let customer = this.customers.find(c => c.phone === feedback.customerPhone && c.companyId === feedback.companyId);
    if (customer) {
      customer.lastSeen = createdAt;
      customer.totalFeedbacks += 1;
      const allCustomerFbs = this.feedbacks.filter(f => f.customerId === customer!.id);
      customer.averageScore = allCustomerFbs.reduce((acc, f) => acc + f.averageScore, 0) / allCustomerFbs.length;
      customer.category = customer.averageScore >= 9 ? 'PROMOTER' : customer.averageScore <= 6 ? 'DETRACTOR' : 'PASSIVE';
      customer.contactLogs.unshift({ id: `l-${Date.now()}`, type: 'VISIT', text: 'Nova avaliação recebida', userId: 'system', userName: 'System', createdAt });
    } else {
      const newCust: Customer = {
        id: feedback.customerId,
        companyId: feedback.companyId,
        name: feedback.customerName,
        phone: feedback.customerPhone,
        email: feedback.email,
        profile: feedback.profile,
        firstSeen: createdAt,
        lastSeen: createdAt,
        averageScore: avg,
        totalFeedbacks: 1,
        category: cat,
        contactLogs: [{ id: `l-${Date.now()}`, type: 'VISIT', text: 'Primeira visita/avaliação', userId: 'system', userName: 'System', createdAt }]
      };
      this.customers.push(newCust);
    }

    if (cat === 'DETRACTOR') {
      this.cases.push({
        id: `case-${newFeedback.id}`,
        feedbackId: newFeedback.id,
        companyId: newFeedback.companyId,
        status: 'OPEN',
        notes: [{ id: 'n-auto', userId: 'system', userName: 'System', text: 'Alerta de Detrator Automático', createdAt }],
        updatedAt: createdAt
      });
    }
    return newFeedback;
  }

  getDashboardStats(companyId: string) {
    const fb = this.getFeedbacks(companyId);
    const cs = this.getCases(companyId);
    const total = fb.length;
    const promoters = fb.filter(f => f.category === 'PROMOTER').length;
    const detractors = fb.filter(f => f.category === 'DETRACTOR').length;
    const passives = fb.filter(f => f.category === 'PASSIVE').length;
    const resolvedDetractors = cs.filter(c => c.status === 'RESOLVED').length;
    const openDetractors = cs.filter(c => c.status !== 'RESOLVED').length;
    const avgScore = total > 0 ? (fb.reduce((acc, f) => acc + f.averageScore, 0) / total) * 10 : 0;
    const catAvg = {
      service: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.service, 0) / total) : 0,
      food: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.food, 0) / total) : 0,
      drinks: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.drinks, 0) / total) : 0,
      structure: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.structure, 0) / total) : 0,
    };
    return { total, promoters, detractors, passives, resolvedDetractors, openDetractors, avgScore: Math.round(avgScore), catAvg };
  }
}

