  }

  // Active Dashboard
  return (
    <Layout 
      user={user} 
      onLogout={handleLogout} 
      activeTab={activeTab} 
      setActiveTab={(tab) => {
        setActiveTab(tab);
        if (tab === 'feedbacks' || tab === 'cases' || tab === 'customers') setHasDetractorAlert(false);
      }}
