                <button onClick={handleSave} className="bg-emerald-500 text-white px-8 py-3 rounded-2xl font-black text-sm flex items-center gap-2 shadow-lg shadow-emerald-500/20">
                  <Save className="w-4 h-4" /> Salvar Pergunta
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

