import React, { useState, useMemo } from 'react';
import { Company, InternalQuestion } from '../types';
import { dataStore } from '../services/dataStore';
import { ChevronRight, ChevronLeft, Send, CheckCircle2 } from 'lucide-react';

interface FeedbackFormProps {
  company: Company;
  onFinished: () => void;
}

const FeedbackForm: React.FC<FeedbackFormProps> = ({ company, onFinished }) => {
  const [step, setStep] = useState(1);
  const internalQuestions = useMemo(() => dataStore.getInternalQuestions(company.id), [company.id]);

  const [formData, setFormData] = useState({
    name: '',
    surname: '',
    phone: '',
    email: '',
    howKnown: '',
    service: 10,
    food: 10,
    drinks: 10,
    structure: 10,
    profile: 'family' as any,
    observation: '',
    internalResponses: {} as any
  });
  const [submitted, setSubmitted] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (step < 2) {
      setStep(2);
      return;
    }

    dataStore.addFeedback({
      companyId: company.id,
      customerId: Date.now().toString(),
      customerName: `${formData.name} ${formData.surname}`,
      customerPhone: formData.phone,
      howKnown: formData.howKnown,
      scores: {
        service: formData.service,
        food: formData.food,
        drinks: formData.drinks,
        structure: formData.structure
      },
      internalResponses: formData.internalResponses,
      profile: formData.profile,
      observation: formData.observation
    });

    setSubmitted(true);
  };

  const handleInternalResponse = (qId: string, value: any) => {
    setFormData({
      ...formData,
      internalResponses: { ...formData.internalResponses, [qId]: value }
    });
  };

  const StarRating = ({ value, onChange, label, max = 10 }: any) => (
    <div className="space-y-2">
      <div className="flex justify-between items-center">
        <label className="text-sm font-bold text-slate-600">{label}</label>
        <span className="text-lg font-black text-primary">{value}</span>
      </div>
      <input 
        type="range" min="1" max={max} 
        value={value} 
        onChange={(e) => onChange(parseInt(e.target.value))}
        className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-primary"
      />
      <div className="flex justify-between text-[10px] font-bold text-slate-400 uppercase">
        <span>Regular</span>
        <span>Perfeito</span>
      </div>
    </div>
  );

  if (submitted) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-[3rem] shadow-xl p-12 text-center animate-in fade-in zoom-in duration-500">
          <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center mx-auto mb-6">
            <CheckCircle2 className="w-10 h-10" />
          </div>
          <h2 className="text-2xl font-black text-slate-900 mb-4">Obrigado pelo seu feedback!</h2>
          <p className="text-slate-500 mb-8 font-medium leading-relaxed">Sua opinião ajuda o <span className="font-bold">{company.name}</span> a oferecer uma experiência cada vez melhor.</p>
          <button 
            onClick={onFinished}
            className="w-full py-5 bg-primary text-white font-black rounded-3xl shadow-lg hover:shadow-primary/30 transition-all"
          >
            Finalizar
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-100 flex flex-col font-inter">
      <header className="bg-white border-b border-slate-200 p-8 flex flex-col items-center">
        <div className="w-20 h-20 rounded-3xl border-4 border-white shadow-2xl overflow-hidden -mt-16 mb-4">
          <img src={company.logo} alt={company.name} className="w-full h-full object-cover" />
        </div>
        <h1 className="text-2xl font-black text-slate-900">{company.name}</h1>
      </header>

      <div className="flex-1 max-w-xl w-full mx-auto p-6 md:p-10">
        <div className="bg-white rounded-[3rem] shadow-2xl overflow-hidden border border-white">
          <div className="h-3 w-full bg-slate-100">
            <div className="h-full bg-primary transition-all duration-700" style={{ width: `${step * 50}%` }}></div>
          </div>

          <form onSubmit={handleSubmit} className="p-10 space-y-10">
            {step === 1 ? (
              <div className="space-y-8 animate-in slide-in-from-right duration-300">
                <div className="space-y-1">
                  <h2 className="text-3xl font-black text-slate-900">Seja bem-vindo!</h2>
                  <p className="text-slate-400 font-medium">Conte-nos um pouco sobre sua visita hoje.</p>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Nome</label>
                    <input 
                      required
                      type="text" 
                      className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold"
                      value={formData.name}
                      onChange={(e) => setFormData({...formData, name: e.target.value})}
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Sobrenome</label>
                    <input 
                      required
                      type="text" 
                      className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold"
                      value={formData.surname}
                      onChange={(e) => setFormData({...formData, surname: e.target.value})}
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">WhatsApp de Contato</label>
                  <input 
                    required
                    type="tel" 
                    placeholder="(00) 00000-0000"
                    className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold"
                    value={formData.phone}
                    onChange={(e) => setFormData({...formData, phone: e.target.value})}
                  />
                </div>

                <div className="space-y-4">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Seu perfil hoje:</label>
                  <div className="grid grid-cols-2 gap-3">
                    {['family', 'friends', 'couple', 'kids'].map(p => (
                      <button
                        key={p}
                        type="button"
                        onClick={() => setFormData({...formData, profile: p as any})}
                        className={`p-4 rounded-2xl border-2 font-black text-xs transition-all ${
                          formData.profile === p 
                            ? 'bg-primary border-primary text-white shadow-lg' 
                            : 'bg-white border-slate-100 text-slate-400'
                        }`}
                      >
                        {p === 'family' ? 'Família' : p === 'friends' ? 'Amigos' : p === 'couple' ? 'Casal' : 'Crianças'}
                      </button>
                    ))}
                  </div>
                </div>

                <button 
                  type="submit"
                  className="w-full py-5 bg-primary text-white font-black rounded-3xl shadow-xl flex items-center justify-center gap-3 hover:translate-y-[-2px] transition-all"
                >
                  Continuar <ChevronRight className="w-5 h-5" />
                </button>
              </div>
            ) : (
              <div className="space-y-10 animate-in slide-in-from-right duration-300">
                <div className="space-y-8">
                  <h3 className="text-[10px] font-black uppercase text-slate-300 tracking-[0.2em]">Avaliação Ativare</h3>
                  <StarRating label="Atendimento" value={formData.service} onChange={(v: number) => setFormData({...formData, service: v})} />
                  <StarRating label="Comida" value={formData.food} onChange={(v: number) => setFormData({...formData, food: v})} />
                  <StarRating label="Bebidas" value={formData.drinks} onChange={(v: number) => setFormData({...formData, drinks: v})} />
                  <StarRating label="Ambiente" value={formData.structure} onChange={(v: number) => setFormData({...formData, structure: v})} />
                </div>

                {/* Perguntas Internas Dinâmicas */}
                {internalQuestions.length > 0 && (
                  <div className="space-y-10 pt-10 border-t border-slate-100">
                    <h3 className="text-[10px] font-black uppercase text-slate-300 tracking-[0.2em]">Checklist da Casa</h3>
                    {internalQuestions.map(q => (
                      <div key={q.id} className="space-y-4">
                        <label className="text-sm font-bold text-slate-700">{q.text} {q.required && '*'}</label>

                        {q.type === 'YES_NO' && (
                          <div className="flex gap-4">
                            {['SIM', 'NÃO'].map(opt => (
                              <button
                                key={opt}
                                type="button"
                                onClick={() => handleInternalResponse(q.id, opt)}
                                className={`flex-1 py-4 rounded-2xl border-2 font-black text-sm transition-all ${
                                  formData.internalResponses[q.id] === opt 
                                    ? 'bg-primary border-primary text-white shadow-lg' 
                                    : 'bg-slate-50 border-slate-50 text-slate-400'
                                }`}
                              >
                                {opt}
                              </button>
                            ))}
                          </div>
                        )}

                        {(q.type === 'SCALE_5' || q.type === 'SCALE_10') && (
                          <StarRating 
                            max={q.type === 'SCALE_5' ? 5 : 10}
                            value={formData.internalResponses[q.id] || 1} 
                            onChange={(v: number) => handleInternalResponse(q.id, v)} 
                          />
                        )}

                        {q.type === 'TEXT' && (
                          <textarea 
                            required={q.required}
                            className="w-full h-24 p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:border-primary font-medium text-sm"
                            placeholder="Sua resposta..."
                            value={formData.internalResponses[q.id] || ''}
                            onChange={(e) => handleInternalResponse(q.id, e.target.value)}
                          />
                        )}
                      </div>
                    ))}
                  </div>
                )}

                <div className="space-y-4 pt-10 border-t border-slate-100">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Observação Final</label>
                  <textarea 
                    className="w-full h-32 p-4 bg-slate-50 border border-slate-100 rounded-3xl outline-none focus:border-primary font-medium text-sm"
                    placeholder="Algo mais que gostaria de nos dizer?"
                    value={formData.observation}
                    onChange={(e) => setFormData({...formData, observation: e.target.value})}
                  />
                </div>

                <div className="flex gap-4">
                  <button type="button" onClick={() => setStep(1)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black rounded-3xl hover:bg-slate-200 transition-all flex items-center justify-center gap-2">
                    <ChevronLeft className="w-5 h-5" /> Voltar
                  </button>
                  <button type="submit" className="flex-[2] py-5 bg-primary text-white font-black rounded-3xl shadow-xl flex items-center justify-center gap-3 hover:translate-y-[-2px] transition-all">
                    Enviar Feedback <Send className="w-5 h-5" />
                  </button>
                </div>
              </div>
            )}
          </form>
        </div>
      </div>
    </div>
  );
};

export default FeedbackForm;

import React, { useState, useEffect } from 'react';
import { User, UserRole } from './types';
import { MOCK_USERS, MOCK_COMPANIES } from './constants';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import CaseManagement from './components/CaseManagement';
import FeedbackForm from './components/FeedbackForm';
import Feedbacks from './components/Feedbacks';
import Customers from './components/Customers';
import InternalFormConfig from './components/InternalFormConfig';
import InternalMetrics from './components/InternalMetrics';
import { LogIn, ShieldAlert } from 'lucide-react';
import { dataStore } from './services/dataStore';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedCompanyId, setSelectedCompanyId] = useState<string>('');
  const [isPublicForm, setIsPublicForm] = useState(false);
  const [loginEmail, setLoginEmail] = useState('');
  const [loginPass, setLoginPass] = useState('');
  const [error, setError] = useState('');

  const [hasDetractorAlert, setHasDetractorAlert] = useState(false);

  useEffect(() => {
    if (user) {
      if (user.role === UserRole.MASTER) {
        setSelectedCompanyId(MOCK_COMPANIES[0].id);
      } else if (user.companyId) {
        setSelectedCompanyId(user.companyId);
      }
    }
  }, [user]);

  const handleFeedbackSubmitted = () => {
    setIsPublicForm(false);
    const currentFeedbacks = dataStore.getFeedbacks(selectedCompanyId || MOCK_COMPANIES[0].id);
    const lastFeedback = currentFeedbacks[currentFeedbacks.length - 1];
    if (lastFeedback?.category === 'DETRACTOR') {
      setHasDetractorAlert(true);
    }
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const found = MOCK_USERS.find(u => u.email === loginEmail);
    if (found) {
      setUser(found);
      setError('');
    } else {
      setError('Credenciais inválidas. Use os botões de teste abaixo.');
    }
  };

  if (isPublicForm) {
    const comp = MOCK_COMPANIES.find(c => c.id === selectedCompanyId) || MOCK_COMPANIES[0];
    return <FeedbackForm company={comp} onFinished={handleFeedbackSubmitted} />;
  }

  if (!user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-6 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]">
        <div className="max-w-md w-full">
          <div className="text-center mb-10">
            <div className="w-16 h-16 bg-primary rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-xl shadow-primary/30">
              <span className="text-3xl font-black text-white italic">A</span>
            </div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tight">Ativare <span className="text-primary">Experience</span></h1>
            <p className="text-slate-500 font-medium mt-2">Gestão Estratégica de CX & Reputação</p>
          </div>

          <div className="bg-white rounded-[3rem] shadow-2xl p-10 border border-white">
            <form onSubmit={handleLogin} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">E-mail de Acesso</label>
                <input 
                  type="email" 
                  value={loginEmail}
                  onChange={(e) => setLoginEmail(e.target.value)}
                  className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl outline-none focus:border-primary transition-all text-sm font-bold"
                  placeholder="Seu e-mail corporativo"
                  required
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Senha</label>
                <input 
                  type="password" 
                  value={loginPass}
                  onChange={(e) => setLoginPass(e.target.value)}
                  className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl outline-none focus:border-primary transition-all text-sm font-bold"
                  placeholder="••••••••"
                  required
                />
              </div>

              {error && (
                <div className="p-4 bg-red-50 rounded-2xl border border-red-100 flex items-start space-x-3">
                  <ShieldAlert className="w-5 h-5 text-red-500 mt-0.5" />
                  <p className="text-xs font-bold text-red-600">{error}</p>
                </div>
              )}

              <button type="submit" className="w-full py-5 bg-primary text-white font-black rounded-3xl shadow-xl hover:bg-[#003680] hover:-translate-y-1 transition-all flex items-center justify-center gap-2">
                <LogIn className="w-5 h-5" /> Entrar no Ativare
              </button>
            </form>

            <div className="mt-8 pt-8 border-t border-slate-100 flex flex-col items-center gap-4">
              <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.2em]">Quick Access</p>
              <div className="flex flex-wrap justify-center gap-2">
                <button onClick={() => { setLoginEmail('master@ativare.com'); setLoginPass('123456'); }} className="px-4 py-2 bg-slate-100 text-[10px] font-black uppercase rounded-xl hover:bg-slate-200 transition-all">Master</button>
                <button onClick={() => { setLoginEmail('dono@pizza.com'); setLoginPass('123456'); }} className="px-4 py-2 bg-slate-100 text-[10px] font-black uppercase rounded-xl hover:bg-slate-200 transition-all">Business</button>
                <button onClick={() => setIsPublicForm(true)} className="px-4 py-2 bg-accent text-white text-[10px] font-black uppercase rounded-xl hover:opacity-90 transition-all">Página Pública</button>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout 
      user={user} 
      onLogout={() => setUser(null)} 
      activeTab={activeTab} 
      setActiveTab={(tab) => {
        setActiveTab(tab);
        if (['feedbacks', 'cases', 'customers'].includes(tab)) setHasDetractorAlert(false);
      }}
      selectedCompanyId={selectedCompanyId}
      setSelectedCompanyId={setSelectedCompanyId}
      hasDetractorAlert={hasDetractorAlert}
    >
      {activeTab === 'dashboard' && <Dashboard companyId={selectedCompanyId} />}
      {activeTab === 'cases' && <CaseManagement companyId={selectedCompanyId} currentUser={user} />}
      {activeTab === 'feedbacks' && <Feedbacks companyId={selectedCompanyId} currentUser={user} />}
      {activeTab === 'customers' && <Customers companyId={selectedCompanyId} currentUser={user} />}
      {activeTab === 'form_config' && <InternalFormConfig companyId={selectedCompanyId} />}
      {activeTab === 'internal_metrics' && <InternalMetrics companyId={selectedCompanyId} />}

      {['benchmarking', 'bi'].includes(activeTab) && (
        <div className="bg-white rounded-[3rem] p-20 text-center border border-dashed border-slate-200">
          <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-8 text-slate-200"><ShieldAlert className="w-12 h-12" /></div>
          <h2 className="text-3xl font-black text-slate-900 mb-2">Módulo Enterprise</h2>
          <p className="text-slate-500 font-medium max-w-sm mx-auto">Este módulo avançado de BI e benchmarking global está em fase final de homologação.</p>
        </div>
      )}
    </Layout>
  );
};

export default App;

import { Feedback, Case, Customer, NPSCategory, InternalQuestion, InternalQuestionType, ContactLog } from '../types';
import { MOCK_COMPANIES } from '../constants';

class DataStore {
  private feedbacks: Feedback[] = [];
  private cases: Case[] = [];
  private customers: Customer[] = [];
  private internalQuestions: InternalQuestion[] = [];

  constructor() {
    this.initMockData();
  }

  private initMockData() {
    MOCK_COMPANIES.forEach(comp => {
      // Mock Internal Questions
      const q1: InternalQuestion = {
        id: `q1-${comp.id}`,
        companyId: comp.id,
        text: 'O garçom ofereceu sobremesa?',
        type: 'YES_NO',
        required: true,
        active: true,
        order: 1
      };
      const q2: InternalQuestion = {
        id: `q2-${comp.id}`,
        companyId: comp.id,
        text: 'Qual a probabilidade de você indicar nosso Happy Hour?',
        type: 'SCALE_10',
        required: false,
        active: true,
        order: 2
      };
      this.internalQuestions.push(q1, q2);

      // Create some unique customers and feedbacks
      for (let j = 0; j < 8; j++) {
        const phone = `1198888000${j}`;
        const customerId = `cust-${comp.id}-${j}`;
        const fbs: Feedback[] = [];

        for(let i = 0; i < 2; i++) {
          const scores = {
            service: Math.floor(Math.random() * 5) + 6,
            food: Math.floor(Math.random() * 5) + 6,
            drinks: Math.floor(Math.random() * 5) + 6,
            structure: Math.floor(Math.random() * 5) + 6,
          };
          const avg = (scores.service + scores.food + scores.drinks + scores.structure) / 4;
          const cat: NPSCategory = avg >= 9 ? 'PROMOTER' : avg <= 6 ? 'DETRACTOR' : 'PASSIVE';

          const f: Feedback = {
            id: `f-${comp.id}-${j}-${i}`,
            companyId: comp.id,
            customerId: customerId,
            customerName: `Cliente Exemplo ${j}`,
            customerPhone: phone,
            howKnown: 'Instagram',
            scores,
            internalResponses: {
              [q1.id]: Math.random() > 0.3 ? 'SIM' : 'NÃO',
              [q2.id]: Math.floor(Math.random() * 10) + 1
            },
            profile: 'friends',
            observation: 'Tudo ótimo.',
            createdAt: new Date(Date.now() - (i * 2 * 24 * 60 * 60 * 1000)).toISOString(),
            category: cat,
            averageScore: avg,
            email: `cliente${j}@email.com`
          };
          this.feedbacks.push(f);
          fbs.push(f);

          // Create a case for detractors
          if (cat === 'DETRACTOR' && i === 0) {
            this.cases.push({
              id: `case-${f.id}`,
              feedbackId: f.id,
              companyId: comp.id,
              status: 'OPEN',
              notes: [],
              updatedAt: f.createdAt
            });
          }
        }

        // Customer Record
        const totalAvg = fbs.reduce((acc, curr) => acc + curr.averageScore, 0) / fbs.length;
        this.customers.push({
          id: customerId,
          companyId: comp.id,
          name: fbs[0].customerName,
          phone: phone,
          email: fbs[0].email,
          profile: fbs[0].profile,
          firstSeen: fbs[fbs.length-1].createdAt,
          lastSeen: fbs[0].createdAt,
          averageScore: totalAvg,
          totalFeedbacks: fbs.length,
          category: totalAvg >= 9 ? 'PROMOTER' : totalAvg <= 6 ? 'DETRACTOR' : 'PASSIVE',
          contactLogs: []
        });
      }
    });
  }

  // --- Internal Questions Management ---
  getInternalQuestions(companyId: string, onlyActive = true) {
    let qs = this.internalQuestions.filter(q => q.companyId === companyId);
    if (onlyActive) qs = qs.filter(q => q.active);
    return qs.sort((a, b) => a.order - b.order);
  }

  saveInternalQuestion(question: InternalQuestion) {
    const idx = this.internalQuestions.findIndex(q => q.id === question.id);
    if (idx >= 0) {
      this.internalQuestions[idx] = question;
    } else {
      this.internalQuestions.push(question);
    }
  }

  deleteInternalQuestion(id: string) {
    this.internalQuestions = this.internalQuestions.filter(q => q.id !== id);
  }

  // --- Internal Metrics Logic ---
  getInternalMetrics(companyId: string) {
    const qs = this.getInternalQuestions(companyId, false);
    const fbs = this.getFeedbacks(companyId);

    return qs.map(q => {
      const responses = fbs
        .map(f => f.internalResponses?.[q.id])
        .filter(r => r !== undefined && r !== null);

      let avg: any = 0;
      if (q.type === 'SCALE_5' || q.type === 'SCALE_10') {
        avg = responses.length > 0 
          ? responses.reduce((acc: number, val: any) => acc + Number(val), 0) / responses.length 
          : 0;
      } else if (q.type === 'YES_NO') {
        const yesCount = responses.filter(r => r === 'SIM').length;
        avg = responses.length > 0 ? (yesCount / responses.length) * 100 : 0; // % de Sim
      }

      return {
        questionId: q.id,
        text: q.text,
        type: q.type,
        totalResponses: responses.length,
        average: avg,
        responses: responses // Para análise qualitativa ou histórica
      };
    });
  }

  // --- Standard Methods ---
  getFeedbacks(companyId?: string) {
    return companyId ? this.feedbacks.filter(f => f.companyId === companyId) : this.feedbacks;
  }

  getCustomers(companyId: string) {
    return this.customers.filter(c => c.companyId === companyId);
  }

  getCaseForFeedback(feedbackId: string) {
    return this.cases.find(c => c.feedbackId === feedbackId);
  }

  getCases(companyId?: string) {
    return companyId ? this.cases.filter(c => c.companyId === companyId) : this.cases;
  }

  addFeedback(feedback: Omit<Feedback, 'id' | 'createdAt' | 'category' | 'averageScore'>) {
    const avg = (feedback.scores.service + feedback.scores.food + feedback.scores.drinks + feedback.scores.structure) / 4;
    let cat: NPSCategory = avg >= 9 ? 'PROMOTER' : avg <= 6 ? 'DETRACTOR' : 'PASSIVE';
    const createdAt = new Date().toISOString();
    const newFeedback: Feedback = { ...feedback, id: `f-${Date.now()}`, createdAt, category: cat, averageScore: avg };
    this.feedbacks.push(newFeedback);
    return newFeedback;
  }

  // Fix: Added missing case metrics to dashboard stats
  getDashboardStats(companyId: string) {
    const fb = this.getFeedbacks(companyId);
    const total = fb.length;
    const avgScore = total > 0 ? (fb.reduce((acc, f) => acc + f.averageScore, 0) / total) * 10 : 0;

    const companyCases = this.getCases(companyId);

    return {
      total,
      promoters: fb.filter(f => f.category === 'PROMOTER').length,
      detractors: fb.filter(f => f.category === 'DETRACTOR').length,
      passives: fb.filter(f => f.category === 'PASSIVE').length,
      avgScore: Math.round(avgScore),
      openDetractors: companyCases.filter(c => c.status === 'OPEN').length,
      resolvedDetractors: companyCases.filter(c => c.status === 'RESOLVED').length,
      catAvg: {
        service: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.service, 0) / total) : 0,
        food: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.food, 0) / total) : 0,
        drinks: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.drinks, 0) / total) : 0,
        structure: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.structure, 0) / total) : 0,
      }
    };
  }

  // Fix: Added missing Case Management methods
  createCaseFromFeedback(feedbackId: string, companyId: string, noteText: string, userName: string, userId: string) {
    const newCase: Case = {
      id: `case-${Date.now()}`,
      feedbackId,
      companyId,
      status: 'OPEN',
      notes: [{
        id: `note-${Date.now()}`,
        userId,
        userName,
        text: noteText || 'Caso aberto para acompanhamento.',
        createdAt: new Date().toISOString()
      }],
      updatedAt: new Date().toISOString()
    };
    this.cases.push(newCase);
    return newCase;
  }

  addCaseNote(caseId: string, userId: string, userName: string, text: string) {
    const c = this.cases.find(item => item.id === caseId);
    if (c) {
      c.notes.push({
        id: `note-${Date.now()}`,
        userId,
        userName,
        text,
        createdAt: new Date().toISOString()
      });
      c.updatedAt = new Date().toISOString();
      if (c.status === 'OPEN') c.status = 'IN_PROGRESS';
    }
  }

  resolveCase(caseId: string, resolutionText: string, userName: string, userId: string) {
    const c = this.cases.find(item => item.id === caseId);
    if (c) {
      c.status = 'RESOLVED';
      c.resolutionText = resolutionText;
      c.notes.push({
        id: `note-res-${Date.now()}`,
        userId,
        userName,
        text: `RESOLUÇÃO: ${resolutionText}`,
        createdAt: new Date().toISOString()
      });
      c.updatedAt = new Date().toISOString();
    }
  }

  // Fix: Added missing Customer & CRM methods
  getCustomerHistory(customerId: string) {
    return this.feedbacks.filter(f => f.customerId === customerId)
      .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }

  addContactLog(customerId: string, log: Omit<ContactLog, 'id' | 'createdAt'>) {
    const customer = this.customers.find(c => c.id === customerId);
    if (customer) {
      customer.contactLogs.unshift({
        ...log,
        id: `log-${Date.now()}`,
        createdAt: new Date().toISOString()
      });
    }
  }
}

