                  <RatingDots label="Atendimento" value={formData.service} onChange={(v: number) => setFormData({...formData, service: v})} />
                  <RatingDots label="Comida" value={formData.food} onChange={(v: number) => setFormData({...formData, food: v})} />
                  <RatingDots label="Bebidas" value={formData.drinks} onChange={(v: number) => setFormData({...formData, drinks: v})} />
                  <RatingDots label="Ambiente" value={formData.structure} onChange={(v: number) => setFormData({...formData, structure: v})} />
                </div>

                {/* Perguntas Internas Dinâmicas */}
                {internalQuestions.length > 0 && (
                  <div className="space-y-10 pt-10 border-t border-slate-100">
