import { Feedback, Case, Customer, NPSCategory, InternalQuestion, InternalQuestionType, ContactLog } from '../types';
import { MOCK_COMPANIES } from '../constants';

class DataStore {
  private feedbacks: Feedback[] = [];
  private cases: Case[] = [];
  private customers: Customer[] = [];
  private internalQuestions: InternalQuestion[] = [];

  constructor() {
    this.initMockData();
  }

  private initMockData() {
    MOCK_COMPANIES.forEach(comp => {
      // Mock Internal Questions
      const q1: InternalQuestion = {
        id: `q1-${comp.id}`,
        companyId: comp.id,
        text: 'O garçom ofereceu sobremesa?',
        type: 'YES_NO',
        required: true,
        active: true,
        order: 1
      };
      const q2: InternalQuestion = {
        id: `q2-${comp.id}`,
        companyId: comp.id,
        text: 'Qual a probabilidade de você indicar nosso Happy Hour?',
        type: 'SCALE_10',
        required: false,
        active: true,
        order: 2
      };
      this.internalQuestions.push(q1, q2);

      // Create some unique customers and feedbacks
      for (let j = 0; j < 8; j++) {
        const phone = `1198888000${j}`;
        const customerId = `cust-${comp.id}-${j}`;

        // Simular fluxo de feedbacks que alimenta o CRM e Casos
        for(let i = 0; i < 2; i++) {
          const scores = {
            service: Math.floor(Math.random() * 5) + 5,
            food: Math.floor(Math.random() * 5) + 5,
            drinks: Math.floor(Math.random() * 5) + 5,
            structure: Math.floor(Math.random() * 5) + 5,
          };

          this.addFeedback({
            companyId: comp.id,
            customerId: customerId,
            customerName: `Cliente Exemplo ${j}`,
            customerPhone: phone,
            howKnown: 'Instagram',
            scores,
            internalResponses: {
              [q1.id]: Math.random() > 0.3 ? 'SIM' : 'NÃO',
              [q2.id]: Math.floor(Math.random() * 10) + 1
            },
            profile: 'friends',
            observation: i === 1 ? 'Melhorou desde a última vez.' : 'Pode melhorar o tempo de espera.',
            email: `cliente${j}@email.com`
          });
        }
      }
    });
  }

  // --- Internal Questions Management ---
  getInternalQuestions(companyId: string, onlyActive = true) {
    let qs = this.internalQuestions.filter(q => q.companyId === companyId);
    if (onlyActive) qs = qs.filter(q => q.active);
    return qs.sort((a, b) => a.order - b.order);
  }

  saveInternalQuestion(question: InternalQuestion) {
    const idx = this.internalQuestions.findIndex(q => q.id === question.id);
    if (idx >= 0) {
      this.internalQuestions[idx] = question;
    } else {
      this.internalQuestions.push(question);
    }
  }

  deleteInternalQuestion(id: string) {
    this.internalQuestions = this.internalQuestions.filter(q => q.id !== id);
  }

  // --- Internal Metrics Logic ---
  getInternalMetrics(companyId: string) {
    const qs = this.getInternalQuestions(companyId, false);
    const fbs = this.getFeedbacks(companyId);

    return qs.map(q => {
      const responses = fbs
        .map(f => f.internalResponses?.[q.id])
        .filter(r => r !== undefined && r !== null);

      let avg: any = 0;
      if (q.type === 'SCALE_5' || q.type === 'SCALE_10') {
        avg = responses.length > 0 
          ? responses.reduce((acc: number, val: any) => acc + Number(val), 0) / responses.length 
          : 0;
      } else if (q.type === 'YES_NO') {
        const yesCount = responses.filter(r => r === 'SIM').length;
        avg = responses.length > 0 ? (yesCount / responses.length) * 100 : 0; // % de Sim
      }

      return {
        questionId: q.id,
        text: q.text,
        type: q.type,
        totalResponses: responses.length,
        average: avg,
        responses: responses
      };
    });
  }

  // --- Core Lifecycle Methods ---
  getFeedbacks(companyId?: string) {
    return companyId ? this.feedbacks.filter(f => f.companyId === companyId) : this.feedbacks;
  }

  getCustomers(companyId: string) {
    return this.customers.filter(c => c.companyId === companyId);
  }

  getCaseForFeedback(feedbackId: string) {
    return this.cases.find(c => c.feedbackId === feedbackId);
  }

  getCases(companyId?: string) {
    return companyId ? this.cases.filter(c => c.companyId === companyId) : this.cases;
  }

  addFeedback(feedback: Omit<Feedback, 'id' | 'createdAt' | 'category' | 'averageScore'>) {
    const avg = (feedback.scores.service + feedback.scores.food + feedback.scores.drinks + feedback.scores.structure) / 4;
    let cat: NPSCategory = avg >= 9 ? 'PROMOTER' : avg <= 6 ? 'DETRACTOR' : 'PASSIVE';
    const createdAt = new Date().toISOString();

    // 1. Criar Registro de Feedback
    const newFeedback: Feedback = { 
      ...feedback, 
      id: `f-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`, 
      createdAt, 
      category: cat, 
      averageScore: avg 
    };
    this.feedbacks.push(newFeedback);

    // 2. Atualizar ou Criar Cliente no CRM
    let customer = this.customers.find(c => c.phone === feedback.customerPhone && c.companyId === feedback.companyId);
    if (!customer) {
      customer = {
        id: feedback.customerId || `cust-${Date.now()}`,
        companyId: feedback.companyId,
        name: feedback.customerName,
        phone: feedback.customerPhone,
        email: feedback.email,
        profile: feedback.profile,
        firstSeen: createdAt,
        lastSeen: createdAt,
        averageScore: avg,
        totalFeedbacks: 1,
        category: cat,
        contactLogs: []
      };
      this.customers.push(customer);
    } else {
      customer.lastSeen = createdAt;
      customer.totalFeedbacks += 1;

      // Recalcular média histórica do cliente
      const customerFeedbacks = this.feedbacks.filter(f => 
        f.customerPhone === customer?.phone && f.companyId === feedback.companyId
      );
      customer.averageScore = customerFeedbacks.reduce((acc, f) => acc + f.averageScore, 0) / customerFeedbacks.length;
      customer.category = customer.averageScore >= 9 ? 'PROMOTER' : customer.averageScore <= 6 ? 'DETRACTOR' : 'PASSIVE';
      customer.name = feedback.customerName; // Atualiza nome se mudou
    }

    // 3. Abertura Automática de Casos para Detratores
    if (cat === 'DETRACTOR') {
      this.createCaseFromFeedback(
        newFeedback.id, 
        feedback.companyId, 
        'Caso gerado automaticamente via Sistema Ativare devido à baixa pontuação.', 
        'Inteligência Ativare', 
        'system'
      );
    }

    return newFeedback;
  }

  getDashboardStats(companyId: string) {
    const fb = this.getFeedbacks(companyId);
    const total = fb.length;
    const avgScore = total > 0 ? (fb.reduce((acc, f) => acc + f.averageScore, 0) / total) * 10 : 0;

    const companyCases = this.getCases(companyId);

    return {
      total,
      promoters: fb.filter(f => f.category === 'PROMOTER').length,
      detractors: fb.filter(f => f.category === 'DETRACTOR').length,
      passives: fb.filter(f => f.category === 'PASSIVE').length,
      avgScore: Math.round(avgScore),
      openDetractors: companyCases.filter(c => c.status === 'OPEN').length,
      resolvedDetractors: companyCases.filter(c => c.status === 'RESOLVED').length,
      catAvg: {
        service: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.service, 0) / total) : 0,
        food: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.food, 0) / total) : 0,
        drinks: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.drinks, 0) / total) : 0,
        structure: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.structure, 0) / total) : 0,
      }
    };
  }

  createCaseFromFeedback(feedbackId: string, companyId: string, noteText: string, userName: string, userId: string) {
    // Evitar duplicidade de caso para o mesmo feedback
    if (this.cases.some(c => c.feedbackId === feedbackId)) return;

    const newCase: Case = {
      id: `case-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
      feedbackId,
      companyId,
      status: 'OPEN',
      notes: [{
        id: `note-${Date.now()}`,
        userId,
        userName,
        text: noteText || 'Caso aberto para acompanhamento.',
        createdAt: new Date().toISOString()
      }],
      updatedAt: new Date().toISOString()
    };
    this.cases.push(newCase);
    return newCase;
  }

  addCaseNote(caseId: string, userId: string, userName: string, text: string) {
    const c = this.cases.find(item => item.id === caseId);
    if (c) {
      c.notes.push({
        id: `note-${Date.now()}`,
        userId,
        userName,
        text,
        createdAt: new Date().toISOString()
      });
      c.updatedAt = new Date().toISOString();
      if (c.status === 'OPEN') c.status = 'IN_PROGRESS';
    }
  }

  resolveCase(caseId: string, resolutionText: string, userName: string, userId: string) {
    const c = this.cases.find(item => item.id === caseId);
    if (c) {
      c.status = 'RESOLVED';
      c.resolutionText = resolutionText;
      c.notes.push({
        id: `note-res-${Date.now()}`,
        userId,
        userName,
        text: `RESOLUÇÃO: ${resolutionText}`,
        createdAt: new Date().toISOString()
      });
      c.updatedAt = new Date().toISOString();
    }
  }

  getCustomerHistory(customerId: string) {
    const customer = this.customers.find(c => c.id === customerId);
    if (!customer) return [];

    return this.feedbacks.filter(f => f.customerPhone === customer.phone && f.companyId === customer.companyId)
      .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }

  addContactLog(customerId: string, log: Omit<ContactLog, 'id' | 'createdAt'>) {
    const customer = this.customers.find(c => c.id === customerId);
    if (customer) {
      customer.contactLogs.unshift({
        ...log,
        id: `log-${Date.now()}`,
        createdAt: new Date().toISOString()
      });
    }
  }
}

export const dataStore = new DataStore();

import React, { useState, useMemo } from 'react';
import { Company, InternalQuestion } from '../types';
import { dataStore } from '../services/dataStore';
import { ChevronRight, ChevronLeft, Send, CheckCircle2, AlertCircle } from 'lucide-react';

interface FeedbackFormProps {
  company: Company;
  onFinished: () => void;
}

const FeedbackForm: React.FC<FeedbackFormProps> = ({ company, onFinished }) => {
  const [step, setStep] = useState(1);
  const [showValidation, setShowValidation] = useState(false);
  const internalQuestions = useMemo(() => dataStore.getInternalQuestions(company.id), [company.id]);

  const [formData, setFormData] = useState({
    name: '',
    surname: '',
    phone: '',
    email: '',
    howKnown: '',
    service: 0, 
    food: 0,    
    drinks: 0,  
    structure: 0, 
    profile: 'family' as any,
    observation: '',
    internalResponses: {} as any
  });
  const [submitted, setSubmitted] = useState(false);

  const isStep1Valid = formData.name.trim() !== '' && formData.surname.trim() !== '' && formData.phone.trim() !== '';

  const isStep2Valid = useMemo(() => {
    const coreRatingsDone = formData.service > 0 && formData.food > 0 && formData.drinks > 0 && formData.structure > 0;

    const requiredInternalDone = internalQuestions
      .filter(q => q.required)
      .every(q => {
        const resp = formData.internalResponses[q.id];
        if (q.type === 'TEXT') return resp && resp.trim() !== '';
        if (q.type === 'SCALE_5' || q.type === 'SCALE_10') return resp > 0;
        if (q.type === 'YES_NO') return resp !== undefined && resp !== null;
        return true;
      });

    return coreRatingsDone && requiredInternalDone;
  }, [formData, internalQuestions]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (step === 1) {
      if (!isStep1Valid) {
        setShowValidation(true);
        return;
      }
      setStep(2);
      setShowValidation(false);
      window.scrollTo(0, 0);
      return;
    }

    if (!isStep2Valid) {
      setShowValidation(true);
      return;
    }

    // Chamada centralizada que dispara CRM, Feedbacks e Casos
    dataStore.addFeedback({
      companyId: company.id,
      customerId: '', // Será gerado pelo dataStore
      customerName: `${formData.name} ${formData.surname}`,
      customerPhone: formData.phone,
      howKnown: formData.howKnown,
      scores: {
        service: formData.service,
        food: formData.food,
        drinks: formData.drinks,
        structure: formData.structure
      },
      internalResponses: formData.internalResponses,
      profile: formData.profile,
      observation: formData.observation,
      email: formData.email
    });

    setSubmitted(true);
  };

  const handleInternalResponse = (qId: string, value: any) => {
    setFormData({
      ...formData,
      internalResponses: { ...formData.internalResponses, [qId]: value }
    });
  };

  const RatingDots = ({ value, onChange, label, max = 10, isError = false }: any) => {
    const [hover, setHover] = useState(0);
    const activeValue = hover || value;

    const getColorClass = (val: number) => {
      if (val === 0) return 'bg-transparent';
      if (val <= 3) return 'bg-red-500';
      if (val <= 6) return 'bg-yellow-400';
      return 'bg-emerald-500';
    };

    const activeColor = getColorClass(activeValue);

    return (
      <div className={`space-y-4 p-4 rounded-3xl transition-all ${isError ? 'bg-red-50 ring-2 ring-red-200 animate-pulse' : ''}`}>
        <div className="flex justify-between items-center">
          <label className="text-sm font-black text-slate-700 uppercase tracking-tight">{label}</label>
          <span className={`text-xl font-black px-3 py-1 rounded-xl min-w-[3rem] text-center ${
            activeValue === 0 ? 'text-slate-300 bg-slate-100' :
            activeValue <= 3 ? 'text-red-500 bg-red-50' : 
            activeValue <= 6 ? 'text-yellow-600 bg-yellow-50' : 
            'text-emerald-500 bg-emerald-50'
          }`}>
            {activeValue === 0 ? '—' : activeValue}
          </span>
        </div>
        <div className="flex justify-between gap-1.5">
          {Array.from({ length: max }).map((_, i) => {
            const dotValue = i + 1;
            const isFilled = dotValue <= activeValue;
            return (
              <button
                key={dotValue}
                type="button"
                onMouseEnter={() => setHover(dotValue)}
                onMouseLeave={() => setHover(0)}
                onClick={() => {
                  onChange(dotValue);
                  setShowValidation(false);
                }}
                className={`
                  flex-1 h-10 rounded-full transition-all duration-200 border-2
                  ${isFilled && activeValue > 0 
                    ? `${activeColor} border-transparent scale-105 shadow-md shadow-${activeColor}/20` 
                    : 'bg-white border-slate-100 hover:border-slate-200'}
                `}
              />
            );
          })}
        </div>
        <div className="flex justify-between px-1 text-[9px] font-black text-slate-300 uppercase tracking-widest">
          <span>Pobre</span>
          <span>Excepcional</span>
        </div>
      </div>
    );
  };

  if (submitted) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-[3rem] shadow-xl p-12 text-center animate-in fade-in zoom-in duration-500">
          <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center mx-auto mb-6">
            <CheckCircle2 className="w-10 h-10" />
          </div>
          <h2 className="text-2xl font-black text-slate-900 mb-4">Obrigado pelo seu feedback!</h2>
          <p className="text-slate-500 mb-8 font-medium leading-relaxed">Sua opinião ajuda o <span className="font-bold">{company.name}</span> a oferecer uma experiência cada vez melhor.</p>
          <button 
            onClick={onFinished}
            className="w-full py-5 bg-primary text-white font-black rounded-3xl shadow-lg hover:shadow-primary/30 transition-all"
          >
            Finalizar
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-100 flex flex-col font-inter">
      <header className="bg-white border-b border-slate-200 p-8 flex flex-col items-center">
        <div className="w-20 h-20 rounded-3xl border-4 border-white shadow-2xl overflow-hidden -mt-16 mb-4">
          <img src={company.logo} alt={company.name} className="w-full h-full object-cover" />
        </div>
        <h1 className="text-2xl font-black text-slate-900">{company.name}</h1>
      </header>

      <div className="flex-1 max-w-xl w-full mx-auto p-6 md:p-10">
        <div className="bg-white rounded-[3rem] shadow-2xl overflow-hidden border border-white">
          <div className="h-3 w-full bg-slate-100">
            <div className="h-full bg-primary transition-all duration-700" style={{ width: `${step * 50}%` }}></div>
          </div>

          <form onSubmit={handleSubmit} className="p-10 space-y-10">
            {step === 1 ? (
              <div className="space-y-8 animate-in slide-in-from-right duration-300">
                <div className="space-y-1">
                  <h2 className="text-3xl font-black text-slate-900">Seja bem-vindo!</h2>
                  <p className="text-slate-400 font-medium">Conte-nos um pouco sobre sua visita hoje.</p>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Nome *</label>
                    <input 
                      required
                      type="text" 
                      className={`w-full p-4 bg-slate-50 border rounded-2xl outline-none focus:border-primary font-bold text-slate-900 ${showValidation && !formData.name ? 'border-red-300 bg-red-50' : 'border-slate-200'}`}
                      value={formData.name}
                      onChange={(e) => setFormData({...formData, name: e.target.value})}
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Sobrenome *</label>
                    <input 
                      required
                      type="text" 
                      className={`w-full p-4 bg-slate-50 border rounded-2xl outline-none focus:border-primary font-bold text-slate-900 ${showValidation && !formData.surname ? 'border-red-300 bg-red-50' : 'border-slate-200'}`}
                      value={formData.surname}
                      onChange={(e) => setFormData({...formData, surname: e.target.value})}
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">WhatsApp de Contato *</label>
                  <input 
                    required
                    type="tel" 
                    placeholder="(00) 00000-0000"
                    className={`w-full p-4 bg-slate-50 border rounded-2xl outline-none focus:border-primary font-bold text-slate-900 ${showValidation && !formData.phone ? 'border-red-300 bg-red-50' : 'border-slate-200'}`}
                    value={formData.phone}
                    onChange={(e) => setFormData({...formData, phone: e.target.value})}
                  />
                </div>

                <div className="space-y-4">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Seu perfil hoje:</label>
                  <div className="grid grid-cols-2 gap-3">
                    {['family', 'friends', 'couple', 'kids'].map(p => (
                      <button
                        key={p}
                        type="button"
                        onClick={() => setFormData({...formData, profile: p as any})}
                        className={`p-4 rounded-2xl border-2 font-black text-xs transition-all ${
                          formData.profile === p 
                            ? 'bg-primary border-primary text-white shadow-lg' 
                            : 'bg-white border-slate-100 text-slate-400'
                        }`}
                      >
                        {p === 'family' ? 'Família' : p === 'friends' ? 'Amigos' : p === 'couple' ? 'Casal' : 'Crianças'}
                      </button>
                    ))}
                  </div>
                </div>

                <button 
                  type="submit"
                  className={`w-full py-5 text-white font-black rounded-3xl shadow-xl flex items-center justify-center gap-3 transition-all ${isStep1Valid ? 'bg-primary hover:translate-y-[-2px]' : 'bg-slate-300 cursor-not-allowed'}`}
                >
                  Continuar <ChevronRight className="w-5 h-5" />
                </button>
              </div>
            ) : (
              <div className="space-y-12 animate-in slide-in-from-right duration-300">
                <div className="space-y-6">
                  <h3 className="text-[10px] font-black uppercase text-slate-300 tracking-[0.2em] border-b border-slate-50 pb-4">Avaliação Ativare</h3>
                  <RatingDots 
                    label="Atendimento" 
                    value={formData.service} 
                    onChange={(v: number) => setFormData({...formData, service: v})} 
                    isError={showValidation && formData.service === 0}
                  />
                  <RatingDots 
                    label="Comida" 
                    value={formData.food} 
                    onChange={(v: number) => setFormData({...formData, food: v})} 
                    isError={showValidation && formData.food === 0}
                  />
                  <RatingDots 
                    label="Bebidas" 
                    value={formData.drinks} 
                    onChange={(v: number) => setFormData({...formData, drinks: v})} 
                    isError={showValidation && formData.drinks === 0}
                  />
                  <RatingDots 
                    label="Ambiente" 
                    value={formData.structure} 
                    onChange={(v: number) => setFormData({...formData, structure: v})} 
                    isError={showValidation && formData.structure === 0}
                  />
                </div>

                {internalQuestions.length > 0 && (
                  <div className="space-y-10 pt-10 border-t border-slate-100">
                    <h3 className="text-[10px] font-black uppercase text-slate-300 tracking-[0.2em] border-b border-slate-50 pb-4">Checklist da Casa</h3>
                    {internalQuestions.map(q => {
                      const resp = formData.internalResponses[q.id];
                      const isMissing = q.required && (resp === undefined || resp === null || resp === 0 || (typeof resp === 'string' && resp.trim() === ''));

                      return (
                        <div key={q.id} className="space-y-4">
                          {q.type === 'YES_NO' && (
                            <div className={`space-y-4 p-4 rounded-3xl transition-all ${showValidation && isMissing ? 'bg-red-50 ring-2 ring-red-200 animate-pulse' : ''}`}>
                              <label className="text-sm font-black text-slate-700 uppercase tracking-tight">{q.text} {q.required && '*'}</label>
                              <div className="flex gap-4">
                                {['SIM', 'NÃO'].map(opt => (
                                  <button
                                    key={opt}
                                    type="button"
                                    onClick={() => handleInternalResponse(q.id, opt)}
                                    className={`flex-1 py-4 rounded-2xl border-2 font-black text-sm transition-all ${
                                      formData.internalResponses[q.id] === opt 
                                        ? 'bg-primary border-primary text-white shadow-lg' 
                                        : 'bg-white border-slate-100 text-slate-400'
                                    }`}
                                  >
                                    {opt}
                                  </button>
                                ))}
                              </div>
                            </div>
                          )}

                          {(q.type === 'SCALE_5' || q.type === 'SCALE_10') && (
                            <RatingDots 
                              max={q.type === 'SCALE_5' ? 5 : 10}
                              label={q.text + (q.required ? ' *' : '')}
                              value={formData.internalResponses[q.id] || 0} 
                              onChange={(v: number) => handleInternalResponse(q.id, v)} 
                              isError={showValidation && isMissing}
                            />
                          )}

                          {q.type === 'TEXT' && (
                            <div className={`space-y-2 p-4 rounded-3xl transition-all ${showValidation && isMissing ? 'bg-red-50 ring-2 ring-red-200 animate-pulse' : ''}`}>
                               <label className="text-sm font-black text-slate-700 uppercase tracking-tight">{q.text} {q.required && '*'}</label>
                              <textarea 
                                required={q.required}
                                className={`w-full h-24 p-4 bg-slate-50 border rounded-2xl outline-none focus:border-primary font-medium text-sm text-slate-900 ${showValidation && isMissing ? 'border-red-300' : 'border-slate-100'}`}
                                placeholder="Sua resposta..."
                                value={formData.internalResponses[q.id] || ''}
                                onChange={(e) => handleInternalResponse(q.id, e.target.value)}
                              />
                            </div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                )}

                <div className="space-y-4 pt-10 border-t border-slate-100">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Observação Final (Opcional)</label>
                  <textarea 
                    className="w-full h-32 p-4 bg-slate-50 border border-slate-100 rounded-3xl outline-none focus:border-primary font-medium text-sm text-slate-900"
                    placeholder="Algo mais que gostaria de nos dizer?"
                    value={formData.observation}
                    onChange={(e) => setFormData({...formData, observation: e.target.value})}
                  />
                </div>

                {showValidation && !isStep2Valid && (
                  <div className="p-4 bg-red-50 border border-red-200 rounded-2xl flex items-center gap-3 text-red-600 animate-in slide-in-from-top">
                    <AlertCircle className="w-5 h-5 flex-shrink-0" />
                    <p className="text-xs font-bold">Por favor, responda a todas as avaliações obrigatórias antes de enviar.</p>
                  </div>
                )}

                <div className="flex gap-4">
                  <button type="button" onClick={() => setStep(1)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black rounded-3xl hover:bg-slate-200 transition-all flex items-center justify-center gap-2">
                    <ChevronLeft className="w-5 h-5" /> Voltar
                  </button>
                  <button 
                    type="submit" 
                    className={`flex-[2] py-5 text-white font-black rounded-3xl shadow-xl flex items-center justify-center gap-3 transition-all ${isStep2Valid ? 'bg-primary shadow-primary/30 hover:translate-y-[-2px]' : 'bg-slate-300 cursor-not-allowed opacity-60'}`}
                  >
                    Enviar Feedback <Send className="w-5 h-5" />
                  </button>
                </div>
              </div>
            )}
          </form>
        </div>
      </div>
    </div>
  );
};

export default FeedbackForm;

import React, { useState, useMemo } from 'react';
import { dataStore } from '../services/dataStore';
import { Feedback, NPSCategory, User, Case } from '../types';
import { 
  Search, 
  ChevronRight, 
  Share2, 
  Star, 
  User as UserIcon,
  Phone,
  Mail,
  MapPin,
  ExternalLink,
  Copy,
  Check,
  X,
  PlusCircle,
  MessageCircle,
  Clock,
  CheckCircle2,
  AlertCircle,
  Send
} from 'lucide-react';

interface FeedbacksProps {
  companyId: string;
  currentUser: User;
}

const Feedbacks: React.FC<FeedbacksProps> = ({ companyId, currentUser }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState<NPSCategory | 'ALL'>('ALL');
  const [selectedFeedback, setSelectedFeedback] = useState<Feedback | null>(null);
  const [showShareModal, setShowShareModal] = useState(false);
  const [copied, setCopied] = useState(false);

  const [internalNote, setInternalNote] = useState('');
  const [resolutionText, setResolutionText] = useState('');

  const feedbacks = useMemo(() => dataStore.getFeedbacks(companyId), [companyId, selectedFeedback]);

  const filteredFeedbacks = useMemo(() => {
    return feedbacks
      .filter(f => {
        const matchesSearch = f.customerName.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesCategory = categoryFilter === 'ALL' || f.category === categoryFilter;
        return matchesSearch && matchesCategory;
      })
      .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }, [feedbacks, searchTerm, categoryFilter]);

  const currentCase = selectedFeedback ? dataStore.getCaseForFeedback(selectedFeedback.id) : null;

  const handleCopyLink = () => {
    const link = `${window.location.origin}/avaliar/${companyId}`;
    navigator.clipboard.writeText(link);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleCreateCase = () => {
    if (selectedFeedback) {
      dataStore.createCaseFromFeedback(
        selectedFeedback.id, 
        companyId, 
        internalNote, 
        currentUser.name, 
        currentUser.id
      );
      setInternalNote('');
      setSelectedFeedback({...selectedFeedback});
    }
  };

  const handleAddNote = () => {
    if (currentCase && internalNote.trim()) {
      dataStore.addCaseNote(currentCase.id, currentUser.id, currentUser.name, internalNote);
      setInternalNote('');
      setSelectedFeedback({...selectedFeedback!});
    }
  };

  const handleResolve = () => {
    if (currentCase && resolutionText.trim()) {
      dataStore.resolveCase(currentCase.id, resolutionText, currentUser.name, currentUser.id);
      setResolutionText('');
      setSelectedFeedback({...selectedFeedback!});
    }
  };

  const CategoryTag = ({ category }: { category: NPSCategory }) => {
    const styles = {
      PROMOTER: 'bg-emerald-50 text-emerald-600 border-emerald-100',
      PASSIVE: 'bg-amber-50 text-amber-600 border-amber-100',
      DETRACTOR: 'bg-red-50 text-red-600 border-red-100'
    };
    const labels = { PROMOTER: 'Promotor', PASSIVE: 'Passivo', DETRACTOR: 'Detrator' };
    return (
      <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wider border ${styles[category]}`}>
        {labels[category]}
      </span>
    );
  };

  const RatingDotsView = ({ label, value }: { label: string, value: number }) => {
    const getColorClass = (val: number) => {
      if (val <= 3) return 'bg-red-500';
      if (val <= 6) return 'bg-yellow-400';
      return 'bg-emerald-500';
    };
    const activeColor = getColorClass(value);

    return (
      <div className="space-y-2">
        <div className="flex justify-between text-[10px] font-black uppercase text-slate-400">
          <span>{label}</span>
          <span className={`font-black ${value <= 3 ? 'text-red-500' : value <= 6 ? 'text-yellow-600' : 'text-emerald-500'}`}>{value}</span>
        </div>
        <div className="flex gap-1">
          {Array.from({ length: 10 }).map((_, i) => (
            <div 
              key={i} 
              className={`flex-1 h-2.5 rounded-full ${
                i + 1 <= value ? activeColor : 'bg-slate-100'
              }`}
            />
          ))}
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-6 relative h-full">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div className="flex flex-1 w-full md:max-w-md bg-white rounded-2xl border border-slate-200 px-4 py-2.5 items-center space-x-3 shadow-sm focus-within:border-primary transition-all">
          <Search className="w-5 h-5 text-slate-400" />
          <input 
            type="text" 
            placeholder="Buscar por nome do cliente..." 
            className="bg-transparent border-none outline-none text-sm w-full text-slate-900 font-medium"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex items-center space-x-3 w-full md:w-auto">
          <select 
            className="bg-white border border-slate-200 rounded-2xl px-4 py-2.5 text-sm font-bold text-slate-700 outline-none focus:border-primary shadow-sm"
            value={categoryFilter}
            onChange={(e) => setCategoryFilter(e.target.value as any)}
          >
            <option value="ALL">Todas Categorias</option>
            <option value="PROMOTER">Promotores</option>
            <option value="PASSIVE">Passivos</option>
            <option value="DETRACTOR">Detratores</option>
          </select>

          <button 
            onClick={() => setShowShareModal(true)}
            className="flex items-center space-x-2 bg-accent hover:bg-[#e65d00] text-white px-5 py-2.5 rounded-2xl font-bold shadow-lg shadow-accent/20 transition-all"
          >
            <Share2 className="w-4 h-4" />
            <span className="hidden sm:inline">Gerar Link</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-[32px] border border-slate-100 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50/50 border-b border-slate-100">
                <th className="px-8 py-5 text-[11px] font-black uppercase text-slate-400 tracking-widest">Data</th>
                <th className="px-8 py-5 text-[11px] font-black uppercase text-slate-400 tracking-widest">Cliente</th>
                <th className="px-8 py-5 text-[11px] font-black uppercase text-slate-400 tracking-widest text-center">Score Médio</th>
                <th className="px-8 py-5 text-[11px] font-black uppercase text-slate-400 tracking-widest text-center">NPS</th>
                <th className="px-8 py-5 text-[11px] font-black uppercase text-slate-400 tracking-widest text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredFeedbacks.length === 0 ? (
                <tr>
                  <td colSpan={5} className="px-8 py-20 text-center text-slate-400 font-medium">Nenhuma avaliação encontrada.</td>
                </tr>
              ) : (
                filteredFeedbacks.map((f) => (
                  <tr 
                    key={f.id} 
                    className="hover:bg-slate-50/80 transition-colors cursor-pointer group"
                    onClick={() => setSelectedFeedback(f)}
                  >
                    <td className="px-8 py-5 whitespace-nowrap text-sm font-semibold text-slate-500">
                      {new Date(f.createdAt).toLocaleDateString('pt-BR')}
                    </td>
                    <td className="px-8 py-5">
                      <div className="flex items-center space-x-3">
                        <div className="w-10 h-10 rounded-xl bg-slate-100 border border-slate-200 flex items-center justify-center font-black text-slate-400">
                          {f.customerName.charAt(0)}
                        </div>
                        <div>
                          <p className="text-sm font-bold text-slate-800">{f.customerName}</p>
                          <p className="text-[10px] text-slate-400 font-medium">{f.customerPhone}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-8 py-5 text-center">
                      <span className={`inline-flex items-center justify-center w-12 h-10 rounded-xl font-black text-sm border ${
                        f.averageScore >= 9 ? 'border-emerald-200 bg-emerald-50 text-emerald-600' : 
                        f.averageScore <= 6 ? 'border-red-200 bg-red-50 text-red-600' : 'border-amber-200 bg-amber-50 text-amber-600'
                      }`}>
                        {f.averageScore.toFixed(1)}
                      </span>
                    </td>
                    <td className="px-8 py-5 text-center">
                      <CategoryTag category={f.category} />
                    </td>
                    <td className="px-8 py-5 text-right">
                      <button className="p-2 text-slate-300 group-hover:text-primary transition-colors">
                        <ChevronRight className="w-5 h-5" />
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {selectedFeedback && (
        <div className="fixed inset-0 z-[110] flex justify-end overflow-hidden">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity" onClick={() => setSelectedFeedback(null)}></div>

          <div className="relative w-full max-width max-w-2xl bg-slate-50 shadow-2xl flex flex-col animate-in slide-in-from-right duration-500">
            <div className="bg-white px-8 py-6 border-b border-slate-200 flex items-center justify-between">
              <div className="flex items-center space-x-4">
                <div className="w-14 h-14 rounded-2xl bg-primary/10 text-primary flex items-center justify-center text-xl font-black">
                  {selectedFeedback.customerName.charAt(0)}
                </div>
                <div>
                  <h3 className="text-xl font-black text-slate-900">{selectedFeedback.customerName}</h3>
                  <div className="flex items-center gap-2 mt-1">
                    <CategoryTag category={selectedFeedback.category} />
                    <span className="text-xs font-bold text-slate-400">• Avaliado em {new Date(selectedFeedback.createdAt).toLocaleDateString('pt-BR')}</span>
                  </div>
                </div>
              </div>
              <button 
                onClick={() => setSelectedFeedback(null)}
                className="p-2 rounded-xl hover:bg-slate-100 text-slate-400 transition-all"
              >
                <X className="w-6 h-6" />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-8">
              <div className="grid grid-cols-2 gap-6">
                <div className="bg-white p-6 rounded-3xl border border-slate-200 space-y-4">
                  <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest flex items-center gap-2">
                    <UserIcon className="w-3 h-3" /> Perfil do Cliente
                  </h4>
                  <div className="space-y-3">
                    <div className="flex items-center gap-3">
                      <div className="p-2 bg-slate-100 rounded-lg"><Phone className="w-4 h-4 text-slate-500" /></div>
                      <span className="text-sm font-bold text-slate-700">{selectedFeedback.customerPhone}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <div className="p-2 bg-slate-100 rounded-lg"><Mail className="w-4 h-4 text-slate-500" /></div>
                      <span className="text-sm font-bold text-slate-700">{selectedFeedback.email || 'N/A'}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <div className="p-2 bg-slate-100 rounded-lg"><MapPin className="w-4 h-4 text-slate-500" /></div>
                      <span className="text-sm font-bold text-slate-700 uppercase text-[10px] tracking-tight">{selectedFeedback.profile}</span>
                    </div>
                  </div>
                </div>

                <div className="bg-white p-6 rounded-3xl border border-slate-200 flex flex-col justify-center items-center text-center">
                  <div className={`w-20 h-20 rounded-full border-4 flex items-center justify-center mb-2 ${
                    selectedFeedback.averageScore >= 9 ? 'border-emerald-500 text-emerald-600' : 
                    selectedFeedback.averageScore <= 6 ? 'border-red-500 text-red-600' : 'border-amber-500 text-amber-600'
                  }`}>
                    <span className="text-3xl font-black">{selectedFeedback.averageScore.toFixed(1)}</span>
                  </div>
                  <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Score de Experiência</p>
                </div>
              </div>

              <div className="bg-white p-6 rounded-3xl border border-slate-200 space-y-8">
                <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest flex items-center gap-2">
                  <Star className="w-3 h-3" /> Detalhes das Notas
                </h4>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  <RatingDotsView label="Atendimento" value={selectedFeedback.scores.service} />
                  <RatingDotsView label="Comida" value={selectedFeedback.scores.food} />
                  <RatingDotsView label="Bebidas" value={selectedFeedback.scores.drinks} />
                  <RatingDotsView label="Ambiente" value={selectedFeedback.scores.structure} />
                </div>
                <div className="pt-6 border-t border-slate-50">
                  <p className="text-[10px] font-black uppercase text-slate-400 mb-2">Comentário do Cliente:</p>
                  <p className="text-sm text-slate-700 italic bg-slate-50 p-4 rounded-2xl border border-slate-100 leading-relaxed">
                    "{selectedFeedback.observation || 'O cliente não deixou comentários adicionais.'}"
                  </p>
                </div>
              </div>

              <div className="bg-[#002e6b] rounded-3xl p-8 shadow-xl shadow-[#002e6b]/20 text-white space-y-6">
                <div className="flex items-center justify-between">
                  <h4 className="text-lg font-black flex items-center gap-2">
                    <AlertCircle className="w-5 h-5 text-accent" />
                    Painel de Resolução
                  </h4>
                  {currentCase && (
                    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border ${
                      currentCase.status === 'RESOLVED' ? 'bg-emerald-500/20 border-emerald-500 text-emerald-300' : 'bg-accent/20 border-accent text-accent'
                    }`}>
                      {currentCase.status === 'RESOLVED' ? 'Resolvido' : 'Caso em Aberto'}
                    </span>
                  )}
                </div>

                {!currentCase ? (
                  <div className="space-y-4">
                    <p className="text-sm text-slate-300">Esta avaliação ainda não possui um caso aberto. Deseja iniciar um protocolo de atendimento para este cliente?</p>
                    <div className="space-y-2">
                      <label className="text-[10px] font-bold uppercase text-slate-400">Observação Inicial</label>
                      <textarea 
                        value={internalNote}
                        onChange={(e) => setInternalNote(e.target.value)}
                        placeholder="Ex: Entrar em contato via WhatsApp para entender melhor o ocorrido..."
                        className="w-full bg-white/5 border border-white/10 rounded-2xl p-4 text-sm outline-none focus:border-accent transition-all h-24 placeholder:text-slate-500"
                      />
                    </div>
                    <button 
                      onClick={handleCreateCase}
                      className="w-full py-4 bg-accent hover:bg-accent/90 text-white font-black rounded-2xl shadow-lg transition-all flex items-center justify-center gap-2"
                    >
                      <PlusCircle className="w-5 h-5" />
                      Abrir Caso de Gestão
                    </button>
                  </div>
                ) : (
                  <div className="space-y-8">
                    <div className="space-y-4">
                      <p className="text-[10px] font-bold uppercase text-slate-400 flex items-center gap-2">
                        <Clock className="w-3 h-3" /> Timeline do Atendimento
                      </p>
                      <div className="space-y-3">
                        {currentCase.notes.map(note => (
                          <div key={note.id} className="bg-white/5 border border-white/10 p-4 rounded-2xl flex flex-col gap-1">
                            <div className="flex justify-between items-center">
                              <span className="text-[10px] font-black text-accent">{note.userName}</span>
                              <span className="text-[9px] text-slate-400">{new Date(note.createdAt).toLocaleString('pt-BR')}</span>
                            </div>
                            <p className="text-xs text-slate-200">{note.text}</p>
                          </div>
                        ))}
                      </div>
                    </div>

                    {currentCase.status !== 'RESOLVED' && (
                      <div className="space-y-6 pt-6 border-t border-white/10">
                        <div className="space-y-4">
                          <textarea 
                            value={internalNote}
                            onChange={(e) => setInternalNote(e.target.value)}
                            placeholder="Adicionar nova observação interna..."
                            className="w-full bg-white/5 border border-white/10 rounded-2xl p-4 text-sm outline-none focus:border-accent transition-all h-20 placeholder:text-slate-500"
                          />
                          <button 
                            onClick={handleAddNote}
                            className="w-full py-3 bg-white/10 hover:bg-white/20 text-white font-bold rounded-2xl transition-all text-xs"
                          >
                            Adicionar Nota Interna
                          </button>
                        </div>

                        <div className="space-y-4 bg-white/5 p-6 rounded-[2rem] border border-white/5">
                          <h5 className="text-sm font-black flex items-center gap-2 text-emerald-400">
                            <CheckCircle2 className="w-4 h-4" /> Finalizar Atendimento
                          </h5>
                          <textarea 
                            value={resolutionText}
                            onChange={(e) => setResolutionText(e.target.value)}
                            placeholder="Descreva a solução final dada ao cliente (obrigatório para resolver)..."
                            className="w-full bg-white/5 border border-white/10 rounded-2xl p-4 text-sm outline-none focus:border-emerald-400 transition-all h-24 placeholder:text-slate-500"
                          />
                          <button 
                            disabled={!resolutionText.trim()}
                            onClick={handleResolve}
                            className="w-full py-4 bg-emerald-500 hover:bg-emerald-600 disabled:opacity-30 disabled:cursor-not-allowed text-white font-black rounded-2xl shadow-lg transition-all flex items-center justify-center gap-2"
                          >
                            Resolver e Encerrar Caso
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                )}
              </div>
            </div>
          </div>
