                  <p className="text-[10px] text-white/50 uppercase font-bold">Total Avaliações</p>
                  <p className="text-2xl font-bold">{stats.total}</p>
                </div>
                <div className="bg-white/10 p-4 rounded-2xl border border-white/10">
                  <p className="text-[10px] text-white/50 uppercase font-bold">Status Atual</p>
                  <p className="text-2xl font-bold">{stats.avgScore >= 80 ? 'Excelente' : stats.avgScore >= 60 ? 'Bom' : 'Atenção'}</p>
                </div>
              </div>
            </div>

            <div className="mt-8 md:mt-0 flex flex-col items-center">
              <div className="relative w-48 h-48 flex items-center justify-center">
                <svg className="w-full h-full transform -rotate-90">
                  <circle cx="96" cy="96" r="80" stroke="currentColor" strokeWidth="12" fill="transparent" className="text-white/10" />
                  <circle cx="96" cy="96" r="80" stroke="currentColor" strokeWidth="12" fill="transparent" 
                    strokeDasharray={502.4} 
                    strokeDashoffset={502.4 - (502.4 * stats.avgScore) / 100} 
                    className="text-accent transition-all duration-1000 ease-out" 
                    strokeLinecap="round" 
                  />
                </svg>
                <div className="absolute flex flex-col items-center justify-center">
                  <span className="text-5xl font-black">{stats.avgScore}</span>
                  <span className="text-xs uppercase font-bold text-white/60">de 100</span>
                </div>
              </div>
            </div>
          </div>
          <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 rounded-full -mr-32 -mt-32 blur-3xl"></div>
          <div className="absolute bottom-0 left-0 w-64 h-64 bg-accent/20 rounded-full -ml-32 -mb-32 blur-3xl"></div>
        </div>

        <div className="bg-white rounded-3xl p-8 border border-slate-100 shadow-sm flex flex-col">
          <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center space-x-2">
            <Award className="w-5 h-5 text-accent" />
            <span>Categorias de Satisfação</span>
          </h3>
          <div className="flex-1 space-y-8">
            <RatingDotsView label="Atendimento" value={stats.catAvg.service} />
            <RatingDotsView label="Comida" value={stats.catAvg.food} />
            <RatingDotsView label="Bebidas" value={stats.catAvg.drinks} />
            <RatingDotsView label="Estrutura" value={stats.catAvg.structure} />
          </div>
        </div>
      </div>

      {/* Main Metrics */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <MetricCard title="Promotores" value={stats.promoters} subValue={stats.total > 0 ? `${Math.round((stats.promoters/stats.total)*100)}% do total` : '0%'} icon={Smile} color="bg-emerald-500" trend={12} />
        <MetricCard title="Passivos" value={stats.passives} subValue={stats.total > 0 ? `${Math.round((stats.passives/stats.total)*100)}% do total` : '0%'} icon={Meh} color="bg-amber-500" trend={-3} />
        <MetricCard title="Detratores (Abertos)" value={stats.openDetractors} subValue="Casos urgentes" icon={Frown} color="bg-red-500" trend={8} />
        <MetricCard title="Casos Resolvidos" value={stats.resolvedDetractors} subValue="Eficiência de gestão" icon={CheckCircle2} color="bg-blue-500" trend={24} />
      </div>

      {/* Evolution Graph */}
      <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
          <div>
            <h3 className="text-xl font-bold text-slate-800">Evolução Semanal</h3>
            <p className="text-sm text-slate-500">Tendência do Score de Experiência nos últimos 7 dias</p>
          </div>
          <div className="flex bg-slate-100 p-1 rounded-xl">
            <button className="px-4 py-1.5 text-xs font-bold bg-white text-slate-700 shadow-sm rounded-lg">7 dias</button>
            <button className="px-4 py-1.5 text-xs font-bold text-slate-400 hover:text-slate-600 transition-colors">30 dias</button>
          </div>
        </div>
        <div className="h-[300px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={chartData}>
              <defs>
                <linearGradient id="colorScore" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#0047a7" stopOpacity={0.1}/>
                  <stop offset="95%" stopColor="#0047a7" stopOpacity={0}/>
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 12, fontWeight: 600, fill: '#94a3b8'}} />
              <YAxis domain={[0, 100]} axisLine={false} tickLine={false} tick={{fontSize: 12, fontWeight: 600, fill: '#94a3b8'}} />
              <Tooltip 
                contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}}
                labelStyle={{fontWeight: 700, color: '#1e293b'}}
              />
              <Area type="monotone" dataKey="score" stroke="#0047a7" strokeWidth={4} fillOpacity={1} fill="url(#colorScore)" />
            </AreaChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Company } from '../types';
import { dataStore } from '../services/dataStore';
import { Store, Camera, Save, MapPin, Phone, Mail, Instagram, User, FileText, Briefcase } from 'lucide-react';

interface CompanyProfileProps {
  companyId: string;
}

const CompanyProfile: React.FC<CompanyProfileProps> = ({ companyId }) => {
  const company = dataStore.getCompany(companyId);
  const [formData, setFormData] = useState<Partial<Company>>(company || {});
  const [isSaved, setIsSaved] = useState(false);

  if (!company) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    dataStore.updateCompany(companyId, formData);
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 3000);
  };

  const InputField = ({ label, icon: Icon, value, onChange, placeholder, type = "text" }: any) => (
    <div className="space-y-2">
      <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 flex items-center gap-2">
        <Icon className="w-3 h-3" /> {label}
      </label>
      <input 
        type={type}
        value={value || ''}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
        className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900 transition-all"
      />
    </div>
  );

  return (
    <div className="max-w-4xl mx-auto pb-20">
      <form onSubmit={handleSubmit} className="space-y-8 animate-in fade-in duration-500">
        {/* Header / Logo Section */}
        <div className="bg-white rounded-[3rem] p-10 border border-slate-100 shadow-sm flex flex-col md:flex-row items-center gap-8">
          <div className="relative group">
            <div className="w-40 h-40 rounded-[2.5rem] overflow-hidden border-4 border-slate-100 shadow-xl">
              <img src={formData.logo || 'https://picsum.photos/seed/ativare/200'} alt="Logo" className="w-full h-full object-cover" />
            </div>
            <button type="button" className="absolute bottom-2 right-2 p-3 bg-primary text-white rounded-2xl shadow-lg hover:scale-110 transition-all">
              <Camera className="w-5 h-5" />
            </button>
          </div>
          <div className="flex-1 space-y-4 text-center md:text-left">
            <div>
              <h2 className="text-3xl font-black text-slate-900">{formData.name}</h2>
              <p className="text-slate-400 font-medium">Configure as informações públicas do seu negócio.</p>
            </div>
            <div className="flex flex-wrap justify-center md:justify-start gap-2">
              <span className="px-3 py-1 bg-slate-100 text-slate-600 rounded-full text-xs font-bold uppercase">{formData.category}</span>
              <span className="px-3 py-1 bg-primary/10 text-primary rounded-full text-xs font-bold uppercase">{formData.city}</span>
            </div>
          </div>
        </div>

        {/* Info Grid */}
        <div className="bg-white rounded-[3rem] p-10 border border-slate-100 shadow-sm">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <InputField 
              label="Nome do Negócio" 
              icon={Store} 
              value={formData.name} 
              onChange={(v: string) => setFormData({...formData, name: v})} 
            />
            <InputField 
              label="CNPJ" 
              icon={FileText} 
              value={formData.cnpj} 
              onChange={(v: string) => setFormData({...formData, cnpj: v})} 
              placeholder="00.000.000/0000-00"
            />
            <InputField 
              label="Categoria" 
              icon={Briefcase} 
              value={formData.category} 
              onChange={(v: string) => setFormData({...formData, category: v})} 
            />
            <InputField 
              label="Nº de Colaboradores" 
              icon={User} 
              value={formData.employees} 
              onChange={(v: string) => setFormData({...formData, employees: v})} 
              placeholder="Ex: 10-20"
            />
            <div className="md:col-span-2">
              <InputField 
                label="Endereço Completo" 
                icon={MapPin} 
                value={formData.address} 
                onChange={(v: string) => setFormData({...formData, address: v})} 
              />
            </div>
            <InputField 
              label="Telefone Comercial" 
              icon={Phone} 
              value={formData.phone} 
              onChange={(v: string) => setFormData({...formData, phone: v})} 
            />
            <InputField 
              label="E-mail de Contato" 
              icon={Mail} 
              value={formData.email} 
              onChange={(v: string) => setFormData({...formData, email: v})} 
            />
            <div className="md:col-span-2">
              <InputField 
                label="Instagram" 
                icon={Instagram} 
                value={formData.instagram} 
                onChange={(v: string) => setFormData({...formData, instagram: v})} 
                placeholder="@seunegocio"
              />
            </div>
          </div>

          <div className="mt-12 flex justify-end">
            <button 
              type="submit"
              className={`px-10 py-5 bg-primary text-white font-black rounded-3xl shadow-xl shadow-primary/30 flex items-center gap-3 hover:-translate-y-1 transition-all ${isSaved ? 'bg-emerald-500 shadow-emerald-500/30' : ''}`}
            >
              {isSaved ? <><Save className="w-5 h-5" /> Alterações Salvas!</> : <><Save className="w-5 h-5" /> Salvar Perfil</>}
            </button>
          </div>
        </div>
      </form>
    </div>
  );
};

export default CompanyProfile;

import React, { useState, useEffect } from 'react';
import { User, UserRole, Company } from './types';
import { MOCK_USERS, MOCK_COMPANIES } from './constants';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import CaseManagement from './components/CaseManagement';
import FeedbackForm from './components/FeedbackForm';
import Feedbacks from './components/Feedbacks';
import Customers from './components/Customers';
import InternalFormConfig from './components/InternalFormConfig';
import InternalMetrics from './components/InternalMetrics';
import CompanyProfile from './components/CompanyProfile';
import { LogIn, ShieldAlert, Rocket, ArrowRight, User as UserIcon, Store, ChevronLeft, ChevronRight, CheckCircle2 } from 'lucide-react';
import { dataStore } from './services/dataStore';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedCompanyId, setSelectedCompanyId] = useState<string>('');
  const [isPublicForm, setIsPublicForm] = useState(false);

  // Auth States
  const [authView, setAuthView] = useState<'LOGIN' | 'REGISTER'>('LOGIN');
  const [loginEmail, setLoginEmail] = useState('');
  const [loginPass, setLoginPass] = useState('');
  const [error, setError] = useState('');

  // Registration States
  const [regStep, setRegStep] = useState(1);
  const [regCompany, setRegCompany] = useState<Partial<Company>>({ category: 'Restaurante' });
  const [regOwner, setRegOwner] = useState<Partial<User>>({});
  const [regPass, setRegPass] = useState('');

  const [hasDetractorAlert, setHasDetractorAlert] = useState(false);

  useEffect(() => {
    if (user) {
      if (user.role === UserRole.MASTER) {
        setSelectedCompanyId(MOCK_COMPANIES[0].id);
      } else if (user.companyId) {
        setSelectedCompanyId(user.companyId);
      }
    }
  }, [user]);

  const handleFeedbackSubmitted = () => {
    setIsPublicForm(false);
    const currentFeedbacks = dataStore.getFeedbacks(selectedCompanyId || MOCK_COMPANIES[0].id);
    const lastFeedback = currentFeedbacks[currentFeedbacks.length - 1];
    if (lastFeedback?.category === 'DETRACTOR') {
      setHasDetractorAlert(true);
    }
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const found = dataStore.findUserByEmail(loginEmail);
    if (found) {
      setUser(found);
      setError('');
    } else {
      setError('Credenciais inválidas. Use os botões de teste abaixo.');
    }
  };

  const handleRegister = (e: React.FormEvent) => {
    e.preventDefault();
    if (regStep === 1) {
      setRegStep(2);
      return;
    }

    // Concluir Registro
    const { user: newUser } = dataStore.registerCompany(regCompany, regOwner);
    setUser(newUser);
    setAuthView('LOGIN');
  };

  if (isPublicForm) {
    const comp = dataStore.getCompany(selectedCompanyId) || MOCK_COMPANIES[0];
    return <FeedbackForm company={comp} onFinished={handleFeedbackSubmitted} />;
  }

  if (!user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-6 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]">
        <div className="max-w-xl w-full">
          <div className="text-center mb-10">
            <div className="w-16 h-16 bg-primary rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-xl shadow-primary/30">
              <span className="text-3xl font-black text-white italic">A</span>
            </div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tight">Ativare <span className="text-primary">Experience</span></h1>
            <p className="text-slate-500 font-medium mt-2">Gestão Estratégica de CX & Reputação</p>
          </div>

          <div className="bg-white rounded-[3rem] shadow-2xl overflow-hidden border border-white">
            <div className="flex border-b border-slate-100">
              <button 
                onClick={() => setAuthView('LOGIN')}
                className={`flex-1 py-6 text-sm font-black uppercase tracking-widest transition-all ${authView === 'LOGIN' ? 'text-primary bg-white' : 'text-slate-300 bg-slate-50'}`}
              >
                Fazer Login
              </button>
              <button 
                onClick={() => setAuthView('REGISTER')}
                className={`flex-1 py-6 text-sm font-black uppercase tracking-widest transition-all ${authView === 'REGISTER' ? 'text-primary bg-white' : 'text-slate-300 bg-slate-50'}`}
              >
                Experimentar Grátis
              </button>
            </div>

            <div className="p-10">
              {authView === 'LOGIN' ? (
                <form onSubmit={handleLogin} className="space-y-6 animate-in fade-in slide-in-from-left duration-300">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">E-mail de Acesso</label>
                    <input 
                      type="email" 
                      value={loginEmail}
                      onChange={(e) => setLoginEmail(e.target.value)}
                      className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl outline-none focus:border-primary transition-all text-sm font-bold text-slate-900 placeholder:text-slate-300"
                      placeholder="Seu e-mail corporativo"
                      required
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Senha</label>
                    <input 
                      type="password" 
                      value={loginPass}
                      onChange={(e) => setLoginPass(e.target.value)}
                      className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl outline-none focus:border-primary transition-all text-sm font-bold text-slate-900 placeholder:text-slate-300"
                      placeholder="••••••••"
                      required
                    />
                  </div>

                  {error && (
                    <div className="p-4 bg-red-50 rounded-2xl border border-red-100 flex items-start space-x-3">
                      <ShieldAlert className="w-5 h-5 text-red-500 mt-0.5" />
                      <p className="text-xs font-bold text-red-600">{error}</p>
                    </div>
                  )}

                  <button type="submit" className="w-full py-5 bg-primary text-white font-black rounded-3xl shadow-xl hover:bg-[#003680] hover:-translate-y-1 transition-all flex items-center justify-center gap-2">
                    <LogIn className="w-5 h-5" /> Entrar no Ativare
                  </button>

                  <div className="pt-4 border-t border-slate-50 flex flex-col items-center gap-4">
                    <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.2em]">Acesso Rápido</p>
                    <div className="flex flex-wrap justify-center gap-2">
                      <button onClick={() => { setLoginEmail('master@ativare.com'); setLoginPass('123456'); }} className="px-4 py-2 bg-slate-100 text-[10px] font-black uppercase rounded-xl hover:bg-slate-200 transition-all text-slate-600">Master</button>
                      <button onClick={() => { setLoginEmail('dono@pizza.com'); setLoginPass('123456'); }} className="px-4 py-2 bg-slate-100 text-[10px] font-black uppercase rounded-xl hover:bg-slate-200 transition-all text-slate-600">Business</button>
                    </div>
                  </div>
                </form>
              ) : (
                <form onSubmit={handleRegister} className="space-y-8 animate-in fade-in slide-in-from-right duration-300">
                  <div className="flex items-center justify-between mb-2">
                    <h3 className="text-xl font-black text-slate-900 flex items-center gap-2">
                      <Rocket className="w-6 h-6 text-accent" />
                      {regStep === 1 ? 'Dados da Empresa' : 'Dados do Gestor'}
                    </h3>
                    <span className="text-[10px] font-black text-slate-300 uppercase bg-slate-50 px-3 py-1 rounded-full">Passo {regStep} de 2</span>
                  </div>

                  {regStep === 1 ? (
                    <div className="grid grid-cols-2 gap-4">
                      <div className="col-span-2 space-y-2">
                        <label className="text-[10px] font-black uppercase text-slate-400">Nome do Negócio</label>
                        <input required type="text" value={regCompany.name} onChange={e => setRegCompany({...regCompany, name: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" placeholder="Ex: Pizzaria Bella Italia" />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[10px] font-black uppercase text-slate-400">CNPJ</label>
                        <input required type="text" value={regCompany.cnpj} onChange={e => setRegCompany({...regCompany, cnpj: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" placeholder="00.000.000/0001-00" />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[10px] font-black uppercase text-slate-400">Categoria</label>
                        <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" value={regCompany.category} onChange={e => setRegCompany({...regCompany, category: e.target.value})}>
                          <option>Restaurante</option>
                          <option>Hamburgueria</option>
                          <option>Pizzaria</option>
                          <option>Bar / Pub</option>
                          <option>Evento / Buffet</option>
                        </select>
                      </div>
                      <div className="col-span-2 space-y-2">
                        <label className="text-[10px] font-black uppercase text-slate-400">Endereço</label>
                        <input required type="text" value={regCompany.address} onChange={e => setRegCompany({...regCompany, address: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" placeholder="Rua, Número, Cidade - UF" />
                      </div>
                    </div>
                  ) : (
                    <div className="space-y-4">
                      <div className="space-y-2">
                        <label className="text-[10px] font-black uppercase text-slate-400">Nome Completo</label>
                        <input required type="text" value={regOwner.name} onChange={e => setRegOwner({...regOwner, name: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" placeholder="Seu nome" />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[10px] font-black uppercase text-slate-400">E-mail Principal</label>
                        <input required type="email" value={regOwner.email} onChange={e => setRegOwner({...regOwner, email: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" placeholder="seu@email.com" />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[10px] font-black uppercase text-slate-400">Defina uma Senha</label>
                        <input required type="password" value={regPass} onChange={e => setRegPass(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" placeholder="••••••••" />
                      </div>
                    </div>
                  )}

                  <div className="flex gap-4">
                    {regStep === 2 && (
                      <button type="button" onClick={() => setRegStep(1)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black rounded-3xl flex items-center justify-center gap-2">
                        <ChevronLeft className="w-5 h-5" /> Voltar
                      </button>
                    )}
                    <button type="submit" className="flex-[2] py-5 bg-primary text-white font-black rounded-3xl shadow-xl hover:bg-[#003680] transition-all flex items-center justify-center gap-2">
                      {regStep === 1 ? 'Próximo Passo' : 'Começar Agora'} <ChevronRight className="w-5 h-5" />
                    </button>
                  </div>

                  <p className="text-center text-[10px] text-slate-400 font-bold uppercase leading-relaxed">
                    Ao clicar em começar, você aceita nossos termos de uso e inicia automaticamente seu período de 15 dias de trial.
                  </p>
                </form>
              )}
            </div>

            <div className="bg-slate-50 p-6 flex justify-center">
              <button onClick={() => setIsPublicForm(true)} className="flex items-center gap-2 text-accent font-black text-xs uppercase hover:underline">
                <Store className="w-4 h-4" /> Visualizar Página de Avaliação Pública
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout 
      user={user} 
      onLogout={() => { setUser(null); setAuthView('LOGIN'); }} 
      activeTab={activeTab} 
      setActiveTab={(tab) => {
        setActiveTab(tab);
        if (['feedbacks', 'cases', 'customers'].includes(tab)) setHasDetractorAlert(false);
      }}
      selectedCompanyId={selectedCompanyId}
      setSelectedCompanyId={setSelectedCompanyId}
      hasDetractorAlert={hasDetractorAlert}
    >
      {activeTab === 'dashboard' && <Dashboard companyId={selectedCompanyId} />}
      {activeTab === 'cases' && <CaseManagement companyId={selectedCompanyId} currentUser={user} />}
      {activeTab === 'feedbacks' && <Feedbacks companyId={selectedCompanyId} currentUser={user} />}
      {activeTab === 'customers' && <Customers companyId={selectedCompanyId} currentUser={user} />}
      {activeTab === 'form_config' && <InternalFormConfig companyId={selectedCompanyId} />}
      {activeTab === 'internal_metrics' && <InternalMetrics companyId={selectedCompanyId} />}
      {activeTab === 'company_profile' && <CompanyProfile companyId={selectedCompanyId} />}

      {['benchmarking', 'bi'].includes(activeTab) && (
        <div className="bg-white rounded-[3rem] p-20 text-center border border-dashed border-slate-200">
          <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-8 text-slate-200"><ShieldAlert className="w-12 h-12" /></div>
          <h2 className="text-3xl font-black text-slate-900 mb-2">Módulo Enterprise</h2>
          <p className="text-slate-500 font-medium max-w-sm mx-auto">Este módulo avançado de BI e benchmarking global está em fase final de homologação.</p>
        </div>
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Company, InternalQuestion } from '../types';
import { dataStore } from '../services/dataStore';
import { ChevronRight, ChevronLeft, Send, CheckCircle2, AlertCircle, LogOut } from 'lucide-react';

interface FeedbackFormProps {
  company: Company;
  onFinished: () => void;
  onBack?: () => void;
}

const FeedbackForm: React.FC<FeedbackFormProps> = ({ company, onFinished, onBack }) => {
  const [step, setStep] = useState(1);
  const [showValidation, setShowValidation] = useState(false);
  const internalQuestions = useMemo(() => dataStore.getInternalQuestions(company.id), [company.id]);

  const [formData, setFormData] = useState({
    name: '',
    surname: '',
    phone: '',
    email: '',
    howKnown: '',
    service: 0, 
    food: 0,    
    drinks: 0,  
    structure: 0, 
    profile: 'family' as any,
    observation: '',
    internalResponses: {} as any
  });
  const [submitted, setSubmitted] = useState(false);

  const isStep1Valid = formData.name.trim() !== '' && formData.surname.trim() !== '' && formData.phone.trim() !== '';

  const isStep2Valid = useMemo(() => {
    const coreRatingsDone = formData.service > 0 && formData.food > 0 && formData.drinks > 0 && formData.structure > 0;

    const requiredInternalDone = internalQuestions
      .filter(q => q.required)
      .every(q => {
        const resp = formData.internalResponses[q.id];
        if (q.type === 'TEXT') return resp && resp.trim() !== '';
        if (q.type === 'SCALE_5' || q.type === 'SCALE_10') return resp > 0;
        if (q.type === 'YES_NO') return resp !== undefined && resp !== null;
        return true;
      });

    return coreRatingsDone && requiredInternalDone;
  }, [formData, internalQuestions]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (step === 1) {
      if (!isStep1Valid) {
        setShowValidation(true);
        return;
      }
      setStep(2);
      setShowValidation(false);
      window.scrollTo(0, 0);
      return;
    }

    if (!isStep2Valid) {
      setShowValidation(true);
      return;
    }

    // Chamada centralizada que dispara CRM, Feedbacks e Casos
    dataStore.addFeedback({
      companyId: company.id,
      customerId: '', // Será gerado pelo dataStore
      customerName: `${formData.name} ${formData.surname}`,
      customerPhone: formData.phone,
      howKnown: formData.howKnown,
      scores: {
        service: formData.service,
        food: formData.food,
        drinks: formData.drinks,
        structure: formData.structure
      },
      internalResponses: formData.internalResponses,
      profile: formData.profile,
      observation: formData.observation,
      email: formData.email
    });

    setSubmitted(true);
  };

  const handleInternalResponse = (qId: string, value: any) => {
    setFormData({
      ...formData,
      internalResponses: { ...formData.internalResponses, [qId]: value }
    });
  };

  const RatingDots = ({ value, onChange, label, max = 10, isError = false }: any) => {
    const [hover, setHover] = useState(0);
    const activeValue = hover || value;

    const getColorClass = (val: number) => {
      if (val === 0) return 'bg-transparent';
      if (val <= 3) return 'bg-red-500';
      if (val <= 6) return 'bg-yellow-400';
      return 'bg-emerald-500';
    };

    const activeColor = getColorClass(activeValue);

    return (
      <div className={`space-y-4 p-4 rounded-3xl transition-all ${isError ? 'bg-red-50 ring-2 ring-red-200 animate-pulse' : ''}`}>
        <div className="flex justify-between items-center">
          <label className="text-sm font-black text-slate-700 uppercase tracking-tight">{label}</label>
          <span className={`text-xl font-black px-3 py-1 rounded-xl min-w-[3rem] text-center ${
            activeValue === 0 ? 'text-slate-300 bg-slate-100' :
            activeValue <= 3 ? 'text-red-500 bg-red-50' : 
            activeValue <= 6 ? 'text-yellow-600 bg-yellow-50' : 
            'text-emerald-500 bg-emerald-50'
          }`}>
            {activeValue === 0 ? '—' : activeValue}
          </span>
        </div>
        <div className="flex justify-between gap-1.5">
          {Array.from({ length: max }).map((_, i) => {
            const dotValue = i + 1;
            const isFilled = dotValue <= activeValue;
            return (
              <button
                key={dotValue}
                type="button"
                onMouseEnter={() => setHover(dotValue)}
                onMouseLeave={() => setHover(0)}
                onClick={() => {
                  onChange(dotValue);
                  setShowValidation(false);
                }}
                className={`
                  flex-1 h-10 rounded-full transition-all duration-200 border-2
                  ${isFilled && activeValue > 0 
                    ? `${activeColor} border-transparent scale-105 shadow-md shadow-${activeColor}/20` 
                    : 'bg-white border-slate-100 hover:border-slate-200'}
                `}
              />
            );
          })}
        </div>
        <div className="flex justify-between px-1 text-[9px] font-black text-slate-300 uppercase tracking-widest">
          <span>Pobre</span>
          <span>Excepcional</span>
        </div>
      </div>
    );
  };

  if (submitted) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-[3rem] shadow-xl p-12 text-center animate-in fade-in zoom-in duration-500">
          <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center mx-auto mb-6">
            <CheckCircle2 className="w-10 h-10" />
          </div>
          <h2 className="text-2xl font-black text-slate-900 mb-4">Obrigado pelo seu feedback!</h2>
          <p className="text-slate-500 mb-8 font-medium leading-relaxed">Sua opinião ajuda o <span className="font-bold">{company.name}</span> a oferecer uma experiência cada vez melhor.</p>
          <button 
            onClick={onFinished}
            className="w-full py-5 bg-primary text-white font-black rounded-3xl shadow-lg hover:shadow-primary/30 transition-all"
          >
            Finalizar
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-100 flex flex-col font-inter">
      <header className="bg-white border-b border-slate-200 p-8 flex flex-col items-center">
        <div className="w-20 h-20 rounded-3xl border-4 border-white shadow-2xl overflow-hidden -mt-16 mb-4">
          <img src={company.logo} alt={company.name} className="w-full h-full object-cover" />
        </div>
        <h1 className="text-2xl font-black text-slate-900">{company.name}</h1>
      </header>

      <div className="flex-1 max-w-xl w-full mx-auto p-6 md:p-10">
        <div className="bg-white rounded-[3rem] shadow-2xl overflow-hidden border border-white">
          <div className="h-3 w-full bg-slate-100">
            <div className="h-full bg-primary transition-all duration-700" style={{ width: `${step * 50}%` }}></div>
          </div>

          <form onSubmit={handleSubmit} className="p-10 space-y-10">
            {step === 1 ? (
              <div className="space-y-8 animate-in slide-in-from-right duration-300">
                <div className="space-y-1">
                  <h2 className="text-3xl font-black text-slate-900">Seja bem-vindo!</h2>
                  <p className="text-slate-400 font-medium">Conte-nos um pouco sobre sua visita hoje.</p>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Nome *</label>
                    <input 
                      required
                      type="text" 
                      className={`w-full p-4 bg-slate-50 border rounded-2xl outline-none focus:border-primary font-bold text-slate-900 ${showValidation && !formData.name ? 'border-red-300 bg-red-50' : 'border-slate-200'}`}
                      value={formData.name}
                      onChange={(e) => setFormData({...formData, name: e.target.value})}
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Sobrenome *</label>
                    <input 
                      required
                      type="text" 
                      className={`w-full p-4 bg-slate-50 border rounded-2xl outline-none focus:border-primary font-bold text-slate-900 ${showValidation && !formData.surname ? 'border-red-300 bg-red-50' : 'border-slate-200'}`}
                      value={formData.surname}
                      onChange={(e) => setFormData({...formData, surname: e.target.value})}
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">WhatsApp de Contato *</label>
                  <input 
                    required
                    type="tel" 
                    placeholder="(00) 00000-0000"
                    className={`w-full p-4 bg-slate-50 border rounded-2xl outline-none focus:border-primary font-bold text-slate-900 ${showValidation && !formData.phone ? 'border-red-300 bg-red-50' : 'border-slate-200'}`}
                    value={formData.phone}
                    onChange={(e) => setFormData({...formData, phone: e.target.value})}
                  />
                </div>

                <div className="space-y-4">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Seu perfil hoje:</label>
                  <div className="grid grid-cols-2 gap-3">
                    {['family', 'friends', 'couple', 'kids'].map(p => (
                      <button
                        key={p}
                        type="button"
                        onClick={() => setFormData({...formData, profile: p as any})}
                        className={`p-4 rounded-2xl border-2 font-black text-xs transition-all ${
                          formData.profile === p 
                            ? 'bg-primary border-primary text-white shadow-lg' 
                            : 'bg-white border-slate-100 text-slate-400'
                        }`}
                      >
                        {p === 'family' ? 'Família' : p === 'friends' ? 'Amigos' : p === 'couple' ? 'Casal' : 'Crianças'}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="space-y-4">
                  <button 
                    type="submit"
                    className={`w-full py-5 text-white font-black rounded-3xl shadow-xl flex items-center justify-center gap-3 transition-all ${isStep1Valid ? 'bg-primary hover:translate-y-[-2px]' : 'bg-slate-300 cursor-not-allowed'}`}
                  >
                    Continuar <ChevronRight className="w-5 h-5" />
                  </button>

                  {onBack && (
                    <button 
                      type="button"
                      onClick={onBack}
                      className="w-full py-4 text-slate-400 font-black text-xs uppercase tracking-widest hover:text-primary transition-all flex items-center justify-center gap-2"
                    >
                      <LogOut className="w-4 h-4" /> Voltar para o Login
                    </button>
                  )}
                </div>
              </div>
            ) : (
              <div className="space-y-12 animate-in slide-in-from-right duration-300">
                <div className="space-y-6">
                  <h3 className="text-[10px] font-black uppercase text-slate-300 tracking-[0.2em] border-b border-slate-50 pb-4">Avaliação Ativare</h3>
                  <RatingDots 
                    label="Atendimento" 
                    value={formData.service} 
                    onChange={(v: number) => setFormData({...formData, service: v})} 
                    isError={showValidation && formData.service === 0}
                  />
                  <RatingDots 
                    label="Comida" 
                    value={formData.food} 
                    onChange={(v: number) => setFormData({...formData, food: v})} 
                    isError={showValidation && formData.food === 0}
                  />
                  <RatingDots 
                    label="Bebidas" 
                    value={formData.drinks} 
                    onChange={(v: number) => setFormData({...formData, drinks: v})} 
                    isError={showValidation && formData.drinks === 0}
                  />
                  <RatingDots 
                    label="Ambiente" 
                    value={formData.structure} 
                    onChange={(v: number) => setFormData({...formData, structure: v})} 
                    isError={showValidation && formData.structure === 0}
                  />
                </div>

                {internalQuestions.length > 0 && (
                  <div className="space-y-10 pt-10 border-t border-slate-100">
                    <h3 className="text-[10px] font-black uppercase text-slate-300 tracking-[0.2em] border-b border-slate-50 pb-4">Checklist da Casa</h3>
                    {internalQuestions.map(q => {
                      const resp = formData.internalResponses[q.id];
                      const isMissing = q.required && (resp === undefined || resp === null || resp === 0 || (typeof resp === 'string' && resp.trim() === ''));

                      return (
                        <div key={q.id} className="space-y-4">
                          {q.type === 'YES_NO' && (
                            <div className={`space-y-4 p-4 rounded-3xl transition-all ${showValidation && isMissing ? 'bg-red-50 ring-2 ring-red-200 animate-pulse' : ''}`}>
                              <label className="text-sm font-black text-slate-700 uppercase tracking-tight">{q.text} {q.required && '*'}</label>
                              <div className="flex gap-4">
                                {['SIM', 'NÃO'].map(opt => (
                                  <button
                                    key={opt}
                                    type="button"
                                    onClick={() => handleInternalResponse(q.id, opt)}
                                    className={`flex-1 py-4 rounded-2xl border-2 font-black text-sm transition-all ${
                                      formData.internalResponses[q.id] === opt 
                                        ? 'bg-primary border-primary text-white shadow-lg' 
                                        : 'bg-white border-slate-100 text-slate-400'
                                    }`}
                                  >
                                    {opt}
                                  </button>
                                ))}
                              </div>
                            </div>
                          )}

                          {(q.type === 'SCALE_5' || q.type === 'SCALE_10') && (
                            <RatingDots 
                              max={q.type === 'SCALE_5' ? 5 : 10}
                              label={q.text + (q.required ? ' *' : '')}
                              value={formData.internalResponses[q.id] || 0} 
                              onChange={(v: number) => handleInternalResponse(q.id, v)} 
                              isError={showValidation && isMissing}
                            />
                          )}

                          {q.type === 'TEXT' && (
                            <div className={`space-y-2 p-4 rounded-3xl transition-all ${showValidation && isMissing ? 'bg-red-50 ring-2 ring-red-200 animate-pulse' : ''}`}>
                               <label className="text-sm font-black text-slate-700 uppercase tracking-tight">{q.text} {q.required && '*'}</label>
                              <textarea 
                                required={q.required}
                                className={`w-full h-24 p-4 bg-slate-50 border rounded-2xl outline-none focus:border-primary font-medium text-sm text-slate-900 ${showValidation && isMissing ? 'border-red-300' : 'border-slate-100'}`}
                                placeholder="Sua resposta..."
                                value={formData.internalResponses[q.id] || ''}
                                onChange={(e) => handleInternalResponse(q.id, e.target.value)}
                              />
                            </div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                )}

                <div className="space-y-4 pt-10 border-t border-slate-100">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Observação Final (Opcional)</label>
                  <textarea 
                    className="w-full h-32 p-4 bg-slate-50 border border-slate-100 rounded-3xl outline-none focus:border-primary font-medium text-sm text-slate-900"
                    placeholder="Algo mais que gostaria de nos dizer?"
                    value={formData.observation}
                    onChange={(e) => setFormData({...formData, observation: e.target.value})}
                  />
                </div>

                {showValidation && !isStep2Valid && (
                  <div className="p-4 bg-red-50 border border-red-200 rounded-2xl flex items-center gap-3 text-red-600 animate-in slide-in-from-top">
                    <AlertCircle className="w-5 h-5 flex-shrink-0" />
                    <p className="text-xs font-bold">Por favor, responda a todas as avaliações obrigatórias antes de enviar.</p>
                  </div>
                )}

                <div className="flex gap-4">
                  <button type="button" onClick={() => setStep(1)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black rounded-3xl hover:bg-slate-200 transition-all flex items-center justify-center gap-2">
                    <ChevronLeft className="w-5 h-5" /> Voltar
                  </button>
                  <button 
                    type="submit" 
                    className={`flex-[2] py-5 text-white font-black rounded-3xl shadow-xl flex items-center justify-center gap-3 transition-all ${isStep2Valid ? 'bg-primary shadow-primary/30 hover:translate-y-[-2px]' : 'bg-slate-300 cursor-not-allowed opacity-60'}`}
                  >
                    Enviar Feedback <Send className="w-5 h-5" />
                  </button>
                </div>
              </div>
            )}
          </form>
        </div>
      </div>
    </div>
  );
};

export default FeedbackForm;

import React, { useState, useEffect } from 'react';
import { User, UserRole, Company } from './types';
import { MOCK_USERS, MOCK_COMPANIES } from './constants';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import CaseManagement from './components/CaseManagement';
import FeedbackForm from './components/FeedbackForm';
import Feedbacks from './components/Feedbacks';
import Customers from './components/Customers';
import InternalFormConfig from './components/InternalFormConfig';
import InternalMetrics from './components/InternalMetrics';
import CompanyProfile from './components/CompanyProfile';
import { LogIn, ShieldAlert, Rocket, ArrowRight, User as UserIcon, Store, ChevronLeft, ChevronRight, CheckCircle2 } from 'lucide-react';
import { dataStore } from './services/dataStore';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedCompanyId, setSelectedCompanyId] = useState<string>('');
  const [isPublicForm, setIsPublicForm] = useState(false);

  // Auth States
  const [authView, setAuthView] = useState<'LOGIN' | 'REGISTER'>('LOGIN');
  const [loginEmail, setLoginEmail] = useState('');
  const [loginPass, setLoginPass] = useState('');
  const [error, setError] = useState('');

  // Registration States
  const [regStep, setRegStep] = useState(1);
  const [regCompany, setRegCompany] = useState<Partial<Company>>({ category: 'Restaurante' });
  const [regOwner, setRegOwner] = useState<Partial<User>>({});
  const [regPass, setRegPass] = useState('');

  const [hasDetractorAlert, setHasDetractorAlert] = useState(false);

  useEffect(() => {
    if (user) {
      if (user.role === UserRole.MASTER) {
        setSelectedCompanyId(MOCK_COMPANIES[0].id);
      } else if (user.companyId) {
        setSelectedCompanyId(user.companyId);
      }
    }
  }, [user]);

  const handleFeedbackSubmitted = () => {
    setIsPublicForm(false);
    const currentFeedbacks = dataStore.getFeedbacks(selectedCompanyId || MOCK_COMPANIES[0].id);
    const lastFeedback = currentFeedbacks[currentFeedbacks.length - 1];
    if (lastFeedback?.category === 'DETRACTOR') {
      setHasDetractorAlert(true);
    }
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const found = dataStore.findUserByEmail(loginEmail);
    if (found) {
      setUser(found);
      setError('');
    } else {
      setError('Credenciais inválidas. Use os botões de teste abaixo.');
    }
  };

  const handleRegister = (e: React.FormEvent) => {
    e.preventDefault();
    if (regStep === 1) {
      setRegStep(2);
      return;
    }

    // Concluir Registro
    const { user: newUser } = dataStore.registerCompany(regCompany, regOwner);
    setUser(newUser);
    setAuthView('LOGIN');
  };

  if (isPublicForm) {
    const comp = dataStore.getCompany(selectedCompanyId) || MOCK_COMPANIES[0];
    return <FeedbackForm 
      company={comp} 
      onFinished={handleFeedbackSubmitted} 
      onBack={() => setIsPublicForm(false)}
    />;
  }

  if (!user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-6 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]">
        <div className="max-w-xl w-full">
          <div className="text-center mb-10">
            <div className="w-16 h-16 bg-primary rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-xl shadow-primary/30">
              <span className="text-3xl font-black text-white italic">A</span>
            </div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tight">Ativare <span className="text-primary">Experience</span></h1>
            <p className="text-slate-500 font-medium mt-2">Gestão Estratégica de CX & Reputação</p>
          </div>

          <div className="bg-white rounded-[3rem] shadow-2xl overflow-hidden border border-white">
            <div className="flex border-b border-slate-100">
              <button 
                onClick={() => setAuthView('LOGIN')}
                className={`flex-1 py-6 text-sm font-black uppercase tracking-widest transition-all ${authView === 'LOGIN' ? 'text-primary bg-white' : 'text-slate-300 bg-slate-50'}`}
              >
                Fazer Login
              </button>
              <button 
                onClick={() => setAuthView('REGISTER')}
                className={`flex-1 py-6 text-sm font-black uppercase tracking-widest transition-all ${authView === 'REGISTER' ? 'text-primary bg-white' : 'text-slate-300 bg-slate-50'}`}
              >
                Experimentar Grátis
              </button>
            </div>

            <div className="p-10">
              {authView === 'LOGIN' ? (
                <form onSubmit={handleLogin} className="space-y-6 animate-in fade-in slide-in-from-left duration-300">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">E-mail de Acesso</label>
                    <input 
                      type="email" 
                      value={loginEmail}
                      onChange={(e) => setLoginEmail(e.target.value)}
                      className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl outline-none focus:border-primary transition-all text-sm font-bold text-slate-900 placeholder:text-slate-300"
                      placeholder="Seu e-mail corporativo"
                      required
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Senha</label>
                    <input 
                      type="password" 
                      value={loginPass}
                      onChange={(e) => setLoginPass(e.target.value)}
                      className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl outline-none focus:border-primary transition-all text-sm font-bold text-slate-900 placeholder:text-slate-300"
                      placeholder="••••••••"
                      required
                    />
                  </div>

                  {error && (
                    <div className="p-4 bg-red-50 rounded-2xl border border-red-100 flex items-start space-x-3">
                      <ShieldAlert className="w-5 h-5 text-red-500 mt-0.5" />
                      <p className="text-xs font-bold text-red-600">{error}</p>
                    </div>
                  )}

                  <button type="submit" className="w-full py-5 bg-primary text-white font-black rounded-3xl shadow-xl hover:bg-[#003680] hover:-translate-y-1 transition-all flex items-center justify-center gap-2">
                    <LogIn className="w-5 h-5" /> Entrar no Ativare
                  </button>

                  <div className="pt-4 border-t border-slate-50 flex flex-col items-center gap-4">
                    <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.2em]">Acesso Rápido</p>
                    <div className="flex flex-wrap justify-center gap-2">
                      <button onClick={() => { setLoginEmail('master@ativare.com'); setLoginPass('123456'); }} className="px-4 py-2 bg-slate-100 text-[10px] font-black uppercase rounded-xl hover:bg-slate-200 transition-all text-slate-600">Master</button>
