      <input 
        type={type}
        value={value || ''}
        readOnly={readOnly}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
        className={`w-full p-4 border rounded-2xl outline-none transition-all font-bold text-slate-900 ${
          readOnly 
            ? 'bg-slate-100 border-slate-100 cursor-not-allowed text-slate-400' 
            : 'bg-slate-50 border-slate-200 focus:border-primary'
        }`}
      />
    </div>
  );

  return (
    <div className="max-w-4xl mx-auto pb-20">
      <form onSubmit={handleSubmit} className="space-y-8 animate-in fade-in duration-500">
        <input 
          type="file" 
          ref={fileInputRef} 
          className="hidden" 
          accept="image/png, image/jpeg, image/webp"
          onChange={handleFileChange}
        />

        {/* Header / Logo Section */}
        <div className="bg-white rounded-[3rem] p-10 border border-slate-100 shadow-sm flex flex-col md:flex-row items-center gap-8">
          <div className="relative group">
            <div className="w-40 h-40 rounded-[2.5rem] overflow-hidden border-4 border-slate-100 shadow-xl bg-slate-50 flex items-center justify-center">
              {formData.logo ? (
                <img src={formData.logo} alt="Logo" className="w-full h-full object-cover" />
              ) : (
                <Store className="w-12 h-12 text-slate-200" />
              )}
            </div>
            <button 
              type="button" 
              onClick={handleLogoClick}
              className="absolute bottom-2 right-2 p-3 bg-primary text-white rounded-2xl shadow-lg hover:scale-110 transition-all z-10"
            >
              <Camera className="w-5 h-5" />
            </button>
          </div>
          <div className="flex-1 space-y-4 text-center md:text-left">
            <div>
              <h2 className="text-3xl font-black text-slate-900">{formData.name}</h2>
              <p className="text-slate-400 font-medium">Configure as informações públicas do seu negócio.</p>
            </div>
            <div className="flex flex-wrap justify-center md:justify-start gap-2">
              <span className="px-3 py-1 bg-slate-100 text-slate-600 rounded-full text-xs font-bold uppercase">{formData.category}</span>
              <span className="px-3 py-1 bg-primary/10 text-primary rounded-full text-xs font-bold uppercase">{formData.city}</span>
            </div>
          </div>
        </div>

        {/* Info Grid */}
        <div className="bg-white rounded-[3rem] p-10 border border-slate-100 shadow-sm">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <InputField 
              label="Nome do Negócio" 
              icon={Store} 
              value={formData.name} 
              onChange={(v: string) => setFormData({...formData, name: v})} 
            />

            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 flex items-center gap-2">
                <FileText className="w-3 h-3" /> CNPJ
              </label>
              <div className="flex gap-2">
                <input 
                  type="text"
                  value={formData.cnpj || ''}
                  readOnly
                  className="flex-1 p-4 bg-slate-100 border border-slate-100 rounded-2xl outline-none font-bold text-slate-400 cursor-not-allowed"
                />
                <button 
                  type="button"
                  onClick={() => setShowCNPJModal(true)}
                  className="px-4 bg-white border border-slate-200 text-slate-400 text-[10px] font-black uppercase tracking-widest rounded-2xl hover:bg-slate-50 transition-all whitespace-nowrap"
                >
                  Solicitar Alteração
                </button>
              </div>
            </div>

            <InputField 
              label="Categoria" 
              icon={Briefcase} 
              value={formData.category} 
              onChange={(v: string) => setFormData({...formData, category: v})} 
            />
            <InputField 
              label="Nº de Colaboradores" 
              icon={UserIcon} 
              value={formData.employees} 
              onChange={(v: string) => setFormData({...formData, employees: v})} 
              placeholder="Ex: 10-20"
            />
            <div className="md:col-span-2">
              <InputField 
                label="Endereço Completo" 
                icon={MapPin} 
                value={formData.address} 
                onChange={(v: string) => setFormData({...formData, address: v})} 
              />
            </div>
            <InputField 
              label="Telefone Comercial" 
              icon={Phone} 
              value={formData.phone} 
              onChange={(v: string) => setFormData({...formData, phone: v})} 
            />
            <InputField 
              label="E-mail de Contato" 
              icon={Mail} 
              value={formData.email} 
              onChange={(v: string) => setFormData({...formData, email: v})} 
            />
            <div className="md:col-span-2">
              <InputField 
                label="Instagram" 
                icon={Instagram} 
                value={formData.instagram} 
                onChange={(v: string) => setFormData({...formData, instagram: v})} 
                placeholder="@seunegocio"
              />
            </div>
          </div>

          <div className="mt-12 flex justify-end">
            <button 
              type="submit"
              className={`px-10 py-5 bg-primary text-white font-black rounded-3xl shadow-xl shadow-primary/30 flex items-center gap-3 hover:-translate-y-1 transition-all ${isSaved ? 'bg-emerald-500 shadow-emerald-500/30' : ''}`}
            >
              {isSaved ? <><Save className="w-5 h-5" /> Perfil Atualizado!</> : <><Save className="w-5 h-5" /> Salvar Alterações</>}
            </button>
          </div>
        </div>

        {/* History of Requests (only if any exist) */}
        {company.cnpjRequests && company.cnpjRequests.length > 0 && (
          <div className="bg-white rounded-[3rem] p-10 border border-slate-100 shadow-sm space-y-6">
            <h3 className="text-sm font-black uppercase tracking-widest text-slate-400 flex items-center gap-2">
              <Clock className="w-4 h-4" /> Histórico de Solicitações de CNPJ
            </h3>
            <div className="space-y-4">
              {company.cnpjRequests.slice().reverse().map(req => (
                <div key={req.id} className="p-5 bg-slate-50 rounded-3xl border border-slate-100 flex items-center justify-between">
                  <div>
                    <p className="text-xs font-bold text-slate-800">Solicitado: <span className="text-slate-500">{req.requestedCNPJ}</span></p>
                    <p className="text-[10px] text-slate-400 mt-1 font-medium italic">"{req.reason}"</p>
                  </div>
                  <div className="text-right">
                    <span className={`px-2 py-0.5 rounded-full text-[9px] font-black uppercase tracking-widest ${
                      req.status === 'PENDING' ? 'bg-amber-100 text-amber-600' : 
                      req.status === 'APPROVED' ? 'bg-emerald-100 text-emerald-600' : 
                      'bg-red-100 text-red-600'
                    }`}>
                      {req.status === 'PENDING' ? 'Em Análise' : req.status === 'APPROVED' ? 'Aprovado' : 'Recusado'}
                    </span>
                    <p className="text-[9px] text-slate-300 mt-1">{new Date(req.createdAt).toLocaleDateString('pt-BR')}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </form>

      {/* CNPJ Change Modal */}
      {showCNPJModal && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => !isRequesting && setShowCNPJModal(false)}></div>
          <div className="bg-white rounded-[3rem] w-full max-w-lg p-10 relative z-10 shadow-2xl border border-white animate-in zoom-in duration-300">
            <button 
              onClick={() => setShowCNPJModal(false)}
              className="absolute top-8 right-8 text-slate-400 hover:text-slate-600"
            >
              <X className="w-6 h-6" />
            </button>

            <div className="w-20 h-20 bg-amber-50 text-amber-500 rounded-[2rem] flex items-center justify-center mb-6">
              <AlertTriangle className="w-10 h-10" />
            </div>

            <h3 className="text-2xl font-black text-slate-900 mb-2">Solicitar Alteração de CNPJ</h3>
            <p className="text-slate-500 text-sm font-medium mb-8">Por questões de segurança, a alteração do CNPJ deve ser aprovada pela equipe Master da plataforma.</p>

            <form onSubmit={handleCNPJRequest} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Novo CNPJ</label>
                <input 
                  required
                  type="text" 
                  value={newRequestedCNPJ}
                  onChange={(e) => setNewRequestedCNPJ(e.target.value)}
                  placeholder="00.000.000/0000-00"
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900"
                />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Motivo da Alteração</label>
                <textarea 
                  required
                  value={cnpjReason}
                  onChange={(e) => setCnpjReason(e.target.value)}
                  placeholder="Explique o motivo da mudança (ex: alteração contratual, erro de digitação)..."
                  className="w-full h-32 p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm outline-none focus:border-primary font-medium text-slate-900"
                />
              </div>

              <button 
                type="submit"
                disabled={isRequesting}
                className="w-full py-5 bg-primary text-white font-black rounded-3xl shadow-xl hover:shadow-primary/30 transition-all flex items-center justify-center gap-2 disabled:opacity-50"
              >
                {isRequesting ? 'Enviando...' : 'Enviar Solicitação'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default CompanyProfile;

import React, { useState, useEffect } from 'react';
import { User, UserRole, Company } from './types';
import { MOCK_USERS, MOCK_COMPANIES } from './constants';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import CaseManagement from './components/CaseManagement';
import FeedbackForm from './components/FeedbackForm';
import Feedbacks from './components/Feedbacks';
import Customers from './components/Customers';
import InternalFormConfig from './components/InternalFormConfig';
import InternalMetrics from './components/InternalMetrics';
import CompanyProfile from './components/CompanyProfile';
import { LogIn, ShieldAlert, Rocket, ArrowRight, User as UserIcon, Store, ChevronLeft, ChevronRight, CheckCircle2 } from 'lucide-react';
import { dataStore } from './services/dataStore';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedCompanyId, setSelectedCompanyId] = useState<string>('');
  const [isPublicForm, setIsPublicForm] = useState(false);

  // Auth States
  const [authView, setAuthView] = useState<'LOGIN' | 'REGISTER'>('LOGIN');
  const [loginEmail, setLoginEmail] = useState('');
  const [loginPass, setLoginPass] = useState('');
  const [error, setError] = useState('');

  // Registration States
  const [regStep, setRegStep] = useState(1);
  const [regCompany, setRegCompany] = useState<Partial<Company>>({ category: 'Restaurante' });
  const [regOwner, setRegOwner] = useState<Partial<User>>({});
  const [regPass, setRegPass] = useState('');

  const [hasDetractorAlert, setHasDetractorAlert] = useState(false);

  useEffect(() => {
    if (user) {
      if (user.role === UserRole.MASTER) {
        setSelectedCompanyId(MOCK_COMPANIES[0].id);
      } else if (user.companyId) {
        setSelectedCompanyId(user.companyId);
      }
    }
  }, [user]);

  const handleFeedbackSubmitted = () => {
    setIsPublicForm(false);
    const currentFeedbacks = dataStore.getFeedbacks(selectedCompanyId || MOCK_COMPANIES[0].id);
    const lastFeedback = currentFeedbacks[currentFeedbacks.length - 1];
    if (lastFeedback?.category === 'DETRACTOR') {
      setHasDetractorAlert(true);
    }
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const found = dataStore.findUserByEmail(loginEmail);
    if (found) {
      setUser(found);
      setError('');
    } else {
      setError('Credenciais inválidas. Use os botões de teste abaixo.');
    }
  };

  const handleRegister = (e: React.FormEvent) => {
    e.preventDefault();
    if (regStep === 1) {
      setRegStep(2);
      return;
    }

    // Concluir Registro
    const { user: newUser } = dataStore.registerCompany(regCompany, regOwner);
    setUser(newUser);
    setAuthView('LOGIN');
  };

  if (isPublicForm) {
    const comp = dataStore.getCompany(selectedCompanyId) || MOCK_COMPANIES[0];
    return <FeedbackForm 
      company={comp} 
      onFinished={handleFeedbackSubmitted} 
      onBack={() => setIsPublicForm(false)}
    />;
  }

  if (!user) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-6 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]">
        <div className="max-w-xl w-full">
          <div className="text-center mb-10">
            <div className="w-16 h-16 bg-primary rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-xl shadow-primary/30">
              <span className="text-3xl font-black text-white italic">A</span>
            </div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tight">Ativare <span className="text-primary">Experience</span></h1>
            <p className="text-slate-500 font-medium mt-2">Gestão Estratégica de CX & Reputação</p>
          </div>

          <div className="bg-white rounded-[3rem] shadow-2xl overflow-hidden border border-white">
            <div className="flex border-b border-slate-100">
              <button 
                onClick={() => setAuthView('LOGIN')}
                className={`flex-1 py-6 text-sm font-black uppercase tracking-widest transition-all ${authView === 'LOGIN' ? 'text-primary bg-white' : 'text-slate-300 bg-slate-50'}`}
              >
                Fazer Login
              </button>
              <button 
                onClick={() => setAuthView('REGISTER')}
                className={`flex-1 py-6 text-sm font-black uppercase tracking-widest transition-all ${authView === 'REGISTER' ? 'text-primary bg-white' : 'text-slate-300 bg-slate-50'}`}
              >
                Experimentar Grátis
              </button>
            </div>

            <div className="p-10">
              {authView === 'LOGIN' ? (
                <form onSubmit={handleLogin} className="space-y-6 animate-in fade-in slide-in-from-left duration-300">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">E-mail de Acesso</label>
                    <input 
                      type="email" 
                      value={loginEmail}
                      onChange={(e) => setLoginEmail(e.target.value)}
                      className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl outline-none focus:border-primary transition-all text-sm font-bold text-slate-900 placeholder:text-slate-300"
                      placeholder="Seu e-mail corporativo"
                      required
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Senha</label>
                    <input 
                      type="password" 
                      value={loginPass}
                      onChange={(e) => setLoginPass(e.target.value)}
                      className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl outline-none focus:border-primary transition-all text-sm font-bold text-slate-900 placeholder:text-slate-300"
                      placeholder="••••••••"
                      required
                    />
                  </div>

                  {error && (
                    <div className="p-4 bg-red-50 rounded-2xl border border-red-100 flex items-start space-x-3">
                      <ShieldAlert className="w-5 h-5 text-red-500 mt-0.5" />
                      <p className="text-xs font-bold text-red-600">{error}</p>
                    </div>
                  )}

                  <button type="submit" className="w-full py-5 bg-primary text-white font-black rounded-3xl shadow-xl hover:bg-[#003680] hover:-translate-y-1 transition-all flex items-center justify-center gap-2">
                    <LogIn className="w-5 h-5" /> Entrar no Ativare
                  </button>

                  <div className="pt-4 border-t border-slate-50 flex flex-col items-center gap-4">
                    <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.2em]">Acesso Rápido</p>
                    <div className="flex flex-wrap justify-center gap-2">
                      <button onClick={() => { setLoginEmail('master@ativare.com'); setLoginPass('123456'); }} className="px-4 py-2 bg-slate-100 text-[10px] font-black uppercase rounded-xl hover:bg-slate-200 transition-all text-slate-600">Master</button>
                      <button onClick={() => { setLoginEmail('dono@pizza.com'); setLoginPass('123456'); }} className="px-4 py-2 bg-slate-100 text-[10px] font-black uppercase rounded-xl hover:bg-slate-200 transition-all text-slate-600">Business</button>
                    </div>
                  </div>
                </form>
              ) : (
                <form onSubmit={handleRegister} className="space-y-8 animate-in fade-in slide-in-from-right duration-300">
                  <div className="flex items-center justify-between mb-2">
                    <h3 className="text-xl font-black text-slate-900 flex items-center gap-2">
                      <Rocket className="w-6 h-6 text-accent" />
                      {regStep === 1 ? 'Dados da Empresa' : 'Dados do Gestor'}
                    </h3>
                    <span className="text-[10px] font-black text-slate-300 uppercase bg-slate-50 px-3 py-1 rounded-full">Passo {regStep} de 2</span>
                  </div>

                  {regStep === 1 ? (
                    <div className="grid grid-cols-2 gap-4">
                      <div className="col-span-2 space-y-2">
                        <label className="text-[10px] font-black uppercase text-slate-400">Nome do Negócio</label>
                        <input required type="text" value={regCompany.name} onChange={e => setRegCompany({...regCompany, name: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" placeholder="Ex: Pizzaria Bella Italia" />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[10px] font-black uppercase text-slate-400">CNPJ</label>
                        <input required type="text" value={regCompany.cnpj} onChange={e => setRegCompany({...regCompany, cnpj: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" placeholder="00.000.000/0001-00" />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[10px] font-black uppercase text-slate-400">Categoria</label>
                        <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" value={regCompany.category} onChange={e => setRegCompany({...regCompany, category: e.target.value})}>
                          <option>Restaurante</option>
                          <option>Hamburgueria</option>
                          <option>Pizzaria</option>
                          <option>Bar / Pub</option>
                          <option>Evento / Buffet</option>
                        </select>
                      </div>
                      <div className="col-span-2 space-y-2">
                        <label className="text-[10px] font-black uppercase text-slate-400">Endereço</label>
                        <input required type="text" value={regCompany.address} onChange={e => setRegCompany({...regCompany, address: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" placeholder="Rua, Número, Cidade - UF" />
                      </div>
                    </div>
                  ) : (
                    <div className="space-y-4">
                      <div className="space-y-2">
                        <label className="text-[10px] font-black uppercase text-slate-400">Nome Completo</label>
                        <input required type="text" value={regOwner.name} onChange={e => setRegOwner({...regOwner, name: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" placeholder="Seu nome" />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[10px] font-black uppercase text-slate-400">E-mail Principal</label>
                        <input required type="email" value={regOwner.email} onChange={e => setRegOwner({...regOwner, email: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" placeholder="seu@email.com" />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[10px] font-black uppercase text-slate-400">Defina uma Senha</label>
                        <input required type="password" value={regPass} onChange={e => setRegPass(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" placeholder="••••••••" />
                      </div>
                    </div>
                  )}

                  <div className="flex gap-4">
                    {regStep === 2 && (
                      <button type="button" onClick={() => setRegStep(1)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black rounded-3xl flex items-center justify-center gap-2">
                        <ChevronLeft className="w-5 h-5" /> Voltar
                      </button>
                    )}
                    <button type="submit" className="flex-[2] py-5 bg-primary text-white font-black rounded-3xl shadow-xl hover:bg-[#003680] transition-all flex items-center justify-center gap-2">
                      {regStep === 1 ? 'Próximo Passo' : 'Começar Agora'} <ChevronRight className="w-5 h-5" />
                    </button>
                  </div>

                  <p className="text-center text-[10px] text-slate-400 font-bold uppercase leading-relaxed">
                    Ao clicar em começar, você aceita nossos termos de uso e inicia automaticamente seu período de 15 dias de trial.
                  </p>
                </form>
              )}
            </div>

            <div className="bg-slate-50 p-6 flex justify-center">
              <button onClick={() => setIsPublicForm(true)} className="flex items-center gap-2 text-accent font-black text-xs uppercase hover:underline">
                <Store className="w-4 h-4" /> Visualizar Página de Avaliação Pública
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout 
      user={user} 
      onLogout={() => { setUser(null); setAuthView('LOGIN'); }} 
      activeTab={activeTab} 
      setActiveTab={(tab) => {
        setActiveTab(tab);
        if (['feedbacks', 'cases', 'customers'].includes(tab)) setHasDetractorAlert(false);
      }}
      selectedCompanyId={selectedCompanyId}
      setSelectedCompanyId={setSelectedCompanyId}
      hasDetractorAlert={hasDetractorAlert}
    >
      {activeTab === 'dashboard' && <Dashboard companyId={selectedCompanyId} />}
      {activeTab === 'cases' && <CaseManagement companyId={selectedCompanyId} currentUser={user} />}
      {activeTab === 'feedbacks' && <Feedbacks companyId={selectedCompanyId} currentUser={user} />}
      {activeTab === 'customers' && <Customers companyId={selectedCompanyId} currentUser={user} />}
      {activeTab === 'form_config' && <InternalFormConfig companyId={selectedCompanyId} />}
      {activeTab === 'internal_metrics' && <InternalMetrics companyId={selectedCompanyId} />}
      {activeTab === 'company_profile' && <CompanyProfile companyId={selectedCompanyId} currentUser={user} />}

      {['benchmarking', 'bi'].includes(activeTab) && (
        <div className="bg-white rounded-[3rem] p-20 text-center border border-dashed border-slate-200">
          <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-8 text-slate-200"><ShieldAlert className="w-12 h-12" /></div>
          <h2 className="text-3xl font-black text-slate-900 mb-2">Módulo Enterprise</h2>
          <p className="text-slate-500 font-medium max-w-sm mx-auto">Este módulo avançado de BI e benchmarking global está em fase final de homologação.</p>
        </div>
      )}
    </Layout>
  );
};

export default App;

export enum UserRole {
  MASTER = 'MASTER',
  BUSINESS = 'BUSINESS',
  USER = 'USER'
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  companyId?: string;
  phone?: string;
}

export interface CNPJRequest {
  id: string;
  userId: string;
  userName: string;
  requestedCNPJ: string;
  reason: string;
  status: 'PENDING' | 'APPROVED' | 'REJECTED';
  createdAt: string;
}

