import { Feedback, Case, Customer, NPSCategory, InternalQuestion, InternalQuestionType, ContactLog, Company, User, UserRole, CNPJRequest } from '../types';
import { MOCK_COMPANIES, MOCK_USERS } from '../constants';

class DataStore {
  // Simplified initialization as MOCK_COMPANIES now contains the trackingCode property
  private companies: Company[] = [...MOCK_COMPANIES];
  private users: User[] = [...MOCK_USERS];
  private feedbacks: Feedback[] = [];
  private cases: Case[] = [];
  private customers: Customer[] = [];
  private internalQuestions: InternalQuestion[] = [];

  constructor() {
    this.initMockData();
  }

  private generateMockTrackingCode(index: number): string {
    const codes = ['PZA123', 'BRG456', 'SSZ789', 'STK001'];
    return codes[index] || this.generateUniqueTrackingCode();
  }

  private generateUniqueTrackingCode(): string {
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
    let code = '';
    let isUnique = false;

    while (!isUnique) {
      code = '';
      for (let i = 0; i < 6; i++) {
        code += chars.charAt(Math.floor(Math.random() * chars.length));
      }
      isUnique = !this.companies.some(c => c.trackingCode === code);
    }

    return code;
  }

  private initMockData() {
    this.companies.forEach(comp => {
      const q1: InternalQuestion = {
        id: `q1-${comp.id}`,
        companyId: comp.id,
        text: 'O garçom ofereceu sobremesa?',
        type: 'YES_NO',
        required: true,
        active: true,
        order: 1
      };
      const q2: InternalQuestion = {
        id: `q2-${comp.id}`,
        companyId: comp.id,
        text: 'Qual a probabilidade de você indicar nosso Happy Hour?',
        type: 'SCALE_10',
        required: false,
        active: true,
        order: 2
      };
      this.internalQuestions.push(q1, q2);

      for (let j = 0; j < 8; j++) {
        const phone = `1198888000${j}`;
        const customerId = `cust-${comp.id}-${j}`;
        for(let i = 0; i < 2; i++) {
          const scores = {
            service: Math.floor(Math.random() * 5) + 5,
            food: Math.floor(Math.random() * 5) + 5,
            drinks: Math.floor(Math.random() * 5) + 5,
            structure: Math.floor(Math.random() * 5) + 5,
          };
          this.addFeedback({
            companyId: comp.id,
            customerId: customerId,
            customerName: `Cliente Exemplo ${j}`,
            customerPhone: phone,
            howKnown: 'Instagram',
            scores,
            internalResponses: { [q1.id]: Math.random() > 0.3 ? 'SIM' : 'NÃO', [q2.id]: Math.floor(Math.random() * 10) + 1 },
            profile: 'friends',
            observation: i === 1 ? 'Melhorou desde a última vez.' : 'Pode melhorar o tempo de espera.',
            email: `cliente${j}@email.com`
          });
        }
      }
    });
  }

  findUserByEmail(email: string) {
    return this.users.find(u => u.email === email);
  }

  registerCompany(companyData: Partial<Company>, ownerData: Partial<User>) {
    const companyId = `comp-${Date.now()}`;
    const trackingCode = this.generateUniqueTrackingCode();
    const trialEndDate = new Date();
    trialEndDate.setDate(trialEndDate.getDate() + 15);

    const newCompany: Company = {
      id: companyId,
      trackingCode: trackingCode,
      name: companyData.name || 'Nova Empresa',
      category: companyData.category || 'Restaurante',
      city: companyData.city || '',
      logo: companyData.logo || 'https://picsum.photos/seed/ativare/200',
      experienceScore: 0,
      cnpj: companyData.cnpj,
      address: companyData.address,
      employees: companyData.employees,
      phone: companyData.phone,
      email: companyData.email,
      instagram: companyData.instagram,
      trialEndDate: trialEndDate.toISOString(),
      cnpjRequests: []
    };

    const newUser: User = {
      id: `u-${Date.now()}`,
      name: ownerData.name || '',
      email: ownerData.email || '',
      role: UserRole.BUSINESS,
      companyId: companyId,
      phone: ownerData.phone
    };

    this.companies.push(newCompany);
    this.users.push(newUser);

    return { company: newCompany, user: newUser };
  }

  getCompany(id: string) {
    return this.companies.find(c => c.id === id);
  }

  getCompanyByTrackingCode(code: string) {
    return this.companies.find(c => c.trackingCode.toUpperCase() === code.toUpperCase());
  }

  getAllCompanies() {
    return this.companies;
  }

  updateCompany(id: string, data: Partial<Company>) {
    const idx = this.companies.findIndex(c => c.id === id);
    if (idx >= 0) {
      this.companies[idx] = { ...this.companies[idx], ...data };
      return this.companies[idx];
    }
    return null;
  }

  requestCNPJChange(companyId: string, request: Omit<CNPJRequest, 'id' | 'status' | 'createdAt'>) {
    const company = this.getCompany(companyId);
    if (company) {
      if (!company.cnpjRequests) company.cnpjRequests = [];
      const newRequest: CNPJRequest = {
        ...request,
        id: `req-${Date.now()}`,
        status: 'PENDING',
        createdAt: new Date().toISOString()
      };
      company.cnpjRequests.push(newRequest);
      return newRequest;
    }
    return null;
  }

  getInternalQuestions(companyId: string, onlyActive = true) {
    let qs = this.internalQuestions.filter(q => q.companyId === companyId);
    if (onlyActive) qs = qs.filter(q => q.active);
    return qs.sort((a, b) => a.order - b.order);
  }

  saveInternalQuestion(question: InternalQuestion) {
    const idx = this.internalQuestions.findIndex(q => q.id === question.id);
    if (idx >= 0) this.internalQuestions[idx] = question;
    else this.internalQuestions.push(question);
  }

  deleteInternalQuestion(id: string) {
    this.internalQuestions = this.internalQuestions.filter(q => q.id !== id);
  }

  getInternalMetrics(companyId: string) {
    const qs = this.getInternalQuestions(companyId, false);
    const fbs = this.getFeedbacks(companyId);
    return qs.map(q => {
      const responses = fbs.map(f => f.internalResponses?.[q.id]).filter(r => r !== undefined && r !== null);
      let avg: any = 0;
      if (q.type === 'SCALE_5' || q.type === 'SCALE_10') {
        avg = responses.length > 0 ? responses.reduce((acc: number, val: any) => acc + Number(val), 0) / responses.length : 0;
      } else if (q.type === 'YES_NO') {
        const yesCount = responses.filter(r => r === 'SIM').length;
        avg = responses.length > 0 ? (yesCount / responses.length) * 100 : 0;
      }
      return { questionId: q.id, text: q.text, type: q.type, totalResponses: responses.length, average: avg, responses: responses };
    });
  }

  getFeedbacks(companyId?: string) {
    return companyId ? this.feedbacks.filter(f => f.companyId === companyId) : this.feedbacks;
  }

  getCustomers(companyId: string) {
    return this.customers.filter(c => c.companyId === companyId);
  }

  getCaseForFeedback(feedbackId: string) {
    return this.cases.find(c => c.feedbackId === feedbackId);
  }

  getCases(companyId?: string) {
    return companyId ? this.cases.filter(c => c.companyId === companyId) : this.cases;
  }

  addFeedback(feedback: Omit<Feedback, 'id' | 'createdAt' | 'category' | 'averageScore'>) {
    const avg = (feedback.scores.service + feedback.scores.food + feedback.scores.drinks + feedback.scores.structure) / 4;
    let cat: NPSCategory = avg >= 9 ? 'PROMOTER' : avg <= 6 ? 'DETRACTOR' : 'PASSIVE';
    const createdAt = new Date().toISOString();
    const newFeedback: Feedback = { ...feedback, id: `f-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`, createdAt, category: cat, averageScore: avg };
    this.feedbacks.push(newFeedback);
    let customer = this.customers.find(c => c.phone === feedback.customerPhone && c.companyId === feedback.companyId);
    if (!customer) {
      customer = { id: feedback.customerId || `cust-${Date.now()}`, companyId: feedback.companyId, name: feedback.customerName, phone: feedback.customerPhone, email: feedback.email, profile: feedback.profile, firstSeen: createdAt, lastSeen: createdAt, averageScore: avg, totalFeedbacks: 1, category: cat, contactLogs: [] };
      this.customers.push(customer);
    } else {
      customer.lastSeen = createdAt;
      customer.totalFeedbacks += 1;
      const customerFeedbacks = this.feedbacks.filter(f => f.customerPhone === customer?.phone && f.companyId === feedback.companyId);
      customer.averageScore = customerFeedbacks.reduce((acc, f) => acc + f.averageScore, 0) / customerFeedbacks.length;
      customer.category = customer.averageScore >= 9 ? 'PROMOTER' : customer.averageScore <= 6 ? 'DETRACTOR' : 'PASSIVE';
      customer.name = feedback.customerName;
    }
    if (cat === 'DETRACTOR') this.createCaseFromFeedback(newFeedback.id, feedback.companyId, 'Caso gerado automaticamente via Sistema Ativare devido à baixa pontuação.', 'Inteligência Ativare', 'system');
    return newFeedback;
  }

  getDashboardStats(companyId: string) {
    const fb = this.getFeedbacks(companyId);
    const total = fb.length;
    const avgScore = total > 0 ? (fb.reduce((acc, f) => acc + f.averageScore, 0) / total) * 10 : 0;
    const companyCases = this.getCases(companyId);
    return {
      total,
      promoters: fb.filter(f => f.category === 'PROMOTER').length,
      detractors: fb.filter(f => f.category === 'DETRACTOR').length,
      passives: fb.filter(f => f.category === 'PASSIVE').length,
      avgScore: Math.round(avgScore),
      openDetractors: companyCases.filter(c => c.status === 'OPEN').length,
      resolvedDetractors: companyCases.filter(c => c.status === 'RESOLVED').length,
      catAvg: {
        service: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.service, 0) / total) : 0,
        food: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.food, 0) / total) : 0,
        drinks: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.drinks, 0) / total) : 0,
        structure: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.structure, 0) / total) : 0,
      }
    };
  }

  createCaseFromFeedback(feedbackId: string, companyId: string, noteText: string, userName: string, userId: string) {
    if (this.cases.some(c => c.feedbackId === feedbackId)) return;
    const newCase: Case = {
      id: `case-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
      feedbackId,
      companyId,
      status: 'OPEN',
      notes: [{ id: `note-${Date.now()}`, userId, userName, text: noteText || 'Caso aberto para acompanhamento.', createdAt: new Date().toISOString() }],
      updatedAt: new Date().toISOString()
    };
    this.cases.push(newCase);
    return newCase;
  }

  addCaseNote(caseId: string, userId: string, userName: string, text: string) {
    const c = this.cases.find(item => item.id === caseId);
    if (c) {
      c.notes.push({ id: `note-${Date.now()}`, userId, userName, text, createdAt: new Date().toISOString() });
      c.updatedAt = new Date().toISOString();
      if (c.status === 'OPEN') c.status = 'IN_PROGRESS';
    }
  }

  resolveCase(caseId: string, resolutionText: string, userName: string, userId: string) {
    const c = this.cases.find(item => item.id === caseId);
    if (c) {
      c.status = 'RESOLVED';
      c.resolutionText = resolutionText;
      c.notes.push({ id: `note-res-${Date.now()}`, userId, userName, text: `RESOLUÇÃO: ${resolutionText}`, createdAt: new Date().toISOString() });
      c.updatedAt = new Date().toISOString();
    }
  }

  getCustomerHistory(customerId: string) {
    const customer = this.customers.find(c => c.id === customerId);
    if (!customer) return [];
    return this.feedbacks.filter(f => f.customerPhone === customer.phone && f.companyId === customer.companyId).sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }

  addContactLog(customerId: string, log: Omit<ContactLog, 'id' | 'createdAt'>) {
    const customer = this.customers.find(c => c.id === customerId);
    if (customer) customer.contactLogs.unshift({ ...log, id: `log-${Date.now()}`, createdAt: new Date().toISOString() });
  }
}

export const dataStore = new DataStore();

import React, { useState, useRef } from 'react';
import { Company, User, UserRole } from '../types';
import { dataStore } from '../services/dataStore';
import { Store, Camera, Save, MapPin, Phone, Mail, Instagram, User as UserIcon, FileText, Briefcase, AlertTriangle, X, Clock, Hash, Copy, Check } from 'lucide-react';

interface CompanyProfileProps {
  companyId: string;
  currentUser: User;
}

const CompanyProfile: React.FC<CompanyProfileProps> = ({ companyId, currentUser }) => {
  const company = dataStore.getCompany(companyId);
  const [formData, setFormData] = useState<Partial<Company>>(company || {});
  const [isSaved, setIsSaved] = useState(false);
  const [showCNPJModal, setShowCNPJModal] = useState(false);
  const [cnpjReason, setCnpjReason] = useState('');
  const [newRequestedCNPJ, setNewRequestedCNPJ] = useState('');
  const [isRequesting, setIsRequesting] = useState(false);
  const [copied, setCopied] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  if (!company) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    dataStore.updateCompany(companyId, formData);
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 3000);
  };

  const handleLogoClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        setFormData(prev => ({ ...prev, logo: base64String }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleCopyCode = () => {
    navigator.clipboard.writeText(company.trackingCode);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleCNPJRequest = (e: React.FormEvent) => {
    e.preventDefault();
    if (!cnpjReason || !newRequestedCNPJ) return;

    setIsRequesting(true);
    dataStore.requestCNPJChange(companyId, {
      userId: currentUser.id,
      userName: currentUser.name,
      requestedCNPJ: newRequestedCNPJ,
      reason: cnpjReason
    });

    setTimeout(() => {
      setIsRequesting(false);
      setShowCNPJModal(false);
      setCnpjReason('');
      setNewRequestedCNPJ('');
      alert('Solicitação enviada com sucesso para análise do Master.');
    }, 1000);
  };

  const InputField = ({ label, icon: Icon, value, onChange, placeholder, type = "text", readOnly = false }: any) => (
    <div className="space-y-2">
      <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 flex items-center gap-2">
        <Icon className="w-3 h-3" /> {label}
      </label>
      <input 
        type={type}
        value={value || ''}
        readOnly={readOnly}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
        className={`w-full p-4 border rounded-2xl outline-none transition-all font-bold text-slate-900 ${
          readOnly 
            ? 'bg-slate-100 border-slate-100 cursor-not-allowed text-slate-400' 
            : 'bg-slate-50 border-slate-200 focus:border-primary'
        }`}
      />
    </div>
  );

  return (
    <div className="max-w-4xl mx-auto pb-20">
      <form onSubmit={handleSubmit} className="space-y-8 animate-in fade-in duration-500">
        <input 
          type="file" 
          ref={fileInputRef} 
          className="hidden" 
          accept="image/png, image/jpeg, image/webp"
          onChange={handleFileChange}
        />

        {/* Header / Logo Section */}
        <div className="bg-white rounded-[3rem] p-10 border border-slate-100 shadow-sm flex flex-col md:flex-row items-center gap-8">
          <div className="relative group">
            <div className="w-40 h-40 rounded-[2.5rem] overflow-hidden border-4 border-slate-100 shadow-xl bg-slate-50 flex items-center justify-center">
              {formData.logo ? (
                <img src={formData.logo} alt="Logo" className="w-full h-full object-cover" />
              ) : (
                <Store className="w-12 h-12 text-slate-200" />
              )}
            </div>
            <button 
              type="button" 
              onClick={handleLogoClick}
              className="absolute bottom-2 right-2 p-3 bg-primary text-white rounded-2xl shadow-lg hover:scale-110 transition-all z-10"
            >
              <Camera className="w-5 h-5" />
            </button>
          </div>
          <div className="flex-1 space-y-4 text-center md:text-left">
            <div>
              <h2 className="text-3xl font-black text-slate-900">{formData.name}</h2>
              <p className="text-slate-400 font-medium">Gerencie a identidade e informações do seu negócio.</p>
            </div>
            <div className="flex flex-wrap justify-center md:justify-start gap-4">
               <div className="flex flex-col">
                  <span className="text-[10px] font-black uppercase text-slate-300 tracking-widest mb-1">Código Público</span>
                  <div className="flex items-center gap-2 bg-slate-50 px-3 py-1.5 rounded-xl border border-slate-100">
                    <span className="text-sm font-black text-primary tracking-[0.1em]">{company.trackingCode}</span>
                    <button 
                      type="button"
                      onClick={handleCopyCode}
                      className={`p-1 rounded-lg transition-all ${copied ? 'text-emerald-500' : 'text-slate-300 hover:text-primary'}`}
                    >
                      {copied ? <Check className="w-4 h-4" /> : <Copy className="w-4 h-4" />}
                    </button>
                  </div>
               </div>
               <div className="flex flex-col">
                  <span className="text-[10px] font-black uppercase text-slate-300 tracking-widest mb-1">Status</span>
                  <span className="px-3 py-1.5 bg-emerald-50 text-emerald-600 rounded-xl text-xs font-bold uppercase border border-emerald-100">Ativo</span>
               </div>
            </div>
          </div>
        </div>

        {/* Info Grid */}
        <div className="bg-white rounded-[3rem] p-10 border border-slate-100 shadow-sm">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 flex items-center gap-2">
                <Hash className="w-3 h-3" /> Código de Acesso Público
              </label>
              <div className="flex gap-2">
                <input 
                  type="text"
                  value={company.trackingCode}
                  readOnly
                  className="flex-1 p-4 bg-slate-100 border border-slate-100 rounded-2xl outline-none font-black text-primary tracking-[0.2em] cursor-not-allowed"
                />
                <button 
                  type="button"
                  onClick={handleCopyCode}
                  className="px-6 bg-primary text-white text-[10px] font-black uppercase tracking-widest rounded-2xl shadow-lg shadow-primary/20 hover:bg-primary/90 transition-all"
                >
                  {copied ? 'Copiado!' : 'Copiar'}
                </button>
              </div>
              <p className="text-[9px] text-slate-400 font-bold uppercase">* Este código é gerado automaticamente e não pode ser alterado.</p>
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 flex items-center gap-2">
                <FileText className="w-3 h-3" /> CNPJ
              </label>
              <div className="flex gap-2">
                <input 
                  type="text"
                  value={formData.cnpj || ''}
                  readOnly
                  className="flex-1 p-4 bg-slate-100 border border-slate-100 rounded-2xl outline-none font-bold text-slate-400 cursor-not-allowed"
                />
                <button 
                  type="button"
                  onClick={() => setShowCNPJModal(true)}
                  className="px-4 bg-white border border-slate-200 text-slate-400 text-[10px] font-black uppercase tracking-widest rounded-2xl hover:bg-slate-50 transition-all whitespace-nowrap"
                >
                  Solicitar Alteração
                </button>
              </div>
            </div>

            <InputField 
              label="Nome do Negócio" 
              icon={Store} 
              value={formData.name} 
              onChange={(v: string) => setFormData({...formData, name: v})} 
            />

            <InputField 
              label="Categoria" 
              icon={Briefcase} 
              value={formData.category} 
              onChange={(v: string) => setFormData({...formData, category: v})} 
            />

            <InputField 
              label="Nº de Colaboradores" 
              icon={UserIcon} 
              value={formData.employees} 
              onChange={(v: string) => setFormData({...formData, employees: v})} 
              placeholder="Ex: 10-20"
            />
            <div className="md:col-span-2">
              <InputField 
                label="Endereço Completo" 
                icon={MapPin} 
                value={formData.address} 
                onChange={(v: string) => setFormData({...formData, address: v})} 
              />
            </div>
            <InputField 
              label="Telefone Comercial" 
              icon={Phone} 
              value={formData.phone} 
              onChange={(v: string) => setFormData({...formData, phone: v})} 
            />
            <InputField 
              label="E-mail de Contato" 
              icon={Mail} 
              value={formData.email} 
              onChange={(v: string) => setFormData({...formData, email: v})} 
            />
            <div className="md:col-span-2">
              <InputField 
                label="Instagram" 
                icon={Instagram} 
                value={formData.instagram} 
                onChange={(v: string) => setFormData({...formData, instagram: v})} 
                placeholder="@seunegocio"
              />
            </div>
          </div>

          <div className="mt-12 flex justify-end">
            <button 
              type="submit"
              className={`px-10 py-5 bg-primary text-white font-black rounded-3xl shadow-xl shadow-primary/30 flex items-center gap-3 hover:-translate-y-1 transition-all ${isSaved ? 'bg-emerald-500 shadow-emerald-500/30' : ''}`}
            >
              {isSaved ? <><Save className="w-5 h-5" /> Perfil Atualizado!</> : <><Save className="w-5 h-5" /> Salvar Alterações</>}
            </button>
          </div>
        </div>

        {/* History of Requests */}
        {company.cnpjRequests && company.cnpjRequests.length > 0 && (
          <div className="bg-white rounded-[3rem] p-10 border border-slate-100 shadow-sm space-y-6">
            <h3 className="text-sm font-black uppercase tracking-widest text-slate-400 flex items-center gap-2">
              <Clock className="w-4 h-4" /> Histórico de Solicitações de CNPJ
            </h3>
            <div className="space-y-4">
              {company.cnpjRequests.slice().reverse().map(req => (
                <div key={req.id} className="p-5 bg-slate-50 rounded-3xl border border-slate-100 flex items-center justify-between">
                  <div>
                    <p className="text-xs font-bold text-slate-800">Solicitado: <span className="text-slate-500">{req.requestedCNPJ}</span></p>
                    <p className="text-[10px] text-slate-400 mt-1 font-medium italic">"{req.reason}"</p>
                  </div>
                  <div className="text-right">
                    <span className={`px-2 py-0.5 rounded-full text-[9px] font-black uppercase tracking-widest ${
                      req.status === 'PENDING' ? 'bg-amber-100 text-amber-600' : 
                      req.status === 'APPROVED' ? 'bg-emerald-100 text-emerald-600' : 
                      'bg-red-100 text-red-600'
                    }`}>
                      {req.status === 'PENDING' ? 'Em Análise' : req.status === 'APPROVED' ? 'Aprovado' : 'Recusado'}
                    </span>
                    <p className="text-[9px] text-slate-300 mt-1">{new Date(req.createdAt).toLocaleDateString('pt-BR')}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </form>

      {/* CNPJ Change Modal */}
      {showCNPJModal && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => !isRequesting && setShowCNPJModal(false)}></div>
          <div className="bg-white rounded-[3rem] w-full max-w-lg p-10 relative z-10 shadow-2xl border border-white animate-in zoom-in duration-300">
            <button 
              onClick={() => setShowCNPJModal(false)}
              className="absolute top-8 right-8 text-slate-400 hover:text-slate-600"
            >
              <X className="w-6 h-6" />
            </button>

            <div className="w-20 h-20 bg-amber-50 text-amber-500 rounded-[2rem] flex items-center justify-center mb-6">
              <AlertTriangle className="w-10 h-10" />
            </div>

            <h3 className="text-2xl font-black text-slate-900 mb-2">Solicitar Alteração de CNPJ</h3>
            <p className="text-slate-500 text-sm font-medium mb-8">Por questões de segurança, a alteração do CNPJ deve ser aprovada pela equipe Master da plataforma.</p>

            <form onSubmit={handleCNPJRequest} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Novo CNPJ</label>
                <input 
                  required
                  type="text" 
                  value={newRequestedCNPJ}
                  onChange={(e) => setNewRequestedCNPJ(e.target.value)}
                  placeholder="00.000.000/0000-00"
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900"
                />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Motivo da Alteração</label>
                <textarea 
                  required
                  value={cnpjReason}
                  onChange={(e) => setCnpjReason(e.target.value)}
                  placeholder="Explique o motivo da mudança (ex: alteração contratual, erro de digitação)..."
                  className="w-full h-32 p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm outline-none focus:border-primary font-medium text-slate-900"
                />
              </div>

              <button 
                type="submit"
                disabled={isRequesting}
                className="w-full py-5 bg-primary text-white font-black rounded-3xl shadow-xl hover:shadow-primary/30 transition-all flex items-center justify-center gap-2 disabled:opacity-50"
              >
                {isRequesting ? 'Enviando...' : 'Enviar Solicitação'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default CompanyProfile;

export enum UserRole {
  MASTER = 'MASTER',
  BUSINESS = 'BUSINESS',
  USER = 'USER'
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  companyId?: string;
  phone?: string;
}

export interface CNPJRequest {
  id: string;
  userId: string;
  userName: string;
  requestedCNPJ: string;
  reason: string;
  status: 'PENDING' | 'APPROVED' | 'REJECTED';
  createdAt: string;
}

export interface Company {
  id: string;
  trackingCode: string; // Código alfanumérico de 6 caracteres
  name: string;
  category: string;
  city: string;
  logo: string;
  experienceScore: number;
  cnpj?: string;
  address?: string;
  employees?: string;
  phone?: string;
  email?: string;
  instagram?: string;
  trialEndDate?: string;
  cnpjRequests?: CNPJRequest[];
}

export type NPSCategory = 'PROMOTER' | 'PASSIVE' | 'DETRACTOR';

export type InternalQuestionType = 'TEXT' | 'SCALE_5' | 'SCALE_10' | 'YES_NO';

export interface InternalQuestion {
  id: string;
  companyId: string;
  text: string;
  type: InternalQuestionType;
  required: boolean;
  active: boolean;
  isPublic: boolean; // Se verdadeiro, aparece no form do cliente. Se falso, é para staff.
  order: number;
}

export interface Feedback {
  id: string;
  companyId: string;
  customerId: string;
  customerName: string;
  customerPhone: string;
  howKnown: string;
  scores: {
    service: number;
    food: number;
    drinks: number;
    structure: number;
  };
  internalResponses?: { [questionId: string]: any };
  profile: 'family' | 'friends' | 'couple' | 'kids';
  observation: string;
  createdAt: string;
  category: NPSCategory;
  averageScore: number;
  email?: string;
}

export type CaseStatus = 'OPEN' | 'IN_PROGRESS' | 'RESOLVED';

export interface CaseNote {
  id: string;
  userId: string;
  userName: string;
  text: string;
  createdAt: string;
}

export interface Case {
  id: string;
  feedbackId: string;
  companyId: string;
  status: CaseStatus;
  assignedTo?: string;
  resolutionText?: string;
  notes: CaseNote[];
  updatedAt: string;
}

