              </div>
              <button type="submit" disabled={isRequesting} className="w-full py-5 bg-primary text-white font-black rounded-3xl shadow-xl disabled:opacity-50">
                {isRequesting ? 'Enviando...' : 'Enviar Solicitação'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

