import React, { useState, useRef } from 'react';
import { User } from '../types';
import { dataStore } from '../services/dataStore';
import { User as UserIcon, Camera, Save, Mail, Phone, Lock, Check, ShieldAlert, Eye, EyeOff } from 'lucide-react';

interface UserProfileProps {
  user: User;
  onUpdate: (user: User) => void;
}

const UserProfile: React.FC<UserProfileProps> = ({ user, onUpdate }) => {
  const [formData, setFormData] = useState<Partial<User>>({
    name: user.name,
    email: user.email,
    phone: user.phone,
    profilePhoto: user.profilePhoto
  });

  const [passwordData, setPasswordData] = useState({
    current: '',
    new: '',
    confirm: ''
  });

  const [isSaved, setIsSaved] = useState(false);
  const [passError, setPassError] = useState('');
  const [passSuccess, setPassSuccess] = useState(false);
  const [showPass, setShowPass] = useState(false);

  const photoInputRef = useRef<HTMLInputElement>(null);

  const handleUpdateProfile = (e: React.FormEvent) => {
    e.preventDefault();
    const updated = dataStore.updateUser(user.id, formData);
    if (updated) {
      onUpdate(updated);
      setIsSaved(true);
      setTimeout(() => setIsSaved(false), 3000);
    }
  };

  const handleChangePassword = (e: React.FormEvent) => {
    e.preventDefault();
    setPassError('');
    setPassSuccess(false);

    if (passwordData.new !== passwordData.confirm) {
      setPassError('As novas senhas não coincidem.');
      return;
    }

    const success = dataStore.updatePassword(user.id, passwordData.current, passwordData.new);
    if (success) {
      setPassSuccess(true);
      setPasswordData({ current: '', new: '', confirm: '' });
    } else {
      setPassError('Senha atual incorreta.');
    }
  };

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({ ...prev, profilePhoto: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-12 pb-20">
      {/* Informações Básicas */}
      <section className="bg-white rounded-[3rem] p-10 border border-slate-100 shadow-sm space-y-8 animate-in fade-in duration-500">
        <div className="flex items-center gap-10">
          <div className="relative group">
             <div className="w-32 h-32 rounded-[2.5rem] overflow-hidden border-4 border-slate-100 shadow-xl bg-slate-50 flex items-center justify-center">
                {formData.profilePhoto ? (
                  <img src={formData.profilePhoto} alt="Profile" className="w-full h-full object-cover" />
                ) : (
                  <img src={`https://ui-avatars.com/api/?name=${user.name}&background=0047a7&color=fff`} className="w-full h-full" alt="Avatar" />
                )}
             </div>
             <button 
                type="button" 
                onClick={() => photoInputRef.current?.click()}
                className="absolute bottom-[-10px] right-[-10px] p-3 bg-primary text-white rounded-2xl shadow-lg hover:scale-110 transition-all z-10"
              >
                <Camera className="w-5 h-5" />
             </button>
             <input type="file" ref={photoInputRef} className="hidden" accept="image/*" onChange={handlePhotoChange} />
          </div>

          <div className="flex-1">
             <h2 className="text-2xl font-black text-slate-900">{user.name}</h2>
             <p className="text-slate-400 font-medium">Configure seus dados pessoais e foto de identificação.</p>
             <div className="flex items-center gap-2 mt-2">
                <span className="text-[10px] font-black uppercase tracking-widest bg-slate-100 text-slate-500 px-3 py-1 rounded-full">ID: {user.id}</span>
                <span className="text-[10px] font-black uppercase tracking-widest bg-primary/10 text-primary px-3 py-1 rounded-full">{user.staffRole || user.role}</span>
             </div>
          </div>
        </div>

        <form onSubmit={handleUpdateProfile} className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-4">
           <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest flex items-center gap-2">
                <UserIcon className="w-3 h-3" /> Nome Completo
              </label>
              <input 
                type="text" 
                value={formData.name}
                onChange={e => setFormData({...formData, name: e.target.value})}
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900"
              />
           </div>
           <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest flex items-center gap-2">
                <Mail className="w-3 h-3" /> E-mail de Acesso
              </label>
              <input 
                type="email" 
                value={formData.email}
                onChange={e => setFormData({...formData, email: e.target.value})}
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900"
              />
           </div>
           <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest flex items-center gap-2">
                <Phone className="w-3 h-3" /> WhatsApp / Telefone
              </label>
              <input 
                type="tel" 
                value={formData.phone || ''}
                onChange={e => setFormData({...formData, phone: e.target.value})}
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900"
              />
           </div>

           <div className="md:col-span-2 flex justify-end">
              <button 
                type="submit" 
                className={`px-8 py-4 text-white font-black rounded-2xl shadow-xl transition-all flex items-center gap-2 ${isSaved ? 'bg-emerald-500' : 'bg-primary hover:scale-105'}`}
              >
                {isSaved ? <><Check className="w-5 h-5" /> Dados Salvos!</> : <><Save className="w-5 h-5" /> Atualizar Perfil</>}
              </button>
           </div>
        </form>
      </section>

      {/* Alterar Senha */}
      <section className="bg-white rounded-[3rem] p-10 border border-slate-100 shadow-sm space-y-8">
        <div className="flex items-center gap-3">
           <div className="p-3 bg-red-50 text-red-500 rounded-2xl"><Lock className="w-5 h-5" /></div>
           <div>
             <h3 className="text-xl font-black text-slate-900">Segurança da Conta</h3>
             <p className="text-slate-400 font-medium">Mantenha sua senha atualizada e segura.</p>
           </div>
        </div>

        <form onSubmit={handleChangePassword} className="space-y-6 max-w-md">
           <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Senha Atual</label>
              <div className="relative">
                <input 
                  type={showPass ? "text" : "password"}
                  required
                  value={passwordData.current}
                  onChange={e => setPasswordData({...passwordData, current: e.target.value})}
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900"
                />
                <button type="button" onClick={() => setShowPass(!showPass)} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400">
                   {showPass ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                </button>
              </div>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                 <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Nova Senha</label>
                 <input 
                   type="password"
                   required
                   value={passwordData.new}
                   onChange={e => setPasswordData({...passwordData, new: e.target.value})}
                   className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900"
                 />
              </div>
              <div className="space-y-2">
                 <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Confirmar Nova Senha</label>
                 <input 
                   type="password"
                   required
                   value={passwordData.confirm}
                   onChange={e => setPasswordData({...passwordData, confirm: e.target.value})}
                   className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900"
                 />
              </div>
           </div>

           {passError && (
             <div className="p-4 bg-red-50 border border-red-100 rounded-2xl flex items-center gap-2 text-red-600 text-xs font-bold">
                <ShieldAlert className="w-4 h-4" /> {passError}
             </div>
           )}

           {passSuccess && (
             <div className="p-4 bg-emerald-50 border border-emerald-100 rounded-2xl flex items-center gap-2 text-emerald-600 text-xs font-bold">
                <Check className="w-4 h-4" /> Senha alterada com sucesso!
             </div>
           )}

           <button 
             type="submit" 
             className="w-full py-4 bg-slate-900 text-white font-black rounded-2xl shadow-xl hover:bg-black transition-all uppercase tracking-widest text-xs"
           >
             Alterar Senha
           </button>
        </form>
      </section>
    </div>
  );
};

export default UserProfile;

import React, { useState, useMemo } from 'react';
import { User, StaffRole } from '../types';
import { dataStore } from '../services/dataStore';
import { Users, Plus, Mail, Shield, ShieldCheck, Eye, Trash2, X, Send, UserPlus, Clock } from 'lucide-react';

interface UsersTeamProps {
  companyId: string;
  currentUser: User;
}

const UsersTeam: React.FC<UsersTeamProps> = ({ companyId, currentUser }) => {
  const [users, setUsers] = useState<User[]>(dataStore.getCompanyUsers(companyId));
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [inviteData, setInviteData] = useState({
    name: '',
    email: '',
    role: 'AGENT' as StaffRole
  });

  const canManage = currentUser.staffRole === 'ADMIN' || currentUser.role === 'BUSINESS';

  const handleInvite = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inviteData.email || !inviteData.name) return;

    const newUser = dataStore.addCompanyUser(companyId, {
      name: inviteData.name,
      email: inviteData.email,
      staffRole: inviteData.role
    });

    setUsers([...users, newUser]);
    setIsModalOpen(false);
    setInviteData({ name: '', email: '', role: 'AGENT' });
    alert(`Convite enviado para ${inviteData.email}! (Simulação de envio de e-mail)`);
  };

  const RoleBadge = ({ role }: { role?: StaffRole }) => {
    const styles = {
      ADMIN: 'bg-indigo-50 text-indigo-600 border-indigo-100',
      AGENT: 'bg-emerald-50 text-emerald-600 border-emerald-100',
      VIEWER: 'bg-slate-50 text-slate-400 border-slate-100'
    };
    const labels = { ADMIN: 'Admin', AGENT: 'Agente', VIEWER: 'Leitura' };
    const Icon = role === 'ADMIN' ? ShieldCheck : role === 'AGENT' ? Shield : Eye;

    return (
      <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wider border flex items-center gap-1 w-fit ${styles[role || 'VIEWER']}`}>
        <Icon className="w-3 h-3" /> {labels[role || 'VIEWER']}
      </span>
    );
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm flex flex-col md:flex-row justify-between items-center gap-6">
         <div className="flex items-center gap-4">
            <div className="p-4 bg-primary/5 text-primary rounded-[2rem]"><Users className="w-8 h-8" /></div>
            <div>
               <h2 className="text-2xl font-black text-slate-900">Gestão de Equipe</h2>
               <p className="text-slate-400 font-medium">Controle quem tem acesso ao Ativare Experience na sua empresa.</p>
            </div>
         </div>
         {canManage && (
           <button 
             onClick={() => setIsModalOpen(true)}
             className="px-8 py-4 bg-primary text-white font-black rounded-2xl shadow-xl shadow-primary/20 hover:scale-105 transition-all flex items-center gap-2"
           >
             <UserPlus className="w-5 h-5" /> Convidar Membro
           </button>
         )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {users.map(u => (
          <div key={u.id} className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm hover:shadow-md transition-all group relative overflow-hidden">
             {u.id === currentUser.id && (
                <div className="absolute top-0 right-0 bg-primary text-white px-3 py-1 text-[8px] font-black uppercase tracking-widest rounded-bl-xl">Você</div>
             )}

             <div className="flex items-center gap-4 mb-6">
                <div className="w-14 h-14 rounded-2xl bg-slate-50 border border-slate-100 overflow-hidden flex items-center justify-center">
                   {u.profilePhoto ? (
                     <img src={u.profilePhoto} className="w-full h-full object-cover" alt="User" />
                   ) : (
                     <img src={`https://ui-avatars.com/api/?name=${u.name}&background=f8fafc&color=94a3b8`} className="w-full h-full" alt="Avatar" />
                   )}
                </div>
                <div>
                   <h4 className="text-base font-black text-slate-800 line-clamp-1">{u.name}</h4>
                   <p className="text-xs text-slate-400 font-medium">{u.email}</p>
                </div>
             </div>

             <div className="space-y-4 pt-6 border-t border-slate-50">
                <div className="flex justify-between items-center">
                   <span className="text-[10px] font-black uppercase text-slate-300 tracking-widest">Nível de Acesso</span>
                   <RoleBadge role={u.staffRole} />
                </div>
                <div className="flex justify-between items-center">
                   <span className="text-[10px] font-black uppercase text-slate-300 tracking-widest">Membro desde</span>
                   <span className="text-[10px] font-bold text-slate-500 uppercase flex items-center gap-1">
                      <Clock className="w-3 h-3" /> {u.createdAt ? new Date(u.createdAt).toLocaleDateString('pt-BR') : 'Mock'}
                   </span>
                </div>
             </div>

             {canManage && u.id !== currentUser.id && (
               <div className="mt-8 flex gap-2">
                  <button className="flex-1 py-2 bg-slate-50 text-slate-400 font-black text-[10px] uppercase rounded-xl hover:bg-slate-100 transition-all">Editar</button>
                  <button className="p-2 text-red-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all">
                     <Trash2 className="w-4 h-4" />
                  </button>
               </div>
             )}
          </div>
        ))}
      </div>

      {/* Modal de Convite */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsModalOpen(false)}></div>
          <div className="bg-white rounded-[3rem] w-full max-w-lg p-10 relative z-10 shadow-2xl border border-white animate-in zoom-in duration-300">
            <button onClick={() => setIsModalOpen(false)} className="absolute top-8 right-8 text-slate-400 hover:text-slate-600"><X className="w-6 h-6" /></button>
            <div className="w-20 h-20 bg-primary/10 text-primary rounded-[2rem] flex items-center justify-center mb-6"><UserPlus className="w-10 h-10" /></div>
            <h3 className="text-2xl font-black text-slate-900 mb-2">Convidar para o Time</h3>
            <p className="text-slate-500 text-sm font-medium mb-8">O membro receberá um e-mail com as instruções de acesso.</p>

            <form onSubmit={handleInvite} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-slate-400">Nome Completo</label>
                <input required type="text" value={inviteData.name} onChange={e => setInviteData({...inviteData, name: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" placeholder="Ex: João Silva" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-slate-400">E-mail Corporativo</label>
                <input required type="email" value={inviteData.email} onChange={e => setInviteData({...inviteData, email: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" placeholder="joao@empresa.com" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-slate-400">Nível de Acesso (Role)</label>
                <div className="grid grid-cols-3 gap-2">
                   {[
                     { id: 'ADMIN', label: 'Admin', icon: ShieldCheck, desc: 'Acesso Total' },
                     { id: 'AGENT', label: 'Agente', icon: Shield, desc: 'Casos/Feedbacks' },
                     { id: 'VIEWER', label: 'Leitura', icon: Eye, desc: 'Apenas Relatórios' }
                   ].map(r => (
                     <button
                        key={r.id}
                        type="button"
                        onClick={() => setInviteData({...inviteData, role: r.id as StaffRole})}
                        className={`p-3 rounded-2xl border-2 flex flex-col items-center gap-1 transition-all ${inviteData.role === r.id ? 'bg-primary/5 border-primary text-primary' : 'bg-white border-slate-100 text-slate-300'}`}
                     >
                        <r.icon className="w-4 h-4" />
                        <span className="text-[9px] font-black uppercase">{r.label}</span>
                     </button>
                   ))}
                </div>
              </div>
              <button type="submit" className="w-full py-5 bg-primary text-white font-black rounded-3xl shadow-xl flex items-center justify-center gap-2 uppercase tracking-widest text-xs">
                 Enviar Convite <Send className="w-4 h-4" />
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default UsersTeam;

export enum UserRole {
  MASTER = 'MASTER',
  BUSINESS = 'BUSINESS',
  USER = 'USER'
}

export type StaffRole = 'ADMIN' | 'AGENT' | 'VIEWER';

export type JobTitle = 'Dono' | 'Gerente' | 'Sub-gerente';

export type PlanType = 'TRIAL' | 'PRO' | 'ENTERPRISE';
export type AccountStatus = 'TRIAL' | 'ACTIVE' | 'SUSPENDED' | 'EXPIRED';

export interface User {
  id: string;
  name: string;
  email: string;
  password?: string;
  role: UserRole;
  staffRole?: StaffRole; // Papel dentro da empresa (Admin, Agente, Somente Leitura)
  companyId?: string;
  phone?: string;
  profilePhoto?: string;
  jobTitle?: JobTitle;
  isOnboarded: boolean;
  createdAt?: string;
}

export interface CNPJRequest {
  id: string;
  userId: string;
  userName: string;
  requestedCNPJ: string;
  reason: string;
  status: 'PENDING' | 'APPROVED' | 'REJECTED';
  createdAt: string;
}

export interface Company {
  id: string;
  trackingCode: string;
  name: string;
  description?: string;
  category: string;
  city: string;
  logo: string;
  experienceScore: number;
  cnpj?: string;
  address?: string;
  employees?: string;
  phone?: string;
  email?: string;
  instagram?: string;
  trialEndDate?: string;
  startDate?: string;
  nextBillingDate?: string;
  plan: PlanType;
  status: AccountStatus;
  maxEvaluations: number;
  maxUsers: number;
  cnpjRequests?: CNPJRequest[];
}

export type NPSCategory = 'PROMOTER' | 'PASSIVE' | 'DETRACTOR';

export type InternalQuestionType = 'TEXT' | 'SCALE_5' | 'SCALE_10' | 'YES_NO';

export interface InternalQuestion {
  id: string;
  companyId: string;
  text: string;
  type: InternalQuestionType;
  required: boolean;
  active: boolean;
  isPublic: boolean;
  order: number;
}

export interface Feedback {
  id: string;
  companyId: string;
  companyTrackingCode: string;
  customerId: string;
  customerName: string;
  customerPhone: string;
  howKnown: string;
  scores: {
    service: number;
    food: number;
    drinks: number;
    structure: number;
  };
  internalResponses?: { [questionId: string]: any };
  profile: 'family' | 'friends' | 'couple' | 'kids';
  observation: string;
  createdAt: string;
  category: NPSCategory;
  averageScore: number;
  email?: string;
}

export type CaseStatus = 'OPEN' | 'IN_PROGRESS' | 'RESOLVED';

export interface CaseNote {
  id: string;
  userId: string;
  userName: string;
  text: string;
  createdAt: string;
}

export interface Case {
  id: string;
  feedbackId: string;
  companyId: string;
  status: CaseStatus;
  assignedTo?: string;
  resolutionText?: string;
  notes: CaseNote[];
  updatedAt: string;
}

export type ContactLogType = 'CALL' | 'WHATSAPP' | 'EMAIL' | 'VISIT' | 'INTERNAL_NOTE';

export interface ContactLog {
  id: string;
  type: ContactLogType;
  text: string;
  userId: string;
  userName: string;
  createdAt: string;
}

export interface Customer {
  id: string;
  companyId: string;
  name: string;
  phone: string;
  email?: string;
  profile?: 'family' | 'friends' | 'couple' | 'kids';
  firstSeen: string;
  lastSeen: string;
  averageScore: number;
  totalFeedbacks: number;
  category: NPSCategory;
  contactLogs: ContactLog[];
}

import { Feedback, Case, Customer, NPSCategory, InternalQuestion, InternalQuestionType, ContactLog, Company, User, UserRole, CNPJRequest, StaffRole, PlanType, AccountStatus } from '../types';
import { MOCK_COMPANIES, MOCK_USERS } from '../constants';

class DataStore {
  private companies: Company[] = [...MOCK_COMPANIES.map(c => ({
    ...c,
    plan: 'PRO' as PlanType,
    status: 'ACTIVE' as AccountStatus,
    startDate: '2023-01-10T10:00:00Z',
    nextBillingDate: '2024-05-10T10:00:00Z',
    maxEvaluations: 500,
    maxUsers: 10,
    cnpj: '12.345.678/0001-99'
  }))];
  private users: User[] = [...MOCK_USERS];
  private feedbacks: Feedback[] = [];
  private cases: Case[] = [];
  private customers: Customer[] = [];
  private internalQuestions: InternalQuestion[] = [];

  constructor() {
    this.initMockData();
  }

  private generateUniqueTrackingCode(): string {
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
    let code = '';
    let isUnique = false;

    while (!isUnique) {
      code = '';
      for (let i = 0; i < 6; i++) {
        code += chars.charAt(Math.floor(Math.random() * chars.length));
      }
      isUnique = !this.companies.some(c => c.trackingCode === code);
    }

    return code;
  }

  private initMockData() {
    this.companies.forEach(comp => {
      const q1: InternalQuestion = {
        id: `q1-${comp.id}`,
        companyId: comp.id,
        text: comp.category === 'Pizzaria' ? 'A massa estava no ponto?' : 'O atendimento foi cordial?',
        type: 'YES_NO',
        required: true,
        active: true,
        isPublic: true,
        order: 1
      };
      this.internalQuestions.push(q1);
    });
  }

  authenticate(email: string, pass: string): User | null {
    const user = this.users.find(u => u.email === email);
    if (user && user.password === pass) {
      return user;
    }
    return null;
  }

  registerAccount(email: string, pass: string): User {
    const newUser: User = {
      id: `u-${Date.now()}`,
      name: '',
      email,
      password: pass,
      role: UserRole.BUSINESS,
      staffRole: 'ADMIN',
      isOnboarded: false,
      createdAt: new Date().toISOString()
    };
    this.users.push(newUser);
    return newUser;
  }

  completeOnboarding(userId: string, companyData: Partial<Company>, responsibleData: Partial<User>) {
    const userIdx = this.users.findIndex(u => u.id === userId);
    if (userIdx === -1) return null;

    const companyId = `comp-${Date.now()}`;
    const trackingCode = this.generateUniqueTrackingCode();
    const trialEndDate = new Date();
    trialEndDate.setDate(trialEndDate.getDate() + 15);

    const newCompany: Company = {
      id: companyId,
      trackingCode,
      name: companyData.name || '',
      description: companyData.description,
      category: companyData.category || 'Restaurante',
      city: companyData.city || '',
      logo: companyData.logo || 'https://picsum.photos/seed/ativare/200',
      experienceScore: 0,
      cnpj: companyData.cnpj,
      address: companyData.address,
      employees: companyData.employees,
      phone: companyData.phone,
      email: companyData.email,
      instagram: companyData.instagram,
      trialEndDate: trialEndDate.toISOString(),
      startDate: new Date().toISOString(),
      plan: 'TRIAL',
      status: 'TRIAL',
      maxEvaluations: 50,
      maxUsers: 3,
      cnpjRequests: []
    };

    this.companies.push(newCompany);

    this.users[userIdx] = {
      ...this.users[userIdx],
      ...responsibleData,
      companyId,
      isOnboarded: true
    };

    return { company: newCompany, user: this.users[userIdx] };
  }

  getCompany(id: string) {
    return this.companies.find(c => c.id === id);
  }

  getCompanyByTrackingCode(code: string) {
    return this.companies.find(c => c.trackingCode.toUpperCase() === code.toUpperCase());
  }

  getAllCompanies() {
    return this.companies;
  }

  updateCompany(id: string, data: Partial<Company>) {
    const idx = this.companies.findIndex(c => c.id === id);
    if (idx >= 0) {
      // CNPJ não pode ser editado diretamente, apenas via solicitação (validado no componente)
      this.companies[idx] = { ...this.companies[idx], ...data };
      return this.companies[idx];
    }
    return null;
  }

  getCompanyUsers(companyId: string) {
    return this.users.filter(u => u.companyId === companyId);
  }

  addCompanyUser(companyId: string, userData: Partial<User>) {
    const newUser: User = {
      id: `u-${Date.now()}`,
      name: userData.name || 'Novo Usuário',
      email: userData.email || '',
      password: userData.password || 'ativare123',
      role: UserRole.USER,
      staffRole: userData.staffRole || 'AGENT',
      companyId,
      isOnboarded: true,
      createdAt: new Date().toISOString()
    };
    this.users.push(newUser);
    return newUser;
  }

  updateUser(id: string, data: Partial<User>) {
    const idx = this.users.findIndex(u => u.id === id);
    if (idx >= 0) {
      this.users[idx] = { ...this.users[idx], ...data };
      return this.users[idx];
    }
    return null;
  }

  updatePassword(userId: string, currentPass: string, newPass: string) {
    const user = this.users.find(u => u.id === userId);
    if (user && user.password === currentPass) {
      user.password = newPass;
      return true;
    }
    return false;
  }

  getInternalQuestions(companyId: string, onlyActive = true) {
    let qs = this.internalQuestions.filter(q => q.companyId === companyId);
    if (onlyActive) qs = qs.filter(q => q.active);
    return qs.sort((a, b) => a.order - b.order);
  }

  saveInternalQuestion(question: InternalQuestion) {
    const idx = this.internalQuestions.findIndex(q => q.id === question.id);
    if (idx >= 0) this.internalQuestions[idx] = question;
    else this.internalQuestions.push(question);
  }

  deleteInternalQuestion(id: string) {
    this.internalQuestions = this.internalQuestions.filter(q => q.id !== id);
  }

  getInternalMetrics(companyId: string) {
    const qs = this.getInternalQuestions(companyId, false);
    const fbs = this.getFeedbacks(companyId);
    return qs.map(q => {
      const responses = fbs.map(f => f.internalResponses?.[q.id]).filter(r => r !== undefined && r !== null);
      let avg: any = 0;
      if (q.type === 'SCALE_5' || q.type === 'SCALE_10') {
        avg = responses.length > 0 ? responses.reduce((acc: number, val: any) => acc + Number(val), 0) / responses.length : 0;
      } else if (q.type === 'YES_NO') {
        const yesCount = responses.filter(r => r === 'SIM').length;
        avg = responses.length > 0 ? (yesCount / responses.length) * 100 : 0;
      }
      return { questionId: q.id, text: q.text, type: q.type, totalResponses: responses.length, average: avg, responses: responses };
    });
  }

  getFeedbacks(companyId?: string) {
    return companyId ? this.feedbacks.filter(f => f.companyId === companyId) : this.feedbacks;
  }

  updateFeedbackInternalResponses(feedbackId: string, responses: { [key: string]: any }) {
    const idx = this.feedbacks.findIndex(f => f.id === feedbackId);
    if (idx >= 0) {
      this.feedbacks[idx].internalResponses = {
        ...this.feedbacks[idx].internalResponses,
        ...responses
      };
      return this.feedbacks[idx];
    }
    return null;
  }

  getCustomers(companyId: string) {
    return this.customers.filter(c => c.companyId === companyId);
  }

  getCaseForFeedback(feedbackId: string) {
    return this.cases.find(c => c.feedbackId === feedbackId);
  }

  getCases(companyId?: string) {
    return companyId ? this.cases.filter(c => c.companyId === companyId) : this.cases;
  }

  addFeedback(feedback: Omit<Feedback, 'id' | 'createdAt' | 'category' | 'averageScore'>) {
    const company = this.getCompany(feedback.companyId);
    if (!company) throw new Error("Empresa não encontrada");

    // Checagem de limites
    const currentMonthFeedbacks = this.getFeedbacks(feedback.companyId).filter(f => {
      const date = new Date(f.createdAt);
      const now = new Date();
      return date.getMonth() === now.getMonth() && date.getFullYear() === now.getFullYear();
    });

    if (currentMonthFeedbacks.length >= company.maxEvaluations) {
      console.warn("Limite de avaliações mensais atingido.");
      // Em produção, isso bloquearia o envio.
    }

    const avg = (feedback.scores.service + feedback.scores.food + feedback.scores.drinks + feedback.scores.structure) / 4;
    let cat: NPSCategory = avg >= 9 ? 'PROMOTER' : avg <= 6 ? 'DETRACTOR' : 'PASSIVE';
    const createdAt = new Date().toISOString();

    const newFeedback: Feedback = { 
      ...feedback, 
      id: `f-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`, 
      createdAt, 
      category: cat, 
      averageScore: avg 
    };

    this.feedbacks.push(newFeedback);

    let customer = this.customers.find(c => c.phone === feedback.customerPhone && c.companyId === feedback.companyId);
    if (!customer) {
      customer = { id: `cust-${Date.now()}`, companyId: feedback.companyId, name: feedback.customerName, phone: feedback.customerPhone, email: feedback.email, profile: feedback.profile, firstSeen: createdAt, lastSeen: createdAt, averageScore: avg, totalFeedbacks: 1, category: cat, contactLogs: [] };
      this.customers.push(customer);
    } else {
      customer.lastSeen = createdAt;
      customer.totalFeedbacks += 1;
      const customerFeedbacks = this.feedbacks.filter(f => f.customerPhone === customer?.phone && f.companyId === feedback.companyId);
      customer.averageScore = customerFeedbacks.reduce((acc, f) => acc + f.averageScore, 0) / customerFeedbacks.length;
      customer.category = customer.averageScore >= 9 ? 'PROMOTER' : customer.averageScore <= 6 ? 'DETRACTOR' : 'PASSIVE';
      customer.name = feedback.customerName;
    }

    if (cat === 'DETRACTOR') {
      this.createCaseFromFeedback(newFeedback.id, feedback.companyId, 'Caso gerado automaticamente devido à baixa pontuação.', 'Sistema Ativare', 'system');
    }

    return newFeedback;
  }

  getDashboardStats(companyId: string) {
    const fb = this.getFeedbacks(companyId);
    const total = fb.length;
    const avgScore = total > 0 ? (fb.reduce((acc, f) => acc + f.averageScore, 0) / total) * 10 : 0;
    const companyCases = this.getCases(companyId);
    return {
      total,
      promoters: fb.filter(f => f.category === 'PROMOTER').length,
      detractors: fb.filter(f => f.category === 'DETRACTOR').length,
      passives: fb.filter(f => f.category === 'PASSIVE').length,
      avgScore: Math.round(avgScore),
      openDetractors: companyCases.filter(c => c.status === 'OPEN').length,
      resolvedDetractors: companyCases.filter(c => c.status === 'RESOLVED').length,
      catAvg: {
        service: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.service, 0) / total) : 0,
        food: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.food, 0) / total) : 0,
        drinks: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.drinks, 0) / total) : 0,
        structure: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.structure, 0) / total) : 0,
      }
    };
  }

  createCaseFromFeedback(feedbackId: string, companyId: string, noteText: string, userName: string, userId: string) {
    if (this.cases.some(c => c.feedbackId === feedbackId)) return;
    const newCase: Case = {
      id: `case-${Date.now()}`,
      feedbackId,
      companyId,
      status: 'OPEN',
      notes: [{ id: `note-${Date.now()}`, userId, userName, text: noteText, createdAt: new Date().toISOString() }],
      updatedAt: new Date().toISOString()
    };
    this.cases.push(newCase);
    return newCase;
  }

  addCaseNote(caseId: string, userId: string, userName: string, text: string) {
    const c = this.cases.find(item => item.id === caseId);
    if (c) {
      c.notes.push({ id: `note-${Date.now()}`, userId, userName, text, createdAt: new Date().toISOString() });
      c.updatedAt = new Date().toISOString();
      if (c.status === 'OPEN') c.status = 'IN_PROGRESS';
    }
  }

  resolveCase(caseId: string, resolutionText: string, userName: string, userId: string) {
    const c = this.cases.find(item => item.id === caseId);
    if (c) {
      c.status = 'RESOLVED';
      c.resolutionText = resolutionText;
      c.notes.push({ id: `note-res-${Date.now()}`, userId, userName, text: `RESOLUÇÃO: ${resolutionText}`, createdAt: new Date().toISOString() });
      c.updatedAt = new Date().toISOString();
    }
  }

  getCustomerHistory(customerId: string) {
    const customer = this.customers.find(c => c.id === customerId);
    if (!customer) return [];
    return this.feedbacks.filter(f => f.customerPhone === customer.phone && f.companyId === customer.companyId).sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }

  addContactLog(customerId: string, log: Omit<ContactLog, 'id' | 'createdAt'>) {
    const customer = this.customers.find(c => c.id === customerId);
    if (customer) customer.contactLogs.unshift({ ...log, id: `log-${Date.now()}`, createdAt: new Date().toISOString() });
  }

  requestCNPJChange(companyId: string, request: Omit<CNPJRequest, 'id' | 'status' | 'createdAt'>) {
    const company = this.getCompany(companyId);
    if (company) {
      if (!company.cnpjRequests) company.cnpjRequests = [];
      const newRequest: CNPJRequest = {
        ...request,
        id: `req-${Date.now()}`,
        status: 'PENDING',
        createdAt: new Date().toISOString()
      };
      company.cnpjRequests.push(newRequest);
      return newRequest;
    }
    return null;
  }
}

export const dataStore = new DataStore();

