        {/* Heatmap Analysis */}
        <div className="lg:col-span-12 bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm space-y-10 print:break-before-page">
           <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
              <div>
                 <h3 className="text-xl font-black text-slate-900">Mapa de Calor (Pontos de Atrito)</h3>
                 <p className="text-slate-400 font-medium text-sm">Identifique dias e horários com maior recorrência de avaliações baixas.</p>
