        {/* Root Cause Analysis */}
        <div className="lg:col-span-6 bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm space-y-8">
           <div>
              <h3 className="text-xl font-black text-slate-900">Análise de Causa Raiz</h3>
