           </div>

           <div className="space-y-6">
              {biData.impacts.map(i => (
                 <div key={i.category} className="space-y-3">
                    <div className="flex justify-between items-end">
                       <span className="text-sm font-black text-slate-700">{i.category}</span>
                       <div className="text-right">
                          <span className="text-[10px] font-black uppercase text-red-400 block">Impacto no Score</span>
                          <span className="text-sm font-black text-slate-900">-{i.impact}%</span>
                       </div>
                    </div>
                    <div className="h-3 w-full bg-slate-50 rounded-full overflow-hidden">
                       <div className="h-full bg-red-400 rounded-full transition-all duration-1000" style={{ width: `${i.impact * 2}%` }}></div>
                    </div>
                 </div>
              ))}
           </div>

           <div className="mt-8 p-6 bg-slate-50 rounded-[2rem] border border-slate-100 flex items-start gap-3">
              <AlertTriangle className="w-5 h-5 text-red-400 mt-1 flex-shrink-0" />
              <p className="text-[10px] font-bold text-slate-500 uppercase leading-relaxed">
                Priorize o treinamento em <span className="text-primary font-black">Atendimento</span>. Melhorar este pilar em 10% pode elevar seu score geral em até 4 pontos.
              </p>
           </div>
        </div>

        {/* Sentiment Cloud */}
        <div className="lg:col-span-6 bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm space-y-10">
           <div>
              <h3 className="text-xl font-black text-slate-900">Análise de Sentimentos</h3>
              <p className="text-slate-400 font-medium text-sm">Palavras-chave recorrentes nos comentários.</p>
           </div>

           <div className="space-y-12">
              <div className="space-y-6">
                 <div className="flex items-center gap-2 px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full w-fit border border-emerald-100">
                    <Smile className="w-4 h-4" />
                    <span className="text-[10px] font-black uppercase tracking-widest">Pontos Fortes</span>
                 </div>
                 <SentimentCloud words={biData.sentiments.positive} color="text-emerald-500" />
              </div>

              <div className="space-y-6">
                 <div className="flex items-center gap-2 px-3 py-1 bg-red-50 text-red-500 rounded-full w-fit border border-red-100">
                    <Frown className="w-4 h-4" />
                    <span className="text-[10px] font-black uppercase tracking-widest">A melhorar</span>
