        </div>
      </div>
    </div>
  );
};

export default BI;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { dataStore } from '../services/dataStore';
import { GoogleGenAI, Type, Chat, GenerateContentResponse } from "@google/genai";
import { 
  LineChart, 
  Line, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  AreaChart, 
  Area,
  BarChart,
  Bar,
  Cell
} from 'recharts';
import { 
  Calendar, 
  Filter, 
  PieChart, 
  TrendingUp, 
  BrainCircuit, 
  Zap, 
  Smile, 
  Frown, 
  Clock, 
  Flame,
  AlertTriangle,
  ChevronRight,
  Info,
  Sparkles,
  FileText,
  CheckCircle2,
  ListChecks,
  Activity,
  ArrowRight,
  Download,
  Loader2,
  MessageSquare,
  X,
  Send,
  User as UserIcon,
  Bot
} from 'lucide-react';

interface AIInsight {
  diagnosis: string;
  strengths: string[];
  improvements: string[];
  actionableSuggestions: {
    title: string;
    description: string;
    impact: 'HIGH' | 'MEDIUM' | 'LOW';
  }[];
  actionPlan: string[];
}

interface Message {
  role: 'user' | 'model';
  text: string;
}

interface BIProps {
  companyId: string;
}

const BI: React.FC<BIProps> = ({ companyId }) => {
  const [timeRange, setTimeRange] = useState<number>(30);
  const [evalType, setEvalType] = useState<string>('ALL');
  const [channel, setChannel] = useState<string>('ALL');

  const [aiInsights, setAiInsights] = useState<AIInsight | null>(null);
  const [loadingAI, setLoadingAI] = useState(false);
  const [checklist, setChecklist] = useState<string[]>([]);

  // Chat States
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [chatMessages, setChatMessages] = useState<Message[]>([]);
  const [inputMessage, setInputMessage] = useState('');
  const [isChatLoading, setIsChatLoading] = useState(false);
  const chatInstance = useRef<Chat | null>(null);
  const chatScrollRef = useRef<HTMLDivElement>(null);

  const biData = useMemo(() => dataStore.getBIData(companyId, timeRange), [companyId, timeRange]);
  const company = useMemo(() => dataStore.getCompany(companyId), [companyId]);

  useEffect(() => {
    if (chatScrollRef.current) {
      chatScrollRef.current.scrollTop = chatScrollRef.current.scrollHeight;
    }
  }, [chatMessages, isChatLoading]);

  const generateAIInsights = async () => {
    if (!biData || loadingAI) return;

    setLoadingAI(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analyze this customer experience data for the business "${company?.name}" and return strategic insights in JSON.
        Data Summary:
        - Total Evaluations: ${biData.rawSummary.totalEvaluations}
        - Detractors: ${biData.rawSummary.detractorsCount}
        - Promoters: ${biData.rawSummary.promotersCount}
        - Category Averages (1-10): Service: ${biData.rawSummary.averageScores.service}, Food: ${biData.rawSummary.averageScores.food}, Drinks: ${biData.rawSummary.averageScores.drinks}, Structure: ${biData.rawSummary.averageScores.structure}
        - Common Positive Words: ${biData.sentiments.positive.join(', ')}
        - Common Negative Words: ${biData.sentiments.negative.join(', ')}
        - Recent Comments: ${biData.rawSummary.recentComments.join(' | ')}
        `,
        config: {
          systemInstruction: "You are a senior business consultant specialized in customer experience. Provide a professional diagnosis and actionable steps. Use Portuguese (PT-BR).",
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              diagnosis: { type: Type.STRING },
              strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
              improvements: { type: Type.ARRAY, items: { type: Type.STRING } },
              actionableSuggestions: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    title: { type: Type.STRING },
                    description: { type: Type.STRING },
                    impact: { type: Type.STRING }
                  },
                  required: ["title", "description", "impact"]
                }
              },
              actionPlan: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["diagnosis", "strengths", "improvements", "actionableSuggestions", "actionPlan"]
          }
        }
      });

      const insights = JSON.parse(response.text) as AIInsight;
      setAiInsights(insights);
      setChecklist([]);
      // Reset chat when insights refresh
      chatInstance.current = null;
      setChatMessages([]);
    } catch (error) {
      console.error("AI Insight Error:", error);
    } finally {
      setLoadingAI(false);
    }
  };

  const handleSendMessage = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputMessage.trim() || isChatLoading || !aiInsights) return;

    const userText = inputMessage;
    setInputMessage('');
    setChatMessages(prev => [...prev, { role: 'user', text: userText }]);
    setIsChatLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      if (!chatInstance.current) {
        const systemInstruction = `
          Você é o Consultor Estratégico Ativare da empresa "${company?.name}".
          Seu objetivo é ajudar o gestor a tomar decisões baseadas EXCLUSIVAMENTE nos dados abaixo.

          CONTEXTO DO NEGÓCIO:
          - Nome: ${company?.name}
          - Diagnóstico Atual: ${aiInsights.diagnosis}
          - Pontos Fortes: ${aiInsights.strengths.join(', ')}
          - Pontos Fracos: ${aiInsights.improvements.join(', ')}
          - Plano de Ação sugerido: ${aiInsights.actionPlan.join(', ')}

          DADOS OPERACIONAIS REAIS:
          - Total de avaliações analisadas: ${biData.rawSummary.totalEvaluations}
          - Notas médias (1-10): Atendimento (${biData.rawSummary.averageScores.service}), Comida (${biData.rawSummary.averageScores.food}), Bebidas (${biData.rawSummary.averageScores.drinks}), Estrutura (${biData.rawSummary.averageScores.structure}).
          - Comentários recentes: ${biData.rawSummary.recentComments.join(' | ')}

          REGRAS CRÍTICAS:
          1. NÃO use conhecimentos externos à empresa. 
          2. NÃO cite concorrentes ou dados de mercado que não foram fornecidos aqui.
          3. Se o usuário perguntar algo fora do escopo do negócio dele, responda educadamente que você foca apenas na performance da "${company?.name}".
          4. Responda de forma executiva, clara e focada em resultados.
          5. Use Português (PT-BR).
        `;

        chatInstance.current = ai.chats.create({
          model: 'gemini-3-flash-preview',
          config: { systemInstruction }
        });
      }

      let fullResponseText = '';
      const responseStream = await chatInstance.current.sendMessageStream({ message: userText });

      // Add empty message for model to stream into
      setChatMessages(prev => [...prev, { role: 'model', text: '' }]);

      for await (const chunk of responseStream) {
        const c = chunk as GenerateContentResponse;
        fullResponseText += c.text;
        setChatMessages(prev => {
          const newMessages = [...prev];
          newMessages[newMessages.length - 1].text = fullResponseText;
          return newMessages;
        });
      }

    } catch (error) {
      console.error("Chat Error:", error);
      setChatMessages(prev => [...prev, { role: 'model', text: 'Desculpe, ocorreu um erro na conexão com a IA. Tente novamente em alguns instantes.' }]);
    } finally {
      setIsChatLoading(false);
    }
  };

  const handlePrint = () => {
    window.print();
  };

  const toggleChecklist = (item: string) => {
    setChecklist(prev => 
      prev.includes(item) ? prev.filter(i => i !== item) : [...prev, item]
    );
  };

  if (!biData) return null;

  const daysLabels = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'];
  const hoursLabels = Array.from({ length: 24 }, (_, i) => `${i}h`);

  const SentimentCloud = ({ words, color }: { words: string[], color: string }) => (
    <div className="flex flex-wrap gap-2 justify-center items-center">
      {words.map((w, idx) => {
        const size = Math.floor(Math.random() * (24 - 12 + 1)) + 12;
        const opacity = (Math.random() * 0.6) + 0.4;
        return (
          <span 
            key={idx} 
            className={`font-black uppercase tracking-tighter cursor-default transition-all hover:scale-110 ${color}`}
            style={{ fontSize: `${size}px`, opacity }}
          >
            {w}
          </span>
        );
      })}
    </div>
  );

  const getHeatmapColor = (value: number) => {
    if (value === 0) return 'bg-slate-50';
    if (value < 2) return 'bg-orange-100';
    if (value < 5) return 'bg-orange-300';
    if (value < 8) return 'bg-orange-500';
    return 'bg-red-600';
  };

  return (
    <div className="space-y-8 pb-20 animate-in fade-in duration-700 print:p-0 print:space-y-4">
      {/* Filters (Hidden on Print) */}
      <div className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm flex flex-wrap gap-4 items-center print:hidden">
         <div className="flex items-center gap-2 bg-slate-50 px-4 py-2 rounded-2xl border border-slate-100">
            <Calendar className="w-4 h-4 text-slate-400" />
            <select value={timeRange} onChange={(e) => setTimeRange(Number(e.target.value))} className="bg-transparent text-sm font-bold text-slate-700 outline-none">
              <option value={7}>Últimos 7 dias</option>
              <option value={30}>Últimos 30 dias</option>
              <option value={90}>Últimos 90 dias</option>
            </select>
         </div>
         <div className="flex items-center gap-2 bg-slate-50 px-4 py-2 rounded-2xl border border-slate-100">
            <PieChart className="w-4 h-4 text-slate-400" />
            <select value={evalType} onChange={(e) => setEvalType(e.target.value)} className="bg-transparent text-sm font-bold text-slate-700 outline-none">
              <option value="ALL">Todas Avaliações</option>
              <option value="POSITIVE">Apenas Positivas</option>
              <option value="DETRACTOR">Apenas Detratores</option>
            </select>
         </div>
         <div className="flex items-center gap-2 bg-slate-50 px-4 py-2 rounded-2xl border border-slate-100">
            <Zap className="w-4 h-4 text-slate-400" />
            <select value={channel} onChange={(e) => setChannel(e.target.value)} className="bg-transparent text-sm font-bold text-slate-700 outline-none">
              <option value="ALL">Todos Canais</option>
              <option value="QR">QR Code</option>
              <option value="LINK">Link Direto</option>
            </select>
         </div>
         <button 
           onClick={handlePrint}
           className="ml-auto flex items-center gap-2 px-6 py-2 bg-slate-900 text-white font-black text-xs uppercase tracking-widest rounded-2xl hover:bg-black transition-all"
         >
            <Download className="w-4 h-4" /> Exportar Relatório
         </button>
      </div>

      {/* AI INSIGHTS SECTION */}
      <section className="space-y-8 print:break-inside-avoid">
        <div className="flex items-center justify-between">
           <div className="flex items-center gap-3">
              <div className="p-3 bg-primary text-white rounded-2xl shadow-lg shadow-primary/20">
                 <BrainCircuit className="w-6 h-6" />
              </div>
              <div>
                 <h2 className="text-2xl font-black text-slate-900">Insights Inteligentes</h2>
                 <p className="text-slate-400 font-medium text-sm">Análise automática baseada no seu histórico.</p>
              </div>
           </div>
           {!aiInsights ? (
             <button 
               onClick={generateAIInsights}
               disabled={loadingAI}
               className="flex items-center gap-2 px-8 py-4 bg-gradient-to-r from-primary to-blue-600 text-white font-black rounded-3xl shadow-xl hover:scale-105 transition-all disabled:opacity-50"
             >
                {loadingAI ? <Loader2 className="w-5 h-5 animate-spin" /> : <Sparkles className="w-5 h-5" />}
                {loadingAI ? 'Analisando dados...' : 'Gerar Insights com IA'}
             </button>
           ) : (
             <button 
               onClick={() => setIsChatOpen(true)}
               className="flex items-center gap-2 px-8 py-4 bg-accent text-white font-black rounded-3xl shadow-xl hover:scale-105 transition-all"
             >
                <MessageSquare className="w-5 h-5" /> Chat com Especialista IA
             </button>
           )}
        </div>

        {aiInsights && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 animate-in slide-in-from-bottom-4 duration-700">
             {/* Automatic Diagnosis */}
             <div className="lg:col-span-8 bg-white rounded-[3rem] p-10 border border-slate-100 shadow-sm space-y-6">
                <div className="flex items-center gap-3 text-primary">
                   <Activity className="w-6 h-6" />
                   <h3 className="text-xl font-black uppercase tracking-tight">Diagnóstico Operacional</h3>
                </div>
                <p className="text-slate-600 leading-relaxed font-medium bg-slate-50 p-8 rounded-[2rem] border border-slate-100">
                   {aiInsights.diagnosis}
                </p>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pt-6">
                   <div className="space-y-4">
                      <h4 className="text-[10px] font-black uppercase text-emerald-500 tracking-widest flex items-center gap-2">
                         <Smile className="w-4 h-4" /> Pontos Fortes
                      </h4>
                      <ul className="space-y-3">
                         {aiInsights.strengths.map((s, idx) => (
                           <li key={idx} className="flex items-start gap-3 text-sm font-bold text-slate-700">
                              <CheckCircle2 className="w-5 h-5 text-emerald-500 flex-shrink-0" /> {s}
                           </li>
                         ))}
                      </ul>
                   </div>
                   <div className="space-y-4">
                      <h4 className="text-[10px] font-black uppercase text-red-500 tracking-widest flex items-center gap-2">
                         <Frown className="w-4 h-4" /> Oportunidades de Melhoria
                      </h4>
                      <ul className="space-y-3">
                         {aiInsights.improvements.map((im, idx) => (
                           <li key={idx} className="flex items-start gap-3 text-sm font-bold text-slate-700">
                              <AlertTriangle className="w-5 h-5 text-red-400 flex-shrink-0" /> {im}
                           </li>
                         ))}
                      </ul>
                   </div>
                </div>
             </div>

             {/* Checklist / Action Plan */}
             <div className="lg:col-span-4 bg-slate-900 rounded-[3rem] p-10 text-white shadow-2xl space-y-8 flex flex-col">
                <div className="flex items-center gap-3">
                   <ListChecks className="w-6 h-6 text-accent" />
                   <h3 className="text-xl font-black">Plano de Ação</h3>
                </div>
                <div className="flex-1 space-y-4">
                   {aiInsights.actionPlan.map((step, idx) => (
                     <button 
                       key={idx}
                       onClick={() => toggleChecklist(step)}
                       className={`w-full flex items-start gap-4 p-4 rounded-2xl border transition-all text-left group ${
                         checklist.includes(step) ? 'bg-emerald-500/10 border-emerald-500/40 opacity-50' : 'bg-white/5 border-white/10 hover:bg-white/10'
                       }`}
                     >
                        <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center flex-shrink-0 transition-all ${
                          checklist.includes(step) ? 'bg-emerald-500 border-emerald-500' : 'border-white/20'
                        }`}>
                           {checklist.includes(step) && <CheckCircle2 className="w-4 h-4" />}
                        </div>
                        <span className={`text-xs font-bold ${checklist.includes(step) ? 'line-through' : ''}`}>{step}</span>
                     </button>
                   ))}
                </div>
                <div className="p-6 bg-white/5 rounded-[2rem] border border-white/5">
                   <p className="text-[10px] font-black uppercase text-white/40 tracking-widest mb-2">Progresso da Semana</p>
                   <div className="flex items-center gap-4">
                      <div className="h-2 flex-1 bg-white/10 rounded-full overflow-hidden">
                         <div className="h-full bg-accent transition-all duration-1000" style={{ width: `${(checklist.length / aiInsights.actionPlan.length) * 100}%` }}></div>
                      </div>
                      <span className="text-xs font-black">{Math.round((checklist.length / aiInsights.actionPlan.length) * 100)}%</span>
                   </div>
                </div>
             </div>

             {/* Actionable Suggestions (Detailed) */}
             <div className="lg:col-span-12 grid grid-cols-1 md:grid-cols-3 gap-8">
                {aiInsights.actionableSuggestions.map((suggestion, idx) => (
