import React, { useState, useMemo, useEffect, useRef } from 'react';
import { dataStore } from '../services/dataStore';
import { GoogleGenAI, Type, Chat, GenerateContentResponse } from "@google/genai";
import { 
  LineChart, 
  Line, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  AreaChart, 
  Area,
  BarChart,
  Bar,
  Cell
} from 'recharts';
import { 
  Calendar, 
  Filter, 
  PieChart, 
  TrendingUp, 
  BrainCircuit, 
  Zap, 
  Smile, 
  Frown, 
  Clock, 
  Flame,
  AlertTriangle,
  ChevronRight,
  Info,
  Sparkles,
  FileText,
  CheckCircle2,
  ListChecks,
  Activity,
  ArrowRight,
  Download,
  Loader2,
  MessageSquare,
  X,
  Send,
  User as UserIcon,
  Bot,
  // Fix: Added ShieldCheck to imports
  ShieldCheck
} from 'lucide-react';

interface AIInsight {
  diagnosis: string;
  strengths: string[];
  improvements: string[];
  actionableSuggestions: {
    title: string;
    description: string;
    impact: 'HIGH' | 'MEDIUM' | 'LOW';
  }[];
  actionPlan: string[];
}

interface Message {
  role: 'user' | 'model';
  text: string;
}

interface BIProps {
  companyId: string;
}

const BI: React.FC<BIProps> = ({ companyId }) => {
  const [timeRange, setTimeRange] = useState<number>(30);
  const [evalType, setEvalType] = useState<string>('ALL');
  const [channel, setChannel] = useState<string>('ALL');

  const [aiInsights, setAiInsights] = useState<AIInsight | null>(null);
  const [loadingAI, setLoadingAI] = useState(false);
  const [checklist, setChecklist] = useState<string[]>([]);

  // Chat States
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [chatMessages, setChatMessages] = useState<Message[]>([]);
  const [inputMessage, setInputMessage] = useState('');
  const [isChatLoading, setIsChatLoading] = useState(false);
  const chatInstance = useRef<Chat | null>(null);
  const chatScrollRef = useRef<HTMLDivElement>(null);

  const biData = useMemo(() => dataStore.getBIData(companyId, timeRange), [companyId, timeRange]);
  const company = useMemo(() => dataStore.getCompany(companyId), [companyId]);

  useEffect(() => {
    if (chatScrollRef.current) {
      chatScrollRef.current.scrollTop = chatScrollRef.current.scrollHeight;
    }
  }, [chatMessages, isChatLoading]);

  const generateAIInsights = async () => {
    if (!biData || loadingAI) return;

    setLoadingAI(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analyze this customer experience data for the business "${company?.name}" and return strategic insights in JSON.
        Data Summary:
        - Total Evaluations: ${biData.rawSummary.totalEvaluations}
        - Detractors: ${biData.rawSummary.detractorsCount}
        - Promoters: ${biData.rawSummary.promotersCount}
        - Category Averages (1-10): Service: ${biData.rawSummary.averageScores.service}, Food: ${biData.rawSummary.averageScores.food}, Drinks: ${biData.rawSummary.averageScores.drinks}, Structure: ${biData.rawSummary.averageScores.structure}
        - Common Positive Words: ${biData.sentiments.positive.join(', ')}
        - Common Negative Words: ${biData.sentiments.negative.join(', ')}
        - Recent Comments: ${biData.rawSummary.recentComments.join(' | ')}
        `,
        config: {
          systemInstruction: "You are a senior business consultant specialized in customer experience. Provide a professional diagnosis and actionable steps. Use Portuguese (PT-BR).",
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              diagnosis: { type: Type.STRING },
              strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
              improvements: { type: Type.ARRAY, items: { type: Type.STRING } },
              actionableSuggestions: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    title: { type: Type.STRING },
                    description: { type: Type.STRING },
                    impact: { type: Type.STRING }
                  },
                  required: ["title", "description", "impact"]
                }
              },
              actionPlan: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["diagnosis", "strengths", "improvements", "actionableSuggestions", "actionPlan"]
          }
        }
      });

      const insights = JSON.parse(response.text) as AIInsight;
      setAiInsights(insights);
      setChecklist([]);
      // Reset chat when insights refresh
      chatInstance.current = null;
      setChatMessages([]);
    } catch (error) {
      console.error("AI Insight Error:", error);
    } finally {
      setLoadingAI(false);
    }
  };

  const handleSendMessage = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputMessage.trim() || isChatLoading || !aiInsights) return;

    const userText = inputMessage;
    setInputMessage('');
    setChatMessages(prev => [...prev, { role: 'user', text: userText }]);
    setIsChatLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      if (!chatInstance.current) {
        const systemInstruction = `
          Você é o Consultor Estratégico Ativare da empresa "${company?.name}".
          Seu objetivo é ajudar o gestor a tomar decisões baseadas EXCLUSIVAMENTE nos dados abaixo.

          CONTEXTO DO NEGÓCIO:
          - Nome: ${company?.name}
          - Diagnóstico Atual: ${aiInsights.diagnosis}
          - Pontos Fortes: ${aiInsights.strengths.join(', ')}
          - Pontos Fracos: ${aiInsights.improvements.join(', ')}
          - Plano de Ação sugerido: ${aiInsights.actionPlan.join(', ')}

          DADOS OPERACIONAIS REAIS:
          - Total de avaliações analisadas: ${biData.rawSummary.totalEvaluations}
          - Notas médias (1-10): Atendimento (${biData.rawSummary.averageScores.service}), Comida (${biData.rawSummary.averageScores.food}), Bebidas (${biData.rawSummary.averageScores.drinks}), Estrutura (${biData.rawSummary.averageScores.structure}).
          - Comentários recentes: ${biData.rawSummary.recentComments.join(' | ')}

          REGRAS CRÍTICAS:
          1. NÃO use conhecimentos externos à empresa. 
          2. NÃO cite concorrentes ou dados de mercado que não foram fornecidos aqui.
          3. Se o usuário perguntar algo fora do escopo do negócio dele, responda educadamente que você foca apenas na performance da "${company?.name}".
          4. Responda de forma executiva, clara e focada em resultados.
          5. Use Português (PT-BR).
        `;

        chatInstance.current = ai.chats.create({
          model: 'gemini-3-flash-preview',
          config: { systemInstruction }
        });
      }

      let fullResponseText = '';
      const responseStream = await chatInstance.current.sendMessageStream({ message: userText });

      // Add empty message for model to stream into
      setChatMessages(prev => [...prev, { role: 'model', text: '' }]);

      for await (const chunk of responseStream) {
        const c = chunk as GenerateContentResponse;
        fullResponseText += c.text;
        setChatMessages(prev => {
          const newMessages = [...prev];
          newMessages[newMessages.length - 1].text = fullResponseText;
          return newMessages;
        });
      }

    } catch (error) {
      console.error("Chat Error:", error);
      setChatMessages(prev => [...prev, { role: 'model', text: 'Desculpe, ocorreu um erro na conexão com a IA. Tente novamente em alguns instantes.' }]);
    } finally {
      setIsChatLoading(false);
    }
  };

  const handlePrint = () => {
    window.print();
  };

  const toggleChecklist = (item: string) => {
    setChecklist(prev => 
      prev.includes(item) ? prev.filter(i => i !== item) : [...prev, item]
    );
  };

  if (!biData) return null;

  const daysLabels = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'];
  const hoursLabels = Array.from({ length: 24 }, (_, i) => `${i}h`);

  const SentimentCloud = ({ words, color }: { words: string[], color: string }) => (
    <div className="flex flex-wrap gap-2 justify-center items-center">
      {words.map((w, idx) => {
        const size = Math.floor(Math.random() * (24 - 12 + 1)) + 12;
        const opacity = (Math.random() * 0.6) + 0.4;
        return (
          <span 
            key={idx} 
            className={`font-black uppercase tracking-tighter cursor-default transition-all hover:scale-110 ${color}`}
            style={{ fontSize: `${size}px`, opacity }}
          >
            {w}
          </span>
        );
      })}
    </div>
  );

  const getHeatmapColor = (value: number) => {
    if (value === 0) return 'bg-slate-50';
    if (value < 2) return 'bg-orange-100';
    if (value < 5) return 'bg-orange-300';
    if (value < 8) return 'bg-orange-500';
    return 'bg-red-600';
  };

  return (
    <div className="space-y-8 pb-20 animate-in fade-in duration-700 print:p-0 print:space-y-4">
      {/* Filters (Hidden on Print) */}
      <div className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm flex flex-wrap gap-4 items-center print:hidden">
         <div className="flex items-center gap-2 bg-slate-50 px-4 py-2 rounded-2xl border border-slate-100">
            <Calendar className="w-4 h-4 text-slate-400" />
