                <div className="flex items-center gap-3">
                   <ListChecks className="w-6 h-6 text-accent" />
                   <h3 className="text-xl font-black">Plano de Ação</h3>
                </div>
                <div className="flex-1 space-y-4">
                   {aiInsights.actionPlan.map((step, idx) => (
                     <button 
                       key={idx}
                       onClick={() => toggleChecklist(step)}
                       className={`w-full flex items-start gap-4 p-4 rounded-2xl border transition-all text-left group ${
                         checklist.includes(step) ? 'bg-emerald-500/10 border-emerald-500/40 opacity-50' : 'bg-white/5 border-white/10 hover:bg-white/10'
                       }`}
                     >
                        <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center flex-shrink-0 transition-all ${
                          checklist.includes(step) ? 'bg-emerald-500 border-emerald-500' : 'border-white/20'
                        }`}>
                           {checklist.includes(step) && <CheckCircle2 className="w-4 h-4" />}
                        </div>
                        <span className={`text-xs font-bold ${checklist.includes(step) ? 'line-through' : ''}`}>{step}</span>
                     </button>
                   ))}
                </div>
                <div className="p-6 bg-white/5 rounded-[2rem] border border-white/5">
                   <p className="text-[10px] font-black uppercase text-white/40 tracking-widest mb-2">Progresso da Semana</p>
                   <div className="flex items-center gap-4">
                      <div className="h-2 flex-1 bg-white/10 rounded-full overflow-hidden">
                         <div className="h-full bg-accent transition-all duration-1000" style={{ width: `${(checklist.length / aiInsights.actionPlan.length) * 100}%` }}></div>
                      </div>
                      <span className="text-xs font-black">{Math.round((checklist.length / aiInsights.actionPlan.length) * 100)}%</span>
                   </div>
                </div>
             </div>

             {/* Actionable Suggestions (Detailed) */}
             <div className="lg:col-span-12 grid grid-cols-1 md:grid-cols-3 gap-8">
                {aiInsights.actionableSuggestions.map((suggestion, idx) => (
                  <div key={idx} className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm space-y-4 hover:shadow-xl transition-all group">
                     <div className="flex justify-between items-start">
                        <div className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${
                          suggestion.impact === 'HIGH' ? 'bg-red-50 text-red-500' :
                          suggestion.impact === 'MEDIUM' ? 'bg-amber-50 text-amber-500' : 'bg-slate-50 text-slate-400'
