                        <ArrowRight className="w-5 h-5 text-slate-200 group-hover:text-primary transition-all group-hover:translate-x-1" />
                     </div>
                     <h4 className="text-lg font-black text-slate-900 leading-tight">{suggestion.title}</h4>
                     <p className="text-sm text-slate-400 font-medium leading-relaxed">{suggestion.description}</p>
                  </div>
                ))}
             </div>

             <div className="lg:col-span-12 flex justify-center">
                <button 
                  onClick={generateAIInsights}
                  className="text-[10px] font-black uppercase text-slate-300 tracking-[0.2em] flex items-center gap-2 hover:text-primary transition-all cursor-pointer"
                >
                   <Sparkles className="w-4 h-4" /> Recalcular Insights com Dados Frescos
                </button>
             </div>
          </div>
        )}
      </section>

      {/* CHAT DRAWER */}
      {isChatOpen && (
        <div className="fixed inset-0 z-[250] flex justify-end">
           <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsChatOpen(false)}></div>
           <div className="relative w-full max-w-lg bg-white shadow-2xl flex flex-col animate-in slide-in-from-right duration-500">
              <div className="bg-[#002e6b] text-white p-6 flex items-center justify-between">
                 <div className="flex items-center gap-3">
                    <div className="w-12 h-12 bg-white/10 rounded-2xl flex items-center justify-center border border-white/20">
                       <Bot className="w-6 h-6 text-accent" />
                    </div>
                    <div>
                       <h3 className="text-lg font-black tracking-tight leading-none">Consultor Ativare</h3>
                       <p className="text-[10px] font-bold text-white/50 uppercase tracking-widest mt-1">Especialista em Experiência</p>
