                 </div>
                 <button onClick={() => setIsChatOpen(false)} className="p-2 hover:bg-white/10 rounded-xl transition-all cursor-pointer">
                    <X className="w-6 h-6" />
                 </button>
              </div>

              <div className="flex-1 overflow-y-auto p-6 space-y-6" ref={chatScrollRef}>
                 {chatMessages.length === 0 && (
                   <div className="h-full flex flex-col items-center justify-center text-center p-8 space-y-4">
                      <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center text-slate-300">
                         <MessageSquare className="w-8 h-8" />
                      </div>
                      <p className="text-sm font-bold text-slate-400 uppercase tracking-widest">Inicie uma conversa estratégica</p>
                      <p className="text-xs text-slate-400">Pergunte sobre pontos específicos do seu atendimento ou peça sugestões de treinamento.</p>
                      <div className="grid grid-cols-1 gap-2 w-full pt-6">
