                            onClick={() => { setInputMessage(q); setTimeout(() => handleSendMessage(), 100); }}
                            className="p-3 text-[10px] font-black uppercase text-primary border border-primary/20 rounded-xl bg-primary/5 hover:bg-primary/10 transition-all text-left cursor-pointer"
                           >
                              {q}
                           </button>
                         ))}
                      </div>
