                 <div className="mt-3 flex items-center gap-1.5 text-[8px] font-black text-slate-300 uppercase tracking-widest justify-center">
                    <ShieldCheck className="w-3 h-3" /> Acesso Seguro • Apenas dados de {company?.name}
                 </div>
