      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 print:grid-cols-1">
        {/* Trend Section */}
        <div className="lg:col-span-8 bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm print:shadow-none print:border-slate-200">
           <div className="flex justify-between items-center mb-10">
