           <div className="space-y-6">
              {biData.impacts.map(i => (
                 <div key={i.category} className="space-y-3">
                    <div className="flex justify-between items-end">
                       <span className="text-sm font-black text-slate-700">{i.category}</span>
                       <div className="text-right">
                          <span className="text-[10px] font-black uppercase text-red-400 block">Impacto no Score</span>
