import React, { useState, useEffect, useRef } from 'react';
import { User, UserRole, Company, JobTitle } from './types';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import CaseManagement from './components/CaseManagement';
import FeedbackForm from './components/FeedbackForm';
import Feedbacks from './components/Feedbacks';
import Customers from './components/Customers';
import InternalFormConfig from './components/InternalFormConfig';
import InternalMetrics from './components/InternalMetrics';
import CompanyProfile from './components/CompanyProfile';
import UserProfile from './components/UserProfile';
import UsersTeam from './components/UsersTeam';
import AccountBilling from './components/AccountBilling';
import Benchmarking from './components/Benchmarking';
import BI from './components/BI';
import LandingPage from './components/LandingPage'; // Importação da nova Landing Page
import { 
  LogIn, 
  ShieldAlert, 
  Rocket, 
  Store, 
  ChevronLeft, 
  ChevronRight, 
  QrCode, 
  Search, 
  User as UserIcon,
  Camera,
  Briefcase,
  Smartphone,
  Mail,
  FileText,
  MapPin,
  Users,
  Lock,
  ArrowLeft
} from 'lucide-react';
import { dataStore } from './services/dataStore';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedCompanyId, setSelectedCompanyId] = useState<string>('');

  // View States
  const [view, setView] = useState<'LANDING' | 'AUTH' | 'APP'>('LANDING');
  const [authView, setAuthView] = useState<'LOGIN' | 'REGISTER'>('LOGIN');

  // Public Routing States
  const [isPublicForm, setIsPublicForm] = useState(false);
  const [trackingCodeInput, setTrackingCodeInput] = useState('');
  const [publicCompany, setPublicCompany] = useState<Company | null>(null);
  const [publicError, setPublicError] = useState('');
  const [isRouting, setIsRouting] = useState(false);

  // Auth Form States
  const [loginEmail, setLoginEmail] = useState('');
  const [loginPass, setLoginPass] = useState('');
  const [error, setError] = useState('');

  // Registration & Onboarding Flow
  const [onboardingStep, setOnboardingStep] = useState(1); 
  const [regEmail, setRegEmail] = useState('');
  const [regPass, setRegPass] = useState('');
  const [regPassConfirm, setRegPassConfirm] = useState('');

  const [onboardingCompany, setOnboardingCompany] = useState<Partial<Company>>({ category: 'Restaurante' });
  const [onboardingUser, setOnboardingUser] = useState<Partial<User>>({ jobTitle: 'Dono' });

  const [hasDetractorAlert, setHasDetractorAlert] = useState(false);

  useEffect(() => {
    if (user) {
      setView('APP');
      if (user.role === UserRole.MASTER) {
        setSelectedCompanyId(dataStore.getAllCompanies()[0]?.id || '');
      } else if (user.companyId) {
        setSelectedCompanyId(user.companyId);
      }
    } else {
      // Se deslogar, volta para landing
      if (view === 'APP') setView('LANDING');
    }
  }, [user]);

  const handleFeedbackSubmitted = () => {
    setIsPublicForm(false);
    setPublicCompany(null);
    setTrackingCodeInput('');
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const authenticatedUser = dataStore.authenticate(loginEmail, loginPass);
    if (authenticatedUser) {
      setUser(authenticatedUser);
      setError('');
    } else {
      setError('Credenciais inválidas. Verifique e-mail e senha.');
    }
  };

  const handleCreateAccount = (e: React.FormEvent) => {
    e.preventDefault();
    if (regPass !== regPassConfirm) {
      setError('As senhas não conferem.');
      return;
    }
    const newUser = dataStore.registerAccount(regEmail, regPass);
    setUser(newUser);
    setError('');
  };

  const handleCompleteOnboarding = (e: React.FormEvent) => {
    e.preventDefault();
    if (onboardingStep === 1) {
      setOnboardingStep(2);
      return;
    }

    if (user) {
      const result = dataStore.completeOnboarding(user.id, onboardingCompany, onboardingUser);
      if (result) {
        setUser(result.user);
        setSelectedCompanyId(result.company.id);
      }
    }
  };

  const handleTrackingCodeSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsRouting(true);
    setPublicError('');

    setTimeout(() => {
      const company = dataStore.getCompanyByTrackingCode(trackingCodeInput);
      if (company) {
        setPublicCompany(company);
        setIsRouting(false);
      } else {
        setPublicError('Código não encontrado. Verifique o código de 6 dígitos.');
        setIsRouting(false);
      }
    }, 800);
  };

  // Public Form View
  if (isPublicForm) {
    if (!publicCompany) {
      return (
        <div className="min-h-screen bg-[#001529] flex items-center justify-center p-6 font-inter text-slate-900">
          <div className="max-w-md w-full bg-white rounded-[3.5rem] shadow-2xl p-12 text-center animate-in zoom-in duration-500 border border-white/10">
             <div className="w-24 h-24 bg-primary/5 text-primary rounded-[2.5rem] flex items-center justify-center mx-auto mb-8 shadow-inner">
               <QrCode className={`w-12 h-12 ${isRouting ? 'animate-pulse' : ''}`} />
             </div>
             <h2 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Portal Ativare</h2>
             <p className="text-slate-400 font-medium mb-10 text-sm">Insira o código público de 6 dígitos para avaliar.</p>
             <form onSubmit={handleTrackingCodeSubmit} className="space-y-8">
                <input 
                  type="text" 
                  maxLength={6}
                  disabled={isRouting}
                  value={trackingCodeInput}
                  onChange={(e) => setTrackingCodeInput(e.target.value.toUpperCase())}
                  placeholder="ABC123"
                  className="w-full p-8 bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] outline-none focus:border-primary text-center text-4xl font-black tracking-[0.4em] text-primary transition-all uppercase"
                />
                {publicError && <p className="text-red-500 text-xs font-bold uppercase">{publicError}</p>}
                <button type="submit" disabled={trackingCodeInput.length < 6 || isRouting} className="w-full py-6 bg-primary text-white font-black rounded-[2rem] shadow-2xl shadow-primary/30 transition-all disabled:opacity-20 uppercase tracking-widest text-xs cursor-pointer">
                  {isRouting ? 'Localizando...' : 'Carregar Avaliação'}
                </button>
             </form>
             <button onClick={() => setIsPublicForm(false)} className="mt-12 text-slate-300 font-black text-[10px] uppercase tracking-[0.2em] flex items-center justify-center gap-2 mx-auto cursor-pointer">
                <ChevronLeft className="w-4 h-4" /> Voltar
              </button>
          </div>
        </div>
      );
    }
    return <FeedbackForm company={publicCompany} onFinished={handleFeedbackSubmitted} onBack={() => { setIsPublicForm(false); setPublicCompany(null); }} />;
  }

  // Landing Page View
  if (view === 'LANDING') {
    return <LandingPage onNavigate={(v) => { setAuthView(v); setView('AUTH'); }} />;
  }

