                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">Cargo</label>
                    <select required value={onboardingUser.jobTitle} onChange={e => setOnboardingUser({...onboardingUser, jobTitle: e.target.value as JobTitle})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900">
                      <option value="Dono">Dono</option>
                      <option value="Gerente">Gerente</option>
                      <option value="Sub-gerente">Sub-gerente</option>
                    </select>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">WhatsApp Pessoal</label>
                    <input required type="tel" value={onboardingUser.phone || ''} onChange={e => setOnboardingUser({...onboardingUser, phone: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">E-mail de Contato</label>
                    <input required type="email" value={onboardingUser.email || ''} onChange={e => setOnboardingUser({...onboardingUser, email: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" />
                  </div>
                </div>

                <div className="flex gap-4">
                  <button type="button" onClick={() => setOnboardingStep(1)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black rounded-3xl text-xs uppercase cursor-pointer">Voltar</button>
                  <button type="submit" className="flex-[2] py-5 bg-emerald-500 text-white font-black rounded-3xl shadow-xl flex items-center justify-center gap-2 uppercase tracking-widest text-xs cursor-pointer">
                    Concluir Onboarding <Rocket className="w-4 h-4" />
                  </button>
                </div>
              </div>
            )}
          </form>
        </div>
      </div>
    );
  }

  // Final App Render
  return (
    <Layout 
      user={user!} 
      onLogout={() => { setUser(null); setView('LANDING'); }} 
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
      selectedCompanyId={selectedCompanyId}
      setSelectedCompanyId={setSelectedCompanyId}
      hasDetractorAlert={hasDetractorAlert}
    >
      {activeTab === 'dashboard' && <Dashboard companyId={selectedCompanyId} />}
      {activeTab === 'cases' && <CaseManagement companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'feedbacks' && <Feedbacks companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'customers' && <Customers companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'form_config' && <InternalFormConfig companyId={selectedCompanyId} />}
      {activeTab === 'internal_metrics' && <InternalMetrics companyId={selectedCompanyId} />}
      {activeTab === 'company_profile' && <CompanyProfile companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'my_profile' && <UserProfile user={user!} onUpdate={(updated) => setUser(updated)} />}
      {activeTab === 'users_team' && <UsersTeam companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'my_account' && <AccountBilling companyId={selectedCompanyId} />}
      {activeTab === 'benchmarking' && <Benchmarking companyId={selectedCompanyId} />}
      {activeTab === 'bi' && <BI companyId={selectedCompanyId} />}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { User, UserRole, Company, JobTitle } from './types';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import CaseManagement from './components/CaseManagement';
import FeedbackForm from './components/FeedbackForm';
import Feedbacks from './components/Feedbacks';
import Customers from './components/Customers';
import InternalFormConfig from './components/InternalFormConfig';
import InternalMetrics from './components/InternalMetrics';
import CompanyProfile from './components/CompanyProfile';
import UserProfile from './components/UserProfile';
import UsersTeam from './components/UsersTeam';
import AccountBilling from './components/AccountBilling';
import Benchmarking from './components/Benchmarking';
import BI from './components/BI';
import LandingPage from './components/LandingPage';
import { 
  LogIn, 
  ShieldAlert, 
  Rocket, 
  Store, 
  ChevronLeft, 
  ChevronRight, 
  QrCode, 
  Search, 
  User as UserIcon,
  Camera,
  Briefcase,
  Smartphone,
  Mail,
  FileText,
  MapPin,
  Users,
  Lock,
  ArrowLeft
} from 'lucide-react';
import { dataStore } from './services/dataStore';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedCompanyId, setSelectedCompanyId] = useState<string>('');

  // View States
  const [view, setView] = useState<'LANDING' | 'AUTH' | 'APP'>('LANDING');
  const [authView, setAuthView] = useState<'LOGIN' | 'REGISTER'>('LOGIN');

  // Public Routing States
  const [isPublicForm, setIsPublicForm] = useState(false);
  const [trackingCodeInput, setTrackingCodeInput] = useState('');
  const [publicCompany, setPublicCompany] = useState<Company | null>(null);
  const [publicError, setPublicError] = useState('');
  const [isRouting, setIsRouting] = useState(false);

  // Auth Form States
  const [loginEmail, setLoginEmail] = useState('');
  const [loginPass, setLoginPass] = useState('');
  const [error, setError] = useState('');

  // Registration & Onboarding Flow
  const [onboardingStep, setOnboardingStep] = useState(1); 
  const [regEmail, setRegEmail] = useState('');
  const [regPass, setRegPass] = useState('');
  const [regPassConfirm, setRegPassConfirm] = useState('');

  const [onboardingCompany, setOnboardingCompany] = useState<Partial<Company>>({ category: 'Restaurante' });
  const [onboardingUser, setOnboardingUser] = useState<Partial<User>>({ jobTitle: 'Dono' });

  const [hasDetractorAlert, setHasDetractorAlert] = useState(false);

  useEffect(() => {
    if (user) {
      setView('APP');
      if (user.role === UserRole.MASTER) {
        setSelectedCompanyId(dataStore.getAllCompanies()[0]?.id || '');
      } else if (user.companyId) {
        setSelectedCompanyId(user.companyId);
      }
    }
  }, [user]);

  const handleLogout = () => {
    // Limpeza completa de sessão
    setUser(null);
    setLoginEmail('');
    setLoginPass('');
    setError('');
    // Redirecionamento obrigatório para Login
    setAuthView('LOGIN');
    setView('AUTH');
  };

  const handleFeedbackSubmitted = () => {
    setIsPublicForm(false);
    setPublicCompany(null);
    setTrackingCodeInput('');
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const authenticatedUser = dataStore.authenticate(loginEmail, loginPass);
    if (authenticatedUser) {
      setUser(authenticatedUser);
      setError('');
    } else {
      setError('Credenciais inválidas. Verifique e-mail e senha.');
    }
  };

  const handleCreateAccount = (e: React.FormEvent) => {
    e.preventDefault();
    if (regPass !== regPassConfirm) {
      setError('As senhas não conferem.');
      return;
    }
    const newUser = dataStore.registerAccount(regEmail, regPass);
    setUser(newUser);
    setError('');
  };

  const handleCompleteOnboarding = (e: React.FormEvent) => {
    e.preventDefault();
    if (onboardingStep === 1) {
      setOnboardingStep(2);
      return;
    }

    if (user) {
      const result = dataStore.completeOnboarding(user.id, onboardingCompany, onboardingUser);
      if (result) {
        setUser(result.user);
        setSelectedCompanyId(result.company.id);
      }
    }
  };

  const handleTrackingCodeSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsRouting(true);
    setPublicError('');

    setTimeout(() => {
      const company = dataStore.getCompanyByTrackingCode(trackingCodeInput);
      if (company) {
        setPublicCompany(company);
        setIsRouting(false);
      } else {
        setPublicError('Código não encontrado. Verifique o código de 6 dígitos.');
        setIsRouting(false);
      }
    }, 800);
  };

  // Public Form View
  if (isPublicForm) {
    if (!publicCompany) {
      return (
        <div className="min-h-screen bg-[#001529] flex items-center justify-center p-6 font-inter text-slate-900">
          <div className="max-w-md w-full bg-white rounded-[3.5rem] shadow-2xl p-12 text-center animate-in zoom-in duration-500 border border-white/10">
             <div className="w-24 h-24 bg-primary/5 text-primary rounded-[2.5rem] flex items-center justify-center mx-auto mb-8 shadow-inner">
               <QrCode className={`w-12 h-12 ${isRouting ? 'animate-pulse' : ''}`} />
             </div>
             <h2 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Portal Ativare</h2>
             <p className="text-slate-400 font-medium mb-10 text-sm">Insira o código público de 6 dígitos para avaliar.</p>
             <form onSubmit={handleTrackingCodeSubmit} className="space-y-8">
                <input 
                  type="text" 
                  maxLength={6}
                  disabled={isRouting}
                  value={trackingCodeInput}
                  onChange={(e) => setTrackingCodeInput(e.target.value.toUpperCase())}
                  placeholder="ABC123"
                  className="w-full p-8 bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] outline-none focus:border-primary text-center text-4xl font-black tracking-[0.4em] text-primary transition-all uppercase"
                />
                {publicError && <p className="text-red-500 text-xs font-bold uppercase">{publicError}</p>}
                <button type="submit" disabled={trackingCodeInput.length < 6 || isRouting} className="w-full py-6 bg-primary text-white font-black rounded-[2rem] shadow-2xl shadow-primary/30 transition-all disabled:opacity-20 uppercase tracking-widest text-xs cursor-pointer">
                  {isRouting ? 'Localizando...' : 'Carregar Avaliação'}
                </button>
             </form>
             <button onClick={() => setIsPublicForm(false)} className="mt-12 text-slate-300 font-black text-[10px] uppercase tracking-[0.2em] flex items-center justify-center gap-2 mx-auto cursor-pointer">
                <ChevronLeft className="w-4 h-4" /> Voltar
              </button>
          </div>
        </div>
      );
    }
    return <FeedbackForm company={publicCompany} onFinished={handleFeedbackSubmitted} onBack={() => { setIsPublicForm(false); setPublicCompany(null); }} />;
  }

  // Landing Page View
  if (view === 'LANDING') {
    return <LandingPage onNavigate={(v) => { setAuthView(v); setView('AUTH'); }} />;
  }

  // Auth View
  if (view === 'AUTH' && !user) {
    return (
      <div className="min-h-screen bg-[#f1f5f9] flex flex-col items-center justify-center p-6 font-inter text-slate-900">
        <button 
          onClick={() => setView('LANDING')}
          className="mb-8 group flex items-center gap-3 bg-white px-6 py-3 rounded-2xl shadow-sm border border-slate-200 text-slate-500 hover:text-primary hover:border-primary transition-all cursor-pointer font-bold text-xs uppercase tracking-widest"
        >
          <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-transform" />
          Voltar para o site
        </button>

        <div className="max-w-xl w-full">
          <div className="text-center mb-10">
            <div className="w-16 h-16 bg-primary rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-xl shadow-primary/30">
              <span className="text-3xl font-black text-white italic">A</span>
            </div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tight">Ativare <span className="text-primary">Experience</span></h1>
          </div>

          <div className="bg-white rounded-[3rem] shadow-2xl overflow-hidden border border-white">
            <div className="flex border-b border-slate-100">
              <button onClick={() => {setAuthView('LOGIN'); setError('');}} className={`flex-1 py-6 text-[10px] font-black uppercase tracking-[0.2em] transition-all cursor-pointer ${authView === 'LOGIN' ? 'text-primary bg-white' : 'text-slate-300 bg-slate-50'}`}>Login</button>
              <button onClick={() => {setAuthView('REGISTER'); setError('');}} className={`flex-1 py-6 text-[10px] font-black uppercase tracking-[0.2em] transition-all cursor-pointer ${authView === 'REGISTER' ? 'text-primary bg-white' : 'text-slate-300 bg-slate-50'}`}>Criar Conta</button>
            </div>

            <div className="p-10">
              {authView === 'LOGIN' ? (
                <form onSubmit={handleLogin} className="space-y-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">E-mail</label>
                    <input type="email" value={loginEmail} onChange={(e) => setLoginEmail(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl outline-none focus:border-primary transition-all text-sm font-bold text-slate-900" placeholder="seu@email.com" required />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Senha</label>
                    <input type="password" value={loginPass} onChange={(e) => setLoginPass(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl outline-none focus:border-primary transition-all text-sm font-bold text-slate-900" placeholder="••••••••" required />
                  </div>
                  {error && <p className="text-red-500 text-xs font-bold uppercase">{error}</p>}
                  <button type="submit" className="w-full py-5 bg-primary text-white font-black rounded-3xl shadow-xl transition-all uppercase tracking-widest text-xs cursor-pointer">Entrar no Sistema</button>
                  <div className="pt-6 border-t border-slate-50 flex flex-col items-center gap-4">
                    <p className="text-[9px] font-black text-slate-300 uppercase tracking-[0.2em]">Acesso Rápido para Testes (Senha: 123)</p>
                    <div className="flex gap-2">
                      <button type="button" onClick={() => { setLoginEmail('master@ativare.com'); setLoginPass('123'); }} className="px-4 py-2 bg-slate-100 text-[9px] font-black uppercase rounded-xl text-slate-500 hover:bg-slate-200 cursor-pointer">Master</button>
                      <button type="button" onClick={() => { setLoginEmail('dono@pizza.com'); setLoginPass('123'); }} className="px-4 py-2 bg-slate-100 text-[9px] font-black uppercase rounded-xl text-slate-500 hover:bg-slate-200 cursor-pointer">Business</button>
                    </div>
                  </div>
                </form>
              ) : (
                <form onSubmit={handleCreateAccount} className="space-y-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">E-mail Principal</label>
                    <input type="email" value={regEmail} onChange={(e) => setRegEmail(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl outline-none focus:border-primary font-bold text-slate-900" required />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Senha</label>
                    <input type="password" value={regPass} onChange={(e) => setRegPass(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl outline-none focus:border-primary font-bold text-slate-900" required />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Confirmar Senha</label>
                    <input type="password" value={regPassConfirm} onChange={(e) => setRegPassConfirm(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl outline-none focus:border-primary font-bold text-slate-900" required />
                  </div>
                  {error && <p className="text-red-500 text-xs font-bold uppercase">{error}</p>}
                  <button type="submit" className="w-full py-5 bg-primary text-white font-black rounded-3xl shadow-xl transition-all uppercase tracking-widest text-xs cursor-pointer">Criar Minha Conta</button>
                </form>
              )}
            </div>
            <div className="bg-slate-50 p-6 flex justify-center border-t border-slate-100">
              <button onClick={() => setIsPublicForm(true)} className="flex items-center gap-2 text-primary font-black text-[10px] uppercase tracking-widest hover:underline cursor-pointer">
                <Search className="w-4 h-4" /> Avaliar com Código Público
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  const selectedCompany = dataStore.getCompany(selectedCompanyId);

  // Mandatory Onboarding Flow
  if (user && !user.isOnboarded && user.role !== UserRole.MASTER) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 font-inter text-slate-900">
        <div className="max-w-2xl w-full bg-white rounded-[3rem] shadow-2xl overflow-hidden border border-white">
          <div className="bg-primary p-12 text-white">
             <div className="flex items-center justify-between mb-8">
                <h2 className="text-2xl font-black uppercase tracking-tight">Onboarding Ativare</h2>
                <span className="bg-white/10 px-4 py-1 rounded-full text-[10px] font-black uppercase tracking-widest">Passo {onboardingStep}/2</span>
             </div>
             <p className="text-white/70 font-medium">Precisamos configurar os dados do seu negócio e do responsável antes de começar.</p>
          </div>

          <form onSubmit={handleCompleteOnboarding} className="p-12 space-y-8 animate-in slide-in-from-bottom duration-500">
            {onboardingStep === 1 ? (
              <div className="space-y-6">
                <div className="flex items-center gap-3 mb-6">
                   <div className="p-3 bg-slate-100 rounded-2xl text-primary"><Store className="w-6 h-6" /></div>
                   <h3 className="text-lg font-black text-slate-900 uppercase">Dados do Negócio</h3>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">Nome do Negócio</label>
                    <input required type="text" value={onboardingCompany.name || ''} onChange={e => setOnboardingCompany({...onboardingCompany, name: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" placeholder="Ex: Pizzaria Bella Italia" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">Categoria</label>
                    <select required value={onboardingCompany.category} onChange={e => setOnboardingCompany({...onboardingCompany, category: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900">
                      <option>Restaurante</option>
                      <option>Hamburgueria</option>
                      <option>Pizzaria</option>
                      <option>Bar / Pub</option>
                    </select>
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-slate-400">Breve Descrição</label>
                  <textarea required value={onboardingCompany.description || ''} onChange={e => setOnboardingCompany({...onboardingCompany, description: e.target.value})} className="w-full h-24 p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-medium text-slate-900 text-sm" placeholder="Fale um pouco sobre seu estabelecimento..." />
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">Endereço</label>
                    <input required type="text" value={onboardingCompany.address || ''} onChange={e => setOnboardingCompany({...onboardingCompany, address: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">Cidade</label>
                    <input required type="text" value={onboardingCompany.city || ''} onChange={e => setOnboardingCompany({...onboardingCompany, city: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" />
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">Telefone Comercial</label>
                    <input required type="tel" value={onboardingCompany.phone || ''} onChange={e => setOnboardingCompany({...onboardingCompany, phone: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">E-mail Comercial</label>
                    <input required type="email" value={onboardingCompany.email || ''} onChange={e => setOnboardingCompany({...onboardingCompany, email: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" />
                  </div>
                </div>

                <button type="submit" className="w-full py-5 bg-primary text-white font-black rounded-3xl shadow-xl flex items-center justify-center gap-2 uppercase tracking-widest text-xs cursor-pointer">
                  Próxima Etapa <ChevronRight className="w-4 h-4" />
                </button>
              </div>
            ) : (
              <div className="space-y-6">
                <div className="flex items-center gap-3 mb-6">
                   <div className="p-3 bg-slate-100 rounded-2xl text-primary"><UserIcon className="w-6 h-6" /></div>
                   <h3 className="text-lg font-black text-slate-900 uppercase">Pessoa Responsável</h3>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">Nome Completo</label>
                    <input required type="text" value={onboardingUser.name || ''} onChange={e => setOnboardingUser({...onboardingUser, name: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">Cargo</label>
                    <select required value={onboardingUser.jobTitle} onChange={e => setOnboardingUser({...onboardingUser, jobTitle: e.target.value as JobTitle})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900">
                      <option value="Dono">Dono</option>
                      <option value="Gerente">Gerente</option>
                      <option value="Sub-gerente">Sub-gerente</option>
                    </select>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">WhatsApp Pessoal</label>
                    <input required type="tel" value={onboardingUser.phone || ''} onChange={e => setOnboardingUser({...onboardingUser, phone: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">E-mail de Contato</label>
                    <input required type="email" value={onboardingUser.email || ''} onChange={e => setOnboardingUser({...onboardingUser, email: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" />
                  </div>
                </div>

                <div className="flex gap-4">
                  <button type="button" onClick={() => setOnboardingStep(1)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black rounded-3xl text-xs uppercase cursor-pointer">Voltar</button>
                  <button type="submit" className="flex-[2] py-5 bg-emerald-500 text-white font-black rounded-3xl shadow-xl flex items-center justify-center gap-2 uppercase tracking-widest text-xs cursor-pointer">
                    Concluir Onboarding <Rocket className="w-4 h-4" />
                  </button>
                </div>
              </div>
            )}
          </form>
        </div>
      </div>
    );
  }

  // Final App Render
  return (
    <Layout 
      user={user!} 
      onLogout={handleLogout} 
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
      selectedCompanyId={selectedCompanyId}
      setSelectedCompanyId={setSelectedCompanyId}
      hasDetractorAlert={hasDetractorAlert}
    >
      {activeTab === 'dashboard' && <Dashboard companyId={selectedCompanyId} />}
      {activeTab === 'cases' && <CaseManagement companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'feedbacks' && <Feedbacks companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'customers' && <Customers companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'form_config' && <InternalFormConfig companyId={selectedCompanyId} />}
      {activeTab === 'internal_metrics' && <InternalMetrics companyId={selectedCompanyId} />}
      {activeTab === 'company_profile' && <CompanyProfile companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'my_profile' && <UserProfile user={user!} onUpdate={(updated) => setUser(updated)} />}
      {activeTab === 'users_team' && <UsersTeam companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'my_account' && <AccountBilling companyId={selectedCompanyId} />}
      {activeTab === 'benchmarking' && <Benchmarking companyId={selectedCompanyId} />}
      {activeTab === 'bi' && <BI companyId={selectedCompanyId} />}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { User, UserRole, Company, JobTitle } from './types';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import CaseManagement from './components/CaseManagement';
import FeedbackForm from './components/FeedbackForm';
import Feedbacks from './components/Feedbacks';
import Customers from './components/Customers';
import InternalFormConfig from './components/InternalFormConfig';
import InternalMetrics from './components/InternalMetrics';
import CompanyProfile from './components/CompanyProfile';
import UserProfile from './components/UserProfile';
import UsersTeam from './components/UsersTeam';
import AccountBilling from './components/AccountBilling';
import Benchmarking from './components/Benchmarking';
import BI from './components/BI';
import LandingPage from './components/LandingPage';
import { 
  LogIn, 
  ShieldAlert, 
  Rocket, 
  Store, 
  ChevronLeft, 
  ChevronRight, 
  QrCode, 
  Search, 
  User as UserIcon,
  Camera,
  Briefcase,
  Smartphone,
  Mail,
  FileText,
  MapPin,
  Users,
  Lock,
  ArrowLeft
} from 'lucide-react';
import { dataStore } from './services/dataStore';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedCompanyId, setSelectedCompanyId] = useState<string>('');

  // View States
  const [view, setView] = useState<'LANDING' | 'AUTH' | 'APP'>('LANDING');
  const [authView, setAuthView] = useState<'LOGIN' | 'REGISTER'>('LOGIN');

  // Public Routing States
  const [isPublicForm, setIsPublicForm] = useState(false);
  const [trackingCodeInput, setTrackingCodeInput] = useState('');
  const [publicCompany, setPublicCompany] = useState<Company | null>(null);
  const [publicError, setPublicError] = useState('');
  const [isRouting, setIsRouting] = useState(false);

  // Auth Form States
  const [loginEmail, setLoginEmail] = useState('');
  const [loginPass, setLoginPass] = useState('');
  const [error, setError] = useState('');

  // Registration & Onboarding Flow
  const [onboardingStep, setOnboardingStep] = useState(1); 
  const [regEmail, setRegEmail] = useState('');
  const [regPass, setRegPass] = useState('');
  const [regPassConfirm, setRegPassConfirm] = useState('');

  const [onboardingCompany, setOnboardingCompany] = useState<Partial<Company>>({ category: 'Restaurante' });
  const [onboardingUser, setOnboardingUser] = useState<Partial<User>>({ jobTitle: 'Dono' });

  const [hasDetractorAlert, setHasDetractorAlert] = useState(false);

  useEffect(() => {
    if (user) {
      setView('APP');
      if (user.role === UserRole.MASTER) {
        setSelectedCompanyId(dataStore.getAllCompanies()[0]?.id || '');
      } else if (user.companyId) {
        setSelectedCompanyId(user.companyId);
      }
    }
  }, [user]);

  const handleLogout = () => {
    // 1. Limpeza completa de sessão
    setUser(null);
    setLoginEmail('');
    setLoginPass('');
    setError('');

    // 2. Redirecionamento obrigatório para tela de LOGIN (Auth view)
    // Conforme requisito: SITE → LOGIN → SAAS → SAIR → LOGIN
    setAuthView('LOGIN');
    setView('AUTH');
  };

  const handleFeedbackSubmitted = () => {
    setIsPublicForm(false);
    setPublicCompany(null);
    setTrackingCodeInput('');
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const authenticatedUser = dataStore.authenticate(loginEmail, loginPass);
    if (authenticatedUser) {
      setUser(authenticatedUser);
      setError('');
    } else {
      setError('Credenciais inválidas. Verifique e-mail e senha.');
    }
  };

  const handleCreateAccount = (e: React.FormEvent) => {
    e.preventDefault();
    if (regPass !== regPassConfirm) {
      setError('As senhas não conferem.');
      return;
    }
    const newUser = dataStore.registerAccount(regEmail, regPass);
    setUser(newUser);
    setError('');
  };

  const handleCompleteOnboarding = (e: React.FormEvent) => {
    e.preventDefault();
    if (onboardingStep === 1) {
      setOnboardingStep(2);
      return;
    }

    if (user) {
      const result = dataStore.completeOnboarding(user.id, onboardingCompany, onboardingUser);
      if (result) {
        setUser(result.user);
        setSelectedCompanyId(result.company.id);
      }
    }
  };

  const handleTrackingCodeSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsRouting(true);
    setPublicError('');

    setTimeout(() => {
      const company = dataStore.getCompanyByTrackingCode(trackingCodeInput);
      if (company) {
        setPublicCompany(company);
        setIsRouting(false);
      } else {
        setPublicError('Código não encontrado. Verifique o código de 6 dígitos.');
        setIsRouting(false);
      }
    }, 800);
  };

  // Public Form View
  if (isPublicForm) {
    if (!publicCompany) {
      return (
        <div className="min-h-screen bg-[#001529] flex items-center justify-center p-6 font-inter text-slate-900">
          <div className="max-w-md w-full bg-white rounded-[3.5rem] shadow-2xl p-12 text-center animate-in zoom-in duration-500 border border-white/10">
             <div className="w-24 h-24 bg-primary/5 text-primary rounded-[2.5rem] flex items-center justify-center mx-auto mb-8 shadow-inner">
               <QrCode className={`w-12 h-12 ${isRouting ? 'animate-pulse' : ''}`} />
             </div>
             <h2 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Portal Ativare</h2>
             <p className="text-slate-400 font-medium mb-10 text-sm">Insira o código público de 6 dígitos para avaliar.</p>
             <form onSubmit={handleTrackingCodeSubmit} className="space-y-8">
                <input 
                  type="text" 
                  maxLength={6}
                  disabled={isRouting}
                  value={trackingCodeInput}
                  onChange={(e) => setTrackingCodeInput(e.target.value.toUpperCase())}
                  placeholder="ABC123"
                  className="w-full p-8 bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] outline-none focus:border-primary text-center text-4xl font-black tracking-[0.4em] text-primary transition-all uppercase"
                />
                {publicError && <p className="text-red-500 text-xs font-bold uppercase">{publicError}</p>}
                <button type="submit" disabled={trackingCodeInput.length < 6 || isRouting} className="w-full py-6 bg-primary text-white font-black rounded-[2rem] shadow-2xl shadow-primary/30 transition-all disabled:opacity-20 uppercase tracking-widest text-xs cursor-pointer">
                  {isRouting ? 'Localizando...' : 'Carregar Avaliação'}
                </button>
             </form>
             <button onClick={() => setIsPublicForm(false)} className="mt-12 text-slate-300 font-black text-[10px] uppercase tracking-[0.2em] flex items-center justify-center gap-2 mx-auto cursor-pointer">
                <ChevronLeft className="w-4 h-4" /> Voltar
              </button>
          </div>
        </div>
      );
    }
    return <FeedbackForm company={publicCompany} onFinished={handleFeedbackSubmitted} onBack={() => { setIsPublicForm(false); setPublicCompany(null); }} />;
  }

  // Landing Page View
  if (view === 'LANDING') {
    return <LandingPage onNavigate={(v) => { setAuthView(v); setView('AUTH'); }} />;
  }

  // Auth View
  if (view === 'AUTH' && !user) {
    return (
      <div className="min-h-screen bg-[#f1f5f9] flex flex-col items-center justify-center p-6 font-inter text-slate-900">
        <div className="max-w-xl w-full">
          <div className="text-center mb-10">
            <div className="w-16 h-16 bg-primary rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-xl shadow-primary/30">
              <span className="text-3xl font-black text-white italic">A</span>
            </div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tight">Ativare <span className="text-primary">Experience</span></h1>
          </div>

          <div className="bg-white rounded-[3rem] shadow-2xl overflow-hidden border border-white">
            <div className="flex border-b border-slate-100">
              <button onClick={() => {setAuthView('LOGIN'); setError('');}} className={`flex-1 py-6 text-[10px] font-black uppercase tracking-[0.2em] transition-all cursor-pointer ${authView === 'LOGIN' ? 'text-primary bg-white' : 'text-slate-300 bg-slate-50'}`}>Login</button>
              <button onClick={() => {setAuthView('REGISTER'); setError('');}} className={`flex-1 py-6 text-[10px] font-black uppercase tracking-[0.2em] transition-all cursor-pointer ${authView === 'REGISTER' ? 'text-primary bg-white' : 'text-slate-300 bg-slate-50'}`}>Criar Conta</button>
            </div>

            <div className="p-10">
              {authView === 'LOGIN' ? (
                <form onSubmit={handleLogin} className="space-y-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">E-mail</label>
                    <input type="email" value={loginEmail} onChange={(e) => setLoginEmail(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl outline-none focus:border-primary transition-all text-sm font-bold text-slate-900" placeholder="seu@email.com" required />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Senha</label>
                    <input type="password" value={loginPass} onChange={(e) => setLoginPass(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl outline-none focus:border-primary transition-all text-sm font-bold text-slate-900" placeholder="••••••••" required />
                  </div>
                  {error && <p className="text-red-500 text-xs font-bold uppercase">{error}</p>}

                  <div className="space-y-4">
                    <button type="submit" className="w-full py-5 bg-primary text-white font-black rounded-3xl shadow-xl transition-all uppercase tracking-widest text-xs cursor-pointer hover:bg-[#003680]">
                      Entrar no Sistema
                    </button>

                    {/* Botão de retorno solicitado: abaixo do Entrar no Sistema */}
                    <button 
                      type="button"
                      onClick={() => setView('LANDING')}
                      className="w-full py-5 bg-white border border-slate-200 text-slate-400 font-black rounded-3xl transition-all uppercase tracking-widest text-xs cursor-pointer hover:text-primary hover:border-primary flex items-center justify-center gap-2"
                    >
                      <ArrowLeft className="w-4 h-4" /> Voltar para o site
                    </button>
                  </div>

                  <div className="pt-6 border-t border-slate-50 flex flex-col items-center gap-4">
                    <p className="text-[9px] font-black text-slate-300 uppercase tracking-[0.2em]">Acesso Rápido para Testes (Senha: 123)</p>
                    <div className="flex gap-2">
                      <button type="button" onClick={() => { setLoginEmail('master@ativare.com'); setLoginPass('123'); }} className="px-4 py-2 bg-slate-100 text-[9px] font-black uppercase rounded-xl text-slate-500 hover:bg-slate-200 cursor-pointer">Master</button>
                      <button type="button" onClick={() => { setLoginEmail('dono@pizza.com'); setLoginPass('123'); }} className="px-4 py-2 bg-slate-100 text-[9px] font-black uppercase rounded-xl text-slate-500 hover:bg-slate-200 cursor-pointer">Business</button>
                    </div>
                  </div>
                </form>
              ) : (
                <form onSubmit={handleCreateAccount} className="space-y-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">E-mail Principal</label>
                    <input type="email" value={regEmail} onChange={(e) => setRegEmail(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl outline-none focus:border-primary font-bold text-slate-900" required />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Senha</label>
                    <input type="password" value={regPass} onChange={(e) => setRegPass(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl outline-none focus:border-primary font-bold text-slate-900" required />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Confirmar Senha</label>
