                  </div>
                  {error && <p className="text-red-500 text-xs font-bold uppercase">{error}</p>}

                  <div className="space-y-4">
                    <button type="submit" className="w-full py-5 bg-primary text-white font-black rounded-3xl shadow-xl transition-all uppercase tracking-widest text-xs cursor-pointer hover:bg-[#003680]">
                      Criar Minha Conta
                    </button>
                    <button 
                      type="button"
                      onClick={() => setView('LANDING')}
                      className="w-full py-5 bg-white border border-slate-200 text-slate-400 font-black rounded-3xl transition-all uppercase tracking-widest text-xs cursor-pointer hover:text-primary hover:border-primary flex items-center justify-center gap-2"
                    >
                      <ArrowLeft className="w-4 h-4" /> Voltar para o site
                    </button>
                  </div>
                </form>
              )}
            </div>
            <div className="bg-slate-50 p-6 flex justify-center border-t border-slate-100">
              <button onClick={() => setIsPublicForm(true)} className="flex items-center gap-2 text-primary font-black text-[10px] uppercase tracking-widest hover:underline cursor-pointer">
                <Search className="w-4 h-4" /> Avaliar com Código Público
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  const selectedCompany = dataStore.getCompany(selectedCompanyId);

  // Mandatory Onboarding Flow
  if (user && !user.isOnboarded && user.role !== UserRole.MASTER) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 font-inter text-slate-900">
