                      <option>Hamburgueria</option>
                      <option>Pizzaria</option>
                      <option>Bar / Pub</option>
                    </select>
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-slate-400">Breve Descrição</label>
                  <textarea required value={onboardingCompany.description || ''} onChange={e => setOnboardingCompany({...onboardingCompany, description: e.target.value})} className="w-full h-24 p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-medium text-slate-900 text-sm" placeholder="Fale um pouco sobre seu estabelecimento..." />
