                    <label className="text-[10px] font-black uppercase text-slate-400">E-mail Comercial</label>
                    <input required type="email" value={onboardingCompany.email || ''} onChange={e => setOnboardingCompany({...onboardingCompany, email: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" />
                  </div>
                </div>

                <button type="submit" className="w-full py-5 bg-primary text-white font-black rounded-3xl shadow-xl flex items-center justify-center gap-2 uppercase tracking-widest text-xs cursor-pointer">
                  Próxima Etapa <ChevronRight className="w-4 h-4" />
                </button>
              </div>
            ) : (
