                    <label className="text-[10px] font-black uppercase text-slate-400">Nome Completo</label>
                    <input required type="text" value={onboardingUser.name || ''} onChange={e => setOnboardingUser({...onboardingUser, name: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">Cargo</label>
                    <select required value={onboardingUser.jobTitle} onChange={e => setOnboardingUser({...onboardingUser, jobTitle: e.target.value as JobTitle})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900">
                      <option value="Dono">Dono</option>
                      <option value="Gerente">Gerente</option>
                      <option value="Sub-gerente">Sub-gerente</option>
                    </select>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">WhatsApp Pessoal</label>
                    <input required type="tel" value={onboardingUser.phone || ''} onChange={e => setOnboardingUser({...onboardingUser, phone: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">E-mail de Contato</label>
                    <input required type="email" value={onboardingUser.email || ''} onChange={e => setOnboardingUser({...onboardingUser, email: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-primary font-bold text-slate-900" />
                  </div>
                </div>

                <div className="flex gap-4">
                  <button type="button" onClick={() => setOnboardingStep(1)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black rounded-3xl text-xs uppercase cursor-pointer">Voltar</button>
                  <button type="submit" className="flex-[2] py-5 bg-emerald-500 text-white font-black rounded-3xl shadow-xl flex items-center justify-center gap-2 uppercase tracking-widest text-xs cursor-pointer">
                    Concluir Onboarding <Rocket className="w-4 h-4" />
                  </button>
                </div>
              </div>
            )}
          </form>
        </div>
      </div>
    );
  }

  // Final App Render
  return (
    <Layout 
      user={user!} 
      onLogout={handleLogout} 
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
      selectedCompanyId={selectedCompanyId}
      setSelectedCompanyId={setSelectedCompanyId}
      hasDetractorAlert={hasDetractorAlert}
    >
      {activeTab === 'dashboard' && <Dashboard companyId={selectedCompanyId} />}
      {activeTab === 'cases' && <CaseManagement companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'feedbacks' && <Feedbacks companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'customers' && <Customers companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'form_config' && <InternalFormConfig companyId={selectedCompanyId} />}
      {activeTab === 'internal_metrics' && <InternalMetrics companyId={selectedCompanyId} />}
      {activeTab === 'company_profile' && <CompanyProfile companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'my_profile' && <UserProfile user={user!} onUpdate={(updated) => setUser(updated)} />}
      {activeTab === 'users_team' && <UsersTeam companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'my_account' && <AccountBilling companyId={selectedCompanyId} />}
      {activeTab === 'benchmarking' && <Benchmarking companyId={selectedCompanyId} />}
      {activeTab === 'bi' && <BI companyId={selectedCompanyId} />}
    </Layout>
  );
};

export default App;

