import { Feedback, Case, Customer, NPSCategory, InternalQuestion, InternalQuestionType, ContactLog, Company, User, UserRole, CNPJRequest, StaffRole, PlanType, AccountStatus, FeedbackChannel, Lead, JobTitle, LeadStage, LeadTemperature } from '../types';
import { MOCK_COMPANIES, MOCK_USERS } from '../constants';

class DataStore {
  private companies: Company[] = [...MOCK_COMPANIES.map(c => ({
    ...c,
    plan: 'PRO' as PlanType,
    status: 'ACTIVE' as AccountStatus,
    startDate: '2023-01-10T10:00:00Z',
    nextBillingDate: '2024-05-10T10:00:00Z',
    maxEvaluations: 500,
    maxUsers: 10,
    cnpj: '12.345.678/0001-99'
  }))];
  private users: User[] = [...MOCK_USERS];
  private leads: Lead[] = [];
  private feedbacks: Feedback[] = [];
  private cases: Case[] = [];
  private customers: Customer[] = [];
  private internalQuestions: InternalQuestion[] = [];

  constructor() {
    this.initMockData();
  }

  private generateUniqueTrackingCode(): string {
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
    let code = '';
    let isUnique = false;

    while (!isUnique) {
      code = '';
      for (let i = 0; i < 6; i++) {
        code += chars.charAt(Math.floor(Math.random() * chars.length));
      }
      isUnique = !this.companies.some(c => c.trackingCode === code);
    }

    return code;
  }

  private initMockData() {
    this.companies.forEach(comp => {
      const q1: InternalQuestion = {
        id: `q1-${comp.id}`,
        companyId: comp.id,
        text: comp.category === 'Pizzaria' ? 'A massa estava no ponto?' : 'O atendimento foi cordial?',
        type: 'YES_NO',
        required: true,
        active: true,
        isPublic: true,
        order: 1
      };
      this.internalQuestions.push(q1);

      const channels: FeedbackChannel[] = ['QR_CODE', 'DIRECT_LINK', 'MANUAL_CODE'];

      // Gerar feedbacks randômicos com variação de tempo para BI
      for (let i = 0; i < 40; i++) {
        const baseScore = (comp.experienceScore / 10) || 8;
        const randomVariance = () => (Math.random() * 3) - 1.5;

        const date = new Date();
        date.setDate(date.getDate() - Math.floor(Math.random() * 60));
        date.setHours(Math.floor(Math.random() * 24));
        date.setMinutes(Math.floor(Math.random() * 60));

        this.addFeedback({
          companyId: comp.id,
          companyTrackingCode: comp.trackingCode,
          customerId: `mock-${i}`,
          customerName: `Cliente Mock ${i}`,
          customerPhone: `(11) 9${Math.floor(10000000 + Math.random() * 90000000)}`,
          howKnown: 'Instagram',
          channel: channels[Math.floor(Math.random() * channels.length)],
          scores: {
            service: Math.max(1, Math.min(10, Math.round(baseScore + randomVariance()))),
            food: Math.max(1, Math.min(10, Math.round(baseScore + randomVariance()))),
            drinks: Math.max(1, Math.min(10, Math.round(baseScore + randomVariance()))),
            structure: Math.max(1, Math.min(10, Math.round(baseScore + randomVariance())))
          },
          profile: 'friends',
          observation: i % 5 === 0 ? 'O atendimento demorou um pouco, mas a comida estava ótima!' : 'Excelente experiência, recomendo!',
          email: `mock${i}@test.com`
        }, date.toISOString());
      }
    });

    // Mock initial leads for CRM
    this.addLead({
      name: 'Fabio Restauranteur',
      email: 'fabio@rest.com',
      phone: '(11) 98888-7777',
      jobTitle: 'Dono',
      companyName: 'Lê Garden Bistrô',
      companyPhone: '(11) 3333-4444',
      city: 'São Paulo',
      employees: '11-50',
      segment: 'Bistrô'
    });
  }

  authenticate(email: string, pass: string): User | null {
    const user = this.users.find(u => u.email === email);
    if (user && user.password === pass) {
      return user;
    }
    return null;
  }

  addLead(leadData: Partial<Lead>) {
    const newLead: Lead = {
      id: `lead-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
      name: leadData.name || '',
      email: leadData.email || '',
      phone: leadData.phone || '',
      jobTitle: leadData.jobTitle || '',
      companyName: leadData.companyName || '',
      companyPhone: leadData.companyPhone || '',
      city: leadData.city || '',
      employees: leadData.employees || '1-10',
      segment: leadData.segment || 'Geral',
      status: 'NEW',
      stage: 'LEAD',
      temperature: 'NEW',
      value: 0,
      forecast: '',
      tasks: [],
      history: [{
        id: `h-${Date.now()}`,
        text: 'Lead capturado via Landing Page.',
        type: 'STAGE_CHANGE',
        createdAt: new Date().toISOString(),
        userName: 'Sistema Ativare'
      }],
      files: [],
      createdAt: new Date().toISOString()
    };
    this.leads.unshift(newLead);
    return newLead;
  }

  getLeads() {
    return this.leads;
  }

  updateLead(id: string, data: Partial<Lead>, userName: string) {
    const idx = this.leads.findIndex(l => l.id === id);
    if (idx >= 0) {
      const oldStage = this.leads[idx].stage;
      this.leads[idx] = { ...this.leads[idx], ...data };

      if (data.stage && data.stage !== oldStage) {
        this.leads[idx].history.unshift({
          id: `h-${Date.now()}`,
          text: `Estágio alterado de ${oldStage} para ${data.stage}`,
          type: 'STAGE_CHANGE',
          createdAt: new Date().toISOString(),
          userName
        });
      }
      return this.leads[idx];
    }
    return null;
  }

  addLeadNote(id: string, text: string, userName: string) {
    const lead = this.leads.find(l => l.id === id);
    if (lead) {
      lead.history.unshift({
        id: `h-${Date.now()}`,
        text,
        type: 'NOTE',
        createdAt: new Date().toISOString(),
        userName
      });
    }
  }

  addLeadTask(id: string, title: string, dueDate: string) {
    const lead = this.leads.find(l => l.id === id);
    if (lead) {
      lead.tasks.push({
        id: `t-${Date.now()}`,
        title,
        dueDate,
        completed: false
      });
    }
  }

  toggleLeadTask(leadId: string, taskId: string) {
    const lead = this.leads.find(l => l.id === leadId);
    if (lead) {
      const task = lead.tasks.find(t => t.id === taskId);
      if (task) task.completed = !task.completed;
    }
  }

  // Novo método para o Master criar contas manualmente
  createAccountManual(companyData: Partial<Company>, userData: Partial<User>) {
    const companyId = `comp-${Date.now()}`;
    const trialEndDate = new Date();
    trialEndDate.setDate(trialEndDate.getDate() + 15);

    const newCompany: Company = {
      id: companyId,
      trackingCode: companyData.trackingCode || this.generateUniqueTrackingCode(),
      name: companyData.name || '',
      category: companyData.category || 'Restaurante',
      city: companyData.city || '',
      logo: companyData.logo || 'https://picsum.photos/seed/ativare/200',
      experienceScore: 0,
      cnpj: companyData.cnpj,
      address: companyData.address,
      employees: companyData.employees,
      phone: companyData.phone,
      plan: 'TRIAL',
      status: 'ACTIVE',
      maxEvaluations: 50,
      maxUsers: 3,
      trialEndDate: trialEndDate.toISOString(),
      startDate: new Date().toISOString()
    };

    const newUser: User = {
      id: `u-${Date.now()}`,
      name: userData.name || '',
      email: userData.email || '',
      password: userData.password || 'ativare123',
      role: UserRole.BUSINESS,
      staffRole: 'ADMIN',
      phone: userData.phone,
      jobTitle: userData.jobTitle || 'Dono',
      companyId: companyId,
      isOnboarded: true,
      createdAt: new Date().toISOString()
    };

    this.companies.push(newCompany);
    this.users.push(newUser);

    return { company: newCompany, user: newUser };
  }

  getCompany(id: string) {
    return this.companies.find(c => c.id === id);
  }

  getCompanyByTrackingCode(code: string) {
    return this.companies.find(c => c.trackingCode.toUpperCase() === code.toUpperCase());
  }

  getAllCompanies() {
    return this.companies;
  }

  updateCompany(id: string, data: Partial<Company>) {
    const idx = this.companies.findIndex(c => c.id === id);
    if (idx >= 0) {
      this.companies[idx] = { ...this.companies[idx], ...data };
      return this.companies[idx];
    }
    return null;
  }

  getCompanyUsers(companyId: string) {
    return this.users.filter(u => u.companyId === companyId);
  }

  addCompanyUser(companyId: string, userData: Partial<User>) {
    const newUser: User = {
      id: `u-${Date.now()}`,
      name: userData.name || 'Novo Usuário',
      email: userData.email || '',
      password: userData.password || 'ativare123',
      role: UserRole.USER,
      staffRole: userData.staffRole || 'AGENT',
      companyId,
      isOnboarded: true,
      createdAt: new Date().toISOString()
    };
    this.users.push(newUser);
    return newUser;
  }

  updateUser(id: string, data: Partial<User>) {
    const idx = this.users.findIndex(u => u.id === id);
    if (idx >= 0) {
      this.users[idx] = { ...this.users[idx], ...data };
      return this.users[idx];
    }
    return null;
  }

  updatePassword(userId: string, currentPass: string, newPass: string) {
    const user = this.users.find(u => u.id === userId);
    if (user && user.password === currentPass) {
      user.password = newPass;
      return true;
    }
    return false;
  }

  getInternalQuestions(companyId: string, onlyActive = true) {
    let qs = this.internalQuestions.filter(q => q.companyId === companyId);
    if (onlyActive) qs = qs.filter(q => q.active);
    return qs.sort((a, b) => a.order - b.order);
  }

  saveInternalQuestion(question: InternalQuestion) {
    const idx = this.internalQuestions.findIndex(q => q.id === question.id);
    if (idx >= 0) this.internalQuestions[idx] = question;
    else this.internalQuestions.push(question);
  }

  deleteInternalQuestion(id: string) {
    this.internalQuestions = this.internalQuestions.filter(q => q.id !== id);
  }

  getInternalMetrics(companyId: string) {
    const qs = this.getInternalQuestions(companyId, false);
    const fbs = this.getFeedbacks(companyId);
    return qs.map(q => {
      const responses = fbs.map(f => f.internalResponses?.[q.id]).filter(r => r !== undefined && r !== null);
      let avg: any = 0;
      if (q.type === 'SCALE_5' || q.type === 'SCALE_10') {
        avg = responses.length > 0 ? responses.reduce((acc: number, val: any) => acc + Number(val), 0) / responses.length : 0;
      } else if (q.type === 'YES_NO') {
        const yesCount = responses.filter(r => r === 'SIM').length;
        avg = responses.length > 0 ? (yesCount / responses.length) * 100 : 0;
      }
      return { questionId: q.id, text: q.text, type: q.type, totalResponses: responses.length, average: avg, responses: responses };
    });
  }

  getFeedbacks(companyId?: string) {
    return companyId ? this.feedbacks.filter(f => f.companyId === companyId) : this.feedbacks;
  }

  updateFeedbackInternalResponses(feedbackId: string, responses: { [key: string]: any }) {
    const idx = this.feedbacks.findIndex(f => f.id === feedbackId);
    if (idx >= 0) {
      this.feedbacks[idx].internalResponses = {
        ...this.feedbacks[idx].internalResponses,
        ...responses
      };
      return this.feedbacks[idx];
    }
    return null;
  }

  getCustomers(companyId: string) {
    return this.customers.filter(c => c.companyId === companyId);
  }

  getCaseForFeedback(feedbackId: string) {
    return this.cases.find(c => c.feedbackId === feedbackId);
  }

  getCases(companyId?: string) {
    return companyId ? this.cases.filter(c => c.companyId === companyId) : this.cases;
  }

  addFeedback(feedback: Omit<Feedback, 'id' | 'createdAt' | 'category' | 'averageScore'>, customDate?: string) {
    const company = this.getCompany(feedback.companyId);
    if (!company) throw new Error("Empresa não encontrada");

    const avg = (feedback.scores.service + feedback.scores.food + feedback.scores.drinks + feedback.scores.structure) / 4;
    let cat: NPSCategory = avg >= 9 ? 'PROMOTER' : avg <= 6 ? 'DETRACTOR' : 'PASSIVE';
    const createdAt = customDate || new Date().toISOString();

    const newFeedback: Feedback = { 
      ...feedback, 
      id: `f-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`, 
      createdAt, 
      category: cat, 
      averageScore: avg 
    };

    this.feedbacks.push(newFeedback);

    const allCompanyFeedbacks = this.feedbacks.filter(f => f.companyId === feedback.companyId);
    company.experienceScore = Math.round((allCompanyFeedbacks.reduce((acc, f) => acc + f.averageScore, 0) / allCompanyFeedbacks.length) * 10);

    let customer = this.customers.find(c => c.phone === feedback.customerPhone && c.companyId === feedback.companyId);
    if (!customer) {
      customer = { id: `cust-${Date.now()}`, companyId: feedback.companyId, name: feedback.customerName, phone: feedback.customerPhone, email: feedback.email, profile: feedback.profile, firstSeen: createdAt, lastSeen: createdAt, averageScore: avg, totalFeedbacks: 1, category: cat, contactLogs: [] };
      this.customers.push(customer);
    } else {
      customer.lastSeen = createdAt;
      customer.totalFeedbacks += 1;
      const customerFeedbacks = this.feedbacks.filter(f => f.customerPhone === customer?.phone && f.companyId === feedback.companyId);
      customer.averageScore = customerFeedbacks.reduce((acc, f) => acc + f.averageScore, 0) / customerFeedbacks.length;
      customer.category = customer.averageScore >= 9 ? 'PROMOTER' : customer.averageScore <= 6 ? 'DETRACTOR' : 'PASSIVE';
      customer.name = feedback.customerName;
    }

    if (cat === 'DETRACTOR') {
      this.createCaseFromFeedback(newFeedback.id, feedback.companyId, 'Caso gerado automaticamente devido à baixa pontuação.', 'Sistema Ativare', 'system');
    }

    return newFeedback;
  }

  getDashboardStats(companyId: string) {
    const fb = this.getFeedbacks(companyId);
    const total = fb.length;
    const avgScore = total > 0 ? (fb.reduce((acc, f) => acc + f.averageScore, 0) / total) * 10 : 0;
    const companyCases = this.getCases(companyId);
    return {
      total,
      promoters: fb.filter(f => f.category === 'PROMOTER').length,
      detractors: fb.filter(f => f.category === 'DETRACTOR').length,
      passives: fb.filter(f => f.category === 'PASSIVE').length,
      avgScore: Math.round(avgScore),
      openDetractors: companyCases.filter(c => c.status === 'OPEN').length,
      resolvedDetractors: companyCases.filter(c => c.status === 'RESOLVED').length,
      catAvg: {
        service: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.service, 0) / total) : 0,
        food: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.food, 0) / total) : 0,
        drinks: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.drinks, 0) / total) : 0,
        structure: total > 0 ? (fb.reduce((acc, f) => acc + f.scores.structure, 0) / total) : 0,
      }
    };
  }

  getBenchmarkingData(companyId: string, segment?: string, region?: string) {
    const currentCompany = this.getCompany(companyId);
    if (!currentCompany) return null;

    const segmentFilter = segment || currentCompany.category;

    const marketCompanies = this.companies.filter(c => c.category === segmentFilter);
    const marketFeedbacks = this.feedbacks.filter(f => {
      const comp = this.getCompany(f.companyId);
      return comp && comp.category === segmentFilter;
    });

    const marketAvgScore = marketCompanies.length > 0 
      ? marketCompanies.reduce((acc, c) => acc + c.experienceScore, 0) / marketCompanies.length 
      : 0;

    const marketCatAvg = {
      service: marketFeedbacks.length > 0 ? (marketFeedbacks.reduce((acc, f) => acc + f.scores.service, 0) / marketFeedbacks.length) : 0,
      food: marketFeedbacks.length > 0 ? (marketFeedbacks.reduce((acc, f) => acc + f.scores.food, 0) / marketFeedbacks.length) : 0,
      drinks: marketFeedbacks.length > 0 ? (marketFeedbacks.reduce((acc, f) => acc + f.scores.drinks, 0) / marketFeedbacks.length) : 0,
      structure: marketFeedbacks.length > 0 ? (marketFeedbacks.reduce((acc, f) => acc + f.scores.structure, 0) / marketFeedbacks.length) : 0,
    };

    const ranking = marketCompanies
      .map(c => ({ name: c.name, score: c.experienceScore }))
      .sort((a, b) => b.score - a.score);

    const position = ranking.findIndex(r => r.name === companyId) + 1;
    const percentile = marketCompanies.length > 0 ? ((marketCompanies.length - position + 1) / marketCompanies.length) * 100 : 0;

    return {
      currentScore: currentCompany.experienceScore,
      marketAverage: Math.round(marketAvgScore),
      marketCatAvg,
      ranking: ranking.slice(0, 10),
      position,
      totalInSegment: marketCompanies.length,
      percentile: Math.round(percentile)
    };
  }

  getBIData(companyId: string, days: number = 30) {
    const now = new Date();
    const startDate = new Date();
    startDate.setDate(now.getDate() - days);

    const fb = this.feedbacks.filter(f => f.companyId === companyId && new Date(f.createdAt) >= startDate);

    // Satisfaction Trend
    const trend: { [key: string]: { sum: number, count: number } } = {};
    fb.forEach(f => {
      const d = new Date(f.createdAt).toLocaleDateString('pt-BR');
      if (!trend[d]) trend[d] = { sum: 0, count: 0 };
      trend[d].sum += f.averageScore;
      trend[d].count += 1;
    });
    const trendData = Object.keys(trend).map(date => ({
      date,
      score: Math.round((trend[date].sum / trend[date].count) * 10)
    })).sort((a,b) => {
      const [d1, m1, y1] = a.date.split('/');
      const [d2, m2, y2] = b.date.split('/');
      return new Date(`${y1}-${m1}-${d1}`).getTime() - new Date(`${y2}-${m2}-${d2}`).getTime();
    });

    // Heatmap (Day vs Hour)
    const heatmap: number[][] = Array.from({ length: 7 }, () => Array(24).fill(0));
    fb.forEach(f => {
      const d = new Date(f.createdAt);
      heatmap[d.getDay()][d.getHours()] += (11 - f.averageScore); // Higher volume/lower score increases intensity
    });

    // Root Cause Analysis
    const impacts = [
      { category: 'Atendimento', score: fb.reduce((acc, f) => acc + f.scores.service, 0) / fb.length, weight: 0.4 },
      { category: 'Comida', score: fb.reduce((acc, f) => acc + f.scores.food, 0) / fb.length, weight: 0.3 },
      { category: 'Bebidas', score: fb.reduce((acc, f) => acc + f.scores.drinks, 0) / fb.length, weight: 0.15 },
      { category: 'Estrutura', score: fb.reduce((acc, f) => acc + f.scores.structure, 0) / fb.length, weight: 0.15 },
    ].map(i => ({
      ...i,
      impact: Math.round((10 - i.score) * i.weight * 10) // Simple impact heuristic
    })).sort((a,b) => b.impact - a.impact);

    // Simulated Sentiment (Top words)
    const positiveWords = ['rápido', 'delicioso', 'atencioso', 'ambiente', 'recomendo', 'perfeito', 'massa', 'limpo', 'música', 'gentil'];
    const negativeWords = ['demora', 'frio', 'caro', 'barulho', 'limpeza', 'esqueceram', 'fila', 'desorganizado', 'pequeno', 'salgado'];

    // AI Prediction (Next score projection)
    const lastScore = trendData.length > 0 ? trendData[trendData.length - 1].score : 80;
    const secondLastScore = trendData.length > 1 ? trendData[trendData.length - 2].score : 80;
    const prediction = Math.min(100, Math.max(0, Math.round(lastScore + (lastScore - secondLastScore) * 0.5)));

    return {
      trendData,
      heatmap,
      impacts,
      sentiments: {
        positive: positiveWords.sort(() => Math.random() - 0.5).slice(0, 8),
        negative: negativeWords.sort(() => Math.random() - 0.5).slice(0, 8)
      },
      prediction,
      // Metadata for AI
      rawSummary: {
        totalEvaluations: fb.length,
        detractorsCount: fb.filter(f => f.category === 'DETRACTOR').length,
        promotersCount: fb.filter(f => f.category === 'PROMOTER').length,
        averageScores: {
          service: fb.reduce((acc, f) => acc + f.scores.service, 0) / fb.length,
          food: fb.reduce((acc, f) => acc + f.scores.food, 0) / fb.length,
          drinks: fb.reduce((acc, f) => acc + f.scores.drinks, 0) / fb.length,
          structure: fb.reduce((acc, f) => acc + f.scores.structure, 0) / fb.length,
        },
        recentComments: fb.filter(f => f.observation).slice(0, 10).map(f => f.observation)
      }
    };
  }

  createCaseFromFeedback(feedbackId: string, companyId: string, noteText: string, userName: string, userId: string) {
    if (this.cases.some(c => c.feedbackId === feedbackId)) return;
    const newCase: Case = {
      id: `case-${Date.now()}`,
      feedbackId,
      companyId,
      status: 'OPEN',
      notes: [{ id: `note-${Date.now()}`, userId, userName, text: noteText, createdAt: new Date().toISOString() }],
      updatedAt: new Date().toISOString()
    };
    this.cases.push(newCase);
    return newCase;
  }

  addCaseNote(caseId: string, userId: string, userName: string, text: string) {
    const c = this.cases.find(item => item.id === caseId);
    if (c) {
      c.notes.push({ id: `note-${Date.now()}`, userId, userName, text, createdAt: new Date().toISOString() });
      c.updatedAt = new Date().toISOString();
      if (c.status === 'OPEN') c.status = 'IN_PROGRESS';
    }
  }

  resolveCase(caseId: string, resolutionText: string, userName: string, userId: string) {
    const c = this.cases.find(item => item.id === caseId);
    if (c) {
      c.status = 'RESOLVED';
      c.resolutionText = resolutionText;
      c.notes.push({ id: `note-res-${Date.now()}`, userId, userName, text: `RESOLUÇÃO: ${resolutionText}`, createdAt: new Date().toISOString() });
      c.updatedAt = new Date().toISOString();
    }
  }

  getCustomerHistory(customerId: string) {
    const customer = this.customers.find(c => c.id === customerId);
    if (!customer) return [];
    return this.feedbacks.filter(f => f.customerPhone === customer.phone && f.companyId === customer.companyId).sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }

  addContactLog(customerId: string, log: Omit<ContactLog, 'id' | 'createdAt'>) {
    const customer = this.customers.find(c => c.id === customerId);
    if (customer) customer.contactLogs.unshift({ ...log, id: `log-${Date.now()}`, createdAt: new Date().toISOString() });
  }

  requestCNPJChange(companyId: string, request: Omit<CNPJRequest, 'id' | 'status' | 'createdAt'>) {
    const company = this.getCompany(companyId);
    if (company) {
      if (!company.cnpjRequests) company.cnpjRequests = [];
      const newRequest: CNPJRequest = {
        ...request,
        id: `req-${Date.now()}`,
        status: 'PENDING',
        createdAt: new Date().toISOString()
      };
      company.cnpjRequests.push(newRequest);
      return newRequest;
    }
    return null;
  }
}

