                       </div>
                    </div>

                    <div className="space-y-3">
                       {selectedLead.tasks.length === 0 ? (
                         <p className="text-center text-[10px] font-bold text-slate-300 uppercase py-10">Nenhuma tarefa agendada.</p>
                       ) : (
                         selectedLead.tasks.map(task => (
                           <div key={task.id} className="flex items-center justify-between p-4 bg-white border border-slate-100 rounded-2xl group">
                              <div className="flex items-center gap-4">
                                 <button onClick={() => dataStore.toggleLeadTask(selectedLead.id, task.id)} className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all ${task.completed ? 'bg-emerald-500 border-emerald-500 text-white' : 'border-slate-200 hover:border-primary'}`}>
                                    {task.completed && <CheckCircle2 className="w-4 h-4" />}
                                 </button>
                                 <div>
                                    <p className={`text-sm font-bold ${task.completed ? 'text-slate-300 line-through' : 'text-slate-700'}`}>{task.title}</p>
                                    <p className="text-[9px] font-black uppercase text-slate-300">Vencimento: {new Date(task.dueDate).toLocaleDateString('pt-BR')}</p>
                                 </div>
                              </div>
                              <button className="opacity-0 group-hover:opacity-100 p-2 text-red-300 hover:text-red-500 transition-all"><Trash2 className="w-4 h-4" /></button>
                           </div>
                         ))
                       )}
                    </div>
                 </div>
               )}

               {activeTab === 'HISTORY' && (
                 <div className="space-y-6 animate-in fade-in duration-300">
                    <div className="space-y-4">
                       <textarea 
                        placeholder="Adicionar nota ou histórico de conversa..." 
                        className="w-full h-24 p-4 bg-slate-50 border border-slate-100 rounded-2xl text-sm outline-none focus:border-primary"
                        value={noteInput}
                        onChange={e => setNoteInput(e.target.value)}
                       />
                       <button onClick={handleAddNote} className="w-full py-3 bg-slate-900 text-white font-black rounded-xl text-xs uppercase tracking-widest flex items-center justify-center gap-2">
                          <Save className="w-4 h-4" /> Salvar Nota
                       </button>
                    </div>

                    <div className="space-y-6 pt-6 border-t border-slate-50">
                       {selectedLead.history.map(item => (
                         <div key={item.id} className="relative pl-6 border-l-2 border-slate-100">
                            <div className={`absolute -left-[9px] top-0 w-4 h-4 rounded-full border-2 border-white flex items-center justify-center ${
                              item.type === 'STAGE_CHANGE' ? 'bg-indigo-500' : 'bg-slate-300'
                            }`}></div>
                            <div className="flex justify-between items-center mb-1">
                               <span className="text-[10px] font-black uppercase text-slate-300 tracking-widest">{item.userName}</span>
                               <span className="text-[9px] font-bold text-slate-400">{new Date(item.createdAt).toLocaleString('pt-BR')}</span>
                            </div>
                            <p className="text-sm text-slate-600 font-medium">{item.text}</p>
                         </div>
                       ))}
                    </div>
                 </div>
               )}

               {activeTab === 'FILES' && (
                 <div className="space-y-6 animate-in fade-in duration-300">
                    <div className="py-20 border-2 border-dashed border-slate-200 rounded-[3rem] text-center space-y-4">
                       <div className="w-12 h-12 bg-slate-50 rounded-full flex items-center justify-center mx-auto text-slate-300"><Paperclip className="w-6 h-6" /></div>
                       <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Nenhum anexo ainda (Propostas, contratos, etc)</p>
                       <button className="px-6 py-2 bg-white border border-slate-200 rounded-xl text-[10px] font-black uppercase text-slate-500 hover:bg-slate-50">Upload de Arquivo</button>
                    </div>
                 </div>
               )}
            </div>

            {/* Footer Actions */}
            <div className="p-8 border-t border-slate-100 bg-slate-50/50 flex gap-3">
               <button className="flex-1 py-4 bg-emerald-500 text-white font-black rounded-2xl shadow-lg hover:bg-emerald-600 transition-all uppercase tracking-widest text-[10px] flex items-center justify-center gap-2">
                  <CheckCircle2 className="w-4 h-4" /> Marcar como Ganho (Won)
               </button>
               <button className="px-8 py-4 bg-white border border-slate-200 text-slate-400 font-black rounded-2xl hover:bg-red-50 hover:text-red-500 transition-all uppercase tracking-widest text-[10px]">
                  Perdido (Lost)
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

