const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedCompanyId, setSelectedCompanyId] = useState<string>('');

  // View States
  const [view, setView] = useState<'LANDING' | 'AUTH' | 'APP'>('LANDING');

  // Lead Modal States (Consultive Sale)
  const [showLeadModal, setShowLeadModal] = useState(false);
  const [leadStep, setLeadStep] = useState(1);
  const [isSubmittingLead, setIsSubmittingLead] = useState(false);
  const [leadSuccess, setLeadSuccess] = useState(false);
  const [leadForm, setLeadForm] = useState({
    name: '',
    email: '',
    phone: '',
    jobTitle: '',
    companyName: '',
    companyPhone: '',
    city: '',
    employees: '1-10'
  });

  // Public Routing States
  const [isPublicForm, setIsPublicForm] = useState(false);
  const [trackingCodeInput, setTrackingCodeInput] = useState('');
  const [publicCompany, setPublicCompany] = useState<Company | null>(null);
  const [publicError, setPublicError] = useState('');
  const [isRouting, setIsRouting] = useState(false);

  // Auth Form States
  const [loginEmail, setLoginEmail] = useState('');
  const [loginPass, setLoginPass] = useState('');
  const [error, setError] = useState('');

  const [hasDetractorAlert, setHasDetractorAlert] = useState(false);

  useEffect(() => {
    if (user) {
      setView('APP');
      if (user.role === UserRole.MASTER) {
        setSelectedCompanyId(dataStore.getAllCompanies()[0]?.id || '');
      } else if (user.companyId) {
        setSelectedCompanyId(user.companyId);
      }
    }
  }, [user]);

  const handleLogout = () => {
    setUser(null);
    setLoginEmail('');
    setLoginPass('');
    setError('');
    setView('AUTH');
  };

  const handleFeedbackSubmitted = () => {
    setIsPublicForm(false);
    setPublicCompany(null);
    setTrackingCodeInput('');
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const authenticatedUser = dataStore.authenticate(loginEmail, loginPass);
    if (authenticatedUser) {
      setUser(authenticatedUser);
      setError('');
    } else {
      setError('Credenciais inválidas. Verifique e-mail e senha.');
    }
  };

  const handleLeadSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmittingLead(true);

    // Simulação de processamento (mesmo backend da Home)
    setTimeout(() => {
      dataStore.addLead(leadForm);
      setIsSubmittingLead(false);
      setLeadSuccess(true);

      // Auto-reset após confirmação
      setTimeout(() => {
        setShowLeadModal(false);
        setLeadSuccess(false);
        setLeadStep(1);
        setLeadForm({
          name: '',
          email: '',
          phone: '',
          jobTitle: '',
          companyName: '',
          companyPhone: '',
          city: '',
          employees: '1-10'
        });
      }, 3000);
    }, 1500);
  };

  const handleTrackingCodeSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsRouting(true);
    setPublicError('');

    setTimeout(() => {
      const company = dataStore.getCompanyByTrackingCode(trackingCodeInput);
      if (company) {
        setPublicCompany(company);
        setIsRouting(false);
      } else {
        setPublicError('Código não encontrado. Verifique o código de 6 dígitos.');
        setIsRouting(false);
      }
    }, 800);
  };

