            </div>

            <form onSubmit={leadStep === 1 ? (e) => { e.preventDefault(); setLeadStep(2); } : handleLeadSubmit} className="space-y-6">
              {leadStep === 1 ? (
                <div className="space-y-4 animate-in slide-in-from-right">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-1">Nome Completo</label>
                    <div className="relative">
                      <UserIcon className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300" />
                      <input required value={leadForm.name} onChange={e => setLeadForm({...leadForm, name: e.target.value})} type="text" className="w-full pl-11 pr-4 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:border-primary font-bold text-slate-900 text-sm" placeholder="Seu nome" />
                    </div>
                  </div>
                  <div className="space-y-1">
