                      <input required value={leadForm.email} onChange={e => setLeadForm({...leadForm, email: e.target.value})} type="email" className="w-full pl-11 pr-4 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:border-primary font-bold text-slate-900 text-sm" placeholder="exemplo@empresa.com" />
