                      <Store className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300" />
                      <input required value={leadForm.companyName} onChange={e => setLeadForm({...leadForm, companyName: e.target.value})} type="text" className="w-full pl-11 pr-4 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:border-primary font-bold text-slate-900 text-sm" placeholder="Nome do seu negócio" />
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                      <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-1">Telefone Empresa</label>
                      <input required value={leadForm.companyPhone} onChange={e => setLeadForm({...leadForm, companyPhone: e.target.value})} type="tel" className="w-full px-4 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:border-primary font-bold text-slate-900 text-sm" placeholder="(00) 0000-0000" />
