                    <button type="submit" disabled={isSubmittingLead} className="flex-1 py-5 bg-primary text-white font-black rounded-2xl shadow-xl shadow-primary/20 flex items-center justify-center gap-2 hover:bg-[#003680] transition-all uppercase tracking-widest text-xs disabled:opacity-50">
                      {isSubmittingLead ? <Loader2 className="w-4 h-4 animate-spin" /> : <><Send className="w-4 h-4" /> Solicitar Demonstração</>}
                    </button>
                  </div>
                </div>
              )}
            </form>
          </div>
        )}
      </div>
    </div>
  );

