  if (isPublicForm) {
    if (!publicCompany) {
      return (
        <div className="min-h-screen bg-[#001529] flex items-center justify-center p-6 font-inter text-slate-900">
          <div className="max-w-md w-full bg-white rounded-[3.5rem] shadow-2xl p-12 text-center animate-in zoom-in duration-500 border border-white/10">
             <div className="w-24 h-24 bg-primary/5 text-primary rounded-[2.5rem] flex items-center justify-center mx-auto mb-8 shadow-inner">
               <QrCode className={`w-12 h-12 ${isRouting ? 'animate-pulse' : ''}`} />
             </div>
             <h2 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Portal Ativare</h2>
