                />
                {publicError && <p className="text-red-500 text-xs font-bold uppercase">{publicError}</p>}
                <button type="submit" disabled={trackingCodeInput.length < 6 || isRouting} className="w-full py-6 bg-primary text-white font-black rounded-[2rem] shadow-2xl shadow-primary/30 transition-all disabled:opacity-20 uppercase tracking-widest text-xs cursor-pointer">
                  {isRouting ? 'Localizando...' : 'Carregar Avaliação'}
