             </form>
             <button onClick={() => setIsPublicForm(false)} className="mt-12 text-slate-300 font-black text-[10px] uppercase tracking-[0.2em] flex items-center justify-center gap-2 mx-auto cursor-pointer">
                <ChevronLeft className="w-4 h-4" /> Voltar
              </button>
          </div>
        </div>
      );
    }
    return <FeedbackForm company={publicCompany} onFinished={handleFeedbackSubmitted} onBack={() => { setIsPublicForm(false); setPublicCompany(null); }} />;
  }

  // Landing Page View
  if (view === 'LANDING') {
    return <LandingPage onNavigate={(v) => { setView('AUTH'); }} />;
  }

  // Auth View
  if (view === 'AUTH' && !user) {
    return (
      <div className="min-h-screen bg-[#f1f5f9] flex flex-col items-center justify-center p-6 font-inter text-slate-900 relative">
        {showLeadModal && <LeadModal />}

        <div className="max-w-md w-full">
          <div className="text-center mb-10">
            <div className="w-16 h-16 bg-primary rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-xl shadow-primary/30">
              <span className="text-3xl font-black text-white italic">A</span>
            </div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tight">Ativare <span className="text-primary">Experience</span></h1>
          </div>

          <div className="bg-white rounded-[3rem] shadow-2xl overflow-hidden border border-white">
            <div className="p-10 space-y-8">
                <div className="text-center">
                  <h2 className="text-xl font-black text-slate-800 uppercase tracking-tight">Acesse sua conta</h2>
                  <p className="text-xs text-slate-400 font-medium">Insira suas credenciais exclusivas Ativare.</p>
                </div>

                <form onSubmit={handleLogin} className="space-y-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">E-mail de Acesso</label>
                    <input type="email" value={loginEmail} onChange={(e) => setLoginEmail(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl outline-none focus:border-primary transition-all text-sm font-bold text-slate-900" placeholder="seu@email.com" required />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Senha</label>
                    <input type="password" value={loginPass} onChange={(e) => setLoginPass(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl outline-none focus:border-primary transition-all text-sm font-bold text-slate-900" placeholder="••••••••" required />
                  </div>
                  {error && <p className="text-red-500 text-xs font-bold uppercase text-center">{error}</p>}

                  <div className="space-y-4">
                    <button type="submit" className="w-full py-5 bg-primary text-white font-black rounded-3xl shadow-xl transition-all uppercase tracking-widest text-xs cursor-pointer hover:bg-[#003680]">
                      Entrar no Sistema
                    </button>

                    <button 
                      type="button"
                      onClick={() => { setShowLeadModal(true); setLeadStep(1); setLeadSuccess(false); }}
                      className="w-full py-4 text-primary font-black rounded-3xl transition-all uppercase tracking-widest text-[10px] flex items-center justify-center gap-2 hover:bg-primary/5"
                    >
                      <Sparkles className="w-4 h-4" /> Não tem acesso ainda? Solicite uma demonstração
                    </button>

                    <button 
                      type="button"
                      onClick={() => setView('LANDING')}
                      className="w-full py-4 text-slate-300 font-black rounded-3xl transition-all uppercase tracking-widest text-[9px] flex items-center justify-center gap-2 hover:text-slate-400"
                    >
                      <ArrowLeft className="w-3 h-3" /> Voltar para o site
                    </button>
                  </div>

                  <div className="pt-6 border-t border-slate-50 flex flex-col items-center gap-4">
                    <p className="text-[9px] font-black text-slate-300 uppercase tracking-[0.2em]">Acesso Master para Testes (Senha: 123)</p>
                    <button type="button" onClick={() => { setLoginEmail('master@ativare.com'); setLoginPass('123'); }} className="px-6 py-2 bg-slate-100 text-[9px] font-black uppercase rounded-xl text-slate-500 hover:bg-slate-200 cursor-pointer">Login Master</button>
                  </div>
                </form>
            </div>
            <div className="bg-slate-50 p-6 flex justify-center border-t border-slate-100">
              <button onClick={() => setIsPublicForm(true)} className="flex items-center gap-2 text-primary font-black text-[10px] uppercase tracking-widest hover:underline cursor-pointer">
                <Search className="w-4 h-4" /> Avaliar com Código Público
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // Final App Render
  return (
    <Layout 
      user={user!} 
      onLogout={handleLogout} 
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
      selectedCompanyId={selectedCompanyId}
      setSelectedCompanyId={setSelectedCompanyId}
      hasDetractorAlert={hasDetractorAlert}
    >
      {activeTab === 'dashboard' && <Dashboard companyId={selectedCompanyId} />}
      {activeTab === 'master_leads' && <MasterLeads currentUser={user!} />}
      {activeTab === 'master_clients' && <MasterClients />}
      {activeTab === 'cases' && <CaseManagement companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'feedbacks' && <Feedbacks companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'customers' && <Customers companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'form_config' && <InternalFormConfig companyId={selectedCompanyId} />}
      {activeTab === 'internal_metrics' && <InternalMetrics companyId={selectedCompanyId} />}
      {activeTab === 'company_profile' && <CompanyProfile companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'my_profile' && <UserProfile user={user!} onUpdate={(updated) => setUser(updated)} />}
      {activeTab === 'users_team' && <UsersTeam companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'my_account' && <AccountBilling companyId={selectedCompanyId} />}
      {activeTab === 'benchmarking' && <Benchmarking companyId={selectedCompanyId} />}
      {activeTab === 'bi' && <BI companyId={selectedCompanyId} />}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { dataStore } from '../services/dataStore';
import { Lead, LeadStage, LeadTemperature, User } from '../types';
import { 
  FileSearch, 
  Mail, 
  Phone, 
  MapPin, 
  Building, 
  Calendar, 
  Users, 
  ChevronRight, 
  ChevronLeft,
  Search,
  Plus,
  DollarSign,
  TrendingUp,
  Clock,
  CheckCircle2,
  AlertCircle,
  MoreVertical,
  X,
  History,
  ListTodo,
  Paperclip,
  Save,
  Trash2,
  Filter,
  ArrowRightLeft
} from 'lucide-react';

interface MasterLeadsProps {
  currentUser: User;
}

// Fix: Moved LeadCard outside of the main component to resolve TypeScript "key" prop error
// and avoid re-creating the component on every render of MasterLeads.
interface LeadCardProps {
  lead: Lead;
  onDragStart: (id: string) => void;
  onClick: (lead: Lead) => void;
}

const LeadCard: React.FC<LeadCardProps> = ({ lead, onDragStart, onClick }) => (
  <div 
    draggable
    onDragStart={() => onDragStart(lead.id)}
    onClick={() => onClick(lead)}
    className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm hover:shadow-md transition-all cursor-pointer group relative mb-3"
  >
    <div className="flex justify-between items-start mb-2">
      <span className={`px-2 py-0.5 rounded-lg text-[8px] font-black uppercase tracking-tight ${
        lead.temperature === 'HOT' ? 'bg-red-50 text-red-500' :
        lead.temperature === 'WARM' ? 'bg-orange-50 text-orange-500' :
        lead.temperature === 'COLD' ? 'bg-blue-50 text-blue-500' : 'bg-slate-50 text-slate-400'
      }`}>
        {lead.temperature === 'NEW' ? 'Novo' : lead.temperature}
      </span>
      <span className="text-[10px] font-bold text-slate-900 flex items-center gap-0.5">
        <DollarSign className="w-3 h-3 text-emerald-500" />
        {lead.value.toLocaleString('pt-BR')}
      </span>
    </div>

    <h4 className="text-xs font-black text-slate-800 line-clamp-1">{lead.companyName}</h4>
    <p className="text-[10px] text-slate-400 font-medium mb-3">{lead.name}</p>

    <div className="flex items-center justify-between pt-3 border-t border-slate-50">
      <div className="flex -space-x-2">
        {lead.tasks.filter(t => !t.completed).length > 0 && (
          <div className="w-5 h-5 rounded-full bg-amber-50 border border-white flex items-center justify-center text-[8px] font-bold text-amber-600" title="Tarefas pendentes">
            {lead.tasks.filter(t => !t.completed).length}
          </div>
        )}
      </div>
      <span className="text-[8px] font-bold text-slate-300 uppercase">{new Date(lead.createdAt).toLocaleDateString('pt-BR')}</span>
    </div>
  </div>
);

const MasterLeads: React.FC<MasterLeadsProps> = ({ currentUser }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedLead, setSelectedLead] = useState<Lead | null>(null);
  const [activeTab, setActiveTab] = useState<'DETAILS' | 'TASKS' | 'HISTORY' | 'FILES'>('DETAILS');
  const [draggedLeadId, setDraggedLeadId] = useState<string | null>(null);

  // States para novos dados
  const [noteInput, setNoteInput] = useState('');
  const [taskInput, setTaskInput] = useState('');
  const [taskDate, setTaskDate] = useState('');

  const leads = dataStore.getLeads();

  const stages: LeadStage[] = ['LEAD', 'QUALIFICATION', 'PROPOSAL', 'NEGOTIATION', 'WON', 'LOST'];

  const stageLabels: Record<LeadStage, string> = {
    LEAD: 'Novos Leads',
    QUALIFICATION: 'Qualificação',
    PROPOSAL: 'Proposta Enviada',
    NEGOTIATION: 'Em Negociação',
    WON: 'Fechado (Ganho)',
    LOST: 'Fechado (Perdido)'
  };

  const filteredLeads = useMemo(() => {
    return leads.filter(l => 
      l.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      l.companyName.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [leads, searchTerm]);

  const handleDragStart = (id: string) => setDraggedLeadId(id);
  const handleDrop = (stage: LeadStage) => {
    if (draggedLeadId) {
      dataStore.updateLead(draggedLeadId, { stage }, currentUser.name);
      setDraggedLeadId(null);
    }
  };

  const handleUpdateLeadValue = (id: string, value: number) => {
    dataStore.updateLead(id, { value }, currentUser.name);
  };

  const handleAddNote = () => {
    if (selectedLead && noteInput.trim()) {
      dataStore.addLeadNote(selectedLead.id, noteInput, currentUser.name);
      setNoteInput('');
    }
  };

  const handleAddTask = () => {
    if (selectedLead && taskInput.trim()) {
