              </div>

              <div className="flex-1 space-y-1">
                {filteredLeads.filter(l => l.stage === stage).map(lead => (
                  <LeadCard 
                    key={lead.id} 
                    lead={lead} 
                    onDragStart={handleDragStart} 
                    onClick={setSelectedLead} 
                  />
                ))}
              </div>

              {stage === 'LEAD' && (
                <button className="mt-2 w-full py-3 border-2 border-dashed border-slate-200 rounded-2xl text-[10px] font-black uppercase text-slate-300 hover:border-primary hover:text-primary transition-all">
                  + Adicionar Manual
                </button>
              )}
            </div>
          ))}
        </div>
      </div>

      {/* Lead Detail Overlay */}
