               <div className="flex items-center gap-5">
                  <div className="w-16 h-16 rounded-[1.5rem] bg-white border border-slate-100 shadow-sm flex items-center justify-center">
                    <Building className="w-8 h-8 text-primary" />
                  </div>
                  <div>
                    <h3 className="text-xl font-black text-slate-900">{selectedLead.companyName}</h3>
                    <p className="text-sm font-bold text-slate-400">{selectedLead.name} • {selectedLead.jobTitle}</p>
                    <div className="flex gap-2 mt-2">
                       <span className="px-2 py-0.5 bg-primary/10 text-primary text-[8px] font-black uppercase rounded-lg border border-primary/10">{selectedLead.stage}</span>
                       <span className="px-2 py-0.5 bg-slate-100 text-slate-500 text-[8px] font-black uppercase rounded-lg border border-slate-100">{selectedLead.segment}</span>
                    </div>
