    const mrr = activeCompanies.reduce((acc, c) => acc + (c.monthlyValue || 0), 0);
    const totalImplementation = activeCompanies.reduce((acc, c) => acc + (c.implementationValue || 0), 0);
    const pipelineRevenue = this.leads.reduce((acc, l) => l.stage !== 'WON' && l.stage !== 'LOST' ? acc + (l.monthlyValue || 0) : acc, 0);

    return {
      mrr,
      arr: mrr * 12,
      totalImplementation,
      pipelineRevenue,
      forecastTotal: mrr + pipelineRevenue,
      activeClients: activeCompanies.length,
      churnedCount: churnedCompanies.length,
      churnMRRLoss: churnedCompanies.reduce((acc, c) => acc + (c.monthlyValue || 0), 0),
      arpu: activeCompanies.length > 0 ? mrr / activeCompanies.length : 0,
      revenueByPlan: activeCompanies.reduce((acc: any, c) => { acc[c.plan] = (acc[c.plan] || 0) + (c.monthlyValue || 0); return acc; }, {}),
      revenueByStage: this.leads.reduce((acc: any, l) => { acc[l.stage] = (acc[l.stage] || 0) + (l.monthlyValue || 0); return acc; }, {}),
      leadsByStage: this.leads.reduce((acc: any, l) => { acc[l.stage] = (acc[l.stage] || 0) + 1; return acc; }, {}),
      mostSoldPlan: 'PRO',
      conversionRate: 15.5,
      churnList: churnedCompanies
    };
  }

  getMasterCSStats() {
    const activeCompanies = this.companies.filter(c => c.status !== 'CANCELED' && c.status !== 'EXPIRED');
    const allFeedbacks = this.feedbacks;

    const globalScore = activeCompanies.length > 0 
      ? activeCompanies.reduce((acc, c) => acc + (c.experienceScore || 0), 0) / activeCompanies.length 
      : 0;

    const promoters = allFeedbacks.filter(f => f.category === 'PROMOTER').length;
    const passives = allFeedbacks.filter(f => f.category === 'PASSIVE').length;
    const detractors = allFeedbacks.filter(f => f.category === 'DETRACTOR').length;
    const totalFbs = allFeedbacks.length;

    const ranking = activeCompanies
      .map(c => ({
        id: c.id,
        name: c.name,
        city: c.city,
        segment: c.category,
        nps: c.experienceScore,
        status: c.experienceScore >= 80 ? 'PROMOTER' : c.experienceScore <= 60 ? 'DETRACTOR' : 'PASSIVE'
      }))
      .sort((a, b) => b.nps - a.nps);

    const atRisk = ranking.filter(r => r.nps < 60);

    const segmentComparison = activeCompanies.reduce((acc: any, c) => {
      if (!acc[c.category]) acc[c.category] = { sum: 0, count: 0 };
      acc[c.category].sum += c.experienceScore;
      acc[c.category].count += 1;
      return acc;
    }, {});

    const segmentAverages = Object.keys(segmentComparison).map(key => ({
      name: key,
      average: Math.round(segmentComparison[key].sum / segmentComparison[key].count)
    }));

    // Mock Trend
    const trendData = [
      { month: 'Jan', nps: globalScore - 4 },
      { month: 'Fev', nps: globalScore - 2 },
      { month: 'Mar', nps: globalScore },
    ];

    return {
      globalScore: Math.round(globalScore),
      distribution: {
        promoters: totalFbs > 0 ? (promoters / totalFbs) * 100 : 0,
        passives: totalFbs > 0 ? (passives / totalFbs) * 100 : 0,
        detractors: totalFbs > 0 ? (detractors / totalFbs) * 100 : 0
      },
      ranking,
      atRisk,
      segmentAverages,
      trendData,
      totalEvaluations: totalFbs
    };
  }

