  }

  getInternalMetrics(companyId: string) {
    const qs = this.getInternalQuestions(companyId, false);
    const fbs = this.getFeedbacks(companyId);
    return qs.map(q => {
      const responses = fbs.map(f => f.internalResponses?.[q.id]).filter(r => r !== undefined && r !== null);
      let avg: any = 0;
      if (q.type === 'SCALE_5' || q.type === 'SCALE_10') {
        avg = responses.length > 0 ? responses.reduce((acc: number, val: any) => acc + Number(val), 0) / responses.length : 0;
      } else if (q.type === 'YES_NO') {
        const yesCount = responses.filter(r => r === 'SIM').length;
        avg = responses.length > 0 ? (yesCount / responses.length) * 100 : 0;
      }
      return { questionId: q.id, text: q.text, type: q.type, totalResponses: responses.length, average: avg, responses: responses };
    });
  }

