  authenticate(email: string, pass: string): User | null {
    const user = this.users.find(u => u.email === email);
    if (user && user.password === pass) return user;
    return null;
  }

  getMasterFinanceStats() {
    const activeCompanies = this.companies.filter(c => c.status === 'ACTIVE' || c.status === 'TRIAL');
    const mrr = activeCompanies.reduce((acc, c) => acc + (c.monthlyValue || 0), 0);
    return {
      mrr, arr: mrr * 12, totalImplementation: 5000, pipelineRevenue: 2500, forecastTotal: mrr + 2500,
      activeClients: activeCompanies.length, churnedCount: 1, churnMRRLoss: 150, arpu: mrr / activeCompanies.length,
      revenueByPlan: { 'PRO': mrr }, revenueByStage: { 'LEAD': 1000 }, leadsByStage: { 'LEAD': 5 },
      mostSoldPlan: 'PRO', conversionRate: 15.5, churnList: this.companies.filter(c => c.status === 'CANCELED')
    };
  }

  getMasterCSStats() {
    const globalScore = this.companies.reduce((acc, c) => acc + c.experienceScore, 0) / this.companies.length;
    return {
      globalScore: Math.round(globalScore),
      distribution: { promoters: 70, passives: 20, detractors: 10 },
      ranking: this.companies.map(c => ({ id: c.id, name: c.name, city: c.city, segment: c.category, nps: c.experienceScore, status: 'PROMOTER' })),
      atRisk: [], segmentAverages: [], trendData: [], totalEvaluations: this.feedbacks.length
    };
  }

