  getCaseForFeedback(fid: string) { return this.cases.find(c => c.feedbackId === fid); }
  getCases(cid?: string) { return cid ? this.cases.filter(c => c.companyId === cid) : this.cases; }

  addFeedback(feedback: Omit<Feedback, 'id' | 'createdAt' | 'category' | 'averageScore'>, customDate?: string) {
    const company = this.getCompany(feedback.companyId);
    if (!company) throw new Error("Empresa não encontrada");

    const avg = (feedback.scores.service + feedback.scores.food + feedback.scores.drinks + feedback.scores.structure) / 4;
    let cat: NPSCategory = avg >= 9 ? 'PROMOTER' : avg <= 6 ? 'DETRACTOR' : 'PASSIVE';
    const createdAt = customDate || new Date().toISOString();

    let customer = this.customers.find(c => c.phone === feedback.customerPhone && c.companyId === feedback.companyId);
    if (!customer) {
      customer = { 
        id: `cust-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`, 
        companyId: feedback.companyId, name: feedback.customerName, phone: feedback.customerPhone, email: feedback.email, profile: feedback.profile, 
        firstSeen: createdAt, lastSeen: createdAt, averageScore: avg, totalFeedbacks: 1, category: cat, contactLogs: [] 
      };
      this.customers.push(customer);
    } else {
      customer.lastSeen = createdAt;
      customer.totalFeedbacks += 1;
      const cFbs = this.feedbacks.filter(f => f.customerId === customer?.id);
      customer.averageScore = (cFbs.reduce((acc, f) => acc + f.averageScore, 0) + avg) / (cFbs.length + 1);
      customer.category = customer.averageScore >= 9 ? 'PROMOTER' : customer.averageScore <= 6 ? 'DETRACTOR' : 'PASSIVE';
      customer.name = feedback.customerName;
    }

    // FIX: Garantir ID único absoluto para evitar colisões no loop de mock e garantir pontos independentes no gráfico
    const newFeedback: Feedback = { 
      ...feedback, 
      id: `f-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`, 
      createdAt, 
      category: cat, 
      averageScore: avg, 
      customerId: customer.id 
    };
    this.feedbacks.push(newFeedback);

    const allCFbs = this.feedbacks.filter(f => f.companyId === feedback.companyId);
    company.experienceScore = Math.round((allCFbs.reduce((acc, f) => acc + f.averageScore, 0) / allCFbs.length) * 10);

    if (cat === 'DETRACTOR') {
      this.createCaseFromFeedback(newFeedback.id, feedback.companyId, 'Recuperação necessária.', 'Sistema', 'system');
    }

    return newFeedback;
  }

  getDashboardStats(cid: string) {
    const fb = this.getFeedbacks(cid);
    return {
      total: fb.length, promoters: fb.filter(f => f.category === 'PROMOTER').length, detractors: fb.filter(f => f.category === 'DETRACTOR').length,
      passives: fb.filter(f => f.category === 'PASSIVE').length, avgScore: Math.round(fb.length > 0 ? (fb.reduce((acc, f) => acc + f.averageScore, 0) / fb.length) * 10 : 0),
      openDetractors: this.cases.filter(c => c.companyId === cid && c.status === 'OPEN').length, resolvedDetractors: this.cases.filter(c => c.companyId === cid && c.status === 'RESOLVED').length,
      catAvg: {
        service: fb.length > 0 ? (fb.reduce((acc, f) => acc + f.scores.service, 0) / fb.length) : 0,
        food: fb.length > 0 ? (fb.reduce((acc, f) => acc + f.scores.food, 0) / fb.length) : 0,
        drinks: fb.length > 0 ? (fb.reduce((acc, f) => acc + f.scores.drinks, 0) / fb.length) : 0,
        structure: fb.length > 0 ? (fb.reduce((acc, f) => acc + f.scores.structure, 0) / fb.length) : 0,
      }
    };
  }

  getBenchmarkingData(cid: string, s?: string) {
    const comp = this.getCompany(cid);
    if (!comp) return null;
    return {
      currentScore: comp.experienceScore, marketAverage: 82, 
      marketCatAvg: { service: 8.2, food: 8.5, drinks: 8.0, structure: 8.1 },
      ranking: [{ name: comp.name, score: comp.experienceScore }, { name: 'Outra Empresa', score: 85 }],
      position: 2, totalInSegment: 150, percentile: 88
    };
  }

  getBIData(cid: string, days = 30) {
    const startDate = new Date(); startDate.setDate(startDate.getDate() - days);
    const fb = this.feedbacks.filter(f => f.companyId === cid && new Date(f.createdAt) >= startDate);
    const trend: any = {};
    fb.forEach(f => {
      const d = new Date(f.createdAt).toLocaleDateString('pt-BR');
      if (!trend[d]) trend[d] = { sum: 0, count: 0 };
      trend[d].sum += f.averageScore; trend[d].count += 1;
    });
    return {
      trendData: Object.keys(trend).map(date => ({ date, score: Math.round((trend[date].sum / trend[date].count) * 10) })),
      heatmap: Array.from({ length: 7 }, () => Array(24).fill(0)),
      impacts: [{ category: 'Atendimento', impact: 15 }], sentiments: { positive: ['pizza', 'massa'], negative: ['demora'] }, prediction: 85,
      rawSummary: { 
        totalEvaluations: fb.length, detractorsCount: fb.filter(f => f.category === 'DETRACTOR').length, promotersCount: fb.filter(f => f.category === 'PROMOTER').length, 
        averageScores: { service: 8, food: 8, drinks: 8, structure: 8 }, 
        recentComments: fb.map(f => f.observation).filter(Boolean)
      }
    };
  }

  createCaseFromFeedback(fid: string, cid: string, n: string, un: string, ui: string) {
    const newCase: Case = { id: `case-${Date.now()}`, feedbackId: fid, companyId: cid, status: 'OPEN', notes: [{ id: `n-${Date.now()}`, userId: ui, userName: un, text: n, createdAt: new Date().toISOString() }], updatedAt: new Date().toISOString() };
    this.cases.push(newCase);
    return newCase;
  }

  addCaseNote(id: string, ui: string, un: string, t: string) {
    const c = this.cases.find(item => item.id === id);
    if (c) {
      c.notes.push({ id: `n-${Date.now()}`, userId: ui, userName: un, text: t, createdAt: new Date().toISOString() });
      c.updatedAt = new Date().toISOString();
    }
  }

  resolveCase(id: string, r: string, un: string, ui: string) {
    const c = this.cases.find(item => item.id === id);
    if (c) {
      c.status = 'RESOLVED';
      c.resolutionText = r;
      c.updatedAt = new Date().toISOString();
    }
  }

  getCustomerHistory(customerId: string) { 
    // FIX: Retornar todos os registros reais, ordenados do mais antigo ao mais novo para o gráfico Recharts
    return this.feedbacks
      .filter(f => f.customerId === customerId)
      .sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime()); 
  }

  addContactLog(cid: string, log: any) {
    const cust = this.customers.find(c => c.id === cid);
    if (cust) cust.contactLogs.unshift({ id: `l-${Date.now()}`, ...log, createdAt: new Date().toISOString() });
  }

  requestCNPJChange(cid: string, r: any) { return null; }
}

