  // --- LOGGING ---
  private addAdminLog(action: string, by: string, targetId: string, targetName: string, details: string) {
    const log: AdminLog = {
      id: `log-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
      action,
      performedBy: by,
      targetId,
      targetName,
      timestamp: new Date().toISOString(),
      details
    };
    this.adminLogs.unshift(log);
    console.debug(`[ADMIN LOG]: ${action} por ${by} em ${targetName}. Detalhes: ${details}`);
  }

  getAdminLogs() { return this.adminLogs; }

  // --- ADMIN ACTIONS ---
  adminUpdateCompany(companyId: string, data: Partial<Company>, adminName: string) {
    const idx = this.companies.findIndex(c => c.id === companyId);
    if (idx >= 0) {
      const old = this.companies[idx];
      this.companies[idx] = { ...old, ...data };
      this.addAdminLog('UPDATE_COMPANY', adminName, companyId, old.name, JSON.stringify(data));
      return this.companies[idx];
    }
    return null;
  }

  adminUpdateUser(userId: string, data: Partial<User>, adminName: string) {
    const idx = this.users.findIndex(u => u.id === userId);
    if (idx >= 0) {
      const old = this.users[idx];
      this.users[idx] = { ...old, ...data };
      this.addAdminLog('UPDATE_USER', adminName, userId, old.name, JSON.stringify(data));
      return this.users[idx];
    }
    return null;
  }

  adminChangeUserPassword(userId: string, newPass: string, adminName: string) {
    const user = this.users.find(u => u.id === userId);
    if (user) {
      user.password = newPass;
      this.addAdminLog('PASSWORD_RESET', adminName, userId, user.name, 'Senha alterada forçadamente via Master.');
      return true;
    }
    return false;
  }

  adminAddCollaborator(companyId: string, userData: Partial<User>, adminName: string) {
    const newUser = this.addCompanyUser(companyId, userData);
    const company = this.getCompany(companyId);
    this.addAdminLog('ADD_COLLABORATOR', adminName, companyId, company?.name || '?', `Novo membro: ${userData.name}`);
    return newUser;
  }

  // --- AUTH & CORE ---
  authenticate(email: string, pass: string): User | null {
    const user = this.users.find(u => u.email === email);
    if (user && user.password === pass) return user;
    return null;
  }

  getMasterFinanceStats() {
    const activeCompanies = this.companies.filter(c => c.status === 'ACTIVE' || c.status === 'TRIAL');
    const mrr = activeCompanies.reduce((acc, c) => acc + (c.monthlyValue || 0), 0);
    return {
      mrr, arr: mrr * 12, totalImplementation: 5000, pipelineRevenue: 2500, forecastTotal: mrr + 2500,
      activeClients: activeCompanies.length, churnedCount: 1, churnMRRLoss: 150, arpu: mrr / activeCompanies.length,
      revenueByPlan: { 'PRO': mrr }, revenueByStage: { 'LEAD': 1000 }, leadsByStage: { 'LEAD': 5 },
      mostSoldPlan: 'PRO', conversionRate: 15.5, churnList: this.companies.filter(c => c.status === 'CANCELED')
    };
  }

  getMasterCSStats() {
    const globalScore = this.companies.reduce((acc, c) => acc + c.experienceScore, 0) / this.companies.length;
    return {
      globalScore: Math.round(globalScore),
      distribution: { promoters: 70, passives: 20, detractors: 10 },
      ranking: this.companies.map(c => ({ id: c.id, name: c.name, city: c.city, segment: c.category, nps: c.experienceScore, status: 'PROMOTER' })),
      atRisk: [], segmentAverages: [], trendData: [], totalEvaluations: this.feedbacks.length
    };
  }

  addLead(l: Partial<Lead>) { 
    const newLead: Lead = {
      id: `lead-${Date.now()}`,
      name: l.name || '', email: l.email || '', phone: l.phone || '', jobTitle: l.jobTitle || '', companyName: l.companyName || '', companyPhone: l.companyPhone || '',
      city: l.city || '', employees: l.employees || '1-10', status: 'NEW', stage: 'LEAD', temperature: 'NEW', value: 0, monthlyValue: 199,
      implementationValue: 500, tasks: [], history: [], files: [], createdAt: new Date().toISOString()
    };
    this.leads.unshift(newLead);
    return newLead; 
  }

  getLeads() { return this.leads; }
  updateLead(id: string, data: any, user: string) { 
    const idx = this.leads.findIndex(l => l.id === id);
    if (idx >= 0) { this.leads[idx] = { ...this.leads[idx], ...data }; return this.leads[idx]; }
    return null;
  }

