  addLeadTask(id: string, t: string, d: string) {}
  toggleLeadTask(id: string, tid: string) {}

  createAccountManual(companyData: any, userData: any) {
    const companyId = `c-${Date.now()}`;
    const newCompany: Company = {
      id: companyId, trackingCode: companyData.trackingCode || Math.random().toString(36).substr(2, 6).toUpperCase(),
      name: companyData.name, category: companyData.category, city: companyData.city, logo: 'https://picsum.photos/seed/ativare/200',
      experienceScore: 0, monthlyValue: 199, implementationValue: 500, plan: 'PRO', status: 'ACTIVE', maxEvaluations: 500, maxUsers: 10, cnpj: companyData.cnpj,
      startDate: new Date().toISOString()
    };
    const newUser: User = {
      id: `u-${Date.now()}`, name: userData.name, email: userData.email, password: userData.password, role: UserRole.BUSINESS, staffRole: 'ADMIN',
      companyId, isOnboarded: true, createdAt: new Date().toISOString()
    };
    this.companies.push(newCompany);
    this.users.push(newUser);
    return { company: newCompany, user: newUser };
  }

  getCompany(id: string) { return this.companies.find(c => c.id === id); }
  getCompanyByTrackingCode(code: string) { return this.companies.find(c => c.trackingCode === code); }
  getAllCompanies() { return this.companies; }
  updateCompany(id: string, data: any) { 
    const idx = this.companies.findIndex(c => c.id === id);
    if (idx >= 0) { this.companies[idx] = { ...this.companies[idx], ...data }; return this.companies[idx]; }
