adModal(true); setLeadStep(1); setLeadSuccess(false); }} className="w-full py-4 text-primary font-black rounded-3xl transition-all uppercase tracking-widest text-[10px] flex items-center justify-center gap-2 hover:bg-primary/5"><Sparkles className="w-4 h-4" /> Não tem acesso ainda? Solicite uma demonstração</button><button type="button" onClick={() => setView('LANDING')} className="w-full py-4 text-slate-300 font-black rounded-3xl transition-all uppercase tracking-widest text-[9px] flex items-center justify-center gap-2 hover:text-slate-400"><ArrowLeft className="w-3 h-3" /> Voltar para o site</button></div><div className="pt-6 border-t border-slate-50 flex flex-col items-center gap-4"><p className="text-[9px] font-black text-slate-300 uppercase tracking-[0.2em]">Acesso Master para Testes (Senha: 123)</p><button type="button" onClick={() => { setLoginEmail('master@ativare.com'); setLoginPass('123'); }} className="px-6 py-2 bg-slate-100 text-[9px] font-black uppercase rounded-xl text-slate-500 hover:bg-slate-200 cursor-pointer">Login Master</button></div></form></div><div className="bg-slate-50 p-6 flex justify-center border-t border-slate-100"><button onClick={() => setIsPublicForm(true)} className="flex items-center gap-2 text-primary font-black text-[10px] uppercase tracking-widest hover:underline cursor-pointer"><Search className="w-4 h-4" /> Avaliar com Código Público</button></div></div></div>
      </div>
    );
  }

  return (
    <Layout 
      user={user!} 
      onLogout={handleLogout} 
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
      selectedCompanyId={selectedCompanyId}
      setSelectedCompanyId={setSelectedCompanyId}
      hasDetractorAlert={hasDetractorAlert}
    >
      {activeTab === 'dashboard' ? (
        user?.role === UserRole.MASTER ? <MasterFinance /> : <Dashboard companyId={selectedCompanyId} />
      ) : null}
      {activeTab === 'master_admin_console' && <MasterAdminPanel currentUser={user!} />}
      {activeTab === 'master_cs' && <MasterCSDashboard />}
      {activeTab === 'master_leads' && <MasterLeads currentUser={user!} />}
      {activeTab === 'master_clients' && <MasterClients />}
      {activeTab === 'cases' && <CaseManagement companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'feedbacks' && <Feedbacks companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'customers' && <Customers companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'form_config' && <InternalFormConfig companyId={selectedCompanyId} />}
      {activeTab === 'internal_metrics' && <InternalMetrics companyId={selectedCompanyId} />}
      {activeTab === 'company_profile' && <CompanyProfile companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'my_profile' && <UserProfile user={user!} onUpdate={(updated) => setUser(updated)} />}
      {activeTab === 'users_team' && <UsersTeam companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'my_account' && <AccountBilling companyId={selectedCompanyId} />}
      {activeTab === 'benchmarking' && <Benchmarking companyId={selectedCompanyId} />}
      {activeTab === 'bi' && <BI companyId={selectedCompanyId} />}
    </Layout>
  );
};

export default App;

