                                  <button onClick={() => handleAction(() => dataStore.adminChangeUserRole(u.id, u.role === UserRole.GUARDIAN ? UserRole.BUSINESS : UserRole.GUARDIAN, currentUser.name))} className={`p-2 rounded-xl transition-all ${u.role === UserRole.GUARDIAN ? 'bg-purple-100 text-purple-600' : 'bg-slate-50 text-slate-300'}`} title="Tornar Guardião"><Shield className="w-4 h-4" /></button>
                               </div>
                            </div>
                         ))}
                      </div>

                      <div className="space-y-4 pt-4 border-t border-slate-50">
                         <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Guardiões Vinculados</h4>
                         {dataStore.getAllUsers().filter(u => u.role === UserRole.GUARDIAN).map(g => (
                            <div key={g.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100">
                               <div className="flex items-center gap-3">
                                  <div className="w-8 h-8 rounded-lg bg-white flex items-center justify-center font-black text-[10px] text-primary shadow-sm">{g.name.charAt(0)}</div>
                                  <div><p className="text-xs font-black text-slate-800">{g.name}</p><p className="text-[9px] text-slate-400 font-bold uppercase">{g.email}</p></div>
                               </div>
                               <button 
                                 onClick={() => handleAction(() => g.linkedCompanyIds?.includes(selectedComp.id) ? dataStore.adminUnlinkGuardianFromCompany(g.id, selectedComp.id, currentUser.name) : dataStore.adminLinkGuardianToCompany(g.id, selectedComp.id, currentUser.name))}
                                 className={`p-2 rounded-xl transition-all ${g.linkedCompanyIds?.includes(selectedComp.id) ? 'bg-red-50 text-red-500' : 'bg-emerald-50 text-emerald-500'}`}
                               >
                                  {g.linkedCompanyIds?.includes(selectedComp.id) ? <Unlink className="w-4 h-4" /> : <Link className="w-4 h-4" />}
                               </button>
                            </div>
                         ))}
                      </div>
                   </div>
                 )}

                 {modalMode === 'LOGS' && (
                   <div className="space-y-6">
                      {dataStore.getAdminLogs().length === 0 ? <p className="text-center py-20 text-slate-300 text-xs font-black uppercase">Nenhum log registrado.</p> : dataStore.getAdminLogs().map(log => (
                          <div key={log.id} className="relative pl-8 border-l-2 border-slate-100">
                             <div className="absolute -left-[9px] top-0 w-4 h-4 rounded-full bg-white border-2 border-primary flex items-center justify-center"><div className="w-1.5 h-1.5 rounded-full bg-primary animate-pulse"></div></div>
                             <div className="flex justify-between items-center mb-1"><span className="text-[10px] font-black text-primary uppercase tracking-widest">{log.performedBy}</span><span className="text-[9px] font-bold text-slate-400">{new Date(log.timestamp).toLocaleString('pt-BR')}</span></div>
                             <p className="text-xs font-black text-slate-800 mb-1">{log.action}: <span className="text-slate-400">{log.targetName}</span></p>
                             <p className="text-[10px] text-slate-500 bg-slate-50 p-3 rounded-xl font-mono">{log.details}</p>
                          </div>
                      ))}
                   </div>
                 )}
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

