                  <div className="grid grid-cols-2 gap-4"><div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-1">Telefone</label><div className="relative"><Smartphone className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300" /><input required value={leadForm.phone} onChange={e => setLeadForm({...leadForm, phone: e.target.value})} type="tel" className="w-full pl-11 pr-4 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:border-primary font-bold text-slate-900 text-sm" placeholder="(00) 00000-0000" /></div></div><div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-1">Cargo</label><select required value={leadForm.jobTitle} onChange={e => setLeadForm({...leadForm, jobTitle: e.target.value})} className="w-full px-4 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:border-primary font-bold text-slate-900 text-sm appearance-none"><option value="">Selecionar...</option><option value="Dono">Dono / CEO</option><option value="Gerente">Gerente</option><option value="Marketing">Marketing / CX</option></select></div></div>
                  <button type="submit" className="w-full py-5 bg-primary text-white font-black rounded-2xl shadow-xl shadow-primary/20 flex items-center justify-center gap-2 hover:bg-[#003680] transition-all uppercase tracking-widest text-xs">Continuar <ChevronRight className="w-4 h-4" /></button>
                </div>
              ) : (
                <div className="space-y-4 animate-in slide-in-from-right">
                   <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-1">Nome da Empresa</label><div className="relative"><Store className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300" /><input required value={leadForm.companyName} onChange={e => setLeadForm({...leadForm, companyName: e.target.value})} type="text" className="w-full pl-11 pr-4 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:border-primary font-bold text-slate-900 text-sm" placeholder="Nome do seu negócio" /></div></div>
                  <div className="grid grid-cols-2 gap-4"><div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-1">Telefone Empresa</label><input required value={leadForm.companyPhone} onChange={e => setLeadForm({...leadForm, companyPhone: e.target.value})} type="tel" className="w-full px-4 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:border-primary font-bold text-slate-900 text-sm" placeholder="(00) 0000-0000" /></div><div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-1">Cidade</label><div className="relative"><MapPin className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300" /><input required value={leadForm.city} onChange={e => setLeadForm({...leadForm, city: e.target.value})} type="text" className="w-full pl-11 pr-4 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:border-primary font-bold text-slate-900 text-sm" placeholder="Ex: São Paulo" /></div></div></div>
                  <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-1">Número de Funcionários</label><select required value={leadForm.employees} onChange={e => setLeadForm({...leadForm, employees: e.target.value})} className="w-full px-4 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:border-primary font-bold text-slate-900 text-sm appearance-none"><option value="1-10">1 a 10 funcionários</option><option value="11-50">11 a 50 funcionários</option><option value="51-200">51 a 200 funcionários</option><option value="200+">Mais de 200 funcionários</option></select></div>
                  <div className="flex gap-3 pt-2"><button type="button" onClick={() => setLeadStep(1)} className="px-6 py-5 bg-slate-100 text-slate-500 font-black rounded-2xl hover:bg-slate-200 transition-all uppercase tracking-widest text-xs">Voltar</button><button type="submit" disabled={isSubmittingLead} className="flex-1 py-5 bg-primary text-white font-black rounded-2xl shadow-xl shadow-primary/20 flex items-center justify-center gap-2 hover:bg-[#003680] transition-all uppercase tracking-widest text-xs disabled:opacity-50">{isSubmittingLead ? <Loader2 className="w-4 h-4 animate-spin" /> : <><Send className="w-4 h-4" /> Solicitar Demonstração</>}</button></div>
                </div>
              )}
            </form>
          </div>
        )}
      </div>
    </div>
  );

  if (isPublicForm) {
    if (!publicCompany) {
      return (
        <div className="min-h-screen bg-[#001529] flex items-center justify-center p-6 font-inter text-slate-900">
          <div className="max-w-md w-full bg-white rounded-[3.5rem] shadow-2xl p-12 text-center animate-in zoom-in duration-500 border border-white/10"><div className="w-24 h-24 bg-primary/5 text-primary rounded-[2.5rem] flex items-center justify-center mx-auto mb-8 shadow-inner"><QrCode className={`w-12 h-12 ${isRouting ? 'animate-pulse' : ''}`} /></div><h2 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Portal Ativare</h2><p className="text-slate-400 font-medium mb-10 text-sm">Insira o código público de 6 dígitos para avaliar.</p><form onSubmit={handleTrackingCodeSubmit} className="space-y-8"><input type="text" maxLength={6} disabled={isRouting} value={trackingCodeInput} onChange={(e) => setTrackingCodeInput(e.target.value.toUpperCase())} placeholder="ABC123" className="w-full p-8 bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] outline-none focus:border-primary text-center text-4xl font-black tracking-[0.4em] text-primary transition-all uppercase" />{publicError && <p className="text-red-500 text-xs font-bold uppercase">{publicError}</p>}<button type="submit" disabled={trackingCodeInput.length < 6 || isRouting} className="w-full py-6 bg-primary text-white font-black rounded-[2rem] shadow-2xl shadow-primary/30 transition-all disabled:opacity-20 uppercase tracking-widest text-xs cursor-pointer">{isRouting ? 'Localizando...' : 'Carregar Avaliação'}</button></form><button onClick={() => setIsPublicForm(false)} className="mt-12 text-slate-300 font-black text-[10px] uppercase tracking-[0.2em] flex items-center justify-center gap-2 mx-auto cursor-pointer"><ChevronLeft className="w-4 h-4" /> Voltar</button></div>
        </div>
      );
    }
    return <FeedbackForm company={publicCompany} onFinished={handleFeedbackSubmitted} onBack={() => { setIsPublicForm(false); setPublicCompany(null); }} />;
  }

  if (view === 'LANDING') return <LandingPage onNavigate={(v) => { setView('AUTH'); }} />;

  if (view === 'AUTH' && !user) {
    return (
      <div className="min-h-screen bg-[#f1f5f9] flex flex-col items-center justify-center p-6 font-inter text-slate-900 relative">
        {showLeadModal && <LeadModal />}
        <div className="max-w-md w-full"><div className="text-center mb-10"><div className="w-16 h-16 bg-primary rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-xl shadow-primary/30"><span className="text-3xl font-black text-white italic">A</span></div><h1 className="text-4xl font-black text-slate-900 tracking-tight">Ativare <span className="text-primary">Experience</span></h1></div><div className="bg-white rounded-[3rem] shadow-2xl overflow-hidden border border-white"><div className="p-10 space-y-8"><div className="text-center"><h2 className="text-xl font-black text-slate-800 uppercase tracking-tight">Acesse sua conta</h2><p className="text-xs text-slate-400 font-medium">Insira suas credenciais exclusivas Ativare.</p></div><form onSubmit={handleLogin} className="space-y-6"><div className="space-y-2"><label className="text-[10px] font-black uppercase tracking-widest text-slate-400">E-mail de Acesso</label><input type="email" value={loginEmail} onChange={(e) => setLoginEmail(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl outline-none focus:border-primary transition-all text-sm font-bold text-slate-900" placeholder="seu@email.com" required /></div><div className="space-y-2"><label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Senha</label><input type="password" value={loginPass} onChange={(e) => setLoginPass(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-200 rounded-3xl outline-none focus:border-primary transition-all text-sm font-bold text-slate-900" placeholder="••••••••" required /></div>{error && <p className="text-red-500 text-xs font-bold uppercase text-center">{error}</p>}<div className="space-y-4"><button type="submit" className="w-full py-5 bg-primary text-white font-black rounded-3xl shadow-xl transition-all uppercase tracking-widest text-xs cursor-pointer hover:bg-[#003680]">Entrar no Sistema</button><button type="button" onClick={() => { setShowLeadModal(true); setLeadStep(1); setLeadSuccess(false); }} className="w-full py-4 text-primary font-black rounded-3xl transition-all uppercase tracking-widest text-[10px] flex items-center justify-center gap-2 hover:bg-primary/5"><Sparkles className="w-4 h-4" /> Não tem acesso ainda? Solicite uma demonstração</button><button type="button" onClick={() => setView('LANDING')} className="w-full py-4 text-slate-300 font-black rounded-3xl transition-all uppercase tracking-widest text-[9px] flex items-center justify-center gap-2 hover:text-slate-400"><ArrowLeft className="w-3 h-3" /> Voltar para o site</button></div><div className="pt-6 border-t border-slate-50 flex flex-col items-center gap-4"><p className="text-[9px] font-black text-slate-300 uppercase tracking-[0.2em]">Acessos Master e Guardião (Senha: 123)</p><div className="flex gap-2"><button type="button" onClick={() => { setLoginEmail('master@ativare.com'); setLoginPass('123'); }} className="px-4 py-2 bg-slate-100 text-[8px] font-black uppercase rounded-lg text-slate-500 hover:bg-slate-200 cursor-pointer">Login Master</button><button type="button" onClick={() => { setLoginEmail('guardian@ativare.com'); setLoginPass('123'); }} className="px-4 py-2 bg-slate-100 text-[8px] font-black uppercase rounded-lg text-slate-500 hover:bg-slate-200 cursor-pointer">Login Guardião</button></div></div></form></div><div className="bg-slate-50 p-6 flex justify-center border-t border-slate-100"><button onClick={() => setIsPublicForm(true)} className="flex items-center gap-2 text-primary font-black text-[10px] uppercase tracking-widest hover:underline cursor-pointer"><Search className="w-4 h-4" /> Avaliar com Código Público</button></div></div></div>
      </div>
    );
  }

  return (
    <Layout 
      user={user!} 
      onLogout={handleLogout} 
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
      selectedCompanyId={selectedCompanyId}
      setSelectedCompanyId={setSelectedCompanyId}
      hasDetractorAlert={hasDetractorAlert}
    >
      {activeTab === 'dashboard' ? (
        user?.role === UserRole.ADM_MASTER ? <MasterFinance /> : <Dashboard companyId={selectedCompanyId} />
      ) : null}
      {activeTab === 'master_admin_console' && <MasterAdminPanel currentUser={user!} />}
      {activeTab === 'cases' && <CaseManagement companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'feedbacks' && <Feedbacks companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'customers' && <Customers companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'form_config' && <InternalFormConfig companyId={selectedCompanyId} />}
      {activeTab === 'internal_metrics' && <InternalMetrics companyId={selectedCompanyId} />}
      {activeTab === 'company_profile' && <CompanyProfile companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'my_profile' && <UserProfile user={user!} onUpdate={(updated) => setUser(updated)} />}
      {activeTab === 'users_team' && <UsersTeam companyId={selectedCompanyId} currentUser={user!} />}
      {activeTab === 'my_account' && <AccountBilling companyId={selectedCompanyId} />}
      {activeTab === 'benchmarking' && <Benchmarking companyId={selectedCompanyId} />}
      {activeTab === 'bi' && <BI companyId={selectedCompanyId} />}
    </Layout>
  );
};

export default App;

import { Feedback, Case, Customer, NPSCategory, InternalQuestion, ContactLog, Company, User, UserRole, StaffRole, PlanType, AccountStatus, FeedbackChannel, Lead, JobTitle, LeadStage, AdminLog, CaseStatus, ContactLogType, InternalQuestionType } from '../types';
import { MOCK_COMPANIES, MOCK_USERS } from '../constants';

class DataStore {
  private companies: Company[] = [...MOCK_COMPANIES];
  private users: User[] = [...MOCK_USERS];
  private leads: Lead[] = [];
  private feedbacks: Feedback[] = [];
  private cases: Case[] = [];
  private customers: Customer[] = [];
  private internalQuestions: InternalQuestion[] = [];
  private adminLogs: AdminLog[] = [];

  constructor() {
    this.initMockData();
  }

  private initMockData() {
    const bellaMGId = 'c-test';
    const bellaMGCode = 'BELLA1';

    const oldFeedbacks = [
      { date: '2025-09-15T19:30:00Z', score: 6, obs: "A pizza demorou muito para chegar." },
      { date: '2025-10-25T22:30:00Z', score: 6, obs: "Esperava mais pelo preço cobrado." }
    ];

    oldFeedbacks.forEach((f, i) => {
      this.addFeedback({
        companyId: bellaMGId,
        companyTrackingCode: bellaMGCode,
        customerId: '',
        customerName: `Cliente Antigo ${i + 1}`,
        customerPhone: `(35) 99999-000${i}`,
        howKnown: 'Indicação',
        scores: { service: f.score, food: f.score, drinks: f.score, structure: f.score },
        profile: 'family',
        observation: f.obs
      }, f.date);
    });

    const recentFeedbacks = [
      { date: '2026-01-25T20:00:00Z', score: 10, obs: "Simplesmente a melhor pizzaria da região." }
    ];

    recentFeedbacks.forEach((f, i) => {
      this.addFeedback({
        companyId: bellaMGId,
        companyTrackingCode: bellaMGCode,
        customerId: '',
        customerName: `Cliente Novo ${i + 1}`,
        customerPhone: `(35) 98888-000${i}`,
        howKnown: 'Instagram',
        scores: { service: f.score, food: f.score, drinks: f.score, structure: f.score },
        profile: 'couple',
        observation: f.obs
      }, f.date);
    });

    this.companies.forEach(comp => {
      if (comp.id === bellaMGId) return;
      for (let i = 0; i < 5; i++) {
        const date = new Date();
        date.setDate(date.getDate() - Math.floor(Math.random() * 60));
        this.addFeedback({
          companyId: comp.id,
          companyTrackingCode: comp.trackingCode,
          customerId: '',
          customerName: `Cliente ${comp.id} ${i}`,
          customerPhone: `(11) 9${Math.floor(10000000 + Math.random() * 90000000)}`,
          howKnown: 'Google',
          scores: { service: 8, food: 8, drinks: 8, structure: 8 },
          profile: 'friends',
          observation: 'Boa experiência.',
        }, date.toISOString());
      }
    });
  }

  // --- LOGGING ---
  private addAdminLog(action: string, by: string, targetId: string, targetName: string, details: string) {
    const log: AdminLog = {
      id: `log-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
      action,
      performedBy: by,
      targetId,
      targetName,
      timestamp: new Date().toISOString(),
      details
    };
    this.adminLogs.unshift(log);
  }

  getAdminLogs() { return this.adminLogs; }

  // --- MASTER ACTIONS ---
  adminUpdateCompany(companyId: string, data: Partial<Company>, adminName: string) {
    const idx = this.companies.findIndex(c => c.id === companyId);
    if (idx >= 0) {
      const old = this.companies[idx];
      this.companies[idx] = { ...old, ...data };
      this.addAdminLog('UPDATE_COMPANY', adminName, companyId, old.name, JSON.stringify(data));
      return this.companies[idx];
    }
    return null;
  }

  adminChangeUserRole(userId: string, newRole: UserRole, adminName: string) {
    const user = this.users.find(u => u.id === userId);
    if (user) {
      const oldRole = user.role;
      user.role = newRole;
      if (newRole !== UserRole.GUARDIAN && newRole !== UserRole.ADM_MASTER) {
        user.linkedCompanyIds = [];
      }
      this.addAdminLog('CHANGE_ROLE', adminName, userId, user.name, `De ${oldRole} para ${newRole}`);
      return user;
    }
    return null;
  }

  adminProvisionGuardian(name: string, email: string, companyId: string, adminName: string) {
    let user = this.users.find(u => u.email.toLowerCase() === email.toLowerCase());
    const company = this.getCompany(companyId);

    if (!user) {
      // Criar novo Guardião
      user = {
        id: `u-${Date.now()}`,
        name,
        email,
        password: '123', // Senha padrão inicial
        role: UserRole.GUARDIAN,
        isOnboarded: true,
        linkedCompanyIds: [companyId],
        createdAt: new Date().toISOString()
      };
      this.users.push(user);
      this.addAdminLog('CREATE_GUARDIAN', adminName, user.id, name, `Novo Guardião criado e vinculado a ${company?.name}`);
    } else {
      // Promover ou garantir que é Guardião e vincular
      if (user.role === UserRole.USER || user.role === UserRole.BUSINESS) {
        user.role = UserRole.GUARDIAN;
      }
      if (!user.linkedCompanyIds) user.linkedCompanyIds = [];
      if (!user.linkedCompanyIds.includes(companyId)) {
        user.linkedCompanyIds.push(companyId);
        this.addAdminLog('LINK_GUARDIAN', adminName, user.id, user.name, `Guardião existente vinculado a ${company?.name}`);
      }
    }
    return user;
  }

  adminLinkGuardianToCompany(userId: string, companyId: string, adminName: string) {
    const user = this.users.find(u => u.id === userId);
    const company = this.companies.find(c => c.id === companyId);
    if (user && company) {
      if (!user.linkedCompanyIds) user.linkedCompanyIds = [];
      if (!user.linkedCompanyIds.includes(companyId)) {
        user.linkedCompanyIds.push(companyId);
        this.addAdminLog('LINK_GUARDIAN', adminName, userId, user.name, `Vinculado à empresa ${company.name}`);
      }
      return user;
    }
    return null;
  }

  adminUnlinkGuardianFromCompany(userId: string, companyId: string, adminName: string) {
    const user = this.users.find(u => u.id === userId);
    if (user && user.linkedCompanyIds) {
      user.linkedCompanyIds = user.linkedCompanyIds.filter(id => id !== companyId);
      const company = this.companies.find(c => c.id === companyId);
      this.addAdminLog('UNLINK_GUARDIAN', adminName, userId, user.name, `Desvinculado da empresa ${company?.name || '?'}`);
      return user;
    }
    return null;
  }

  adminResetPassword(userId: string, newPass: string, adminName: string) {
    const user = this.users.find(u => u.id === userId);
    if (user) {
      user.password = newPass;
      this.addAdminLog('RESET_PASSWORD', adminName, userId, user.name, 'Senha redefinida pelo Master');
      return true;
    }
    return false;
  }

  adminAddCollaborator(companyId: string, data: any, adminName: string) {
    const newUser = this.addCompanyUser(companyId, data);
    this.addAdminLog('ADD_COLLABORATOR', adminName, newUser.id, newUser.name, `Adicionado à empresa ${companyId}`);
    return newUser;
  }

  adminRemoveCollaborator(userId: string, adminName: string) {
    const user = this.users.find(u => u.id === userId);
    if (user) {
      this.users = this.users.filter(u => u.id !== userId);
      this.addAdminLog('REMOVE_COLLABORATOR', adminName, userId, user.name, 'Usuário removido da plataforma');
      return true;
    }
    return false;
  }

  // --- CORE ---
  authenticate(email: string, pass: string): User | null {
    const user = this.users.find(u => u.email === email);
    if (user && user.password === pass) return user;
    return null;
  }

  getCompany(id: string) { return this.companies.find(c => c.id === id); }
  getCompanyByTrackingCode(code: string) { return this.companies.find(c => c.trackingCode === code); }
  getAllCompanies() { return this.companies; }

  getCompanyUsers(cid: string) { return this.users.filter(u => u.companyId === cid); }
  getAllUsers() { return this.users; }

  updateCompany(id: string, data: any) { 
    const idx = this.companies.findIndex(c => c.id === id);
    if (idx >= 0) { this.companies[idx] = { ...this.companies[idx], ...data }; return this.companies[idx]; }
    return null;
  }

  addCompanyUser(cid: string, data: any) {
    const newUser: User = { id: `u-${Date.now()}`, ...data, companyId: cid, role: data.role || UserRole.USER, isOnboarded: true, createdAt: new Date().toISOString() };
    this.users.push(newUser);
    return newUser;
  }

  updateUser(id: string, data: any) {
    const idx = this.users.findIndex(u => u.id === id);
    if (idx >= 0) { this.users[idx] = { ...this.users[idx], ...data }; return this.users[idx]; }
    return null;
  }

  addFeedback(feedback: Omit<Feedback, 'id' | 'createdAt' | 'category' | 'averageScore'>, customDate?: string) {
    const company = this.getCompany(feedback.companyId);
    if (!company) throw new Error("Empresa não encontrada");
    const avg = (feedback.scores.service + feedback.scores.food + feedback.scores.drinks + feedback.scores.structure) / 4;
    let cat: NPSCategory = avg >= 9 ? 'PROMOTER' : avg <= 6 ? 'DETRACTOR' : 'PASSIVE';
    const createdAt = customDate || new Date().toISOString();

    let customer = this.customers.find(c => c.phone === feedback.customerPhone && c.companyId === feedback.companyId);
    if (!customer) {
      customer = { id: `cust-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`, companyId: feedback.companyId, name: feedback.customerName, phone: feedback.customerPhone, email: feedback.email, profile: feedback.profile, firstSeen: createdAt, lastSeen: createdAt, averageScore: avg, totalFeedbacks: 1, category: cat, contactLogs: [] };
      this.customers.push(customer);
    } else {
      customer.lastSeen = createdAt;
      customer.totalFeedbacks += 1;
      const cFbs = this.feedbacks.filter(f => f.customerId === customer?.id);
      customer.averageScore = (cFbs.reduce((acc, f) => acc + f.averageScore, 0) + avg) / (cFbs.length + 1);
      customer.category = customer.averageScore >= 9 ? 'PROMOTER' : customer.averageScore <= 6 ? 'DETRACTOR' : 'PASSIVE';
      customer.name = feedback.customerName;
    }

    const newFeedback: Feedback = { ...feedback, id: `f-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`, createdAt, category: cat, averageScore: avg, customerId: customer.id };
    this.feedbacks.push(newFeedback);

    const allCFbs = this.feedbacks.filter(f => f.companyId === feedback.companyId);
    company.experienceScore = Math.round((allCFbs.reduce((acc, f) => acc + f.averageScore, 0) / allCFbs.length) * 10);
    return newFeedback;
  }

  getFeedbacks(cid?: string) { return cid ? this.feedbacks.filter(f => f.companyId === cid) : this.feedbacks; }
  getCustomers(cid: string) { return this.customers.filter(c => c.companyId === cid); }
  getCustomerHistory(customerId: string) { return this.feedbacks.filter(f => f.customerId === customerId).sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime()); }
  getCases(cid?: string) { return cid ? this.cases.filter(c => c.companyId === cid) : this.cases; }
  getCaseForFeedback(fid: string) { return this.cases.find(c => c.feedbackId === fid); }

  getDashboardStats(cid: string) {
    const fb = this.getFeedbacks(cid);
    return {
      total: fb.length, promoters: fb.filter(f => f.category === 'PROMOTER').length, detractors: fb.filter(f => f.category === 'DETRACTOR').length,
      passives: fb.filter(f => f.category === 'PASSIVE').length, avgScore: Math.round(fb.length > 0 ? (fb.reduce((acc, f) => acc + f.averageScore, 0) / fb.length) * 10 : 0),
      openDetractors: this.cases.filter(c => c.companyId === cid && c.status === 'OPEN').length, resolvedDetractors: this.cases.filter(c => c.companyId === cid && c.status === 'RESOLVED').length,
      catAvg: {
        service: fb.length > 0 ? (fb.reduce((acc, f) => acc + f.scores.service, 0) / fb.length) : 0,
        food: fb.length > 0 ? (fb.reduce((acc, f) => acc + f.scores.food, 0) / fb.length) : 0,
        drinks: fb.length > 0 ? (fb.reduce((acc, f) => acc + f.scores.drinks, 0) / fb.length) : 0,
        structure: fb.length > 0 ? (fb.reduce((acc, f) => acc + f.scores.structure, 0) / fb.length) : 0,
      }
    };
  }

  getBIData(cid: string, days = 30) {
    const startDate = new Date(); startDate.setDate(startDate.getDate() - days);
    const fb = this.feedbacks.filter(f => f.companyId === cid && new Date(f.createdAt) >= startDate);
    const trend: any = {};
    fb.forEach(f => {
      const d = new Date(f.createdAt).toLocaleDateString('pt-BR');
      if (!trend[d]) trend[d] = { sum: 0, count: 0 };
      trend[d].sum += f.averageScore; trend[d].count += 1;
    });
    return {
      trendData: Object.keys(trend).map(date => ({ date, score: Math.round((trend[date].sum / trend[date].count) * 10) })),
      heatmap: Array.from({ length: 7 }, () => Array(24).fill(0)), impacts: [], sentiments: { positive: [], negative: [] }, prediction: 85,
      rawSummary: { totalEvaluations: fb.length, detractorsCount: fb.filter(f => f.category === 'DETRACTOR').length, promotersCount: fb.filter(f => f.category === 'PROMOTER').length, averageScores: { service: 8, food: 8, drinks: 8, structure: 8 }, recentComments: fb.map(f => f.observation).filter(Boolean) }
    };
  }

  getBenchmarkingData(cid: string, s?: string) {
    const comp = this.getCompany(cid);
    if (!comp) return null;
    return { currentScore: comp.experienceScore, marketAverage: 82, marketCatAvg: { service: 8.2, food: 8.5, drinks: 8.0, structure: 8.1 }, ranking: [{ name: comp.name, score: comp.experienceScore }, { name: 'Outra Empresa', score: 85 }], position: 2, totalInSegment: 150, percentile: 88 };
  }

  getMasterFinanceStats() {
    const activeCompanies = this.companies.filter(c => c.status === 'ACTIVE' || c.status === 'TRIAL');
    const mrr = activeCompanies.reduce((acc, c) => acc + (c.monthlyValue || 0), 0);
    return { mrr, arr: mrr * 12, totalImplementation: 5000, pipelineRevenue: 2500, forecastTotal: mrr + 2500, activeClients: activeCompanies.length, churnedCount: 0, churnMRRLoss: 0, arpu: mrr / activeCompanies.length, revenueByPlan: { 'PRO': mrr }, revenueByStage: { 'LEAD': 1000 }, leadsByStage: { 'LEAD': 5 }, mostSoldPlan: 'PRO', conversionRate: 15.5, churnList: [] };
  }

  getMasterCSStats() {
    const globalScore = this.companies.reduce((acc, c) => acc + c.experienceScore, 0) / this.companies.length;
    return { globalScore: Math.round(globalScore), distribution: { promoters: 70, passives: 20, detractors: 10 }, ranking: this.companies.map(c => ({ id: c.id, name: c.name, city: c.city, segment: c.category, nps: c.experienceScore, status: 'PROMOTER' as any })), atRisk: [], segmentAverages: [], trendData: [], totalEvaluations: this.feedbacks.length };
  }

  getInternalQuestions(cid: string, active = true) { 
    return this.internalQuestions.filter(q => q.companyId === cid && (!active || q.active)); 
  }

  saveInternalQuestion(q: InternalQuestion) {
    const idx = this.internalQuestions.findIndex(iq => iq.id === q.id);
    if (idx >= 0) {
      this.internalQuestions[idx] = q;
    } else {
      this.internalQuestions.push(q);
    }
  }

  deleteInternalQuestion(id: string) {
    this.internalQuestions = this.internalQuestions.filter(q => q.id !== id);
  }

  getInternalMetrics(cid: string) {
    const questions = this.internalQuestions.filter(q => q.companyId === cid);
    const feedbacks = this.feedbacks.filter(f => f.companyId === cid);

    return questions.map(q => {
      const responses = feedbacks.map(f => f.internalResponses?.[q.id]).filter(v => v !== undefined && v !== null);
      let avg = 0;
      if (q.type === 'SCALE_5' || q.type === 'SCALE_10') {
        const nums = responses.filter(v => typeof v === 'number') as number[];
        avg = nums.length > 0 ? nums.reduce((a, b) => a + b, 0) / nums.length : 0;
      } else if (q.type === 'YES_NO') {
        const yesCount = responses.filter(v => v === 'SIM').length;
        avg = responses.length > 0 ? (yesCount / responses.length) * 100 : 0;
      }

      return {
        text: q.text,
        type: q.type,
        totalResponses: responses.length,
        average: avg
      };
    });
  }

  updateFeedbackInternalResponses(fid: string, r: any) {
    const fb = this.feedbacks.find(f => f.id === fid);
    if (fb) {
      fb.internalResponses = { ...(fb.internalResponses || {}), ...r };
      return fb;
    }
    return null;
  }

  createCaseFromFeedback(fid: string, cid: string, n: string, un: string, ui: string) {
    const newCase: Case = {
      id: `case-${Date.now()}`,
      feedbackId: fid,
      companyId: cid,
      status: 'OPEN',
      notes: n ? [{ id: `n-${Date.now()}`, text: n, userName: un, userId: ui, createdAt: new Date().toISOString() }] : [],
      updatedAt: new Date().toISOString()
    };
    this.cases.push(newCase);
    return newCase;
  }

  addCaseNote(id: string, ui: string, un: string, t: string) {
    const c = this.cases.find(item => item.id === id);
    if (c) {
      c.notes.unshift({ id: `n-${Date.now()}`, text: t, userId: ui, userName: un, createdAt: new Date().toISOString() });
      c.updatedAt = new Date().toISOString();
    }
  }

  resolveCase(id: string, r: string, un: string, ui: string) {
    const c = this.cases.find(item => item.id === id);
    if (c) {
      c.status = 'RESOLVED';
      c.resolutionText = r;
      c.updatedAt = new Date().toISOString();
      this.addCaseNote(id, ui, un, `Caso Resolvido: ${r}`);
    }
  }

  addContactLog(customerId: string, log: any) {
    const customer = this.customers.find(c => c.id === customerId);
    if (customer) {
      const newLog: ContactLog = {
        id: `log-${Date.now()}`,
        ...log,
        createdAt: new Date().toISOString()
      };
      customer.contactLogs.unshift(newLog);
    }
  }

  addLead(l: any) {
    const newLead: Lead = {
      id: `lead-${Date.now()}`,
      ...l,
      status: 'NEW',
      tasks: [],
      history: [{
        id: `hist-${Date.now()}`,
        text: 'Lead criado no sistema.',
        type: 'NOTE',
        createdAt: new Date().toISOString(),
        userName: 'Sistema'
      }],
      files: [],
      createdAt: new Date().toISOString()
    };
    this.leads.unshift(newLead);
    return newLead;
  }

  getLeads() { return this.leads; }

  updateLead(id: string, data: any, user: string) {
    const idx = this.leads.findIndex(l => l.id === id);
    if (idx >= 0) {
      const old = this.leads[idx];
      if (data.stage && data.stage !== old.stage) {
        this.addLeadNote(id, `Estágio alterado de ${old.stage} para ${data.stage}`, user);
      }
      this.leads[idx] = { ...old, ...data };
      return this.leads[idx];
    }
    return null;
  }

  addLeadNote(leadId: string, text: string, userName: string) {
    const lead = this.leads.find(l => l.id === leadId);
    if (lead) {
      lead.history.unshift({
        id: `note-${Date.now()}`,
        text,
        type: 'NOTE',
        createdAt: new Date().toISOString(),
        userName
      });
    }
  }

  addLeadTask(leadId: string, title: string, dueDate: string) {
    const lead = this.leads.find(l => l.id === leadId);
    if (lead) {
      lead.tasks.unshift({
        id: `task-${Date.now()}`,
        title,
        dueDate,
        completed: false
      });
    }
  }

  toggleLeadTask(leadId: string, taskId: string) {
    const lead = this.leads.find(l => l.id === leadId);
    if (lead) {
      const task = lead.tasks.find(t => t.id === taskId);
      if (task) task.completed = !task.completed;
    }
  }

  createAccountManual(c: any, u: any) {
    const companyId = `c-${Date.now()}`;
    const newCompany: Company = {
      id: companyId,
      trackingCode: c.trackingCode || Math.random().toString(36).substring(2, 8).toUpperCase(),
      experienceScore: 0,
      status: 'ACTIVE',
      plan: 'PRO',
      monthlyValue: 199,
      implementationValue: 500,
      maxEvaluations: 500,
      maxUsers: 10,
      startDate: new Date().toISOString(),
      ...c
    };
    this.companies.push(newCompany);
    this.addCompanyUser(companyId, { ...u, role: UserRole.BUSINESS, staffRole: 'ADMIN' });
    return newCompany;
  }

  updatePassword(id: string, current: string, next: string) {
    const user = this.users.find(u => u.id === id);
    if (user && user.password === current) {
      user.password = next;
      return true;
    }
    return false;
  }

  requestCNPJChange(cid: string, r: any) {
    this.addAdminLog('CNPJ_CHANGE_REQUEST', r.userName, cid, 'Company', `Solicitado: ${r.requestedCNPJ}. Motivo: ${r.reason}`);
    return true;
  }
}

