    const recentFeedbacks = [
      { date: '2026-01-25T20:00:00Z', score: 10, obs: "Simplesmente a melhor pizzaria da região." }
    ];

    recentFeedbacks.forEach((f, i) => {
      this.addFeedback({
        companyId: bellaMGId,
