  // --- LOGGING ---
  private addAdminLog(action: string, by: string, targetId: string, targetName: string, details: string) {
    const log: AdminLog = {
      id: `log-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
      action,
      performedBy: by,
      targetId,
      targetName,
      timestamp: new Date().toISOString(),
      details
    };
    this.adminLogs.unshift(log);
  }

  getAdminLogs() { return this.adminLogs; }

  // --- MASTER ACTIONS ---
  adminUpdateCompany(companyId: string, data: Partial<Company>, adminName: string) {
    const idx = this.companies.findIndex(c => c.id === companyId);
    if (idx >= 0) {
      const old = this.companies[idx];
      this.companies[idx] = { ...old, ...data };
      this.addAdminLog('UPDATE_COMPANY', adminName, companyId, old.name, JSON.stringify(data));
      return this.companies[idx];
    }
    return null;
  }

  adminChangeUserRole(userId: string, newRole: UserRole, adminName: string) {
    const user = this.users.find(u => u.id === userId);
    if (user) {
      const oldRole = user.role;
      user.role = newRole;
      this.addAdminLog('CHANGE_ROLE', adminName, userId, user.name, `De ${oldRole} para ${newRole}`);
      return user;
    }
    return null;
  }

  adminResetPassword(userId: string, newPass: string, adminName: string) {
    const user = this.users.find(u => u.id === userId);
    if (user) {
      user.password = newPass;
      this.addAdminLog('RESET_PASSWORD', adminName, userId, user.name, 'Senha redefinida pelo Master');
      return true;
    }
    return false;
  }

  /**
   * Criação manual de conta provisionada pelo Master
   */
  createAccountManual(companyData: any, userData: any, adminName: string) {
    const trackingCode = companyData.trackingCode || Math.random().toString(36).substring(2, 8).toUpperCase();
    const newCompany: Company = {
      id: `c-${Date.now()}`,
      ...companyData,
      trackingCode,
      experienceScore: 0,
      logo: 'https://picsum.photos/seed/company/200',
      status: 'ACTIVE',
      monthlyValue: companyData.plan === 'PRO' ? 199 : 499,
      implementationValue: 500,
      maxEvaluations: companyData.plan === 'PRO' ? 500 : 5000,
      maxUsers: companyData.plan === 'PRO' ? 10 : 50,
      startDate: new Date().toISOString()
    };
    this.companies.push(newCompany);

    const newUser: User = {
      id: `u-${Date.now()}`,
      ...userData,
      companyId: newCompany.id,
      role: UserRole.BUSINESS,
      staffRole: 'ADMIN',
      isOnboarded: false,
      mustChangePassword: true,
      createdAt: new Date().toISOString()
    };
    this.users.push(newUser);

    this.addAdminLog('CREATE_ACCOUNT_MANUAL', adminName, newCompany.id, newCompany.name, `Conta criada para ${userData.email}`);

    // Adiciona ao CRM como WON imediatamente para impacto financeiro
    this.addLead({
      name: userData.name,
      email: userData.email,
      phone: userData.phone || companyData.phone,
      companyName: companyData.name,
      city: companyData.city,
      employees: companyData.employees,
      monthlyValue: newCompany.monthlyValue,
      implementationValue: newCompany.implementationValue,
      stage: 'WON',
      source: 'Provisionamento Master'
    });

    return { company: newCompany, user: newUser };
  }

  adminProvisionGuardian(name: string, email: string, companyId: string, adminName: string) {
    let user = this.users.find(u => u.email === email);
    if (!user) {
      user = {
        id: `u-${Date.now()}`,
        name,
        email,
        role: UserRole.GUARDIAN,
        isOnboarded: false,
        mustChangePassword: true,
        linkedCompanyIds: [companyId],
        createdAt: new Date().toISOString()
      };
      this.users.push(user);
    } else if (user.role === UserRole.GUARDIAN) {
      if (!user.linkedCompanyIds) user.linkedCompanyIds = [];
      if (!user.linkedCompanyIds.includes(companyId)) user.linkedCompanyIds.push(companyId);
    }
    this.addAdminLog('PROVISION_GUARDIAN', adminName, user.id, user.name, `Guardião vinculado à empresa ${companyId}`);
    return user;
  }

  adminUnlinkGuardianFromCompany(userId: string, companyId: string, adminName: string) {
    const user = this.users.find(u => u.id === userId);
    if (user && user.role === UserRole.GUARDIAN && user.linkedCompanyIds) {
      user.linkedCompanyIds = user.linkedCompanyIds.filter(id => id !== companyId);
      this.addAdminLog('UNLINK_GUARDIAN', adminName, userId, user.name, `Desvinculado da empresa ${companyId}`);
      return true;
    }
    return false;
  }

  adminLinkGuardianToCompany(userId: string, companyId: string, adminName: string) {
    const user = this.users.find(u => u.id === userId);
    if (user && user.role === UserRole.GUARDIAN) {
      if (!user.linkedCompanyIds) user.linkedCompanyIds = [];
      if (!user.linkedCompanyIds.includes(companyId)) {
        user.linkedCompanyIds.push(companyId);
        this.addAdminLog('LINK_GUARDIAN', adminName, userId, user.name, `Vinculado à empresa ${companyId}`);
        return true;
      }
    }
    return false;
  }

  adminRemoveCollaborator(userId: string, adminName: string) {
    const idx = this.users.findIndex(u => u.id === userId);
    if (idx >= 0) {
      const user = this.users[idx];
      this.users.splice(idx, 1);
      this.addAdminLog('REMOVE_USER', adminName, userId, user.name, 'Usuário removido pelo Master');
      return true;
    }
    return false;
  }

  // --- CORE ---
  authenticate(email: string, pass: string): User | null {
    const user = this.users.find(u => u.email === email);
    if (user && user.password === pass) return user;
    return null;
  }

  getCompany(id: string) { return this.companies.find(c => c.id === id); }
  getCompanyByTrackingCode(code: string) { return this.companies.find(c => c.trackingCode === code); }
  getAllCompanies() { return this.companies; }
  getCompanyUsers(cid: string) { return this.users.filter(u => u.companyId === cid); }
  getAllUsers() { return this.users; }

  updateCompany(id: string, data: any) { 
    const idx = this.companies.findIndex(c => c.id === id);
    if (idx >= 0) { this.companies[idx] = { ...this.companies[idx], ...data }; return this.companies[idx]; }
    return null;
  }

  addCompanyUser(cid: string, data: any) {
    const newUser: User = { id: `u-${Date.now()}`, ...data, companyId: cid, role: data.role || UserRole.USER, isOnboarded: true, createdAt: new Date().toISOString() };
    this.users.push(newUser);
    return newUser;
  }

  updateUser(id: string, data: any) {
    const idx = this.users.findIndex(u => u.id === id);
    if (idx >= 0) { this.users[idx] = { ...this.users[idx], ...data }; return this.users[idx]; }
    return null;
  }

  addFeedback(feedback: Omit<Feedback, 'id' | 'createdAt' | 'category' | 'averageScore'>, customDate?: string) {
    const company = this.getCompany(feedback.companyId);
    if (!company) throw new Error("Empresa não encontrada");
    const avg = (feedback.scores.service + feedback.scores.food + feedback.scores.drinks + feedback.scores.structure) / 4;
    let cat: NPSCategory = avg >= 9 ? 'PROMOTER' : avg <= 6 ? 'DETRACTOR' : 'PASSIVE';
    const createdAt = customDate || new Date().toISOString();

    let customer = this.customers.find(c => c.phone === feedback.customerPhone && c.companyId === feedback.companyId);
    if (!customer) {
      customer = { id: `cust-${Date.now()}`, companyId: feedback.companyId, name: feedback.customerName, phone: feedback.customerPhone, email: feedback.email, profile: feedback.profile, firstSeen: createdAt, lastSeen: createdAt, averageScore: avg, totalFeedbacks: 1, category: cat, contactLogs: [] };
      this.customers.push(customer);
    } else {
      customer.lastSeen = createdAt;
      customer.totalFeedbacks += 1;
      const cFbs = this.feedbacks.filter(f => f.customerId === customer?.id);
      customer.averageScore = (cFbs.reduce((acc, f) => acc + f.averageScore, 0) + avg) / (cFbs.length + 1);
      customer.category = customer.averageScore >= 9 ? 'PROMOTER' : customer.averageScore <= 6 ? 'DETRACTOR' : 'PASSIVE';
    }

    const newFeedback: Feedback = { ...feedback, id: `f-${Date.now()}`, createdAt, category: cat, averageScore: avg, customerId: customer.id };
    this.feedbacks.push(newFeedback);
    return newFeedback;
  }

  getFeedbacks(cid?: string) { return cid ? this.feedbacks.filter(f => f.companyId === cid) : this.feedbacks; }
  getCustomers(cid: string) { return this.customers.filter(c => c.companyId === cid); }

  /**
   * FIX: Added missing getCustomerHistory method.
   */
  getCustomerHistory(customerId: string) {
    return this.feedbacks.filter(f => f.customerId === customerId);
  }

  getDashboardStats(cid: string) {
    const fb = this.getFeedbacks(cid);
    return {
      total: fb.length, promoters: fb.filter(f => f.category === 'PROMOTER').length, detractors: fb.filter(f => f.category === 'DETRACTOR').length,
      passives: fb.filter(f => f.category === 'PASSIVE').length, avgScore: Math.round(fb.length > 0 ? (fb.reduce((acc, f) => acc + f.averageScore, 0) / fb.length) * 10 : 0),
      openDetractors: this.cases.filter(c => c.companyId === cid && c.status === 'OPEN').length, resolvedDetractors: this.cases.filter(c => c.companyId === cid && c.status === 'RESOLVED').length,
      catAvg: {
        service: fb.length > 0 ? (fb.reduce((acc, f) => acc + f.scores.service, 0) / fb.length) : 0,
        food: fb.length > 0 ? (fb.reduce((acc, f) => acc + f.scores.food, 0) / fb.length) : 0,
        drinks: fb.length > 0 ? (fb.reduce((acc, f) => acc + f.scores.drinks, 0) / fb.length) : 0,
        structure: fb.length > 0 ? (fb.reduce((acc, f) => acc + f.scores.structure, 0) / fb.length) : 0,
      }
    };
  }

  getMasterFinanceStats() {
    const wonLeads = this.leads.filter(l => l.stage === 'WON');

    // MRR = Somatório de mensalidades de leads WON + Clientes Provisionados
    const mrr = wonLeads.reduce((acc, l) => acc + (l.monthlyValue || 0), 0);
    const setupTotal = wonLeads.reduce((acc, l) => acc + (l.implementationValue || 0), 0);
    const consultingTotal = wonLeads.reduce((acc, l) => acc + (l.consultingValue || 0), 0);

    // Pipeline = Valor potencial em negociação (não WON nem LOST)
    const pipelineRevenue = this.leads
      .filter(l => !['WON', 'LOST'].includes(l.stage))
      .reduce((acc, l) => acc + (l.monthlyValue || 0), 0);

    return {
      mrr,
      arr: mrr * 12,
      totalImplementation: setupTotal,
      totalConsulting: consultingTotal,
      pipelineRevenue,
      activeClients: wonLeads.length,
      leadsCount: this.leads.length,
      conversionRate: (wonLeads.length / (this.leads.length || 1)) * 100,
      arpu: mrr / (wonLeads.length || 1),
      revenueByPlan: {
        'PRO': wonLeads.filter(l => l.monthlyValue < 400).reduce((acc, l) => acc + l.monthlyValue, 0),
        'ENTERPRISE': wonLeads.filter(l => l.monthlyValue >= 400).reduce((acc, l) => acc + l.monthlyValue, 0)
      },
      revenueByStage: {
        'LEAD': this.leads.filter(l => l.stage === 'LEAD').reduce((acc, l) => acc + l.monthlyValue, 0),
        'CONTACTED': this.leads.filter(l => l.stage === 'CONTACTED').reduce((acc, l) => acc + l.monthlyValue, 0),
        'INTEREST': this.leads.filter(l => l.stage === 'INTEREST').reduce((acc, l) => acc + l.monthlyValue, 0),
        'PROPOSAL': this.leads.filter(l => l.stage === 'PROPOSAL').reduce((acc, l) => acc + l.monthlyValue, 0),
      },
      leadsByStage: {
        'LEAD': this.leads.filter(l => l.stage === 'LEAD').length,
        'CONTACTED': this.leads.filter(l => l.stage === 'CONTACTED').length,
        'INTEREST': this.leads.filter(l => l.stage === 'INTEREST').length,
        'PROPOSAL': this.leads.filter(l => l.stage === 'PROPOSAL').length,
      }
    };
  }

  getMasterCSStats() {
    const globalScore = this.companies.reduce((acc, c) => acc + c.experienceScore, 0) / (this.companies.length || 1);
    return { globalScore: Math.round(globalScore), distribution: { promoters: 70, passives: 20, detractors: 10 }, ranking: this.companies.map(c => ({ id: c.id, name: c.name, city: c.city, segment: c.category, nps: c.experienceScore, status: 'PROMOTER' as any })), atRisk: [], segmentAverages: [], trendData: [], totalEvaluations: this.feedbacks.length };
  }

  getInternalQuestions(cid: string, active = true) { return this.internalQuestions.filter(q => q.companyId === cid && (!active || q.active)); }
  saveInternalQuestion(q: InternalQuestion) {
    const idx = this.internalQuestions.findIndex(iq => iq.id === q.id);
    idx >= 0 ? this.internalQuestions[idx] = q : this.internalQuestions.push(q);
  }
  deleteInternalQuestion(id: string) { this.internalQuestions = this.internalQuestions.filter(q => q.id !== id); }

  getInternalMetrics(cid: string) {
    return this.internalQuestions.filter(q => q.companyId === cid).map(q => {
      const resp = this.feedbacks.filter(f => f.companyId === cid).map(f => f.internalResponses?.[q.id]).filter(v => v !== undefined);
      let avg = 0;
      if (q.type === 'SCALE_5' || q.type === 'SCALE_10') avg = resp.length ? resp.reduce((a, b) => a + b, 0) / resp.length : 0;
      else if (q.type === 'YES_NO') avg = resp.length ? (resp.filter(v => v === 'SIM').length / resp.length) * 100 : 0;
      return { text: q.text, type: q.type, totalResponses: resp.length, average: avg };
    });
  }

  updateFeedbackInternalResponses(fid: string, r: any) {
    const fb = this.feedbacks.find(f => f.id === fid);
    if (fb) { fb.internalResponses = { ...(fb.internalResponses || {}), ...r }; return fb; }
    return null;
  }

  /**
   * FIX: Added missing getCases method.
   */
  getCases(cid: string) {
    return this.cases.filter(c => c.companyId === cid);
  }

  /**
   * FIX: Added missing getCaseForFeedback method.
   */
  getCaseForFeedback(feedbackId: string) {
    return this.cases.find(c => c.feedbackId === feedbackId);
  }

  createCaseFromFeedback(fid: string, cid: string, n: string, un: string, ui: string) {
    const newCase: Case = { id: `case-${Date.now()}`, feedbackId: fid, companyId: cid, status: 'OPEN', notes: n ? [{ id: `n-${Date.now()}`, text: n, userName: un, userId: ui, createdAt: new Date().toISOString() }] : [], updatedAt: new Date().toISOString() };
    this.cases.push(newCase);
    return newCase;
  }

  addCaseNote(id: string, ui: string, un: string, t: string) {
    const c = this.cases.find(item => item.id === id);
    if (c) { c.notes.unshift({ id: `n-${Date.now()}`, text: t, userId: ui, userName: un, createdAt: new Date().toISOString() }); c.updatedAt = new Date().toISOString(); }
  }

  resolveCase(id: string, r: string, un: string, ui: string) {
    const c = this.cases.find(item => item.id === id);
    if (c) { c.status = 'RESOLVED'; c.resolutionText = r; c.updatedAt = new Date().toISOString(); this.addCaseNote(id, ui, un, `Caso Resolvido: ${r}`); }
  }

  addContactLog(customerId: string, log: any) {
    const customer = this.customers.find(c => c.id === customerId);
    if (customer) customer.contactLogs.unshift({ id: `log-${Date.now()}`, ...log, createdAt: new Date().toISOString() });
  }

  addLead(l: any) {
    const newLead: Lead = {
      id: `lead-${Date.now()}`,
      stage: 'LEAD',
      temperature: 'NEW',
      monthlyValue: 0,
      implementationValue: 0,
      consultingValue: 0,
      value: 0,
      contractStatus: 'NONE',
      source: 'Desconhecido',
      ...l,
      status: 'NEW',
      tasks: [],
      history: [{ id: `h-${Date.now()}`, text: `Lead criado via ${l.source || 'Sistema'}.`, type: 'NOTE', createdAt: new Date().toISOString(), userName: 'Sistema' }],
      files: [],
      createdAt: new Date().toISOString()
    };
    this.leads.unshift(newLead);
    return newLead;
  }

  getLeads() { return this.leads; }
  updateLead(id: string, data: any, user: string) {
    const idx = this.leads.findIndex(l => l.id === id);
    if (idx >= 0) {
      const old = this.leads[idx];
      if (data.stage && data.stage !== old.stage) {
        this.addLeadNote(id, `Estágio alterado de ${old.stage} para ${data.stage}`, user);
      }
      this.leads[idx] = { ...old, ...data };
      return this.leads[idx];
    }
    return null;
  }

  addLeadNote(leadId: string, text: string, userName: string) {
    const lead = this.leads.find(l => l.id === leadId);
    if (lead) lead.history.unshift({ id: `note-${Date.now()}`, text, type: 'NOTE', createdAt: new Date().toISOString(), userName });
  }

  addLeadTask(leadId: string, title: string, dueDate: string) {
    const lead = this.leads.find(l => l.id === leadId);
    if (lead) lead.tasks.unshift({ id: `t-${Date.now()}`, title, dueDate, completed: false });
  }

  toggleLeadTask(leadId: string, taskId: string) {
    const lead = this.leads.find(l => l.id === leadId);
    if (lead) { const t = lead.tasks.find(tk => tk.id === taskId); if (t) t.completed = !t.completed; }
  }

  deleteLead(id: string) { this.leads = this.leads.filter(l => l.id !== id); }

  requestCNPJChange(cid: string, r: any) { this.addAdminLog('CNPJ_CHANGE_REQUEST', r.userName, cid, 'Company', `Solicitado: ${r.requestedCNPJ}. Motivo: ${r.reason}`); return true; }
  updatePassword(id: string, curr: string, next: string) { const u = this.users.find(item => item.id === id); if (u && u.password === curr) { u.password = next; return true; } return false; }

  /**
   * FIX: Added missing getBenchmarkingData method.
   */
  getBenchmarkingData(companyId: string, segment?: string) {
    const company = this.getCompany(companyId);
    if (!company) return null;
    const targetSegment = segment || company.category;
    const segmentCompanies = this.companies.filter(c => c.category === targetSegment);
    const marketAverage = segmentCompanies.length > 0 ? segmentCompanies.reduce((acc, c) => acc + c.experienceScore, 0) / segmentCompanies.length : 0;
    const sortedRanking = [...segmentCompanies].sort((a, b) => b.experienceScore - a.experienceScore);
    const position = sortedRanking.findIndex(c => c.id === companyId) + 1;
    const percentile = segmentCompanies.length > 0 ? Math.round(((segmentCompanies.length - position) / segmentCompanies.length) * 100) : 0;

    return {
      currentScore: company.experienceScore,
      marketAverage: Math.round(marketAverage),
      percentile,
      position,
      totalInSegment: segmentCompanies.length,
      ranking: sortedRanking.map(c => ({ name: c.name, score: c.experienceScore })),
      marketCatAvg: { service: 8.5, food: 8.8, drinks: 8.2, structure: 8.0 }
    };
  }

  /**
   * FIX: Added missing getBIData method.
   */
  getBIData(companyId: string, timeRange: number) {
    const feedbacks = this.getFeedbacks(companyId);
    return {
      rawSummary: {
        totalEvaluations: feedbacks.length,
        detractorsCount: feedbacks.filter(f => f.category === 'DETRACTOR').length,
        promotersCount: feedbacks.filter(f => f.category === 'PROMOTER').length,
        averageScores: { 
          service: feedbacks.length > 0 ? (feedbacks.reduce((acc, f) => acc + f.scores.service, 0) / feedbacks.length).toFixed(1) : 0, 
          food: feedbacks.length > 0 ? (feedbacks.reduce((acc, f) => acc + f.scores.food, 0) / feedbacks.length).toFixed(1) : 0, 
          drinks: feedbacks.length > 0 ? (feedbacks.reduce((acc, f) => acc + f.scores.drinks, 0) / feedbacks.length).toFixed(1) : 0, 
          structure: feedbacks.length > 0 ? (feedbacks.reduce((acc, f) => acc + f.scores.structure, 0) / feedbacks.length).toFixed(1) : 0 
        },
        recentComments: feedbacks.slice(0, 5).map(f => f.observation).filter(o => o)
      },
      sentiments: {
        positive: ['Sabor', 'Atendimento', 'Ambiente', 'Rápido', 'Cortesia', 'Preço'],
        negative: ['Demora', 'Barulho', 'Fila', 'Ar-condicionado', 'Confusão']
      },
      trendData: Array.from({ length: 7 }, (_, i) => ({ date: `D${i+1}`, score: 70 + Math.random() * 20 })),
      prediction: 88,
      heatmap: Array.from({ length: 7 }, () => Array.from({ length: 24 }, () => Math.floor(Math.random() * 10))),
      impacts: [
        { category: 'Atendimento', impact: 15 },
        { category: 'Tempo de Espera', impact: 12 },
        { category: 'Temperatura Comida', impact: 8 }
      ]
    };
  }
}

