        <MetricCard title="Promotores" value={stats.promoters} subValue={stats.total > 0 ? `${Math.round((stats.promoters/stats.total)*100)}% do total` : '0%'} icon={Smile} color="bg-emerald-500" trend={12} />
        <MetricCard title="Passivos" value={stats.passives} subValue={stats.total > 0 ? `${Math.round((stats.passives/stats.total)*100)}% do total` : '0%'} icon={Meh} color="bg-amber-500" trend={-3} />
        <MetricCard title="Detratores (Abertos)" value={stats.openDetractors} subValue="Casos urgentes" icon={Frown} color="bg-red-500" trend={8} />
        <MetricCard title="Casos Resolvidos" value={stats.resolvedDetractors} subValue="Eficiência de gestão" icon={CheckCircle2} color="bg-blue-500" trend={24} />
      </div>

      {/* Evolution Graph */}
      <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
          <div>
            <h3 className="text-xl font-bold text-slate-800">Evolução Semanal</h3>
            <p className="text-sm text-slate-500">Tendência do Score de Experiência nos últimos 7 dias</p>
          </div>
          <div className="flex bg-slate-100 p-1 rounded-xl">
            <button className="px-4 py-1.5 text-xs font-bold bg-white text-slate-700 shadow-sm rounded-lg">7 dias</button>
            <button className="px-4 py-1.5 text-xs font-bold text-slate-400 hover:text-slate-600 transition-colors">30 dias</button>
          </div>
        </div>
        <div className="h-[300px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={chartData}>
              <defs>
                <linearGradient id="colorScore" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#0047a7" stopOpacity={0.1}/>
                  <stop offset="95%" stopColor="#0047a7" stopOpacity={0}/>
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 12, fontWeight: 600, fill: '#94a3b8'}} />
              <YAxis domain={[0, 100]} axisLine={false} tickLine={false} tick={{fontSize: 12, fontWeight: 600, fill: '#94a3b8'}} />
              <Tooltip 
                contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}}
                labelStyle={{fontWeight: 700, color: '#1e293b'}}
              />
              <Area type="monotone" dataKey="score" stroke="#0047a7" strokeWidth={4} fillOpacity={1} fill="url(#colorScore)" />
            </AreaChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { dataStore } from '../services/dataStore';
import { Case, CaseStatus, Feedback, User } from '../types';
import { 
  AlertCircle, 
  Clock, 
  CheckCircle2, 
  MoreVertical, 
  User as UserIcon,
  MessageSquare,
  ArrowRight
} from 'lucide-react';

interface CaseManagementProps {
  companyId: string;
  currentUser: User;
}

const CaseManagement: React.FC<CaseManagementProps> = ({ companyId, currentUser }) => {
  const [filter, setFilter] = useState<CaseStatus | 'ALL'>('ALL');
  const [selectedCase, setSelectedCase] = useState<Case | null>(null);
  const [resolutionText, setResolutionText] = useState('');

  const cases = dataStore.getCases(companyId);
  const feedbacks = dataStore.getFeedbacks(companyId);

  const filteredCases = filter === 'ALL' ? cases : cases.filter(c => c.status === filter);

  const getFeedbackForCase = (feedbackId: string) => feedbacks.find(f => f.id === feedbackId);

  const handleResolve = () => {
    if (selectedCase && resolutionText.trim()) {
      dataStore.resolveCase(selectedCase.id, resolutionText, currentUser.name, currentUser.id);
      setSelectedCase(null);
      setResolutionText('');
    }
  };

  const StatusBadge = ({ status }: { status: CaseStatus }) => {
    const styles = {
      OPEN: 'bg-red-50 text-red-600 border-red-100',
      IN_PROGRESS: 'bg-amber-50 text-amber-600 border-amber-100',
      RESOLVED: 'bg-emerald-50 text-emerald-600 border-emerald-100'
    };
    const labels = {
      OPEN: 'Aberto',
      IN_PROGRESS: 'Em Atendimento',
      RESOLVED: 'Resolvido'
    };
    return (
      <span className={`px-2.5 py-0.5 rounded-full text-[10px] font-black uppercase tracking-wider border ${styles[status]}`}>
        {labels[status]}
      </span>
    );
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      {/* Cases List */}
      <div className="lg:col-span-2 space-y-6">
        <div className="bg-white rounded-3xl p-6 border border-slate-100 shadow-sm">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
            <h3 className="text-lg font-bold text-slate-800">Fila de Atendimento</h3>
            <div className="flex bg-slate-100 p-1 rounded-xl">
              {['ALL', 'OPEN', 'RESOLVED'].map(s => (
                <button
                  key={s}
                  onClick={() => setFilter(s as any)}
                  className={`px-4 py-1.5 text-xs font-bold rounded-lg transition-all ${
                    filter === s ? 'bg-white text-slate-700 shadow-sm' : 'text-slate-400 hover:text-slate-600'
                  }`}
                >
                  {s === 'ALL' ? 'Todos' : s === 'OPEN' ? 'Abertos' : 'Resolvidos'}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-3">
            {filteredCases.length === 0 ? (
              <div className="py-12 text-center text-slate-400 font-medium">Nenhum caso encontrado para este filtro.</div>
            ) : (
              filteredCases.map(c => {
                const fb = getFeedbackForCase(c.feedbackId);
                return (
                  <div 
                    key={c.id} 
                    onClick={() => setSelectedCase(c)}
                    className={`p-5 rounded-2xl border transition-all cursor-pointer hover:border-primary/50 hover:shadow-md ${
                      selectedCase?.id === c.id ? 'border-primary bg-primary/5 shadow-inner' : 'border-slate-100 bg-white'
                    }`}
                  >
                    <div className="flex justify-between items-start">
                      <div className="flex items-center space-x-4">
                        <div className="w-12 h-12 rounded-xl bg-red-100 flex items-center justify-center text-red-600 font-bold">
                          {fb?.customerName.substring(0, 2).toUpperCase()}
                        </div>
                        <div>
                          <p className="font-bold text-slate-800">{fb?.customerName}</p>
                          <p className="text-xs text-slate-400 font-medium">{fb?.customerPhone}</p>
                        </div>
                      </div>
                      <StatusBadge status={c.status} />
                    </div>
                    <p className="mt-4 text-sm text-slate-600 line-clamp-2 italic">"{fb?.observation}"</p>
                    <div className="mt-4 pt-4 border-t border-slate-100 flex justify-between items-center">
                      <div className="flex items-center space-x-2 text-xs font-bold text-slate-400">
                        <Clock className="w-3 h-3" />
                        <span>Há {Math.floor(Math.random() * 5) + 1} horas</span>
                      </div>
                      <button className="text-primary font-bold text-xs flex items-center space-x-1">
                        <span>Ver Detalhes</span>
                        <ArrowRight className="w-3 h-3" />
                      </button>
                    </div>
                  </div>
                );
              })
            )}
          </div>
        </div>
      </div>

      {/* Detail View / Resolution */}
      <div className="lg:col-span-1">
        {selectedCase ? (
          <div className="bg-white rounded-3xl p-8 border border-slate-100 shadow-xl sticky top-8">
            <div className="flex justify-between items-start mb-6">
              <h3 className="text-xl font-bold text-slate-800">Detalhes do Caso</h3>
              <button onClick={() => setSelectedCase(null)} className="text-slate-400 hover:text-slate-600">&times;</button>
            </div>

            <div className="space-y-6">
              <div className="bg-slate-50 p-4 rounded-2xl">
                <p className="text-[10px] font-black uppercase text-slate-400 mb-2 tracking-widest">Avaliação Origem</p>
                <div className="flex items-center justify-between mb-2">
                  <span className="text-sm font-bold text-slate-700">Média:</span>
                  <span className="text-sm font-black text-red-500">{(getFeedbackForCase(selectedCase.feedbackId)?.averageScore || 0).toFixed(1)} / 10</span>
                </div>
                <div className="grid grid-cols-2 gap-2">
                  {Object.entries(getFeedbackForCase(selectedCase.feedbackId)?.scores || {}).map(([key, val]) => (
                    <div key={key} className="flex justify-between text-[10px] uppercase font-bold text-slate-500 bg-white p-1.5 rounded-lg border border-slate-100">
                      <span>{key}</span>
                      <span>{val}</span>
                    </div>
                  ))}
                </div>
              </div>

              <div>
                <p className="text-[10px] font-black uppercase text-slate-400 mb-2 tracking-widest">Feedback do Cliente</p>
                <div className="bg-red-50 p-4 rounded-2xl border border-red-100 italic text-sm text-slate-700">
                  "{getFeedbackForCase(selectedCase.feedbackId)?.observation}"
                </div>
              </div>

              {selectedCase.status === 'RESOLVED' ? (
                <div className="space-y-4">
                  <div className="bg-emerald-50 p-4 rounded-2xl border border-emerald-100">
                    <p className="text-[10px] font-black uppercase text-emerald-600 mb-2 tracking-widest flex items-center gap-1">
                      <CheckCircle2 className="w-3 h-3" /> Resolução
                    </p>
                    <p className="text-sm text-slate-700">{selectedCase.resolutionText}</p>
                  </div>
                </div>
              ) : (
                <div className="space-y-4">
                  <div>
                    <label className="text-[10px] font-black uppercase text-slate-400 mb-2 block tracking-widest">Ação Tomada (Obrigatório)</label>
                    <textarea
                      value={resolutionText}
                      onChange={(e) => setResolutionText(e.target.value)}
                      placeholder="Descreva como resolveu este problema..."
                      className="w-full h-32 p-4 rounded-2xl bg-slate-50 border border-slate-200 text-sm outline-none focus:border-primary focus:ring-2 focus:ring-primary/20 transition-all text-slate-900"
                    ></textarea>
                  </div>
                  <button 
                    onClick={handleResolve}
                    disabled={!resolutionText.trim()}
                    className="w-full py-4 bg-primary text-white font-bold rounded-2xl hover:bg-[#003680] shadow-lg shadow-primary/20 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    Marcar como Resolvido
                  </button>
                </div>
              )}
            </div>
          </div>
        ) : (
          <div className="bg-white rounded-3xl p-12 border border-dashed border-slate-300 flex flex-col items-center justify-center text-center">
            <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center text-slate-300 mb-4">
              <MessageSquare className="w-8 h-8" />
            </div>
            <p className="text-sm font-bold text-slate-500">Selecione um caso ao lado para visualizar os detalhes e tomar uma ação.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default CaseManagement;

import React, { useState, useMemo } from 'react';
import { Company, InternalQuestion, Feedback } from '../types';
import { dataStore } from '../services/dataStore';
import { ChevronRight, ChevronLeft, Send, CheckCircle2, AlertCircle, LogOut, Award, ShieldCheck, Star } from 'lucide-react';

interface FeedbackFormProps {
  company: Company;
  onFinished: () => void;
  onBack?: () => void;
}

const FeedbackForm: React.FC<FeedbackFormProps> = ({ company, onFinished, onBack }) => {
  const [step, setStep] = useState(1);
  const [showValidation, setShowValidation] = useState(false);

  // O formulário é DINÂMICO baseado no que a empresa configurou como público
  const internalQuestions = useMemo(() => 
    dataStore.getInternalQuestions(company.id).filter(q => q.isPublic), 
  [company.id]);

  const [formData, setFormData] = useState({
    name: '',
    surname: '',
    phone: '',
    email: '',
    howKnown: '',
    service: 0, 
    food: 0,    
    drinks: 0,  
    structure: 0, 
    profile: 'family' as any,
    observation: '',
    internalResponses: {} as any
  });
  const [submitted, setSubmitted] = useState(false);

  const isStep1Valid = formData.name.trim() !== '' && formData.surname.trim() !== '' && formData.phone.trim() !== '';

  const isStep2Valid = useMemo(() => {
    const coreRatingsDone = formData.service > 0 && formData.food > 0 && formData.drinks > 0 && formData.structure > 0;

    const requiredInternalDone = internalQuestions
      .filter(q => q.required)
      .every(q => {
        const resp = formData.internalResponses[q.id];
        if (q.type === 'TEXT') return resp && resp.trim() !== '';
        if (q.type === 'SCALE_5' || q.type === 'SCALE_10') return resp > 0;
        if (q.type === 'YES_NO') return resp !== undefined && resp !== null;
        return true;
      });

    return coreRatingsDone && requiredInternalDone;
  }, [formData, internalQuestions]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (step === 1) {
      if (!isStep1Valid) {
        setShowValidation(true);
        return;
      }
      setStep(2);
      setShowValidation(false);
      window.scrollTo({ top: 0, behavior: 'smooth' });
      return;
    }

    if (!isStep2Valid) {
      setShowValidation(true);
      return;
    }

    // Salva o feedback com o trackingCode como CHAVE DE PROPRIEDADE (Ownership Key)
    dataStore.addFeedback({
      companyId: company.id,
      companyTrackingCode: company.trackingCode, // CORE: Roteamento definitivo
      customerId: '', 
      customerName: `${formData.name} ${formData.surname}`,
      customerPhone: formData.phone,
      howKnown: formData.howKnown,
      scores: {
        service: formData.service,
        food: formData.food,
        drinks: formData.drinks,
        structure: formData.structure
      },
      internalResponses: formData.internalResponses,
      profile: formData.profile,
      observation: formData.observation,
      email: formData.email
    });

    setSubmitted(true);
  };

  const handleInternalResponse = (qId: string, value: any) => {
    setFormData({
      ...formData,
      internalResponses: { ...formData.internalResponses, [qId]: value }
    });
  };

  const RatingDots = ({ value, onChange, label, max = 10, isError = false }: any) => {
    const [hover, setHover] = useState(0);
    const activeValue = hover || value;

    const getColorClass = (val: number) => {
      if (val === 0) return 'bg-transparent';
      if (val <= 3) return 'bg-red-500';
      if (val <= 6) return 'bg-yellow-400';
      return 'bg-emerald-500';
    };

    const activeColor = getColorClass(activeValue);

    return (
      <div className={`space-y-4 p-6 rounded-[2rem] transition-all border ${isError ? 'bg-red-50 border-red-200 animate-pulse' : 'bg-slate-50 border-slate-100'}`}>
        <div className="flex justify-between items-center">
          <label className="text-xs font-black text-slate-800 uppercase tracking-wider">{label}</label>
          <span className={`text-xl font-black px-3 py-1 rounded-xl min-w-[3rem] text-center ${
            activeValue === 0 ? 'text-slate-300' :
            activeValue <= 3 ? 'text-red-600 bg-red-50' : 
            activeValue <= 6 ? 'text-yellow-600 bg-yellow-50' : 
            'text-emerald-600 bg-emerald-50'
          }`}>
            {activeValue === 0 ? '—' : activeValue}
          </span>
        </div>
        <div className="flex justify-between gap-1">
          {Array.from({ length: max }).map((_, i) => {
            const dotValue = i + 1;
            const isFilled = dotValue <= activeValue;
            return (
              <button
                key={dotValue}
                type="button"
                onMouseEnter={() => setHover(dotValue)}
                onMouseLeave={() => setHover(0)}
                onClick={() => {
                  onChange(dotValue);
                  setShowValidation(false);
                }}
                className={`
                  flex-1 h-10 rounded-full transition-all duration-200 border-2
                  ${isFilled && activeValue > 0 
                    ? `${activeColor} border-transparent scale-105` 
                    : 'bg-white border-slate-200 hover:border-slate-300'}
                `}
              />
            );
          })}
        </div>
        <div className="flex justify-between px-1 text-[8px] font-black text-slate-300 uppercase tracking-widest">
          <span>Ruim</span>
          <span>Excelente</span>
        </div>
      </div>
    );
  };

  if (submitted) {
    return (
      <div className="min-h-screen bg-[#001529] flex items-center justify-center p-6">
        <div className="max-w-md w-full bg-white rounded-[3.5rem] shadow-2xl p-16 text-center animate-in zoom-in duration-500">
          <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-[2.5rem] flex items-center justify-center mx-auto mb-8 shadow-inner">
            <CheckCircle2 className="w-12 h-12" />
          </div>
          <h2 className="text-3xl font-black text-slate-900 mb-4">Feedback Enviado!</h2>
          <p className="text-slate-500 mb-10 font-medium text-sm leading-relaxed">Sua avaliação para <span className="text-primary font-bold">{company.name}</span> foi registrada com sucesso sob o protocolo <span className="font-mono text-primary font-bold">{company.trackingCode}</span>.</p>
          <button 
            onClick={onFinished}
            className="w-full py-5 bg-primary text-white font-black rounded-3xl shadow-xl uppercase tracking-widest text-xs"
          >
            Concluir
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-100 flex flex-col font-inter pb-20">
      <header className="bg-white border-b border-slate-100 p-12 flex flex-col items-center sticky top-0 z-50">
        <div className="w-24 h-24 rounded-[2rem] border-4 border-white shadow-2xl overflow-hidden -mt-24 mb-6 bg-white">
          <img src={company.logo} alt={company.name} className="w-full h-full object-cover" />
        </div>
        <div className="text-center">
          <h1 className="text-2xl font-black text-slate-900 tracking-tight">{company.name}</h1>
          <div className="flex items-center justify-center gap-2 mt-2">
            <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest bg-slate-50 px-3 py-1 rounded-full border border-slate-100">CÓDIGO: {company.trackingCode}</span>
          </div>
        </div>
      </header>

      <div className="flex-1 max-w-2xl w-full mx-auto px-6 mt-10">
        <div className="bg-white rounded-[3.5rem] shadow-2xl overflow-hidden border border-white">
          <div className="h-2 w-full bg-slate-50">
            <div className="h-full bg-primary transition-all duration-1000" style={{ width: `${step * 50}%` }}></div>
          </div>

          <form onSubmit={handleSubmit} className="p-12 space-y-12">
            {step === 1 ? (
              <div className="space-y-10 animate-in slide-in-from-right duration-500">
                <div className="space-y-2">
                  <h2 className="text-3xl font-black text-slate-900">Olá!</h2>
                  <p className="text-slate-400 font-medium">Sua experiência é fundamental para evoluirmos.</p>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Nome *</label>
                    <input 
                      required
                      type="text" 
                      className={`w-full p-5 bg-slate-50 border rounded-3xl outline-none focus:border-primary font-bold text-slate-900 transition-all ${showValidation && !formData.name ? 'border-red-300 ring-4 ring-red-50' : 'border-slate-100'}`}
                      value={formData.name}
                      onChange={(e) => setFormData({...formData, name: e.target.value})}
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Sobrenome *</label>
                    <input 
                      required
                      type="text" 
                      className={`w-full p-5 bg-slate-50 border rounded-3xl outline-none focus:border-primary font-bold text-slate-900 transition-all ${showValidation && !formData.surname ? 'border-red-300 ring-4 ring-red-50' : 'border-slate-100'}`}
                      value={formData.surname}
                      onChange={(e) => setFormData({...formData, surname: e.target.value})}
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">WhatsApp *</label>
                  <input 
                    required
                    type="tel" 
                    placeholder="(00) 00000-0000"
                    className={`w-full p-5 bg-slate-50 border rounded-3xl outline-none focus:border-primary font-bold text-slate-900 transition-all ${showValidation && !formData.phone ? 'border-red-300 ring-4 ring-red-50' : 'border-slate-100'}`}
                    value={formData.phone}
                    onChange={(e) => setFormData({...formData, phone: e.target.value})}
                  />
                </div>

                <div className="space-y-4">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Como você se identifica?</label>
                  <div className="grid grid-cols-2 gap-3">
                    {[
                      { id: 'family', label: 'Em Família' },
                      { id: 'friends', label: 'Com Amigos' },
                      { id: 'couple', label: 'Em Casal' },
                      { id: 'kids', label: 'Com Crianças' }
                    ].map(p => (
                      <button
                        key={p.id}
                        type="button"
                        onClick={() => setFormData({...formData, profile: p.id as any})}
                        className={`p-5 rounded-[2rem] border-2 font-black text-[10px] uppercase tracking-widest transition-all ${
                          formData.profile === p.id 
                            ? 'bg-primary border-primary text-white shadow-xl' 
                            : 'bg-white border-slate-100 text-slate-400 hover:border-slate-200'
                        }`}
                      >
                        {p.label}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="space-y-4 pt-4">
                  <button 
                    type="submit"
                    className={`w-full py-6 text-white font-black rounded-3xl shadow-2xl flex items-center justify-center gap-3 transition-all uppercase tracking-widest text-xs ${isStep1Valid ? 'bg-primary hover:-translate-y-1' : 'bg-slate-300 cursor-not-allowed opacity-50'}`}
                  >
                    Próxima Etapa <ChevronRight className="w-5 h-5" />
                  </button>

                  {onBack && (
                    <button 
                      type="button"
                      onClick={onBack}
                      className="w-full py-4 text-slate-300 font-black text-[9px] uppercase tracking-[0.3em] hover:text-primary transition-all flex items-center justify-center gap-2"
                    >
                      <LogOut className="w-4 h-4" /> Cancelar Avaliação
                    </button>
                  )}
                </div>
              </div>
            ) : (
              <div className="space-y-12 animate-in slide-in-from-right duration-500">
                <div className="space-y-8">
                  <div className="flex items-center gap-3">
                    <Star className="w-5 h-5 text-primary" />
                    <h3 className="text-xs font-black uppercase text-slate-400 tracking-[0.2em]">Avaliação Geral</h3>
                  </div>
                  <RatingDots 
                    label="Qualidade do Serviço" 
                    value={formData.service} 
                    onChange={(v: number) => setFormData({...formData, service: v})} 
                    isError={showValidation && formData.service === 0}
                  />
                  <RatingDots 
                    label="Qualidade da Comida" 
                    value={formData.food} 
                    onChange={(v: number) => setFormData({...formData, food: v})} 
                    isError={showValidation && formData.food === 0}
                  />
                  <RatingDots 
                    label="Qualidade das Bebidas" 
                    value={formData.drinks} 
                    onChange={(v: number) => setFormData({...formData, drinks: v})} 
                    isError={showValidation && formData.drinks === 0}
                  />
                  <RatingDots 
                    label="Estrutura e Ambiente" 
                    value={formData.structure} 
                    onChange={(v: number) => setFormData({...formData, structure: v})} 
                    isError={showValidation && formData.structure === 0}
                  />
                </div>

                {/* Perguntas DINÂMICAS do Negócio via Tracking Code */}
                {internalQuestions.length > 0 && (
                  <div className="space-y-10 pt-10 border-t border-slate-100">
                    <div className="flex items-center gap-3">
                      <Award className="w-5 h-5 text-primary" />
                      <h3 className="text-xs font-black uppercase text-slate-400 tracking-[0.2em]">Exclusivo: {company.name}</h3>
                    </div>
                    {internalQuestions.map(q => {
                      const resp = formData.internalResponses[q.id];
                      const isMissing = q.required && (resp === undefined || resp === null || resp === 0 || (typeof resp === 'string' && resp.trim() === ''));

                      return (
                        <div key={q.id} className="space-y-4">
                          {q.type === 'YES_NO' && (
                            <div className={`space-y-6 p-8 rounded-[2rem] transition-all border ${showValidation && isMissing ? 'bg-red-50 border-red-200 animate-pulse' : 'bg-slate-50 border-slate-100'}`}>
                              <label className="text-xs font-black text-slate-800 uppercase tracking-tight leading-relaxed">{q.text} {q.required && '*'}</label>
                              <div className="flex gap-4">
                                {['SIM', 'NÃO'].map(opt => (
                                  <button
                                    key={opt}
                                    type="button"
                                    onClick={() => handleInternalResponse(q.id, opt)}
                                    className={`flex-1 py-5 rounded-[1.5rem] border-2 font-black text-xs transition-all uppercase tracking-widest ${
                                      formData.internalResponses[q.id] === opt 
                                        ? 'bg-primary border-primary text-white shadow-xl' 
                                        : 'bg-white border-slate-200 text-slate-400 hover:border-slate-300'
                                    }`}
                                  >
                                    {opt}
                                  </button>
                                ))}
                              </div>
                            </div>
                          )}

                          {(q.type === 'SCALE_5' || q.type === 'SCALE_10') && (
                            <RatingDots 
                              max={q.type === 'SCALE_5' ? 5 : 10}
                              label={q.text + (q.required ? ' *' : '')}
                              value={formData.internalResponses[q.id] || 0} 
                              onChange={(v: number) => handleInternalResponse(q.id, v)} 
                              isError={showValidation && isMissing}
                            />
                          )}

                          {q.type === 'TEXT' && (
                            <div className={`space-y-4 p-8 rounded-[2rem] transition-all border ${showValidation && isMissing ? 'bg-red-50 border-red-200 animate-pulse' : 'bg-slate-50 border-slate-100'}`}>
                               <label className="text-xs font-black text-slate-800 uppercase tracking-tight">{q.text} {q.required && '*'}</label>
                              <textarea 
                                required={q.required}
                                className={`w-full h-32 p-6 bg-white border rounded-3xl outline-none focus:border-primary font-medium text-sm text-slate-900 shadow-inner ${showValidation && isMissing ? 'border-red-300' : 'border-slate-200'}`}
                                placeholder="Sua mensagem..."
                                value={formData.internalResponses[q.id] || ''}
                                onChange={(e) => handleInternalResponse(q.id, e.target.value)}
                              />
                            </div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                )}

                <div className="space-y-4 pt-10 border-t border-slate-100">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Observações Finais</label>
                  <textarea 
                    className="w-full h-40 p-8 bg-slate-50 border border-slate-100 rounded-[2.5rem] outline-none focus:border-primary font-medium text-sm text-slate-900 shadow-inner"
                    placeholder="Algo que gostaria de destacar positivamente ou sugerir melhoria?"
                    value={formData.observation}
                    onChange={(e) => setFormData({...formData, observation: e.target.value})}
                  />
                </div>

                {showValidation && !isStep2Valid && (
                  <div className="p-6 bg-red-50 border border-red-100 rounded-[2rem] flex items-center gap-4 text-red-600 animate-in slide-in-from-top">
                    <AlertCircle className="w-6 h-6 flex-shrink-0" />
                    <p className="text-xs font-black uppercase tracking-wider">Preencha todos os campos obrigatórios para continuar.</p>
                  </div>
                )}

                <div className="flex gap-6">
                  <button type="button" onClick={() => setStep(1)} className="flex-1 py-6 bg-slate-100 text-slate-400 font-black rounded-3xl hover:bg-slate-200 transition-all uppercase tracking-widest text-xs">Anterior</button>
                  <button 
                    type="submit" 
                    className={`flex-[2] py-6 text-white font-black rounded-3xl shadow-2xl flex items-center justify-center gap-3 transition-all uppercase tracking-widest text-xs ${isStep2Valid ? 'bg-primary shadow-primary/30 hover:-translate-y-1' : 'bg-slate-300 cursor-not-allowed opacity-50'}`}
                  >
                    Finalizar Avaliação <Send className="w-5 h-5" />
                  </button>
                </div>
              </div>
            )}
          </form>
        </div>
      </div>
    </div>
  );
};

export default FeedbackForm;

import React, { useState, useMemo } from 'react';
import { dataStore } from '../services/dataStore';
import { Feedback, NPSCategory, User, Case, InternalQuestion } from '../types';
import { 
  Search, 
  ChevronRight, 
  Share2, 
  Star, 
  User as UserIcon,
  Phone,
  Mail,
  MapPin,
  ExternalLink,
  Copy,
  Check,
  X,
  PlusCircle,
  MessageSquare,
  Clock,
  CheckCircle2,
  AlertCircle,
  Send,
  QrCode,
  ShieldCheck
} from 'lucide-react';

interface FeedbacksProps {
  companyId: string;
  currentUser: User;
}

const Feedbacks: React.FC<FeedbacksProps> = ({ companyId, currentUser }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState<NPSCategory | 'ALL'>('ALL');
  const [selectedFeedback, setSelectedFeedback] = useState<Feedback | null>(null);
  const [showShareModal, setShowShareModal] = useState(false);
  const [copied, setCopied] = useState(false);

  const [internalNote, setInternalNote] = useState('');
  const [resolutionText, setResolutionText] = useState('');

  const feedbacks = useMemo(() => dataStore.getFeedbacks(companyId), [companyId, selectedFeedback]);
  const company = useMemo(() => dataStore.getCompany(companyId), [companyId]);

  // Perguntas internas para staff (não públicas)
  const staffQuestions = useMemo(() => 
    dataStore.getInternalQuestions(companyId, false).filter(q => !q.isPublic && q.active), 
  [companyId]);

  const filteredFeedbacks = useMemo(() => {
    return feedbacks
      .filter(f => {
        const matchesSearch = f.customerName.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesCategory = categoryFilter === 'ALL' || f.category === categoryFilter;
        return matchesSearch && matchesCategory;
      })
      .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }, [feedbacks, searchTerm, categoryFilter]);

  const currentCase = selectedFeedback ? dataStore.getCaseForFeedback(selectedFeedback.id) : null;

  const getEvaluationLink = () => {
    if (!company) return '';
    return `${window.location.origin}/avaliar/${company.trackingCode}`;
  };

  const handleCopyLink = () => {
    navigator.clipboard.writeText(getEvaluationLink());
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleCreateCase = () => {
    if (selectedFeedback) {
      dataStore.createCaseFromFeedback(selectedFeedback.id, companyId, internalNote, currentUser.name, currentUser.id);
      setInternalNote('');
      setSelectedFeedback({...selectedFeedback});
    }
  };

  const handleAddNote = () => {
    if (currentCase && internalNote.trim()) {
      dataStore.addCaseNote(currentCase.id, currentUser.id, currentUser.name, internalNote);
      setInternalNote('');
      setSelectedFeedback({...selectedFeedback!});
    }
  };

  const handleResolve = () => {
    if (currentCase && resolutionText.trim()) {
      dataStore.resolveCase(currentCase.id, resolutionText, currentUser.name, currentUser.id);
      setResolutionText('');
      setSelectedFeedback({...selectedFeedback!});
    }
  };

  const handleStaffResponse = (qId: string, value: any) => {
    if (selectedFeedback) {
      const updated = dataStore.updateFeedbackInternalResponses(selectedFeedback.id, { [qId]: value });
      if (updated) setSelectedFeedback({ ...updated });
    }
  };

  const CategoryTag = ({ category }: { category: NPSCategory }) => {
    const styles = {
      PROMOTER: 'bg-emerald-50 text-emerald-600 border-emerald-100',
      PASSIVE: 'bg-amber-50 text-amber-600 border-amber-100',
      DETRACTOR: 'bg-red-50 text-red-600 border-red-100'
    };
    const labels = { PROMOTER: 'Promotor', PASSIVE: 'Passivo', DETRACTOR: 'Detrator' };
    return (
      <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wider border ${styles[category]}`}>
        {labels[category]}
      </span>
    );
  };

  const RatingDotsView = ({ label, value, max = 10, onChange }: any) => {
    const getColorClass = (val: number) => {
      if (val === 0) return 'bg-slate-100';
      if (val <= (max * 0.3)) return 'bg-red-500';
      if (val <= (max * 0.6)) return 'bg-yellow-400';
      return 'bg-emerald-500';
    };

    return (
      <div className="space-y-2">
        <div className="flex justify-between text-[10px] font-black uppercase text-slate-400">
          <span>{label}</span>
          <span className={`font-black ${value === 0 ? 'text-slate-300' : value <= (max * 0.3) ? 'text-red-500' : value <= (max * 0.6) ? 'text-yellow-600' : 'text-emerald-500'}`}>{value || '—'}</span>
        </div>
        <div className="flex gap-1">
          {Array.from({ length: max }).map((_, i) => (
            <button 
              key={i} 
              disabled={!onChange}
              onClick={() => onChange && onChange(i + 1)}
              className={`flex-1 h-2.5 rounded-full transition-all ${
                i + 1 <= value ? getColorClass(value) : 'bg-slate-100'
              } ${onChange ? 'hover:scale-110 cursor-pointer' : ''}`}
            />
          ))}
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-6 relative h-full">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div className="flex flex-1 w-full md:max-w-md bg-white rounded-2xl border border-slate-200 px-4 py-2.5 items-center space-x-3 shadow-sm focus-within:border-primary transition-all">
          <Search className="w-5 h-5 text-slate-400" />
          <input 
            type="text" 
            placeholder="Buscar por nome do cliente..." 
            className="bg-transparent border-none outline-none text-sm w-full text-slate-900 font-medium"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex items-center space-x-3 w-full md:w-auto">
          <select 
            className="bg-white border border-slate-200 rounded-2xl px-4 py-2.5 text-sm font-bold text-slate-700 outline-none focus:border-primary shadow-sm"
            value={categoryFilter}
            onChange={(e) => setCategoryFilter(e.target.value as any)}
          >
            <option value="ALL">Todas Categorias</option>
            <option value="PROMOTER">Promotores</option>
            <option value="PASSIVE">Passivos</option>
            <option value="DETRACTOR">Detratores</option>
          </select>

          <button 
            onClick={() => setShowShareModal(true)}
            className="flex items-center space-x-2 bg-accent hover:bg-[#e65d00] text-white px-5 py-2.5 rounded-2xl font-bold shadow-lg shadow-accent/20 transition-all"
          >
            <Share2 className="w-4 h-4" />
            <span className="hidden sm:inline">Gerar Link</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-[32px] border border-slate-100 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50/50 border-b border-slate-100">
                <th className="px-8 py-5 text-[11px] font-black uppercase text-slate-400 tracking-widest">Data</th>
                <th className="px-8 py-5 text-[11px] font-black uppercase text-slate-400 tracking-widest">Cliente</th>
                <th className="px-8 py-5 text-[11px] font-black uppercase text-slate-400 tracking-widest text-center">Score Médio</th>
                <th className="px-8 py-5 text-[11px] font-black uppercase text-slate-400 tracking-widest text-center">NPS</th>
                <th className="px-8 py-5 text-[11px] font-black uppercase text-slate-400 tracking-widest text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredFeedbacks.length === 0 ? (
                <tr>
                  <td colSpan={5} className="px-8 py-20 text-center text-slate-400 font-medium">Nenhuma avaliação encontrada.</td>
                </tr>
              ) : (
                filteredFeedbacks.map((f) => (
                  <tr 
                    key={f.id} 
                    className="hover:bg-slate-50/80 transition-colors cursor-pointer group"
                    onClick={() => setSelectedFeedback(f)}
                  >
                    <td className="px-8 py-5 whitespace-nowrap text-sm font-semibold text-slate-500">
                      {new Date(f.createdAt).toLocaleDateString('pt-BR')}
                    </td>
                    <td className="px-8 py-5">
                      <div className="flex items-center space-x-3">
                        <div className="w-10 h-10 rounded-xl bg-slate-100 border border-slate-200 flex items-center justify-center font-black text-slate-400">
                          {f.customerName.charAt(0)}
                        </div>
                        <div>
                          <p className="text-sm font-bold text-slate-800">{f.customerName}</p>
                          <p className="text-[10px] text-slate-400 font-medium">{f.customerPhone}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-8 py-5 text-center">
                      <span className={`inline-flex items-center justify-center w-12 h-10 rounded-xl font-black text-sm border ${
                        f.averageScore >= 9 ? 'border-emerald-200 bg-emerald-50 text-emerald-600' : 
                        f.averageScore <= 6 ? 'border-red-200 bg-red-50 text-red-600' : 'border-amber-200 bg-amber-50 text-amber-600'
                      }`}>
                        {f.averageScore.toFixed(1)}
                      </span>
                    </td>
                    <td className="px-8 py-5 text-center">
                      <CategoryTag category={f.category} />
                    </td>
                    <td className="px-8 py-5 text-right">
                      <button className="p-2 text-slate-300 group-hover:text-primary transition-colors">
                        <ChevronRight className="w-5 h-5" />
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {selectedFeedback && (
        <div className="fixed inset-0 z-[110] flex justify-end overflow-hidden">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity" onClick={() => setSelectedFeedback(null)}></div>

          <div className="relative w-full max-width max-w-2xl bg-slate-50 shadow-2xl flex flex-col animate-in slide-in-from-right duration-500">
            <div className="bg-white px-8 py-6 border-b border-slate-200 flex items-center justify-between">
              <div className="flex items-center space-x-4">
                <div className="w-14 h-14 rounded-2xl bg-primary/10 text-primary flex items-center justify-center text-xl font-black">
                  {selectedFeedback.customerName.charAt(0)}
                </div>
                <div>
                  <h3 className="text-xl font-black text-slate-900">{selectedFeedback.customerName}</h3>
                  <div className="flex items-center gap-2 mt-1">
                    <CategoryTag category={selectedFeedback.category} />
                    <span className="text-xs font-bold text-slate-400">• Avaliado em {new Date(selectedFeedback.createdAt).toLocaleDateString('pt-BR')}</span>
                  </div>
                </div>
              </div>
              <button 
                onClick={() => setSelectedFeedback(null)}
                className="p-2 rounded-xl hover:bg-slate-100 text-slate-400 transition-all"
              >
                <X className="w-6 h-6" />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-8">
              <div className="grid grid-cols-2 gap-6">
                <div className="bg-white p-6 rounded-3xl border border-slate-200 space-y-4">
                  <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest flex items-center gap-2">
                    <UserIcon className="w-3 h-3" /> Perfil do Cliente
                  </h4>
                  <div className="space-y-3">
                    <div className="flex items-center gap-3">
                      <div className="p-2 bg-slate-100 rounded-lg"><Phone className="w-4 h-4 text-slate-500" /></div>
                      <span className="text-sm font-bold text-slate-700">{selectedFeedback.customerPhone}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <div className="p-2 bg-slate-100 rounded-lg"><Mail className="w-4 h-4 text-slate-500" /></div>
                      <span className="text-sm font-bold text-slate-700">{selectedFeedback.email || 'N/A'}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <div className="p-2 bg-slate-100 rounded-lg"><MapPin className="w-4 h-4 text-slate-500" /></div>
                      <span className="text-sm font-bold text-slate-700 uppercase text-[10px] tracking-tight">{selectedFeedback.profile}</span>
                    </div>
                  </div>
                </div>

                <div className="bg-white p-6 rounded-3xl border border-slate-200 flex flex-col justify-center items-center text-center">
                  <div className={`w-20 h-20 rounded-full border-4 flex items-center justify-center mb-2 ${
                    selectedFeedback.averageScore >= 9 ? 'border-emerald-500 text-emerald-600' : 
                    selectedFeedback.averageScore <= 6 ? 'border-red-500 text-red-600' : 'border-amber-500 text-amber-600'
                  }`}>
                    <span className="text-3xl font-black">{selectedFeedback.averageScore.toFixed(1)}</span>
                  </div>
                  <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Score de Experiência</p>
                </div>
              </div>

              {/* Seção de Métricas Internas (Staff) */}
              <div className="bg-indigo-50/30 p-8 rounded-[2.5rem] border border-indigo-100 space-y-6">
                <div className="flex items-center justify-between">
                  <h4 className="text-[10px] font-black uppercase text-indigo-400 tracking-[0.2em] flex items-center gap-2">
                    <ShieldCheck className="w-4 h-4" /> Métricas Internas de Staff
                  </h4>
                  <span className="text-[8px] font-black uppercase bg-indigo-100 text-indigo-500 px-2 py-0.5 rounded">Visível apenas para equipe</span>
                </div>

                <div className="space-y-8">
                   {staffQuestions.length === 0 ? (
                     <p className="text-center text-[10px] font-bold text-slate-400 uppercase py-4">Nenhuma métrica interna configurada.</p>
                   ) : (
                     staffQuestions.map(q => (
                       <div key={q.id}>
                         {q.type === 'YES_NO' ? (
                            <div className="space-y-3">
                              <label className="text-[11px] font-bold text-slate-700 uppercase">{q.text}</label>
                              <div className="flex gap-2">
                                {['SIM', 'NÃO'].map(opt => (
                                  <button
                                    key={opt}
                                    onClick={() => handleStaffResponse(q.id, opt)}
                                    className={`flex-1 py-3 rounded-xl font-black text-[10px] transition-all border-2 ${
                                      selectedFeedback.internalResponses?.[q.id] === opt 
                                        ? 'bg-indigo-500 border-indigo-500 text-white shadow-lg' 
                                        : 'bg-white border-slate-100 text-slate-400'
                                    }`}
                                  >
                                    {opt}
                                  </button>
                                ))}
                              </div>
                            </div>
                         ) : q.type === 'TEXT' ? (
                            <div className="space-y-2">
                              <label className="text-[11px] font-bold text-slate-700 uppercase">{q.text}</label>
                              <textarea 
                                value={selectedFeedback.internalResponses?.[q.id] || ''}
                                onChange={(e) => handleStaffResponse(q.id, e.target.value)}
                                className="w-full h-20 p-4 bg-white border border-slate-100 rounded-2xl text-sm outline-none focus:border-indigo-500 font-medium text-slate-900"
                                placeholder="Observação interna..."
                              />
                            </div>
                         ) : (
                           <RatingDotsView 
                             label={q.text} 
                             max={q.type === 'SCALE_5' ? 5 : 10}
                             value={selectedFeedback.internalResponses?.[q.id] || 0}
                             onChange={(v: number) => handleStaffResponse(q.id, v)}
                           />
                         )}
                       </div>
                     ))
                   )}
                </div>
              </div>

              <div className="bg-white p-6 rounded-3xl border border-slate-200 space-y-8">
                <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest flex items-center gap-2">
                  <Star className="w-3 h-3" /> Notas do Cliente
                </h4>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  <RatingDotsView label="Atendimento" value={selectedFeedback.scores.service} />
                  <RatingDotsView label="Comida" value={selectedFeedback.scores.food} />
                  <RatingDotsView label="Bebidas" value={selectedFeedback.scores.drinks} />
                  <RatingDotsView label="Ambiente" value={selectedFeedback.scores.structure} />
                </div>
                <div className="pt-6 border-t border-slate-50">
                  <p className="text-[10px] font-black uppercase text-slate-400 mb-2">Observação do Cliente:</p>
                  <p className="text-sm text-slate-700 italic bg-slate-50 p-4 rounded-2xl border border-slate-100 leading-relaxed">
                    "{selectedFeedback.observation || 'O cliente não deixou comentários adicionais.'}"
                  </p>
                </div>
              </div>

              <div className="bg-[#002e6b] rounded-3xl p-8 shadow-xl shadow-[#002e6b]/20 text-white space-y-6">
                <div className="flex items-center justify-between">
                  <h4 className="text-lg font-black flex items-center gap-2">
                    <AlertCircle className="w-5 h-5 text-accent" />
                    Painel de Resolução
                  </h4>
                  {currentCase && (
                    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border ${
                      currentCase.status === 'RESOLVED' ? 'bg-emerald-500/20 border-emerald-500 text-emerald-300' : 'bg-accent/20 border-accent text-accent'
                    }`}>
                      {currentCase.status === 'RESOLVED' ? 'Resolvido' : 'Caso em Aberto'}
                    </span>
