export interface Company {
  id: string;
  trackingCode: string;
  name: string;
  description?: string;
  category: string;
  city: string;
  logo: string;
  experienceScore: number;
  cnpj?: string;
  address?: string;
  employees?: string;
  phone?: string;
  email?: string;
  trialEndDate?: string;
  startDate?: string;
  nextBillingDate?: string;
  churnDate?: string;
  monthlyValue: number;
  implementationValue: number;
  plan: PlanType;
  status: AccountStatus;
