export interface Feedback {
  id: string;
  companyId: string;
  companyTrackingCode: string;
  customerId: string;
  customerName: string;
  customerPhone: string;
  howKnown: string;
  channel?: FeedbackChannel;
  scores: {
    service: number;
    food: number;
    drinks: number;
    structure: number;
  };
